INSERT INTO `anivoc_action_effects` (`id`, `name`, `description`, `created_at`, `updated_at`, `is_ingredient`) VALUES
(1, 'Speed Lines (Forward)', 'Horizontal lines radiating outward from the character or converging toward them from the edges. Suggests rapid forward motion or the camera rushing toward a subject. Use as: charging attack, fast approach, zoom-in effect.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(2, 'Speed Lines (Radial)', 'Lines radiating outward from a central point (usually the character) in all directions like a starburst. Suggests an explosion of movement or energy from that point. Use as: power release, impact aftermath, \"feel the force\" moment.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(3, 'Motion Blur Trail', 'The character\'s body has a ghostly afterimage trail behind them in the direction of movement. Multiple semi-transparent copies suggest extreme speed. Use as: fast movement, teleportation blur, dodge in slow motion.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(4, 'Wind Lines (Directional)', 'Curved or straight lines in a single direction suggesting strong wind blowing through the scene. Hair and loose clothing stream with it. Use as: high-speed movement through air, rooftop wind, dramatic arrival.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(5, 'Impact Starburst', 'A sharp, jagged star/burst shape at the point of contact. Lines radiate outward from the impact point. The classic \"hit\" visual. Use as: punch landing, collision, strike contact, any physical impact.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(6, 'Shockwave Ring', 'Concentric rings expanding outward from an impact or power release point. Visible distortion in the air. Ground may crack beneath. Use as: massive strike, power release, landing from a height, explosion center.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(7, 'Crack Lines (Ground/Surface)', 'Spider-web pattern of cracks radiating from a point on the ground or a surface. Dust or debris rising. Use as: heavy landing, stomp attack, weight of power, breaking through a surface.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(8, 'Debris Explosion', 'Chunks of ground, rubble, or objects flying outward from a central point. Dust cloud billowing. Fragments at various sizes. Use as: destruction, impact zone, \"that broke something\", environmental damage.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(9, 'Dust Cloud (Landing)', 'A billowing cloud of dust and particles expanding outward at ground level. Character silhouette visible within or emerging from it. Use as: dramatic landing, arrival from height, obscuring the moment before reveal.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(10, 'Aura Glow (Single Color)', 'A solid-color luminous glow surrounding the character\'s body. Edges are soft and radiating. Color indicates type: blue = calm/ice, red = rage/fire, gold = hero/divine, purple = evil/magic. Use as: power state, ability active, emotional intensity made visible.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(11, 'Aura Glow (Dual Color)', 'Two-tone aura — one color close to the body, another at the outer edge. Often indicates conflict (inner vs outer self) or transformation in progress. Use as: power struggle, transformation mid-point, corruption vs purity.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(12, 'Energy Particles (Rising)', 'Small glowing particles floating upward around the character like embers or fireflies. Gentle, ambient energy. Use as: power building slowly, magical atmosphere, peaceful power state, aftermath of ability use.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(13, 'Energy Particles (Explosive)', 'Particles shooting outward in all directions from the character at high speed. Dense and bright. Use as: power burst, ability activation, transformation peak, energy release.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(14, 'Magic Circle (Ground)', 'Geometric/arcane circle pattern on the ground beneath the character, glowing with magical light. Runes, sigils, or geometric patterns visible. Use as: spell casting, summoning ritual, standing on sacred ground, power channeling.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(15, 'Magic Circle (Floating)', 'Same arcane circle pattern but floating in the air — in front of, behind, or around the character. Use as: shield formation, projectile launch, ability targeting, defensive barrier.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(16, 'Fire Burst', 'Flames erupting from a point — from hands, weapon, or the ground. Flames are sharp, dynamic, and directional. Heat shimmer visible. Use as: fire attack, explosion, elemental power, rage manifestation.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(17, 'Ice Shatter', 'Crystalline ice forming or shattering around a point. Sharp geometric shards. Frost particles in the air. Cold color palette (blues/whites). Use as: ice attack, freezing, cold power, defensive barrier breaking.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(18, 'Lightning Arc', 'Jagged white/blue electrical arcs crackling between points or along a weapon/body. Bright white core with blue/purple edges. Small sparks and particles. Use as: electric attack, overload, charged weapon, shock effect.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(19, 'Wind Slash Marks', 'Crescent-shaped invisible-force marks in the air — shown as distortion lines or light-blue curved slashes. Use as: ranged wind attack, blade strike trail, cutting force visualization.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(20, 'Darkness Tendrils', 'Shadow-like tendrils or wisps reaching outward from a dark source — coiling, grasping, or spreading. Dark purple/black with faint luminous edges. Use as: dark power, shadow attack, corruption spreading, void energy.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(21, 'Sweat Drops (Nervous)', 'Small teardrop-shaped sweat drops flying off the face or body. Usually 2-4 drops placed at temples or forehead. Use as: nervousness, effort, \"oh no\", comedic tension indicator.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(22, 'Stars After Hit', 'Small cartoon star shapes orbiting around the character\'s head after being struck. Classic knock-out visual. Use as: comedic hit, being punched, \"I see stars\", slapstick reaction.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(23, 'Comedic Impact (Flat)', 'Character is shown completely flattened — squished into a 2D shape from an impact. Perfectly flat against a surface. Use as: slapstick hit, comedic squish, \"pancake\" moment, cartoon physics.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(24, 'Pain Sparkles', 'Small sparkle or star effects around the point of pain — often on the face after being hit, or on an injured limb. Bright, sharp, and painful-looking. Use as: minor injury indicator, \"ouch\", comedic pain sell.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(25, 'Exaggerated Sound Effect Kanji', 'Large Japanese onomatopoeia text rendered as a visual effect overlaid on the action. Examples: パン (pan/slap), ガン (gan/heavy hit), ポチャン (pochan/splash). Use as: comedic timing punctuation, slapstick impact, manga-style action beat.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(26, 'Smoke/Mist Layer', 'A layer of smoke or mist at ground level or filling the scene. Partially obscures lower bodies or backgrounds. Use as: mysterious atmosphere, post-explosion, fog of war, dramatic entrance concealment.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(27, 'Lens Flare Burst', 'A bright light source creating a starburst flare effect — rays radiating from a point with secondary reflections and color fringing. Use as: dramatic light source, power reveal, sun behind character, flashback trigger.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(28, 'Screen Shake Lines', 'The entire frame appears to be vibrating — drawn with slight displacement or multiple overlapping outlines of the same scene. Use as: earthquake, massive impact nearby, power too large to contain, trembling ground.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(29, 'Rain Overlay', 'Diagonal rain streaks across the entire frame. Can be heavy (thick streaks, dark atmosphere) or light (fine mist, romantic). Use as: mood setter, emotional scene, tragic moment, washing-away metaphor.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(30, 'Cherry Blossom Petals', 'Sakura petals drifting through the frame — from one direction or floating freely. Pink/white against any background. Use as: peaceful moment, farewell, spring/renewal, romantic scene, tragic beauty.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1);
INSERT INTO `anivoc_backgrounds` (`id`, `name`, `description`, `created_at`, `updated_at`, `is_ingredient`) VALUES
(1, 'The \"Speed Line Tunnel\" (Concentrated Focus)', 'The classic radiating lines showing intense focus or rapid motion. Visual Description: Straight lines radiating outward from a central point (usually the character or focal point). Lines are typically black or dark on a lighter background, or white on dark. Density increases toward the edges. Variants: Straight Radial (lines from exact center), Curved Radial (lines curve showing rotation), Asymmetric Burst (lines concentrated on one side). Color Schemes: Black on white (manga style), white on black (night/dramatic), colored lines matching scene mood. Context: Moment of realization, sudden impact, intense concentration, speed/motion emphasis, or dramatic declaration. Emotional Weight: Intensity, focus, urgency, dramatic emphasis.', '2026-01-27 00:02:03', '2026-01-27 00:02:03', 1),
(2, 'The \"Action Blur Streaks\" (Directional Motion)', 'Horizontal or directional streaks showing movement through space. Visual Description: Parallel streaks moving in the direction of motion. Can be simple lines or smeared/blurred versions of the background itself. Often mixed with motion blur on the character. Variants: Horizontal Speed (left-right movement), Vertical Drop (falling or launching upward), Diagonal Charge (dynamic attack or dodge), Curved Chase (following a curved path). Color Schemes: Blurred versions of environment colors, or simplified to two-tone streaks. Context: Running, flying, vehicles in motion, charging attacks, dodging. Emotional Weight: Speed, urgency, excitement, pursuit.', '2026-01-27 00:02:03', '2026-01-27 00:02:03', 1),
(3, 'The \"Impact Shockwave\" (Point of Contact)', 'Concentric circles or explosive patterns from a collision point. Visual Description: Circular or semi-circular rings emanating from impact point. Can be perfect circles or distorted by the force direction. Often combined with debris, dust, or light. Variants: Perfect Rings (clean concentric circles for controlled power), Irregular Burst (chaotic explosive pattern for wild power), Ground Shockwave (ripples spreading across ground surface), Air Pressure Wave (visible distortion in the air itself). Color Schemes: White/yellow for energy impacts, brown/grey for physical impacts, element-colored for magic. Context: Punch landing, explosion, magical attack hit, sonic boom, power clash. Emotional Weight: Power, force, impact magnitude, overwhelming strength.', '2026-01-27 00:02:03', '2026-01-27 00:02:03', 1),
(4, 'The \"Vortex Spiral\" (Rotation & Power)', 'Spiraling patterns showing rotation, suction, or overwhelming force. Visual Description: Lines or shapes spiraling inward toward center (suction/absorption) or outward from center (explosion/expansion). Can be smooth curves or jagged energy. Variants: Inward Spiral (being pulled/absorbed), Outward Spiral (explosive release), Double Spiral (two opposing forces creating turbulence), Galaxy Spiral (cosmic scale, slower elegant rotation). Color Schemes: Monochrome for drama, multiple colors for chaotic energy, single color for elemental power. Context: Teleportation, summoning, black hole effects, tornado, drilling attacks, whirlpool. Emotional Weight: Inevitability, overwhelming force, being drawn in, chaos.', '2026-01-27 00:02:03', '2026-01-27 00:02:03', 1),
(5, 'The \"Fracture Web\" (Breaking Point)', 'Cracks spreading from impact showing structural failure. Visual Description: Spider-web pattern of cracks radiating from a central impact point. Cracks can be thin lines or gaping fissures. Often shown on ground, walls, or barriers. Variants: Surface Crack (thin lines on surface only), Deep Fissure (wide gaps showing depth), Shatter Pattern (about to completely break apart), Reality Crack (breaking the fabric of space itself). Color Schemes: Black lines on surface color, or glowing light bleeding through cracks. Context: Breaking through defenses, shattering barriers, ground-shattering impact, reality breaking. Emotional Weight: Destruction, breakthrough, limits exceeded, breaking point.', '2026-01-27 00:02:03', '2026-01-27 00:02:03', 1),
(6, 'The \"Sakura Scatter\" (Transience & Beauty)', 'Cherry blossom petals drifting, the most iconic anime background. Visual Description: Pink or white petals floating through the air, usually moving horizontally or diagonally across frame. Can be sparse or dense. Petals shown with simple petal shape or detailed. Variants: Gentle Drift (slow, peaceful movement), Sudden Gust (burst of petals in wind), Carpet of Petals (ground covered in fallen petals), Single Petal Focus (one petal\'s journey emphasized). Color Schemes: Soft pink and white, sometimes with green leaves, golden sunlight filtering through. Context: Spring scenes, goodbyes, new beginnings, romantic moments, contemplation of impermanence. Emotional Weight: Beauty, transience, nostalgia, bittersweet, Japanese aesthetic (mono no aware).', '2026-01-27 00:02:03', '2026-01-27 00:02:03', 1),
(7, 'The \"Storm Approach\" (Gathering Tension)', 'Dark clouds gathering, showing impending crisis. Visual Description: Heavy, dark clouds accumulating in sky. Can show progression from clear to covered. Often with increasing wind effects on environment. Lightning optional but common. Variants: Distant Storm (clouds on horizon, threat approaching), Overhead Darkness (sky completely covered), Swirling Vortex (storm clouds rotating - supernatural), Breaking Storm (first drops falling, tension about to break). Color Schemes: Dark greys and blacks, sometimes purple or green tint for supernatural, bright white lightning. Context: Tension building, villain approaching, disaster coming, emotional turmoil manifesting, before the battle. Emotional Weight: Dread, inevitability, gathering force, oppression.', '2026-01-27 00:02:03', '2026-01-27 00:02:03', 1),
(8, 'The \"Rain Veil\" (Melancholy & Cleansing)', 'Rain creating a visual and emotional barrier. Visual Description: Vertical lines of rain, can be light drizzle (thin lines) or heavy downpour (thick, dense lines). Often shown with puddles, reflections, and characters getting wet. Variants: Light Drizzle (gentle, contemplative rain), Heavy Downpour (intense, obscuring rain), Backlit Rain (rain visible against light source), Rain Curtain (rain so heavy it creates a solid-looking wall). Color Schemes: Grey tones, sometimes blue-grey, with white streaks for rain, reflections adding color. Context: Sadness, acceptance, cleansing/renewal, hiding tears, dramatic confrontation, washing away the past. Emotional Weight: Melancholy, catharsis, isolation, washing away, renewal.', '2026-01-27 00:02:03', '2026-01-27 00:02:03', 1),
(9, 'The \"Sunset Gradient\" (Endings & Nostalgia)', 'The golden hour palette showing transitions. Visual Description: Sky transitioning from yellow/orange at horizon to pink/purple at top. Often includes sun as silhouette element. Long shadows. Everything bathed in warm light. Variants: Peaceful Sunset (soft gradients, calm clouds), Dramatic Sunset (intense colors, dramatic cloud formations), Last Light (sun just disappearing, final moments), Twilight Fade (sunset transitioning to night, deep purples). Color Schemes: Orange, pink, purple, yellow, gold, with dark silhouettes. Context: End of day/arc/journey, reflection on past, parting, promise for tomorrow, peaceful endings. Emotional Weight: Nostalgia, bittersweetness, closure, peaceful acceptance, hope.', '2026-01-27 00:02:03', '2026-01-27 00:02:03', 1),
(10, 'The \"Snow Silence\" (Muffled Stillness)', 'Falling snow creating isolation and quiet. Visual Description: White flakes falling against darker background. Can accumulate on surfaces. Often softens all colors and muffles the mood. Breath visible as mist. Variants: Gentle Snowfall (large, slow flakes, peaceful), Blizzard (heavy, obscuring snow, harsh), First Snow (just beginning to fall, magical), Deep Snow (already accumulated, world transformed). Color Schemes: White snow against blue-grey or dark backgrounds, muted colors overall. Context: Isolation, purity, death/stillness, new beginnings (blank slate), quiet conversations, loneliness. Emotional Weight: Isolation, purity, silence, cold (emotional or literal), stillness.', '2026-01-27 00:02:03', '2026-01-27 00:02:03', 1),
(11, 'The \"Spotlight Void\" (Focused Isolation)', 'Character in circle of light, everything else black. Visual Description: Character or focal point illuminated, surrounded by pure black or very dark background. Sharp boundary between light and dark. Sometimes with visible light beam source. Variants: Single Spotlight (one character alone), Multiple Spots (several characters in separate pools), Narrowing Spotlight (light area shrinking - pressure increasing), Expanding Spotlight (light area growing - hope/understanding spreading). Color Schemes: Usually stark white light on black, or warm/cool toned light. Context: Interrogation, confession, internal monologue, making a stand, being judged, moment of truth. Emotional Weight: Isolation, focus, pressure, judgment, truth revealing.', '2026-01-27 00:02:03', '2026-01-27 00:02:03', 1),
(12, 'The \"Sparkle Screen\" (Joy Overflow)', 'Entire background becomes sparkles and light. Visual Description: Background transforms into field of sparkles, stars, or light particles. Can completely replace normal setting. Often with bokeh effect (soft circular lights). Variants: Dense Sparkle Field (countless tiny sparkles), Floating Orbs (larger, softer light spheres), Star Field (pointed star shapes), Rainbow Sparkle (multi-colored light particles). Color Schemes: White and gold most common, pink for romance, rainbow for maximum joy. Context: Extreme happiness, love revelation, magical moments, idealized vision, fantasy sequence. Emotional Weight: Joy, love, idealization, magical, dreamlike.', '2026-01-27 00:02:03', '2026-01-27 00:02:03', 1),
(13, 'The \"Gradient Mood Wash\" (Emotional Color)', 'Entire scene tinted with emotional color. Visual Description: Solid color gradient (usually top to bottom or radial) overlaying or replacing background. Simple but powerfully communicates mood. Variants: Vertical Gradient (color shift from top to bottom), Radial Gradient (color radiating from or converging to character), Diagonal Gradient (dynamic angle showing transition), Dual Tone (sharp divide between two colors - conflict). Color Schemes: Red = anger/passion/danger, Blue = sadness/cold/calm, Purple = mystery/supernatural, Yellow = happiness/energy, Green = sickness/envy/nature, Orange = warmth/nostalgia. Context: Intense emotional moments, internal feelings visualized, simplified dramatic scenes. Emotional Weight: Direct emotional communication, no subtlety needed.', '2026-01-27 00:02:03', '2026-01-27 00:02:03', 1),
(14, 'The \"Pattern Break\" (Reality Shift)', 'Realistic background suddenly becomes abstract patterns. Visual Description: Normal detailed background abruptly shifts to simplified patterns - stripes, dots, geometric shapes, manga screentones. Indicates shift from external reality to internal state. Variants: Stripe Pattern (vertical or diagonal lines), Dot Pattern (screentone dots - manga technique), Geometric Chaos (random shapes), Floral Pattern (flowers and organic shapes - usually positive). Color Schemes: Often monochrome or limited palette, high contrast. Context: Comedy moments, extreme shock, entering fantasy/internal world, breaking the fourth wall. Emotional Weight: Unreality, comedy, shock, entering subjective space.', '2026-01-27 00:02:03', '2026-01-27 00:02:03', 1),
(15, 'The \"Negative Space Void\" (Emptiness Emphasis)', 'Vast emptiness emphasizing isolation or contemplation. Visual Description: Character surrounded by huge amounts of empty space. Minimal detail, often just a solid color or very simple gradient. Character appears small in frame. Variants: White Void (pure white emptiness - death, heaven, nothingness), Black Void (pure black emptiness - despair, space, isolation), Colored Void (single color field - specific emotion), Minimal Horizon (just a horizon line in emptiness). Color Schemes: Usually monochrome - white, black, or single solid color. Context: Loneliness, contemplation, death/afterlife, internal mental space, insignificance vs. vastness. Emotional Weight: Isolation, emptiness, contemplation, insignificance, peace or despair.', '2026-01-27 00:02:03', '2026-01-27 00:02:03', 1),
(16, 'The \"Dappled Light Forest\" (Natural Peace)', 'Sunlight filtering through leaves creating light patterns. Visual Description: Light breaking through tree canopy in shafts or dappled patterns. Moving leaf shadows. Green-dominated palette with golden light accents. Variants: Morning Forest (fresh light, misty, awakening), Midday Dapple (strong light contrast, warm), Enchanted Grove (magical quality, glowing elements), Dense Canopy (mostly shadow with rare light breaks). Color Schemes: Various greens, golden sunlight, brown earth tones. Context: Natural settings, peaceful moments, encounters with nature, spiritual places, beginning journeys. Emotional Weight: Peace, natural beauty, grounding, spirituality, beginning.', '2026-01-27 00:02:03', '2026-01-27 00:02:03', 1),
(17, 'The \"Flowing Water\" (Time & Change)', 'Rivers, streams, or water features showing flow and time. Visual Description: Water in motion - flowing, cascading, or streaming. Can be calm flow or rushing rapids. Reflections and light on water surface important. Variants: Gentle Stream (peaceful, contemplative flow), Rushing River (powerful, unstoppable force), Waterfall (dramatic descent, barrier), Still Pond (reflective, meditative - technically no flow but water). Color Schemes: Blues and aquas with white foam/spray, reflections of surroundings. Context: Passage of time, cleansing, journey metaphor, life\'s flow, can\'t go back (river flows one way). Emotional Weight: Flow, change, time passing, cleansing, journey.', '2026-01-27 00:02:03', '2026-01-27 00:02:03', 1),
(18, 'The \"Flower Field Expanse\" (Life & Beauty)', 'Wide field of flowers showing vitality and peace. Visual Description: Expansive field of flowers, often viewed from within or as vista. Flowers can be specific type or mixed. Usually shown with gentle wind movement. Variants: Sunflower Field (bright, optimistic, all facing same way), Wildflower Meadow (diverse, natural, untamed), Rose Garden (romantic, cultivated, thorns with beauty), Lotus Pond (spiritual, Eastern philosophy, purity). Color Schemes: Vibrant multi-colors or specific flower color dominating, green stems/leaves, blue sky. Context: Peace, vitality, hope, romance, spiritual moments, life flourishing, memory of happier times. Emotional Weight: Life, beauty, hope, peace, vitality, romance.', '2026-01-27 00:02:03', '2026-01-27 00:02:03', 1),
(19, 'The \"Mountain Vista\" (Scale & Journey)', 'Distant mountains showing scope and challenge. Visual Description: Mountain ranges visible in distance, often with atmospheric perspective (hazier in distance). Can be viewed from below or from another peak. Scale emphasized. Variants: Distant Goal (mountain to be reached), Peak Achieved (view from summit), Mountain Range (multiple peaks, journey ahead), Sacred Mountain (single imposing peak with spiritual significance). Color Schemes: Blue-purple atmospheric perspective, white snow caps, browns and greys for rock. Context: Challenge ahead, journey\'s scope, achievement, perspective on how far they\'ve come, spiritual quests. Emotional Weight: Challenge, scope, achievement, journey, spiritual elevation.', '2026-01-27 00:02:03', '2026-01-27 00:02:03', 1),
(20, 'The \"Starfield Night\" (Infinity & Wonder)', 'Night sky filled with stars showing vastness. Visual Description: Dark sky (deep blue to black) filled with stars of varying sizes and brightness. Can include Milky Way band, shooting stars, or nebulae. Variants: Clear Starfield (simple stars on dark sky), Milky Way Band (galaxy visible as cloudy band), Shooting Star (wishes, fate, momentary magic), Nebula Sky (colorful cosmic clouds - more fantastical). Color Schemes: Deep blues and blacks, white stars, sometimes purple/pink/blue nebula colors. Context: Night scenes, contemplation of vastness, infinity, dreams, wishes, cosmic perspective, smallness. Emotional Weight: Wonder, vastness, dreams, infinity, smallness, perspective.', '2026-01-27 00:02:03', '2026-01-27 00:02:03', 1),
(21, 'The \"Neon Night City\" (Modern Energy)', 'City at night with neon lights and signs. Visual Description: Urban nightscape with bright neon signs, lit windows, street lights. Reflections on wet streets common. High contrast between bright lights and dark shadows. Variants: Busy Street (crowded with lights and people), Empty Alley (lonely despite urban setting), Rooftop View (looking down at city lights), Rainy Neon (rain intensifying light reflections). Color Schemes: Bright neons (pink, blue, green, yellow) against dark backgrounds, lots of reflection. Context: Urban life, loneliness in crowds, cyberpunk settings, nightlife, modern isolation, energy of city. Emotional Weight: Energy, loneliness, modernity, artificial, nocturnal life.', '2026-01-27 00:02:03', '2026-01-27 00:02:03', 1),
(22, 'The \"School Hallway\" (Youth & Routine)', 'The quintessential anime setting - school corridor. Visual Description: Long hallway with windows on one side, classroom doors on other. Afternoon light streaming through windows creating rectangle patterns. Often empty or with distant figures. Variants: After School Empty (quiet, nostalgic), Between Classes (busy with students), Morning Light (fresh, beginning), Sunset Corridor (orange light, day ending). Color Schemes: Neutral walls (cream, white), blue sky through windows, wooden floors, golden sunlight. Context: School life, youth, routine, private conversations, memories of school days, isolation vs. belonging. Emotional Weight: Nostalgia, youth, routine, belonging or isolation, formative years.', '2026-01-27 00:02:03', '2026-01-27 00:02:03', 1),
(23, 'The \"Abandoned Building\" (Decay & Past)', 'Ruined or empty structure showing neglect. Visual Description: Decaying structure - broken windows, peeling paint, overgrown plants, rubble. Light streaming through gaps. Nature reclaiming space. Variants: Recent Abandonment (still mostly intact), Advanced Decay (nature taking over), Post-Apocalyptic (catastrophic damage), Haunted Atmosphere (supernatural implications). Color Schemes: Muted, desaturated colors, dust browns and greys, green plant intrusion, harsh light through breaks. Context: Past glory gone, meeting places for outcasts, hideouts, confronting past, post-disaster, haunted. Emotional Weight: Decay, past, abandonment, haunting, nature\'s persistence.', '2026-01-27 00:02:03', '2026-01-27 00:02:03', 1),
(24, 'The \"Train Platform\" (Transition Spaces)', 'Railway station platform as liminal space. Visual Description: Platform with tracks, often with train present or arriving. Can be busy or empty. Benches, signs, overhead structures. Sense of coming/going. Variants: Waiting Platform (anticipation, stillness), Arriving Train (meeting, beginning), Departing Train (goodbye, ending), Empty Night Platform (loneliness, missing the train). Color Schemes: Industrial colors - greys, blues, metal, with bright train colors or advertising. Context: Goodbyes, meetings, journeys beginning/ending, running late, missing someone, transition moments. Emotional Weight: Transition, goodbye, meeting, journey, timing (too late/too early).', '2026-01-27 00:02:03', '2026-01-27 00:02:03', 1),
(25, 'The \"Rooftop Refuge\" (Elevated Escape)', 'School or building rooftop as private space. Visual Description: Flat rooftop with fence, often with view of city or sky beyond. Water tower or ventilation structures. Open sky dominant. Wind effect common. Variants: School Rooftop (chain fence, lunch spot), Building Summit (higher view, more dramatic), Sunset Rooftop (orange sky, day ending), Starlit Rooftop (night, intimate). Color Schemes: Concrete greys, metal fence, expansive sky (blue or sunset colors), clouds. Context: Private conversations, confessions, escape from below, elevated perspective, romantic moments, contemplation. Emotional Weight: Escape, elevation, privacy, openness, between earth and sky.', '2026-01-27 00:02:03', '2026-01-27 00:02:03', 1),
(26, 'The \"Void Between Worlds\" (Liminal Cosmic)', 'Non-space between realities. Visual Description: Abstract space that\'s neither sky nor ground. Floating platforms, geometric shapes, impossible perspectives. Colors often unnatural. Variants: Geometric Void (angular shapes floating), Cosmic Between (stars but wrong somehow), White Liminal (bright undefined space), Dark Chaos (swirling dark unreality). Color Schemes: Often monochrome with bright accents, or impossible color combinations. Context: Dream sequences, between dimensions, mental spaces, supernatural confrontations, nowhere places. Emotional Weight: Unreality, disorientation, supernatural, between states.', '2026-01-27 00:02:03', '2026-01-27 00:02:03', 1),
(27, 'The \"Inner Mind Palace\" (Psyche Visualization)', 'Visual representation of mental space. Visual Description: Stylized representation of consciousness - can be architecture, abstract space, or symbolic landscape. Often personal symbols incorporated. Variants: Memory Hall (corridor of memories), Fractured Mind (broken/shattered space), Organized Palace (neat mental filing system), Chaotic Swirl (disordered thoughts visualized). Color Schemes: Highly variable - can reflect mental state or personality. Context: Psychic battles, therapy/introspection, memory exploration, mental breakdown/healing. Emotional Weight: Internal, psychological, self-exploration, mental state.', '2026-01-27 00:02:03', '2026-01-27 00:02:03', 1),
(28, 'The \"Ethereal Light Realm\" (Divine/Heavenly)', 'Bright, pure space suggesting heaven or divine. Visual Description: Predominantly white or golden space. Soft light seeming to come from everywhere. Often includes floating particles, feathers, or gentle rays. Cloudy or misty. Variants: Pure White (heaven, death, purity), Golden Divine (God\'s presence, holy), Soft Cloud (peaceful afterlife), Angelic Realm (feathers, wings, halos). Color Schemes: White, gold, soft pastels, light blues. Context: Near-death, divine encounters, heavenly realms, ultimate peace, post-death, angelic appearances. Emotional Weight: Divine, pure, peaceful, death (peaceful), transcendence.', '2026-01-27 00:02:03', '2026-01-27 00:02:03', 1),
(29, 'The \"Shadow Dimension\" (Dark Realm)', 'Dark, oppressive supernatural space. Visual Description: Predominantly dark with unnatural shadows. May include red or purple accents. Threatening shapes in darkness. Gravity feels wrong. Variants: Pure Darkness (void of demon realm), Red Hell (demonic, torture, punishment), Purple Nightmare (dream horror, fear), Writhing Shadows (alive darkness). Color Schemes: Blacks, dark purples, reds, minimal light sources. Context: Demon realm, nightmares, dark magic, villain\'s domain, corruption spreading, hell. Emotional Weight: Fear, evil, corruption, nightmare, demonic.', '2026-01-27 00:02:03', '2026-01-27 00:02:03', 1),
(30, 'The \"Glitch Reality\" (Digital Breakdown)', 'Reality experiencing digital errors. Visual Description: Normal background corrupted with digital artifacts - pixelation, color separation, missing chunks, repeated sections, scan lines. Variants: Minor Glitch (small artifacts appearing), Major Corruption (large portions distorted), Reality Tear (digital and real mixing), System Crash (complete breakdown). Color Schemes: Normal colors corrupted with RGB separation, blacks, whites, error colors. Context: Virtual reality failing, simulation hypothesis, AI perspective, reality hacking, matrix breaking. Emotional Weight: Unreality, artificial, system failure, truth revealing.', '2026-01-27 00:02:03', '2026-01-27 00:02:03', 1);
INSERT INTO `anivoc_categories` (`id`, `name`, `table_name`, `description`, `item_count`, `is_complete`, `created_at`, `updated_at`) VALUES
(1, 'Expressions', 'anivoc_expressions', 'Facial expressions and emotional states (Volumes 1-20)', 100, 1, '2026-01-26 23:26:07', '2026-01-26 23:26:07'),
(2, 'Backgrounds', 'anivoc_backgrounds', 'Background techniques for atmosphere and emotion (6 volumes)', 30, 1, '2026-01-26 23:26:07', '2026-01-26 23:26:07'),
(3, 'Motion & Impact', 'anivoc_motion_impact', 'Motion lines and impact effects showing dynamics', 27, 0, '2026-01-26 23:26:07', '2026-01-26 23:26:07'),
(4, 'Lighting Schemes', 'anivoc_lighting', 'Lighting techniques for mood and atmosphere', 29, 0, '2026-01-26 23:26:07', '2026-01-26 23:26:07'),
(5, 'Transitions & Cuts', 'anivoc_transitions', 'Scene change techniques and visual flow', 25, 0, '2026-01-26 23:26:07', '2026-01-26 23:26:07'),
(6, 'Color Coding', 'anivoc_color_coding', 'Color psychology and palette storytelling', 46, 0, '2026-01-26 23:26:07', '2026-01-26 23:26:07'),
(7, 'Scale & Perspective', 'anivoc_scale_perspective', 'Size relationships and spatial tricks (3 volumes)', 40, 1, '2026-01-26 23:26:07', '2026-01-26 23:26:07'),
(8, 'Symbolic Objects', 'anivoc_symbolic_objects', 'Objects with specific emotional/narrative meaning', 0, 0, '2026-01-26 23:26:07', '2026-01-26 23:26:07'),
(9, 'Text & Graphics', 'anivoc_text_graphics', 'Text as visual element and graphic overlays', 0, 0, '2026-01-26 23:26:07', '2026-01-26 23:26:07'),
(10, 'Panel & Frame', 'anivoc_panel_frame', 'Frame manipulation and meta-structural techniques', 0, 0, '2026-01-26 23:26:07', '2026-01-26 23:26:07'),
(11, 'Scene Functions', 'anivoc_scene_functions', 'Catalogue of scene functions / dramaturgical tags (anime-focused). Use for tagging, curation, scheduling and coverage metadata.', 89, 1, '2026-01-31 13:19:44', '2026-01-31 13:19:44'),
(12, 'Poses', 'poses', 'Standard character body poses — idle, conversational, seated, gestural. Img2img-stable frames: swap character, structure holds.', 40, 0, '2026-02-01 00:00:00', '2026-02-01 18:31:48'),
(14, 'Camera Angles', 'camera_angles', 'Shot framing and camera placement vocabulary. The composition layer — how to frame expressions and poses into reusable shot templates.', 30, 0, '2026-02-01 00:00:00', '2026-02-01 18:31:48'),
(15, 'Hand Gestures', 'anivoc_hand_gestures', 'Isolated hand and gesture reference library. Explicit finger-position descriptions for AI gen accuracy. Compositable into any pose or expression frame.', 35, 0, '2026-02-01 00:00:00', '2026-02-01 00:00:00'),
(16, 'Chibi Modes', 'anivoc_chibi_modes', 'Super-deformed style modes and comedic chibi states. Deformation ratios, reaction modes, action modes, and special states. Own visual language for comedic inserts.', 25, 0, '2026-02-01 00:00:00', '2026-02-01 00:00:00'),
(17, 'Action Effects', 'anivoc_action_effects', 'Reusable combat, kinetic, elemental, comedic, and atmospheric effect overlays. Layer on top of poses and expressions for complete shot composition.', 30, 0, '2026-02-01 00:00:00', '2026-02-01 00:00:00'),
(18, 'Duo Compositions', 'anivoc_duo_compositions', 'Two-character shot layouts and spatial relationship templates. The positional grammar of duo shots — how characters relate to each other in the frame.', 30, 0, '2026-02-01 00:00:00', '2026-02-01 00:00:00'),
(19, 'Character States', 'anivoc_character_states', 'Visual condition layer — what a character looks like RIGHT NOW. Damage, environment, power, equipment, emotion, supernatural. Composites onto any pose/expression frame.', 30, 0, '2026-02-01 00:00:00', '2026-02-01 00:00:00'),
(20, 'Shot Pacing', 'anivoc_shot_pacing', 'Timing and duration weight vocabulary. How long each shot type needs to exist for its narrative function. Directly maps to frame budget planning. Includes pacing patterns (rhythmic shot sequences).', 25, 0, '2026-02-01 00:00:00', '2026-02-01 00:00:00');
INSERT INTO `anivoc_character_states` (`id`, `name`, `description`, `created_at`, `updated_at`, `is_ingredient`) VALUES
(1, 'Fresh Wound (Bleeding)', 'Active wound visible — blood wet and bright red. Bandage absent or freshly torn. Wound location specific (arm, side, forehead). Blood streaks follow gravity. Use as: mid-battle injury, just got hit, urgent situation.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(2, 'Treated Wound (Bandaged)', 'Wound wrapped in cloth or bandage. Possibly bloodstained through. No active bleeding. Arm in sling, or bandage around head/torso. Use as: post-battle recovery, between fights, traveling while injured.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(3, 'Battle Scarred (Chronic)', 'Old scars visible — white/silver lines on skin. No active bleeding. Part of character\'s permanent look. One eye scarred shut, or a large scar across the face/chest. Use as: veteran character baseline, intimidation, history told on the body.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(4, 'Exhaustion (Physical Limit)', 'Body at its limit. Heavy bags under eyes. Skin pale. Sweat dried on forehead. Clothes disheveled. Posture slightly collapsed even when standing. Use as: after long battle, end of marathon, depleted mana/stamina.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(5, 'Poisoned / Sick', 'Skin has a sickly green or grey tint. Dark veins visible near the wound or spreading. Sweat cold and clammy. Lips cracked. Eyes unfocused. Use as: poison effect, illness, curse spreading, contamination.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(6, 'Drenched (Rain)', 'Soaked through completely. Hair matted flat to head. Clothes heavy and clinging. Water dripping from chin and hair tips. Skin glistening. Use as: caught in rain, fell in water, emotional rain scene, just arrived.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(7, 'Dusty / Dirty (Desert/Ruins)', 'Covered in a layer of fine dust or grit. Clothes faded and caked. Face has streaks of dirt (especially under eyes and across cheeks). Hair tangled and dusty. Use as: wasteland travel, ruins exploration, long journey aftermath.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(8, 'Ash-Covered (Post-Explosion)', 'Grey-white ash coating hair, shoulders, and face. Some ash still drifting and settling. Clothes singed at edges. Eyes squinting against residual smoke. Use as: survived explosion, aftermath of fire, apocalyptic environment.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(9, 'Mud-Caked (Ground Combat)', 'Thick mud on clothes, hands, and parts of face. Splattered pattern (not uniform). Hair stuck with dried mud chunks. Use as: trench warfare, crawling escape, ground-level fight, survival scenario.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(10, 'Snow/Ice Crusted', 'Ice crystals forming on hair, eyelashes, and clothing edges. Skin red from cold. Breath visible as heavy fog. Fingers and nose red. Use as: blizzard survival, frozen environment, ice power aftermath.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(11, 'Powered Up (Aura Active)', 'Energy visibly radiating from the body. Hair lifting or floating. Clothes billowing despite no wind. Skin may glow faintly. Eyes brighter or changed color. Veins of light visible under skin. Use as: combat power-up, transformation mid-sequence, ability fully active.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(12, 'Transformed (Beast/Demon)', 'Partially or fully transformed into non-human form. Claws, fangs, tail, wings, or other features visible. Clothes torn or absent. Skin tone shifted (darker, scaled, furred). Eyes inhuman (slits, glowing). Use as: werewolf shift, demon form, beast mode activated.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(13, 'Corrupted (Darkness Spreading)', 'Dark veins or black cracks spreading across the skin from one point. One side of body darker than the other. Eyes partially black. Aura flickering between normal and dark. Use as: corruption in progress, possession taking hold, curse active.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(14, 'Glowing (Energy Overload)', 'Body is emitting visible light — too bright to look at directly. Outline is white or colored. Details of face are partially washed out by the glow. Light casting hard shadows on surroundings. Use as: power release, final attack charging, divine manifestation.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(15, 'Spectral / Ghost Form', 'Body is semi-transparent. You can see through parts of it. Edges are blurry/dissolving. Color is desaturated or shifted to blue/white. Floating slightly off the ground. Use as: death state, spectral projection, ghost form, astral travel.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(16, 'Full Armor (Battle Ready)', 'Complete armor set visible — helmet, chest plate, gauntlets, greaves. Clean or polished. No damage. Weapon sheathed or at rest. Use as: pre-battle formation, guard duty, parade, intimidation through preparation.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(17, 'Damaged Armor (Mid-Battle)', 'Armor cracked, dented, or partially destroyed. Pieces missing. Scorch marks or sword gouges visible. Underneath clothing torn. Use as: survived heavy attack, armor at its limit, heroic persistence despite damage.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(18, 'Stripped / Civilian Clothes', 'No armor, no weapons. Ordinary clothes — shirt, pants, jacket. Vulnerable appearance. Use as: off-duty, infiltration/disguise, powerless moment, stripped of identity as a fighter.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(19, 'Formal Uniform (Authority)', 'Crisp, clean uniform. Pressed and buttoned. Insignia/rank visible. No wrinkles, no damage. Use as: ceremony, official appearance, authority assertion, character in their \"role\".', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(20, 'Torn Clothes (Vulnerability)', 'Clothes ripped and hanging. Not from battle — from restraint, struggle, or emotional moment. Skin exposed. Use as: escape from captivity, emotional breakdown aftermath, vulnerable/stripped moment.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(21, 'Sweat-Soaked (Stress/Effort)', 'Heavy sweat visible — shirt darkened, hair plastered to forehead, sweat beading on skin and dripping. Not from rain. Use as: intense effort, nervous breakdown point, holding back rage, physical strain.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(22, 'Tears (Crying)', 'Tear tracks visible on face. Eyes red and puffy. Nose slightly red. Lips trembling or pressed tight. Use as: emotional moment, grief, relief crying, confession aftermath.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(23, 'Blushing (Full Face)', 'Deep red flush across cheeks, nose, and possibly ears. Skin otherwise normal. Use as: embarrassment, romantic moment, anger (tsundere), physical exertion visible on face.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(24, 'Pale / Bloodless', 'Skin shifted to grey-white. Lips colorless. Dark circles under eyes appearing. Veins slightly visible on temples. Use as: shock, fear, blood loss, seeing something horrifying, illness onset.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(25, 'Disheveled (Just Woke Up)', 'Hair in complete disarray — cowlicks, tangles, sticking up at odd angles. Clothes rumpled. Eyes half-lidded. Pillow crease on cheek. Use as: morning scene, waking up, post-sleep state, comedic \"just rolled out of bed\".', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(26, 'Under Mind Control', 'Eyes glazed or glowing with an unnatural color. Pupils dilated or replaced. Movements slightly jerky/puppet-like. Veins of control energy visible (glowing lines on skin). Use as: possession active, mind control in effect, being puppeted.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(27, 'Masked / Identity Hidden', 'Face covered — mask, hood, scarf, or bandage. Only eyes visible (or no face visible at all). Use as: disguise, anonymous threat, mysterious figure, identity concealment.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(28, 'On Fire / Burning', 'Flames visibly wreathing parts of the body. Clothes burning away. Smoke rising. Skin reddened or charred at edges. Not necessarily painful — could be a power state. Use as: fire power active, burning alive, phoenix moment, rage made literal.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(29, 'Frozen Mid-Action', 'Body locked in place — either literally frozen (ice crystals visible) or time-stopped. Expression and pose completely fixed. No movement possible. Use as: time freeze, ice attack hit, stasis, suspended animation.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(30, 'Fading / Disappearing', 'Parts of the body becoming transparent or dissolving. Usually starts at the extremities and works inward. Particles breaking off. Use as: dying, being erased from reality, sacrifice completion, time running out.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1);
INSERT INTO `anivoc_chibi_modes` (`id`, `name`, `description`, `created_at`, `updated_at`, `is_ingredient`) VALUES
(1, 'Standard SD (2-Head Body)', 'Classic super-deformed ratio. Body is approximately 2 heads tall. Legs are stubby nubs. Arms are small but expressive. Head is the dominant mass — takes up half the frame. Use as: default chibi mode for reaction shots, character sheets, comedic inserts.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(2, 'Extreme SD (1.5-Head Body)', 'Maximum deformation. Body is barely there — just a round torso blob beneath the enormous head. Limbs are tiny stubs. Used for peak comedic impact or maximum cute. Use as: reaction close-ups, mascot mode, \"aww\" moments.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(3, 'Tall SD (3-Head Body)', 'Less deformed — body is 3 heads tall. Limbs are short but more defined than standard SD. Retains more of the character\'s normal proportions while still being clearly chibi. Use as: action chibi, comedic scenes that need the character to still move dynamically.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(4, 'Chibi Shock (Flat Eyes)', 'Standard SD body. Eyes become flat horizontal lines (squeezed shut from shock). Mouth is a tiny O or completely missing. Body is rigid and straight like a board. Use as: \"what did you just say\", comedic shock, punchline reaction.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(5, 'Chibi Sparkle Eyes (Awe)', 'Standard SD body. Eyes are enormous — taking up 60%+ of the head — and filled with stars, sparkles, or shine effects. Mouth is a tiny happy curve. Use as: seeing something amazing, hero worship in SD, \"so cute!\" reaction.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(6, 'Chibi Swirl Eyes (Dizzy)', 'Standard SD body. Eyes are drawn as spiral/swirl shapes instead of normal irises. Body may be wobbling or tilted. Use as: hit reaction, drunk, dizzy from spinning, \"I\'m going to faint\".', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(7, 'Chibi X Eyes (Dead)', 'Standard SD body. Eyes are drawn as X marks. Body is completely limp — collapsed, ragdolled, or slumped. No soul home. Use as: defeated, knocked out, \"that was too much\", comedic death.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(8, 'Chibi Dot Eyes (Blank)', 'Standard SD body. Eyes are simple black dots — no iris, no highlight, no expression. Face is otherwise neutral. Body is stiff and upright. Use as: processing failure, \"does not compute\", blank stare after bad joke.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(9, 'Chibi Cry Flood (Waterfall)', 'Standard SD body. Eyes squeezed shut. Two massive rivers of tears shooting horizontally out of the eyes. Mouth is a wobbly W shape. Body may be running or clinging to something. Use as: comedic crying, begging, fake tears, gag sadness.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(10, 'Chibi Anger Puff (Steam)', 'Standard SD body but slightly inflated/rounder. Face is bright red. Steam or smoke puffing from ears or head. Eyes are sharp angry slashes. Small fangs visible. Use as: \"I\'m so mad right now\", comedic rage, tsundere snap in SD.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(11, 'Chibi Blush Bomb', 'Standard SD body. Entire face is bright red from forehead to chin. Eyes are closed happy crescents or wide and panicked. Heart effects floating around. Use as: embarrassment overload, \"stop saying nice things\", romance comedic beat.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(12, 'Chibi Tremble (Scared)', 'Standard SD body. Body is visibly shaking — drawn with vibration lines around the entire form. Eyes are huge and watery. Teeth chattering. Use as: scared reaction, \"please don\'t\", comedic cowardice, facing something terrifying.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(13, 'Chibi Running (Noodle Legs)', 'SD body in a running pose. Legs are drawn as wobbly noodle-like lines moving in a blur. Arms pumping. Expression determined or panicked. Use as: comedic chase, running away, \"gotta go\", frantic movement.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(14, 'Chibi Faceplant', 'SD body has fallen face-first into the ground, floor, or a surface. Only the back and legs (stubby) are visible. Dust cloud or impact stars around the head. Use as: trip reaction, comedic fall, \"nope\", failed attempt.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(15, 'Chibi Ragdoll Toss', 'SD body is being flung through the air in a limp, ragdoll state. Limbs trailing randomly. Expression blank or shocked. Speed lines around the body. Use as: being thrown, hit reaction comedic, \"why\", launched by explosion.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(16, 'Chibi Spin Dizzy', 'SD body spinning in place. A motion blur circle around the character. Eyes are swirls. Stars or birds circling the head (classic cartoon knock-out visual). Use as: hit aftermath, spinning from surprise, comedic disorientation.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(17, 'Chibi Bounce (Happy Run)', 'SD body hopping forward in a bouncing gait. Each bounce includes a small jump with arms swinging. Cheerful expression. Sparkles or hearts trailing behind. Use as: excited movement, going somewhere happily, cute travel montage.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(18, 'Chibi Stomp (Angry March)', 'SD body marching forward with exaggerated stomping steps. Each footfall has an impact effect (crack lines, dust). Arms swinging aggressively. Angry expression. Use as: \"I\'m coming to find you\", furious march, comedic revenge walk.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(19, 'Chibi Ghost Mode', 'SD body becomes semi-transparent/ghostly. Floats slightly above the ground. Eyes are hollow or glowing. A blue/white tint to the body. Small ghost tail at the bottom. Use as: \"my soul left\", comedic death state, exhaustion beyond exhaustion.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(20, 'Chibi Deflate', 'SD body appears to be deflating — shrinking and flattening like a balloon losing air. Body becomes progressively flatter each frame. Face droops. Use as: emotional defeat, \"I give up\", disappointment, energy completely drained.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(21, 'Chibi Inflate (Puffer)', 'SD body inflates and rounds out like a balloon — becoming a perfect sphere with tiny limbs. Face is squished flat by the expansion. Use as: eating too much, comedic anger puff (extreme), \"I\'m going to burst\".', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(22, 'Chibi Shadow Clone', 'Multiple SD copies of the character stacked, overlapping, or running in different directions simultaneously. Each has a slightly different expression. Use as: \"too many tasks\", being in multiple places, comedic chaos, indecision.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(23, 'Chibi Costume Change', 'SD body with an exaggerated costume or outfit swap — significantly different from their normal look. The outfit change is the comedic focus. Use as: disguise attempt, seasonal outfit, fan service chibi variant, event special.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(24, 'Chibi Chibi (Inception)', 'A normal-sized character holding or looking at a tiny chibi version of themselves. The chibi-within-the-scene is even more deformed. Use as: \"this is how others see me\", comedic self-awareness, reaction to being called cute.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(25, 'Chibi Sparkle Trail', 'SD body moving through space leaving a trail of sparkles, stars, or hearts behind them. The trail is longer than the body. Use as: magical movement, \"following this character\", cute entrance, idol chibi mode.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1);
INSERT INTO `anivoc_color_coding` (`id`, `name`, `description`, `created_at`, `updated_at`, `is_ingredient`) VALUES
(1, 'The \"Red Rage Tint\" (Anger/Danger Wash)', 'Everything tinted red showing rage, danger, or violence. Visual Description: Entire scene washed with red overlay or lighting. Can be subtle pink tint to deep crimson. Shadows become darker red. Highlights become hot white-red. Desaturates other colors. Technical Details: Intensity Levels (subtle 10-20% overlay to overwhelming 80%+ red dominance), Red Variants (pink-red passion, blood-red violence, orange-red heat, crimson danger), Application Method (overall color grade, lighting, atmospheric effect, or literal red environment), Other Color Treatment (either desaturated or shifted toward red spectrum). Psychological Effect: Increased heart rate, tension, aggression, danger sense, heat sensation. Emotional Associations: Rage, anger, violence, danger, passion, bloodlust, warning, heat, fire. Common Contexts: Berserker rage activation, Extreme danger/violence, Fire/explosion environments, Villain power manifestation, Blood-soaked scenes, Passionate intensity. Character State Indicators: Rage mode activated, Killing intent, Loss of control, Extreme emotion. Cultural Notes: Universal danger/anger association across cultures. Akira Influence: Pioneered specific reds for neon violence, each shade meaning-laden.', '2026-01-27 00:26:18', '2026-01-27 00:26:18', 1),
(2, 'The \"Blue Melancholy\" (Sadness/Isolation Wash)', 'Cool blue dominates showing sadness, loneliness, or emotional coldness. Visual Description: Scene dominated by blues and cool tones. Warm colors desaturated or absent. Creates cold, distant, melancholic atmosphere. Shadows deep blue-black. Technical Details: Blue Range (pale ice-blue isolation to deep navy deep sadness to teal underwater/memory), Temperature (cool color temperature 5000-8000K), Saturation (can be highly saturated intense emotion or desaturated numbness), Warm Color Removal (yellows, oranges, reds minimized or eliminated). Psychological Effect: Lowered emotional temperature, introspection trigger, sadness, calm or melancholy. Emotional Associations: Sadness, loneliness, isolation, depression, cold (emotional/physical), distance, melancholy, rain, tears, loss. Common Contexts: Depressive episodes, Isolation/loneliness scenes, Rainy melancholy, Emotional distance, Mourning/grief, Cold environments (physical and emotional), Underwater or memory sequences. Subcategory Meanings: Pale Blue = Emptiness/isolation, Deep Blue = Profound sadness, Teal = Memory/subconscious, Navy = Night/deep emotion. Time Association: Often night, early morning, or twilight. Water Connection: Blue strongly associated with water = tears, rain, drowning in emotion.', '2026-01-27 00:26:18', '2026-01-27 00:26:18', 1),
(3, 'The \"Green Sickness\" (Poison/Corruption/Envy)', 'Sickly green indicating poison, corruption, illness, or envy. Visual Description: Yellow-green or blue-green tint creating nauseous, unnatural feeling. Makes skin look sickly. Associated with toxins, corruption, or negative nature. Technical Details: Green Variants (yellow-green sickness/poison, blue-green corruption/rot, lime green toxic/radioactive, dark green decay/death), Skin Rendering (makes skin tones appear ill, pale, corpse-like), Atmosphere (often includes green fog, gas, or lighting), Contrast (often contrasted with healthy pink or warm tones). Psychological Effect: Nausea, disgust, unease, wrongness, danger (toxic), envy. Emotional Associations: Sickness, poison, envy, jealousy, corruption, decay, toxic, unnatural, radioactive, evil (specific type). Common Contexts: Poison/toxin scenes, Corruption spreading, Illness/disease, Radioactive environments, Envy visualization, Rot/decay, Mad science experiments, Toxic magic. Positive Green Excluded: Natural healthy green (forests, life) is different green; this is unnatural green. Horror Usage: Common in body horror, corruption, transformation gone wrong. Villain Association: Certain villain types (toxic, corruptive, envious).', '2026-01-27 00:26:18', '2026-01-27 00:26:18', 1),
(4, 'The \"Yellow Warmth\" (Joy/Nostalgia/Comfort)', 'Golden yellow creating warmth, happiness, or nostalgic glow. Visual Description: Warm yellow-gold dominates scene. Creates sunny, warm, happy, or nostalgic atmosphere. Associated with light, warmth, memory\'s golden glow. Technical Details: Yellow Range (pale yellow gentle happiness, golden nostalgia/precious memories, amber warm comfort, bright yellow energetic joy), Light Quality (often soft, glowing, slightly overexposed feel), Shadow Treatment (warm orange shadows), Combination (often with soft focus for nostalgia). Psychological Effect: Warmth, happiness, optimism, energy, comfort, nostalgia trigger. Emotional Associations: Happiness, joy, warmth, nostalgia, comfort, sunlight, hope, energy, optimism, childhood innocence, precious moments. Common Contexts: Happy memories/flashbacks, Childhood scenes, Warm summer days, Comfort/safety moments, Morning hope, Divine blessing (gold variant), Precious moments. Memory Treatment: Memories often shown in golden glow (\"golden days\"). Time Association: Morning, sunny afternoon, \"golden hour\" of memory. Contrast Usage: Yellow warmth often contrasted with blue sadness in before/after.', '2026-01-27 00:26:18', '2026-01-27 00:26:18', 1),
(5, 'The \"Purple Mystery\" (Supernatural/Royal/Ambiguous)', 'Purple dominance indicating supernatural, mysterious, or royal elements. Visual Description: Purple, violet, or magenta tones create otherworldly, mysterious, or regal atmosphere. Associated with magic, nobility, and ambiguity. Technical Details: Purple Range (violet spiritual/mysterious, royal purple nobility/power, magenta intense supernatural, dark purple ominous magic, lavender gentle mystical), Rarity Factor (purple less common than other colors, creates \"special\" feeling), Combination (often with black ominous or white divine). Psychological Effect: Mystery, unease, fascination, otherworldliness, sense of power. Emotional Associations: Mystery, supernatural, magic, royalty, ambiguity, forbidden, luxury, spirituality, twilight, liminal spaces. Common Contexts: Magical effects/environments, Supernatural beings, Royal/noble settings, Forbidden powers, Dimension between worlds, Twilight realms, Mysterious characters, Psychic powers. Ambiguity: Purple = neither clearly good nor evil, mysterious alignment. Historical Context: Purple dye historically rare and expensive = nobility. Modern Anime: Often used for mysterious or powerful characters\' color schemes.', '2026-01-27 00:26:18', '2026-01-27 00:26:18', 1),
(6, 'The \"Orange Energy\" (Excitement/Explosion/Intensity)', 'Hot orange indicating explosive energy, excitement, or intensity. Visual Description: Dominant orange creates high-energy, explosive, intense atmosphere. Associated with fire, explosions, and peak intensity. Technical Details: Orange Range (bright orange energy/enthusiasm, red-orange explosive/intense, yellow-orange warm excitement, deep orange smoldering power), Light Quality (often harsh, bright, energetic), Movement (frequently combined with motion effects), Heat (suggests heat, both physical and emotional). Psychological Effect: Excitement, energy boost, intensity, heat sensation, alertness. Emotional Associations: Excitement, energy, explosion, fire, intensity, enthusiasm, power release, peak moment, hot, dynamic. Common Contexts: Explosions, Fire scenes, High-energy action, Enthusiasm/excitement peaks, Power releases, Sunset intensity, Training intensity. Action Association: Strong connection to action sequences and physical intensity. Transitional Use: Often used in transitions between calm and peak action.', '2026-01-27 00:26:18', '2026-01-27 00:26:18', 1),
(7, 'The \"White Purity\" (Divine/Death/Overexposure)', 'Overwhelming white indicating divinity, death, or blown-out reality. Visual Description: Scene dominated by white or overexposed to white. Can indicate divine realm, death/afterlife, or reality overload. Detail bleached out by brightness. Technical Details: White Types (pure white divine/death, warm white heavenly/peaceful, cool white clinical/harsh, overblown white reality breakdown), Detail Level (from soft detail visible to complete whiteout), Edge Treatment (can be soft/glowing or harsh/clinical). Psychological Effect: Transcendence, peace, emptiness, sensory overload, purity sense, death acceptance. Emotional Associations: Purity, divinity, death, heaven, emptiness, void, cleansing, overload, transcendence, peace, clinical, sterile. Common Contexts: Death/near-death, Divine realms, Heaven/afterlife, Complete peace, Memory erasure, Sensory overload, Clinical/hospital, Purification. Dual Nature: Can be peaceful (death/heaven) or disturbing (void/clinical). Contrast Usage: Often used as contrast to dark/colorful scenes for impact.', '2026-01-27 00:26:18', '2026-01-27 00:26:18', 1),
(8, 'The \"Black Void\" (Evil/Death/Emptiness/Depression)', 'Overwhelming darkness indicating evil, death, or consuming emptiness. Visual Description: Deep blacks dominate, minimal light. Creates oppressive, ominous, or empty atmosphere. Can indicate evil presence, death, or absolute despair. Technical Details: Black Types (pure black void/nothingness, blue-black night/cold death, red-black evil/demonic, grey-black depression/emptiness), Contrast (often punctuated by small lights making darkness more oppressive), Detail (shadows within shadows, barely visible detail). Psychological Effect: Fear, oppression, emptiness, dread, heavy emotion, primal darkness fear. Emotional Associations: Evil, death, darkness, void, nothingness, depression, despair, fear, unknown, demonic, emptiness, crushing weight. Common Contexts: Villain domains, Death scenes, Demon realms, Deep depression, Void spaces, Absolute despair, Shadow worlds, Loss of hope. Light Contrast: Small lights in darkness can show hope or make darkness more oppressive. Cultural Universal: Darkness = danger/unknown across all cultures.', '2026-01-27 00:26:18', '2026-01-27 00:26:18', 1),
(9, 'The \"Pink Romance\" (Love/Innocence/Fantasy)', 'Soft pink indicating romance, innocence, or fantasy idealization. Visual Description: Gentle to vibrant pink creates romantic, innocent, or fantastical atmosphere. Associated with love, youth, and idealized perspectives. Technical Details: Pink Range (pale pink innocent/gentle, hot pink passionate romance, rose pink mature romance, magenta pink fantasy), Softness (often soft focus, glowing), Combination (with sparkles, flowers, soft light). Psychological Effect: Romance feelings, innocence, softness, fantasy acceptance, idealization. Emotional Associations: Romance, love, innocence, youth, gentleness, fantasy, idealization, feminine (cultural), cuteness, sweetness. Common Contexts: Romantic moments, Love confessions, Innocent youth, Fantasy sequences, Magical girl genres, Idealized perspectives, Spring/cherry blossoms. Genre Association: Strong in shoujo, romance, magical girl genres. Idealization: Shows subject through rose-colored glasses.', '2026-01-27 00:26:18', '2026-01-27 00:26:18', 1),
(10, 'The \"Brown Earth\" (Grounded/Past/Natural/Decay)', 'Brown tones indicating groundedness, past, nature, or decay. Visual Description: Brown, tan, sepia dominates creating grounded, historical, natural, or decaying atmosphere. Can be warm (comfort) or dull (decay). Technical Details: Brown Types (warm brown earth/comfort, sepia old memories/past, red-brown rust/decay, yellow-brown autumn/age, grey-brown dust/abandonment), Texture (often emphasizes texture, roughness), Saturation (usually low saturation). Psychological Effect: Grounding, nostalgia, stability, age feeling, sometimes depression or boredom. Emotional Associations: Earth, stability, past, age, autumn, decay, rust, dust, abandonment, natural, humble, historical. Common Contexts: Historical/period pieces, Old photographs/memories, Abandoned places, Autumn scenes, Poverty/humble settings, Decay/rust, Desert/earth environments. Time Indicator: Often indicates past, either as memory or historical setting. Sepia Specific: Sepia specifically codes as \"old photograph\" or distant memory.', '2026-01-27 00:26:18', '2026-01-27 00:26:18', 1),
(11, 'The \"Desaturation Despair\" (Color Draining Away)', 'Color gradually draining to grayscale indicating hope loss. Visual Description: Scene progressively loses color saturation, moving from full color toward grayscale. Shows life, hope, or vitality draining away. Technical Details: Progression Speed (slow fade over minutes or rapid drain in seconds), Completion (can go to complete grayscale or stop at low saturation), Selective Draining (all colors drain equally or specific colors fade first), Reversibility (can be reversed for hope returning, creating powerful emotional arc). Animation Method: Progressive saturation reduction frame by frame, creating gradual emotional descent visualization. Psychological Effect: Sadness increasing, hope draining, life leaving, despair growing, emotional numbness setting in. Emotional Narrative: Tracks emotional descent visually, vitality loss made visible, hope disappearing before eyes, life draining from world, entering depression state, reality becoming meaningless and grey. Common Contexts: Character losing hope, Death approaching, Depression onset visualization, Trauma impact showing, Entering despair state, Life draining from body/world, Reality becoming meaningless. Reversal Powerful: Color returning equals hope returning, life affirmed, meaning restored, recovery beginning, reason to live found again. Akira Example: Used sophisticated saturation shifts to show character state changes, pioneering this technique in anime. Gradual Process: Usually shown as gradual process so viewer feels hope draining, not instant shift.', '2026-01-27 00:26:18', '2026-01-27 00:26:18', 1),
(12, 'The \"Saturation Surge\" (Color Exploding)', 'Colors suddenly become hyper-saturated indicating intensity peak. Visual Description: Colors suddenly become dramatically more saturated, vibrant, almost overwhelming to senses. Shows emotional or power peak moment. Technical Details: Intensity Increase (50-200% saturation increase from baseline), Speed (instant surge or rapid build over 1-3 seconds), Selective Surge (all colors intensify or specific color dominates surge), Duration (brief flash under 1 second or sustained intensity for entire sequence). Visual Impact: Can be almost painful in brightness, overwhelming senses intentionally, eye-catching and impossible to ignore, creates visceral response. Psychological Effect: Intensity felt viscerally, overwhelm, power surge sensation, emotional peak recognition, sensory assault (intentional). Emotional Narrative: Emotional explosion visualized, power release shown through color, intensity peak reached, breaking point achieved, ecstasy or agony extremes, reality enhancement or distortion, peak experience visualization. Common Contexts: Power-up moments and transformations, Emotional peaks (rage, joy, passion), Drug or poison effects visualization, Reality enhancement moments, Sensory overwhelming sequences, Critical turning point moments, Peak experiences. Danger Version: Can indicate dangerous intensity level, reality breakdown imminent, too much sensation. Contrast Effect: More powerful and noticeable after desaturated scenes, creating dramatic shift. Audio Parallel: Often accompanied by audio intensification matching visual surge.', '2026-01-27 00:26:18', '2026-01-27 00:26:18', 1),
(13, 'The \"Color Temperature Shift\" (Warm to Cool/Cool to Warm)', 'Shift from warm to cool colors or vice versa showing emotional or situation change. Visual Description: Color temperature of entire scene shifts between warm tones (reds, oranges, yellows) and cool tones (blues, cyans, purples) or reverse direction. Shows fundamental emotional or situational change. Technical Details: Shift Direction with specific meanings (Warm to Cool equals loss, sadness, death, emotional distance, hope fading; Cool to Warm equals hope emerging, life returning, comfort found, connection made, warmth entering), Transition Speed (gradual showing process of change, or sudden for shock value), Kelvin Shift range (subtle 500K change to extreme 3000K+ dramatic shift). Psychological Effect: Emotional shift felt viscerally in body, temperature sensation change (feeling colder or warmer), mood alteration through color. Emotional Narrative: Tracks emotional journey visually, relationship changes shown through color, situation evolution made visible, hope and despair cycles, life and death transitions, connection and isolation shifts. Common Contexts: Before and after tragedy, Relationship warming or cooling over time, Morning hope transitioning to evening sadness, Life transitioning to death, Connection shifting to isolation, Summer memories contrasted with winter present, Mood evolution sequences. Powerful Tool: Viewers feel temperature shift emotionally and sometimes physically. Seasonal Association: Often tied to seasonal changes reflecting emotional states (spring warmth, winter cold).', '2026-01-27 00:26:18', '2026-01-27 00:26:18', 1),
(14, 'The \"Monochrome to Color\" (Wizard of Oz Effect)', 'Black and white world becoming color showing awakening or revelation. Visual Description: Scene begins in grayscale and suddenly gains color, or color gradually seeps into grey world. Shows world coming alive, revelation occurring, or character awakening to life. Technical Details: Transition Style variations (Sudden full color for dramatic revelation moment, Color seeping in gradually for awakening process, Specific element colored first to draw focus), Selective Coloring technique (single element colored in otherwise grey world for emphasis). Cultural Reference: Named after famous \"Wizard of Oz\" transition from sepia Kansas to colorful Oz. Psychological Effect: Wonder, awakening sensation, life beginning, revelation, beauty discovered, world transformed. Emotional Narrative: Awakening to life and possibilities, discovering meaning in existence, escaping depression into hope, seeing truth clearly, world coming alive around character, hope emerging from darkness, first time truly experiencing something. Common Contexts: Awakening from depression, Falling in love transformation, Discovering life purpose, Escaping mundane world into meaningful one, Truth revealed visually, Coming alive emotionally, First time experiencing something important. Reverse Effect: Color draining to monochrome shows loss, numbness setting in, descending into despair, life leaving. Selective Color Power: Single red item in grey world equals focus object, only thing with meaning, what matters most, only thing truly alive.', '2026-01-27 00:26:18', '2026-01-27 00:26:18', 1),
(15, 'The \"Color Inversion\" (Negative World)', 'Colors inverting to negatives showing reality break or other realm entry. Visual Description: Colors flip to their opposites or negatives - red becomes cyan, blue becomes orange, yellow becomes purple, creating alien wrongness. Shows reality breaking down or entering fundamentally different realm. Technical Details: Inversion Type variations (Full inversion where all colors flip to opposites, Partial inversion affecting specific colors only, Flash inversion as momentary glitch), Trigger Events (reality break or glitch, dimensional shift occurring, power surge overload, system malfunction). Disorientation Factor: Extremely disorienting intentionally, signals something fundamentally wrong with reality, impossible to ignore wrongness. Psychological Effect: Wrongness sensation, unreality, disturbed feeling, alien perspective, other-dimensional, reality questioned. Emotional Narrative: Reality breaking down around character, entering fundamentally other realm, madness visualization, dimensional shift made visible, fundamental wrongness of situation, alien perspective shown, glitch in the matrix. Common Contexts: Reality glitches and breakdowns, Other dimensions or parallel worlds, Madness visualization sequences, Power overload moments, Digital or system errors, Death realms or afterlife, Inverted mirror worlds. Horror Usage: Common in horror anime for wrongness indication, unsettling viewers. Brief Flash: Often used as brief flash to show reality instability, glitch moment, dimensional weakness. Digital Association: Strong association with digital/cyber errors and corrupted data.', '2026-01-27 00:26:18', '2026-01-27 00:26:18', 1),
(16, 'The \"Sepia Memory Fade\" (Present to Past)', 'Colors shifting to sepia or warm brown showing entering memory or past. Visual Description: Full color present-day scene transitions to sepia or warm brown monochrome tones, indicating temporal shift from present moment to memory or historical past. Technical Details: Sepia Tone characteristics (warm brown monochrome, nostalgic quality, old photograph aesthetic), Transition Style options (gradual fade over 2-5 seconds, instant shift for sudden memory, edge-vignette spreading inward from corners), Intensity levels (subtle sepia tint maintaining some color, to full monochrome brown), Detail Treatment (can soften focus during transition for dreamlike quality). Universal Signifier: Almost universal visual language for \"this is the past\" or \"this is memory\" across cultures and media. Psychological Effect: Nostalgia trigger, temporal distance felt, old photograph aesthetic, pastness sensation, memory quality. Emotional Narrative: Entering character memory space, recalling past events, historical flashback indication, nostalgia for what was, looking back across time, temporal distance visualization, remembering. Common Contexts: Flashback sequences, Old photographs coming to life, Distant memories recalled, Historical period scenes, Nostalgia moments, Character exploring their past, Memory montages. Photograph Association: Strongly associated with vintage photographs and family albums, triggers nostalgia response. Warmth Factor: Warm brown tone often makes memories seem idealized, gentle, softer than reality, rose-tinted glasses effect. Return to Color: Transition back to full color indicates return to present, memory ending.', '2026-01-27 00:26:18', '2026-01-27 00:26:18', 1),
(17, 'The \"Complementary Clash\" (Opposing Colors Fighting)', 'Complementary colors in conflict showing opposition or impossible choice. Visual Description: Complementary color pairs (colors opposite on color wheel) placed in stark visual opposition creating tension. Shows conflict, fundamental opposition, or choice between incompatible paths. Technical Details: Complementary Pairs used (Red versus Cyan or Green for fire/ice, passion/calm, Blue versus Orange for cold/warm, logic/emotion, Yellow versus Purple for joy/mystery, light/shadow, Green versus Magenta for nature/artificial, life/death), Application Methods (different characters in complementary schemes, split screen or lighting with opposing colors, atmospheric color opposition, power aura clashes), Intensity Maximization (high saturation on both sides maximizes visual clash and discomfort). Visual Tension: Creates uncomfortable visual vibration at color boundaries, intentional eye strain, visual tension matching narrative tension, impossible to look away quality. Psychological Effect: Conflict sensation, opposition recognized, choice pressure, tension, incompatibility feeling, struggle visualization. Emotional Narrative: Opposition made visible through color, choice between incompatible paths, incompatible forces in conflict, struggle between opposites, impossible reconciliation, duality of existence, picking a side. Common Contexts: Hero versus villain with opposing color schemes, Moral choices shown through split lighting, Conflicting forces or ideologies, Impossible choice moments, Character battling internal conflict, Elemental battles (fire versus ice), Light versus dark confrontations. Resolution Indication: Colors mixing or blending equals conflict resolution, compromise found, unity achieved. One Color Dominating: Victory of that side, defeat of the other. Akira Mastery: Akira used complementary clashes masterfully for visual intensity in conflict scenes, setting standard.', '2026-01-27 00:26:18', '2026-01-27 00:26:18', 1),
(18, 'The \"Color Bleeding\" (Reality Dissolving)', 'Colors bleeding, running, or melting showing reality instability or transformation. Visual Description: Colors bleed beyond their proper boundaries, run like wet paint, or melt like wax. Shows reality breaking down, fundamental instability, or active transformation state between forms. Technical Details: Bleed Style variations (Watercolor run effect with colors flowing, Paint drip with gravity-affected bleeding, Digital glitch bleed with corrupted pixels, Oil paint mixing with colors swirling together), Direction Control (directional bleeding like dripping downward, or omnidirectional dissolving outward), Speed Range (slow seep creating dread, to rapid melt for shock). Instability Signifier: Shows something fundamentally unstable or in transition, reality not solid, boundaries breaking down, things not holding together. Psychological Effect: Unease and wrongness, instability sensation, dissolution fear, transformation anxiety, loss of boundaries concern, reality questioned. Emotional Narrative: Reality becoming unstable around character, transformation process occurring actively, boundaries dissolving between states, identity melting or changing, death of stability and certainty, becoming something else, world not holding together. Common Contexts: Reality breaking down sequences, Transformation sequences showing change, Death or dissolution scenes, Psychedelic or drug experiences, Barrier between worlds thinning, Identity crisis visualization, Dimensional instability, Dream-reality boundary breaking. Art Style Indicator: Often indicates artistic or experimental sequence ahead, non-literal storytelling. Transformation Process: Shows active process of one state becoming another, not instant change.', '2026-01-27 00:26:18', '2026-01-27 00:26:18', 1),
(19, 'The \"Chromatic Aberration\" (Color Separation)', 'RGB colors separating showing reality glitch, extreme speed, or dimensional stress. Visual Description: Colors separate into distinct red, green, and blue channels that are slightly offset from each other, creating rainbow-fringe effect at edges. Shows glitch in reality, extreme speed distortion, or dimensional/sensory stress. Technical Details: Offset Amount range (subtle 1-2 pixel offset for mild effect, to extreme 10+ pixel separation for severe distortion), Direction Control (directional offset suggesting motion direction, or radial separation from impact point), Trigger Events (extreme motion or speed, reality glitch or error, digital system malfunction, impact moment, dimensional stress), Associated Effects (often combined with scanlines for digital feel, static or digital noise, distortion waves). Glitch Aesthetic: Strong association with digital errors, computer glitches, corrupted data, cyberpunk visual language, system failure indication. Psychological Effect: Disorientation, speed sensation, digital wrongness feeling, hyper-reality, sensory overload, system failure recognition. Emotional Narrative: Reality glitching or breaking, digital world nature acknowledged, extreme speed beyond normal perception, vision breakdown from speed, sensory overload visualization, system error or corruption, too fast for reality to process. Common Contexts: Digital or cyber world scenes, Extreme speed moments (supersonic, teleportation), Reality glitches and errors, System malfunctions and failures, Impact moments as brief flash, VR or simulation reveals, Overpowered attacks exceeding normal limits, Dimensional barrier stress. Brief Effect Usage: Often used as single-frame or brief flash during impacts for subliminal effect. Modern Trend: Increasingly popular in cyberpunk and digital-themed anime, Gen Z aesthetic. Speed Indicator: Suggests motion too fast for reality to keep up.', '2026-01-27 00:26:18', '2026-01-27 00:26:18', 1),
(20, 'The \"Rainbow Gradient Flow\" (Spectrum Transition)', 'Colors flowing through full rainbow spectrum showing magic, transformation, or transcendence. Visual Description: Colors transition smoothly through complete rainbow spectrum (Red-Orange-Yellow-Green-Blue-Indigo-Violet) in flowing gradient. Shows magical transformation, transcendence, or complete emotional journey through all states. Technical Details: Spectrum Coverage (full ROYGBIV complete spectrum, or partial spectrum focusing on specific range), Transition Style (smooth gradient with seamless blending, or distinct color bands with visible separation), Movement Patterns (static gradient, flowing like water, pulsing with energy, rotating like wheel), Application Areas (single transforming element, lighting and atmosphere, entire scene color shift, character aura or power display). Magical Association: Strong association with magic and supernatural, transformation and change, transcendence beyond normal, divine intervention, limitless magical possibility. Psychological Effect: Wonder and awe, sense of completeness, magic recognition, transcendence feeling, childlike wonder revival, escapism. Emotional Narrative: Complete transformation occurring, full spectrum of emotion experienced, magical power unleashed, transcendence achieved, divine intervention occurring, wholeness and completeness achieved, all possibilities opening, journey through all emotional states. Common Contexts: Magical girl transformation sequences, Ultimate power release moments, Transcendence scenes, Divine blessing or intervention, Complete emotional journey visualization, Prism magic effects, Rainbow bridge mythology references (Bifrost), Hope and promise symbols. Completeness Symbol: Full spectrum represents completeness, totality, all possibilities contained, nothing excluded. Hope Symbol: Rainbow universally symbolizes hope, promise after storm, covenant, better future, optimism. Genre Association: Particularly common in magical girl genre, fantasy anime, hopeful narratives.', '2026-01-27 00:26:18', '2026-01-27 00:26:18', 1),
(21, 'The \"Protagonist Warm\" (Hero Color Psychology)', 'Main characters often coded with warm, approachable colors signaling heroic nature. Visual Description: Heroes typically use warm color schemes including oranges, reds, warm browns, and golds in their design. Makes them visually approachable, energetic, warm, and easy to identify with emotionally. Technical Details: Common Hero Colors and meanings (Orange or Red equals energy, passion, heroic determination, never-give-up spirit; Gold or Yellow equals hope, light-bringing, optimism, sun-like warmth; Warm Brown equals grounded, humble origins, natural, relatable), Application Areas (hair color, eye color, clothing and costume, personal aura or energy), Consistency Rule (colors maintained across costume changes and power-ups for character recognition). Psychological Effect: Approachability, warmth, ease of identification, energy radiating, likability, relatability. Character Psychology: Energetic and driven, approachable and friendly, warm-hearted, hope-bringing like sun, passionate about beliefs, engaging personality, relatable to audience, never gives up. Common Examples: Naruto with orange jumpsuit equals energetic, warm, never-give-up spirit; Son Goku with orange gi equals energetic, pure-hearted, simple; Monkey D. Luffy with red vest equals passionate, warm, adventurous spirit. Contrast Strategy: Often deliberately contrasted with cool-colored rivals or villains for visual and thematic opposition. Visibility Factor: Warm colors naturally stand out in scenes, easy to track during action sequences, draws eye naturally. Cultural Universality: Warm colors equal approachable and friendly across virtually all cultures. Genre Prevalence: Especially common in shonen, adventure, and heroic narratives.', '2026-01-27 00:26:18', '2026-01-27 00:26:18', 1),
(22, 'The \"Rival Cool\" (Opposite Number Colors)', 'Rivals coded with cool colors contrasting warm protagonists, showing personality opposition. Visual Description: Rival characters typically use cool color schemes including blues, purples, and dark greens in their design. Creates both visual and personality contrast with warm-colored heroes, showing different approach to similar goals. Technical Details: Common Rival Colors and meanings (Blue equals cool-headed, composed, strategic thinking, emotional control; Purple equals mysterious, powerful, noble bearing, enigmatic; Dark Green equals calculating, sometimes envious, analytical), Contrast Principle (deliberately opposite to protagonist warmth, creating visual tension), Evolution Possibility (colors may warm up as character allies with protagonist, showing thawing). Psychological Effect: Distance and aloofness, coolness under pressure, calculation rather than passion, mystery, strategic mindset. Character Psychology: Cool-headed and rational, calculating and strategic, emotionally distant initially, composed under pressure, mysterious motivations, strategic rather than impulsive, emotionally controlled and disciplined, lone wolf tendency. Common Examples: Sasuke Uchiha with dark blue and purple versus Naruto orange showing cold calculation versus warm passion; Vegeta with blue and white armor versus Goku orange showing pride versus pure heart; Todoroki Shouto with red-white split showing internal hot-cold conflict. Complementary Design: Often uses colors complementary to protagonist creating pleasing visual contrast when together. Character Development: Color palette warming indicates emotional growth and opening up. Visual Balance: Creates aesthetically pleasing contrast in shared scenes. Thawing Indicator: Gradual color warming shows character warming emotionally, becoming friendlier.', '2026-01-27 00:26:18', '2026-01-27 00:26:18', 1),
(23, 'The \"Villain Desaturated\" (Evil Muted or Extreme)', 'Villains often use desaturated colors or extreme monochromes showing inhumanity. Visual Description: Villains coded with either muted and desaturated colors showing coldness and lack of humanity, or extreme blacks and blood reds showing pure menace. Deliberately lacks the vibrant color saturation of heroes. Technical Details: Villain Color Strategies (Desaturated or grey tones for cold, inhuman, emotionless; Pure black for evil, void, consuming darkness; Dark purple for mysterious evil, corruption; Blood red for violence, rage, cruelty; Sickly green for corruption, toxic, unnatural), Contrast with Heroes (less vibrant and saturated than heroes except when using evil red, creating visual wrongness). Psychological Effect: Menace, coldness, inhumanity, wrongness sensation, fear response, alienness. Character Psychology: Cold and inhuman, menacing presence, corrupted or evil nature, void-like consuming, threatening to others, unnatural existence, removed from humanity. Common Examples: Frieza with purple and white palette equals alien, cold, powerful tyrant; Orochimaru with pale skin and purple equals creepy, inhuman, snake-like; All For One with pure black equals void, consuming evil, darkness incarnate. Evolution Through Redemption: Redemption arcs often add color warmth and increase saturation showing humanity returning. Power Display: Sometimes becomes more saturated during power displays showing intensity. Inhuman Indicator: Desaturation strongly suggests non-human or has lost humanity. Corruption Visual: Dark or sickly colors show corruption of what should be natural.', '2026-01-27 00:26:18', '2026-01-27 00:26:18', 1),
(24, 'The \"Love Interest Soft\" (Romance Color Palette)', 'Love interests often use soft pastels or specific romantic colors creating idealized appearance. Visual Description: Romantic interests typically use soft, approachable, gentle colors including pinks, soft blues, whites, and pastels. Creates romantic, gentle, pure, idealized visual appearance triggering romantic associations. Technical Details: Common Romance Colors and meanings (Soft pink equals gentle romance, innocence, sweetness; Pastel blue equals calm beauty, purity, serenity; White equals purity, ideal, perfection; Lavender equals gentle mystery, femininity, grace), Saturation Level (usually lower saturation than action-oriented characters, creating softness), Consistency with Nature (colors often associated with flowers, spring, natural beauty, cherry blossoms). Psychological Effect: Gentleness, romance feelings, idealization, softness, approachability, nurturing sense, peaceful. Character Psychology: Gentle and kind, romantic and loving, pure-hearted, idealized by protagonist, soft personality, feminine qualities (culturally), nurturing nature, peaceful disposition, emotionally sensitive. Common Examples: Hinata Hyuga with lavender and white equals gentle, pure, shy romantic; Sakura-named characters often pink-coded for cherry blossom association; White or pale blue characters for ethereal, angelic beauties. Genre Variation: More pronounced and common in romance and shoujo genres versus action genres. Subversion Potential: Tough love interests may use this palette ironically, or character may evolve into softer colors. Cultural Association: Pink and soft colors strongly equal femininity in many Asian cultures. Idealization: Soft palette shows character viewed through rose-colored glasses, idealized.', '2026-01-27 00:26:18', '2026-01-27 00:26:18', 1),
(25, 'The \"Mentor Wise\" (Elder Sage Palette)', 'Mentors and wise characters coded with dignified, muted, natural colors suggesting experience. Visual Description: Mentor and sage characters use dignified, mature colors including greys, muted blues, earth tones, and white hair. Suggests accumulated wisdom, age, experience, and calm understanding earned through years. Technical Details: Common Mentor Colors and meanings (Grey or white equals age, wisdom, seen much; Muted blue equals calm wisdom, tranquility; Earth brown equals grounded experience, fundamental understanding; Muted purple equals mystical wisdom, spiritual insight), Saturation Level (lower saturation suggests maturity, experience, moved beyond youthful vibrancy), Contrast with Youth (deliberately less vibrant than young protagonists showing age difference, experience gap). Psychological Effect: Respect naturally given, wisdom sensed, calm and patience, experience trusted, reliability, groundedness. Character Psychology: Wise from experience, experienced in life and combat, calm and patient, trustworthy guide, aged but not weak, seen-it-all perspective, grounded in fundamentals, patient teacher. Common Examples: Jiraiya with white hair and red-grey clothing equals experienced sage and teacher; Master Roshi with orange gi and purple equals old master with hidden power; Gandalf-type figures with grey or white robes. White Hair Universal: Almost universal visual code for age, wisdom, experience across cultures. Earth Tones Meaning: Suggest character grounded, connected to fundamental truths, stripped of excess. Evolution: Hero characters may gradually adopt mentor-like colors as they mature, come full circle.', '2026-01-27 00:26:18', '2026-01-27 00:26:18', 1),
(26, 'The \"Innocent White\" (Pure Character Coding)', 'Innocent or pure characters coded with white or very light colors showing untainted nature. Visual Description: Characters representing ultimate innocence, purity, or otherworldly untainted nature use white, cream, or very pale colors exclusively in their design. Creates visual purity, stands out dramatically. Technical Details: White Coding Spectrum (Pure white equals ultimate purity, angelic, divine; Cream or ivory equals soft innocence, gentle purity; Pale pastels equals gentle purity, not harsh), Application Areas (hair color often white or platinum, clothing entirely white or cream, often entire color palette very light), Contrast Effect (stands out dramatically against darker or more colorful cast members). Psychological Effect: Purity sensation, innocence recognized, otherworldliness, fragility sensed, specialness, untainted quality, separation from normal. Character Psychology: Pure and untainted, innocent and uncorrupted, untouched by darkness or evil, angelic or divine nature, otherworldly origin, fragile requiring protection, special and set apart, pristine. Common Examples: Angels and divine beings with pure white, Innocent children with white or cream palette, Pure-hearted heroines with white and pale colors, Sacrificial characters often white-coded. Corruption Indicator: Any color staining or darkening white palette equals corruption occurring, loss of innocence, taint spreading. Sacrifice Association: Often characters destined to sacrifice themselves for others, purity through sacrifice. Target Status: Visual purity makes them targets for corruption by villains or objects requiring protection by heroes. Contrast Drama: White against dark creates maximum visual and thematic contrast.', '2026-01-27 00:26:18', '2026-01-27 00:26:18', 1),
(27, 'The \"Berserker Red\" (Rage Character Palette)', 'Rage and berserker characters dominated by reds and hot colors showing violent nature. Visual Description: Characters with inherent rage, berserker nature, or violent tendencies use intense reds, oranges, and hot colors throughout their design. Suggests barely controlled heat, violence, uncontrolled destructive emotion always simmering. Technical Details: Rage Palette Range (Blood red equals violence, rage, cruelty; Orange-red equals hot explosive temper; Dark red equals smoldering anger, barely controlled; Red accents on dark base equals rage barely contained under surface), Intensity Level (high saturation, intense colors, nothing subtle), Aura Effect (often surrounded by visible red aura when angry or fighting, intensifying palette). Psychological Effect: Danger sensed, heat felt, aggression recognized, intensity, barely controlled violence, warning triggered. Character Psychology: Aggressive and violent, hot-tempered and explosive, passionate to extreme, dangerous to others and self, powerful through rage, barely in control, explosive reactions, burns hot emotionally. Common Examples: Berserker class characters with red color schemes, Hot-headed warriors with red and orange, Rage-powered characters with intensifying red auras during power-up, Fire users often red-coded matching their element. Power Display: Red color intensifies dramatically during rage moments or power displays. Warning Function: Red color scheme warns viewer immediately of dangerous, volatile nature. Heat Association: Red equals heat equals burning uncontrolled emotion, fire metaphor. Genre: Particularly common in battle shonen, action anime, warrior characters.', '2026-01-27 00:26:18', '2026-01-27 00:26:18', 1),
(28, 'The \"Stoic Blue\" (Calm Warrior Coding)', 'Calm, controlled warriors coded with cool blues showing disciplined nature. Visual Description: Disciplined, emotionally controlled warrior characters use blue color schemes throughout design. Suggests ice-like control, discipline, emotional restraint, strategic calm mind even in battle. Technical Details: Calm Palette Range (Ice blue equals cold control, perfect discipline, frozen emotions; Deep blue equals calm depth, serious demeanor, ocean-like composure; Blue-grey equals stoic, nearly emotionless, steel-like), Temperature Emphasis (cool color temperature emphasizes emotional coolness, controlled nature, lack of hot passion), Contrast Usage (often deliberately contrasted against red berserker types creating ice versus fire dynamic). Psychological Effect: Calm recognized, control sensed, discipline, coldness, emotional distance, professionalism, strategic mindset. Character Psychology: Controlled and disciplined, calm under any pressure, strategic rather than impulsive, emotionally restrained and controlled, professional warrior, ice-like composure, analytical fighter, rarely loses composure. Common Examples: Ice magic users with blue palette matching powers, Disciplined swordsmen with blue clothing or accents, Strategic tactical fighters with cool blue schemes, Stoic characters with blue-grey palettes. Ice Powers Correlation: Often literally possess ice or cold-based powers matching their color psychology. Emotional Arc: Blue palette may warm gradually if character learns to express emotions, showing growth. Professional Indicator: Blue suggests trained professional versus hot-blooded amateur. Distance: Blue creates emotional distance, keeps others at arm\'s length.', '2026-01-27 00:26:18', '2026-01-27 00:26:18', 1),
(29, 'The \"Mysterious Purple\" (Enigma Character Palette)', 'Mysterious, ambiguous characters coded with purples showing unclear allegiance. Visual Description: Characters with mysterious nature, ambiguous moral allegiance, or special unique powers use purple and violet color schemes. Purple occupies middle ground, neither clearly hero red-orange nor villain black, creating ambiguity. Technical Details: Mystery Palette Range (Royal purple equals powerful mystery, nobility, hidden strength; Dark purple equals ominous mystery, potential threat; Violet equals spiritual mystery, otherworldly; Magenta equals intense mysterious power, alien), Ambiguity Factor (purple occupies space between warm red and cool blue, neither clearly good nor evil), Rarity Effect (purple relatively rare in nature and design equals special, unique, set apart). Psychological Effect: Mystery and intrigue, ambiguity about allegiance, specialness sensed, power recognized, enigmatic quality, neither trusted nor feared. Character Psychology: Mysterious and enigmatic, ambiguous moral alignment, special or unique, powerful in unclear ways, neither clearly good nor evil, unique among others, keeps secrets, allegiance unclear. Common Examples: Mysterious mentors with purple robes who may help or hinder, Ambiguous alignment characters with purple schemes, Special power holders with purple energy, Magic users with purple coloring, Characters with hidden agendas. Moral Ambiguity: Purple palette equals character not clearly hero or villain, keeps audience guessing. Revelation: Often revealed as ally despite suspicious appearance, or vice versa. Power Indication: Purple often indicates special, unique, or forbidden powers. Spiritual: Sometimes indicates spiritual or mystical connection.', '2026-01-27 00:26:18', '2026-01-27 00:26:18', 1),
(30, 'The \"Corrupted Dark\" (Fallen Character Transition)', 'Characters undergoing corruption show progressive darkening and color shift. Visual Description: Characters falling to evil, being corrupted, or losing themselves show their color palette progressively darkening, desaturating, or shifting toward evil-associated colors. Visual corruption tracking internal corruption. Technical Details: Corruption Progression Stages (Stage 1: original colors slightly darkened, first signs; Stage 2: saturation decreasing, darker shades dominating, halfway fallen; Stage 3: colors fully dark, corrupted, or shifted to evil palette, transformation complete), Evil Color Shift (movement toward blacks, dark purples, sickly greens, blood reds from original palette), Reversibility (colors can return to original if redeemed, showing recovery and purification). Visual Storytelling: Color change shows internal corruption made visible externally, moral fall visualized, darkness spreading. Psychological Effect: Wrongness sensed, loss recognized, corruption spreading, fall from grace, tragedy, darkness consuming. Character Psychology: Falling from grace, corrupting internally, losing true self, becoming evil, tragic transformation, lost innocence, consumed by darkness, no longer who they were. Common Examples: Anakin transitioning to Darth Vader with light to black shift, Corrupted heroes with colors progressively darkening, Possessed characters with sudden color shifts, Cursed characters with gradual palette corruption. Gradual Change: Progressive color change tracks corruption journey across episodes or arc. Redemption: Colors returning to original palette equals redemption achieved, purification, recovery of true self. Tragic Visual: Constant visual reminder of what was lost, who they used to be. Point of No Return: Sometimes color shift indicates passed point where return is impossible.', '2026-01-27 00:26:18', '2026-01-27 00:26:18', 1);
INSERT INTO `anivoc_color_coding` (`id`, `name`, `description`, `created_at`, `updated_at`, `is_ingredient`) VALUES
(31, 'The \"Hospital Sterile\" (Clinical White-Blue)', 'Hospital and medical settings use cold white-blue palette creating clinical atmosphere. Visual Description: Medical environments dominated by sterile whites, pale blues, cool fluorescent tones creating clinical, cold, impersonal institutional feeling. Emphasizes sterility, cleanliness, but also emotional coldness. Technical Details: Medical Palette Components (Sterile white equals clean, clinical, impersonal; Pale blue equals medical, cold, institutional; Cool fluorescent lighting equals artificial, harsh, unnatural; Steel grey equals equipment, machinery, impersonal), Saturation Level (very low saturation, almost monochromatic, drained of life), Lighting Quality (harsh fluorescent overhead lighting, no warm natural light, clinical precision). Psychological Effect: Sterility sensed, coldness felt, illness association, vulnerability, institutional powerlessness, clinical detachment, life-on-edge. Environmental Psychology: Clinical and impersonal, sick and vulnerable, sterile and lifeless, cold and unwelcoming, artificial environment, institutional control, life-and-death liminal space, vulnerability maximized. Common Contexts: Hospital scenes and medical emergencies, Injury recovery sequences, Birth and death scenes, Vulnerable character moments, Medical procedures, Life-hanging-in-balance, Illness visualization. Warmth Intrusion: Warm colors like flowers from visitors or sunlight through windows stand out dramatically against cold palette, offering hope. Life-Death Threshold: Hospital as liminal space between life and death, colors emphasize threshold. Vulnerability: Characters at their most physically and emotionally vulnerable, palette emphasizes helplessness. Institutional: Cold colors emphasize institutional, impersonal nature versus home warmth. Recovery: Gradual warming of palette can show recovery, life returning.', '2026-01-27 00:26:18', '2026-01-27 00:26:18', 1),
(32, 'The \"School Warmth\" (Youth Institution Palette)', 'School settings use warm, bright, youthful palette creating hopeful atmosphere. Visual Description: School environments use warm wood tones, bright whites, cheerful accent colors creating youthful, energetic, hopeful atmosphere. Suggests formative period, growth, social connection, nostalgia. Technical Details: School Palette Components (Warm wood tones equals traditional, warm, natural; Bright white equals clean, hopeful, fresh start; Cheerful accent colors equals youthful energy, diversity; Green from chalkboards and nature equals growth, learning, life), Natural Light Emphasis (emphasis on natural sunlight streaming through windows, golden afternoon light), Saturation Level (moderate to high saturation, vibrant and full of life). Psychological Effect: Youth and vitality, hope for future, energy, nostalgia trigger, formative period recognition, social connection, coming-of-age. Environmental Psychology: Youthful and energetic, formative and important, hopeful about future, energetic and alive, nostalgic for viewer, coming-of-age setting, social and connected, growth and learning. Common Contexts: School life slice-of-life, Youth and coming-of-age stories, Nostalgia flashback sequences, Character formation periods, Social drama settings, First love and friendship. Nostalgia Power: School color palette triggers powerful nostalgic responses in viewers recalling their own youth. Golden Light: Often bathed in golden afternoon light creating nostalgic, precious memory quality. Social Space: Warm colors emphasize social connection, relationships forming, community. Genre: Central to slice-of-life, romance, coming-of-age genres.', '2026-01-27 00:26:18', '2026-01-27 00:26:18', 1),
(33, 'The \"Urban Neon\" (City Night Palette)', 'Urban nighttime environments use neon, artificial color palette creating cyberpunk atmosphere. Visual Description: City night scenes dominated by artificial neon colors including hot pinks, cyans, greens, purples reflecting off wet streets. High contrast between bright neon lights and deep dark shadows. Technical Details: Urban Night Palette Components (Neon pink equals nightlife, artificial pleasure, seedy; Cyan or blue equals cool artificial light, technology; Neon green equals signs, technology, alien; Purple or magenta equals mysterious urban, ambiguous; Deep blacks equals night shadows, darkness between lights), Contrast Level (extreme contrast between bright lights and dark shadows, no middle ground), Reflection Effect (wet pavement doubles and intensifies neon colors, creates depth). Psychological Effect: Urban energy, loneliness in crowds, modernity, artificial life replacing natural, nocturnal world, seedy underbelly, technological. Environmental Psychology: Urban and modern, nocturnal and night-life, artificial replacing natural, lonely despite crowds, modern alienation, cyberpunk future, nightlife and pleasure, seedy underbelly, energetic but cold. Common Contexts: Cyberpunk setting establishment, Urban night scenes, Red light districts and nightlife, Modern alienation themes, Detective noir atmospheres, Technology-dominated futures. Blade Runner Legacy: Strong visual influence from Blade Runner aesthetic, established cyberpunk visual language. Akira Pioneer: Akira perfected neon-lit Tokyo night cityscape colors, set standard for anime. Rain Enhancement: Rain and wet streets dramatically intensify neon reflections, creating iconic look. Alienation: Bright lights paradoxically create loneliness, surrounded by people but isolated.', '2026-01-27 00:26:18', '2026-01-27 00:26:18', 1),
(34, 'The \"Forest Green\" (Natural World Palette)', 'Forest and nature settings dominated by greens and earth tones. Visual Description: Natural forest environments use various shades of green, browns, earth tones creating vibrant living atmosphere or threatening wilderness depending on tone. Shows connection to nature, life, primal world. Technical Details: Nature Palette Components (Bright green equals healthy, vibrant nature, life; Dark green equals deep forest, mystery, primal; Earth brown equals grounded, natural, fundamental; Sky blue equals open, freedom, vastness), Variety Emphasis (many different shades of green showing depth, complexity, richness of nature), Natural Light Quality (dappled light filtering through leaves, natural sun, organic). Psychological Effect: Natural and organic, grounding, life and growth (or threatening wilderness and primal danger depending on treatment), peaceful or dangerous. Environmental Psychology: Natural and alive, grounding and fundamental, peaceful and serene (or threatening and dangerous), primal and ancient, pure and unspoiled, growing and living, organic and real. Common Contexts: Forest adventures and journeys, Nature scenes and celebrations, Spiritual journeys and quests, Primal conflicts and survival, Escape from civilization, Return to nature themes. Mood Variation: Bright vibrant green equals life, hope, peace, safety in nature; Dark deep green equals threatening unknown, primal danger, wilderness. Ghibli Influence: Studio Ghibli masters of natural green palettes, showing nature\'s sacred beauty. Contrast Usage: Natural green versus industrial grey equals nature versus technology conflict, common theme. Spiritual: Green forests often represent spiritual spaces, sacred groves, connection to divine through nature.', '2026-01-27 00:26:18', '2026-01-27 00:26:18', 1),
(35, 'The \"Desert Orange\" (Wasteland Heat Palette)', 'Desert and wasteland environments dominated by hot oranges, yellows, browns. Visual Description: Desert and wasteland environments use hot color palette including oranges, yellows, tans, reds creating oppressive heat, desolation, harshness feeling. Everything stripped to essentials for survival. Technical Details: Desert Palette Components (Sandy yellow equals desert, heat, desolation; Orange-brown equals rock, harshness, unforgiving; Hot sky equals washed out blue or orange from heat; Red accents equals extreme heat, danger, warning), Saturation Treatment (can be vibrant and intense, or washed out and bleached by harsh sun), Atmospheric Haze (heat shimmer, atmospheric haze, mirage effects). Psychological Effect: Heat felt, desolation, harshness and unforgiving nature, survival mode, minimalism, testing environment, stripped to essentials. Environmental Psychology: Hot and oppressive, harsh and unforgiving, desolate and empty, survival-focused, minimal and stripped bare, testing and challenging, unforgiving of weakness, exposed and vulnerable, purified through hardship. Common Contexts: Desert journeys and crossings, Post-apocalyptic wasteland settings, Survival stories and tests, Testing and trial sequences, Spiritual quests and vision journeys, Exile and banishment, Purification through hardship. Minimalism: Reduced color palette mirrors being stripped to essentials, survival fundamentals. Testing Ground: Desert as place of testing, transformation, proving worth through survival. Water Blue Contrast: Any water or oasis blues stand out dramatically against hot orange-yellow palette. Spiritual: Desert often represents spiritual testing, wandering, finding truth through hardship. Post-Apocalyptic: Common palette for post-apocalyptic settings showing civilization stripped away.', '2026-01-27 00:26:18', '2026-01-27 00:26:18', 1),
(36, 'The \"Winter Blue-White\" (Cold Season Palette)', 'Winter environments dominated by blues, whites, greys creating cold atmosphere. Visual Description: Winter scenes use cold color palette including whites, pale blues, greys creating cold, quiet, isolated atmosphere that can be peaceful or harsh depending on treatment. Technical Details: Winter Palette Components (White snow equals purity, blank slate, death or rest; Pale blue equals cold, ice, winter sky; Grey equals overcast, coldness, bleakness; Dark evergreen equals life persisting, endurance), Light Quality (flat overcast light, or sharp cold winter sun, both feel cold), Saturation Level (generally desaturated, muted, life drained by cold). Psychological Effect: Cold felt, isolation, quiet and stillness, death or peaceful rest, harsh beauty, waiting, dormancy. Environmental Psychology: Cold and harsh (or peaceful and serene), quiet and still, isolated and alone (or peacefully solitary), death and ending (or rest and renewal), pure and clean, waiting and dormant, harsh beauty, endurance required. Common Contexts: Winter scenes and seasonal changes, Isolation stories, Death and ending sequences, Peaceful reflection moments, Harsh survival scenarios, Blank slate and fresh starts, Dormancy before renewal. Dual Nature Interpretation: Positive reading equals quiet beauty, rest, peace, purity, renewal coming; Negative reading equals deadly cold, isolation, harsh, death, bleakness. Blank Slate: Snow covering everything equals fresh start, past covered, clean slate, potential. Breath Visible: Visible breath in cold air adds to atmosphere, emphasizes cold, makes characters vulnerable. Death or Rest: Winter can represent death and ending, or necessary rest before spring renewal.', '2026-01-27 00:26:18', '2026-01-27 00:26:18', 1),
(37, 'The \"Underworld Purple-Black\" (Hell/Death Realm)', 'Underworld and death realm environments use dark purples, blacks, sickly colors. Visual Description: Death realms, underworlds, demon worlds use dark purples, blacks, sickly greens, blood reds creating ominous, evil, deathly atmosphere. Everything inverted from natural healthy world. Technical Details: Underworld Palette Components (Black or dark purple equals death, evil realm, void; Sickly green equals decay, toxic, corruption; Blood red equals violence, demonic, cruelty; Dark blue equals cold death, frozen), Light Sources (unnatural light including green flame, red glow, purple energy, no natural sunlight), Saturation Treatment (can be desaturated for death, or hyper-saturated for demonic intensity). Psychological Effect: Fear and dread, evil sensed, death presence, unnatural wrongness, demonic, ominous threat, nightmare quality. Environmental Psychology: Evil and malevolent, deathly and lifeless, demonic and corrupted, unnatural and wrong, ominous and threatening, fearful and nightmare, corrupt and rotting, beyond natural law. Common Contexts: Hell and underworld scenes, Demon realms and dimensions, Death spaces and afterlife, Nightmare worlds and dreamscapes, Villain lairs and domains, Corruption spreading, Evil dimensions. Inversion: Often inverts natural order with purple skies, green fire, showing fundamental wrongness. Wrongness Indicator: Colors signal this place fundamentally wrong, against nature, evil. No Life: Absence of healthy vibrant colors equals no natural life, only death and corruption. Genre: Common in dark fantasy, horror, supernatural anime. Fear Response: Color palette designed to trigger fear and unease in viewers.', '2026-01-27 00:26:18', '2026-01-27 00:26:18', 1),
(38, 'The \"Heaven Gold-White\" (Divine Realm Palette)', 'Heaven and divine realms dominated by golds, whites, soft light. Visual Description: Divine realms, heaven, afterlife use brilliant whites, golds, soft pastels creating ethereal, peaceful, transcendent atmosphere. Everything suffused with gentle light. Technical Details: Divine Palette Components (Brilliant white equals purity, divine, transcendent; Gold equals divine radiance, sacred, precious; Soft pastels equals gentle, heavenly, peaceful; Sky blue equals infinite, open, endless), Light Quality (soft glowing light seemingly sourceless, fills everything, not harsh despite brightness), Saturation Treatment (soft and gentle, not harsh or overwhelming despite brightness). Psychological Effect: Peace and serenity, transcendence beyond earthly, divine presence, pure and holy, heavenly, safe and protected, eternal. Environmental Psychology: Divine and holy, peaceful and serene, transcendent beyond earthly concerns, pure and perfect, heavenly and blessed, safe and protected, eternal and timeless, blissful and joyful, beyond suffering. Common Contexts: Heaven and afterlife scenes, Divine encounters and blessings, Peaceful death transitions, Spiritual realms and dimensions, Ultimate peace achieved, Religious and sacred spaces, Transcendence moments. Opposite Underworld: Direct visual and thematic inversion of underworld dark colors, light versus dark. Soft Power: Bright but not harsh or dangerous, welcoming despite intensity. Timeless Quality: Colors suggest beyond time, eternal, unchanging perfection. Safety: Sense of ultimate safety, protection, nothing can harm here. Genre: Common in religious, spiritual, afterlife-themed anime.', '2026-01-27 00:26:18', '2026-01-27 00:26:18', 1),
(39, 'The \"Industrial Grey\" (Factory/Urban Decay)', 'Industrial and abandoned urban environments use greys, rusted browns. Visual Description: Industrial settings and abandoned urban spaces use cold greys, rusted browns, dingy colors creating harsh, decayed, inhuman atmosphere. Everything mechanical, no organic life. Technical Details: Industrial Palette Components (Grey concrete equals cold, industrial, inhuman; Rust brown-orange equals decay, age, abandonment; Dull steel equals machinery, inhuman, mechanical; Dingy yellow equals harsh artificial light, sickly), Texture Emphasis (rough, decayed, rusted textures prominent, tactile unpleasantness), Saturation Level (very low, drained of life and color, desaturated). Psychological Effect: Harshness, decay and abandonment, inhuman and mechanical, industrial coldness, urban decay, post-industrial wasteland, soulless. Environmental Psychology: Industrial and mechanical, inhuman and cold, decayed and abandoned, harsh and unforgiving, cold and unwelcoming, abandoned by humanity, post-industrial collapse, mechanical replacing organic, soulless and empty. Common Contexts: Factory settings and industrial zones, Abandoned buildings and ruins, Urban decay and collapse, Post-apocalyptic industrial, Dystopian future settings, Mechanical versus human themes, Dehumanization visualization. Human Absence: Lack of warm organic colors equals lack of humanity, mechanical world. Decay: Rust showing time passing, abandonment, things falling apart without maintenance. Dystopian: Often used for dystopian future settings, warnings about industrial society. Inhuman: Grey mechanical world versus warm human world contrast. Post-Industrial: Showing what remains after industry collapses or humanity leaves.', '2026-01-27 00:26:18', '2026-01-27 00:26:18', 1),
(40, 'The \"Magical Saturated\" (Fantasy World Vibrancy)', 'Fantasy and magical worlds use hyper-saturated, vibrant colors beyond reality. Visual Description: Magical and fantasy realms use extremely vibrant, saturated colors far beyond realistic levels creating fantastical, otherworldly atmosphere. Colors that would clash in reality work in magical contexts. Technical Details: Magical Palette Components (Hyper-saturated primaries equals magical, unreal, impossible; Impossible color combinations equals fantasy logic, anything possible; Glowing colors equals magical energy, power; Rainbow variety equals limitless possibility, all colors), Saturation Level (150-200% of normal saturation, impossibly vivid), Color Combinations (colors that clash in reality harmonize in fantasy, rules don\'t apply). Psychological Effect: Wonder and awe, fantasy recognized, impossibility embraced, magical, childlike wonder revived, escapism, rules suspended. Environmental Psychology: Magical and enchanted, fantastical and impossible, wonderful and amazing, childlike wonder, dreamlike and unreal, escapist fantasy, unlimited possibility, free from reality constraints, imagination unleashed. Common Contexts: Fantasy worlds and dimensions, Magical dimensions and realms, Dream sequences and imagination, Children perspective and stories, Escapist fantasy settings, Magical girl transformations, Storybook worlds. Reality Marker: Hyper-saturation signals clearly \"this is not real world,\" fantasy rules apply. Freedom: Impossible colors equal freedom from reality constraints, anything possible. Ghibli-Disney Influence: Influenced by animated fantasy traditions, particularly Ghibli films and Disney. Childhood: Often associated with childhood perspective where world seems more colorful, magical. Wonder: Designed to create sense of wonder, magic, possibility beyond everyday world.', '2026-01-27 00:26:18', '2026-01-27 00:26:18', 1),
(41, 'The \"White Flash Transition\" (Scene Change/Death)', 'Sudden white flash transitioning scenes or indicating death, transcendence, or divine moment. Visual Description: Sudden flash to pure brilliant white, often washing out entire scene completely before transitioning to next scene or indicating death, transcendence, or divine intervention moment. Technical Details: Flash Types and Durations (Quick flash lasting 1-3 frames equals simple scene transition, Sustained white lasting 1-2 seconds equals death or transcendence, Pulsing white repeatedly equals supernatural event occurring, Slow fade to white equals peaceful passing or divine arrival), Transition Use (Scene changes and cuts, Time jumps forward or backward, Location shifts, Reality shifts between worlds or states), Symbolic Use beyond transitions (Death moment, Transcendence achieved, Divine intervention, Memory flash, Revelation, Purification). Psychological Effect: Shock, transition, transcendence, death, divine presence, reset, new beginning, blinding revelation, purification, erasure. Emotional Narrative: Scene change, death occurring, transcendence achieved, divine light, memory flash, reality shift, new chapter beginning, purification, overwhelming light, truth revealed. Common Contexts: Scene transitions, Death moments, Divine interventions, Transcendence, Memory flashbacks, Time skips, Reality breaks, Explosion impacts, Blinding light, Overexposure effects. Opposite: Black fade or transition has opposite meaning - darkness and ending versus light and transcendence. Duration Meaning: Very brief flash equals simple transition; Sustained white equals highly significant event like death or divine intervention. Sound: Often accompanied by high-pitched tone or complete silence emphasizing moment. Genre: Universal across all anime genres for both practical transitions and symbolic moments. Practical and Symbolic: Serves both practical editing purpose and deep symbolic meaning. Cultural: White as death, purity, divine across many Asian cultures including Japan.', '2026-02-01 12:21:19', '2026-02-01 12:21:19', 1),
(42, 'The \"Black Fade\" (Ending/Darkness/Death)', 'Fade to black showing ending, darkness descending, death, or loss of consciousness. Visual Description: Scene fading progressively to complete black, darkness overtaking and consuming screen. Shows ending and finality, loss of consciousness, death, or darkness descending and winning. Technical Details: Fade Types (Slow gentle fade equals peaceful ending, Rapid quick fade equals sudden darkness or violence, Iris close effect equals old film style and finality, Edges closing inward equals tunnel vision and consciousness fading), Contexts (Scene endings, Loss of consciousness, Death, Sleep and dreams, Despair consuming, Episode endings, Story conclusions). Symbolic Meanings: Ending and conclusion, Death or loss of consciousness, Darkness descending and winning, Despair consuming everything, Story ending, Sleep or unconsciousness, Void and nothingness, Finality. Psychological Effect: Ending, darkness, finality, loss, death, unconsciousness, despair, conclusion, emptiness, void, closure. Emotional Narrative: Story ending, death occurring, consciousness fading away, darkness winning, despair overwhelming, sleep, conclusion reached, final moment, lights going out, end. Common Contexts: Scene and episode endings, Death scenes, Loss of consciousness, Despair moments, Sleep sequences, Story conclusions, Fade to credits, Tunnel vision, Blackout, Defeat. Opposite: White flash or fade represents light and transcendence versus black fade representing darkness and ending. Classic: Classic film technique adapted and used extensively by anime. Speed Meaning: Slow fade equals peaceful or accepting; Rapid fade equals sudden or violent. Silence: Often accompanied by silence or progressively fading sound. Genre: Universal ending technique across all genres. Finality: Creates sense of finality and conclusion.', '2026-02-01 12:21:19', '2026-02-01 12:21:19', 1),
(43, 'The \"Single Color Spotlight\" (Focus/Importance)', 'Single element shown in color while rest of scene monochrome showing focus and supreme importance. Visual Description: Entire scene rendered in black-and-white or heavily desaturated except for single element shown in full vivid color. Draws absolute focus to that colored element as most important thing in frame. Technical Details: Color Choice carrying meaning (Red equals danger, blood, love, passion, violence; Yellow or Gold equals treasure, important object, value; Blue equals sadness, key emotional element, melancholy; Green equals life, nature, hope, growth; Any color equals this matters most right now), Element Types (Physical object like rose, weapon, key, Object; Important person or character; Liquid like blood, tears, poison; Abstract like aura, memory, emotion), Maximum Contrast (Maximum possible contrast between grey desaturated world and single colored element). Symbolic Meanings: This element is most important thing, Focus attention here, Only thing with life or meaning, What matters in this moment, Obsession, Memory of color in grey present, Only thing real or alive, What character sees. Psychological Effect: Focus, importance, obsession, what matters, life in grey dead world, meaning, attention, contrast, significance. Emotional Narrative: This is what matters most, focus on this, only thing alive or real, obsession, memory in grey present, meaning in meaningless world, what character fixated on. Common Contexts: Important object focus, Life in dead world, Obsession visualization, Memory moments, What character sees or focuses on, Contrast emphasis, Symbolic importance, Noir style. Schindler List Influence: Famous live-action use of girl in red coat influenced anime usage. Noir: Common in noir-style anime for dramatic focus. Obsession: Often shows what character obsessed with or focused on exclusively. Multiple Colors: Sometimes multiple colored elements showing multiple important focal points. Genre: Drama, noir, psychological, artistic anime. Technique: Powerful focusing technique drawing eye.', '2026-02-01 12:21:19', '2026-02-01 12:21:19', 1),
(44, 'The \"Dual-Tone Split\" (Internal Conflict Visualization)', 'Character or scene split between two contrasting colors showing internal conflict, duality, or two sides. Visual Description: Character, face, or scene literally split down middle or otherwise divided with two different contrasting colors on each side. Visually represents internal conflict, duality, two opposing sides, or choice between opposites. Technical Details: Split Types (Vertical split down middle most common equals two equal opposing sides, Horizontal split equals upper or lower duality, Diagonal split equals dynamic active conflict, Shifting boundary equals conflict actively in flux), Color Pairs and Meanings (Red versus Blue equals passion versus logic or hot versus cold, Light versus Dark equals good versus evil, Warm versus Cool equals different emotions or states, Character-specific colors equals two personas or identities), Application Areas (Character face split in half, Full body split, Scene split, Screen split between two characters showing contrast). Symbolic Meanings: Internal conflict, Two sides of self, Duality of nature, Choice between paths, Split personality, Torn between options, Two natures, Good versus evil within, Identity crisis. Psychological Effect: Conflict, duality, torn, two sides, internal struggle, choice, split self, contradiction, war within, unable to reconcile. Emotional Narrative: Torn between two sides, internal conflict, duality of nature, choosing between paths, split personality, two selves fighting, contradiction, cannot be both, must choose. Common Contexts: Internal conflict, Split personality, Moral choices, Two sides of character, Torn between people or loyalties, Good versus evil within, Identity crisis, Transformation midpoint, Character duality. Todoroki Example: My Hero Academia Todoroki with red and white split perfectly embodies this technique. Literal versus Metaphorical: Can be literal character design or metaphorical visual effect. Resolution: One color dominating equals conflict resolved, choice made, side winning. Dynamic: Boundary between colors can shift showing conflict changing. Genre: Particularly effective in psychological, supernatural, conflict-driven anime. Visual Impact: Creates immediate visual understanding of internal state.', '2026-02-01 12:21:19', '2026-02-01 12:21:19', 1);
INSERT INTO `anivoc_duo_compositions` (`id`, `name`, `description`, `created_at`, `updated_at`, `is_ingredient`) VALUES
(1, 'Face-to-Face (Equal)', 'Both characters facing each other at the same scale, roughly equal distance from the center of frame. Eye level is matched. Symmetrical or near-symmetrical layout. Use as: dialogue, standoff, duel setup, negotiation, rivals meeting.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(2, 'Face-to-Face (Close)', 'Both characters facing each other but very close — faces almost touching. Intimate framing. Use as: confession moment, threat delivery, \"say that again\", kiss setup, whispered secret.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(3, 'Face-to-Face (Power Imbalance)', 'Both facing each other but one is larger in frame (closer to camera or physically towering). The smaller character looks up. Use as: villain confronting hero, mentor addressing student, intimidation, \"you\'re nothing\".', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(4, 'Charging at Each Other', 'Both characters mid-rush toward each other, converging at the center. Bodies leaning forward, arms extended. About to collide. Use as: battle start, clash moment, head-on confrontation.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(5, 'Side by Side (Equal)', 'Both characters standing next to each other, facing the same direction (toward camera or toward something off-screen). Shoulders roughly even. Use as: team intro, \"we\'re together\", shared moment, looking at something.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(6, 'Side by Side (Leaning)', 'Standing next to each other but one is leaning slightly toward the other — shoulders touching or nearly touching. Casual intimacy. Use as: friends at rest, couple moment, comfort, \"I\'m here\".', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(7, 'Side by Side (Height Difference)', 'Standing next to each other with a noticeable height difference — one significantly taller. Both facing the same direction. Use as: mentor/student, adult/child, tall cool character + short energetic character.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(8, 'Over-the-Shoulder (A watching B)', 'Character A in foreground with back to camera, looking at Character B who faces toward the camera in the background. Use as: A observing B, stalking, \"who is that person\", the audience seeing B through A\'s perspective.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(9, 'Shoulder Peek', 'Character A is in the foreground facing away. Character B peeks over A\'s shoulder — their face visible just above A\'s shoulder line. Use as: curious observation, \"what\'s that?\", eavesdropping, comedic intrusion.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(10, 'Following Behind', 'Character A walks in the foreground (back to camera). Character B follows behind at a slight distance, looking at A\'s back. Use as: following, trailing, \"I\'m watching you\", loyalty walk, silent following.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(11, 'One Above, One Below (Looming)', 'Character A is positioned higher in the frame (on elevated ground, standing over B). Character B is lower, looking up. Use as: power dynamic, villain looming, \"look down on\", authority over submission.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(12, 'One Kneeling, One Standing', 'Character A stands. Character B kneels before them — in submission, proposal, oath, or injury. Use as: loyalty oath, marriage proposal, villain demanding submission, injured character.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(13, 'Seated and Standing', 'One character is seated (chair, throne, ground). The other stands nearby — either looking down at the seated one or being looked at by them. Use as: interview, throne room scene, casual asymmetric conversation.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(14, 'Back to Back (Combat)', 'Both characters standing with backs pressed together, facing opposite directions. Both in combat-ready stances. Use as: surrounded scenario, duo vs crowd, \"I\'ve got your back\", trust formation.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(15, 'Back to Back (Emotional)', 'Both characters with backs to each other but not touching — a gap between them. Both looking away. Use as: after an argument, \"I can\'t face you\", rejection, painful separation.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(16, 'Back to Back (Resting)', 'Both seated or standing with backs touching, relaxed. Leaning into each other. Use as: rest after battle, comfortable companionship, \"we made it\", peaceful duo moment.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(17, 'Embrace (Full)', 'Both characters wrapped in each other\'s arms. Full body contact. Faces close or buried in each other. Use as: reunion, comfort after trauma, emotional breakthrough, \"I thought I lost you\".', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(18, 'One-Sided Hug', 'Character A hugs B, but B\'s arms are at their sides — not reciprocating (yet). B may look surprised or stiff. Use as: unexpected comfort, \"I\'m here\", one person needs it more, comedic awkward hug.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(19, 'Hand Holding (Walking)', 'Both characters side by side, hands linked between them. Walking or standing. Use as: couple moment, childhood memory, trust, \"don\'t let go\", romantic progression.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(20, 'Hand Grab (Urgent)', 'One character\'s hand reaching out and grabbing the other\'s wrist or hand — forcefully, desperately. The grabbed character is mid-turning away. Use as: \"don\'t go\", desperate plea, \"wait\", last chance.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(21, 'Forehead Touch', 'Both characters close, foreheads pressed together. Eyes closed or locked. Very intimate framing. Use as: near-kiss, emotional connection, shared resolve, \"we\'re in this together\".', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(22, 'One Carrying the Other', 'Character A carries B — either in arms (bridal carry), on their back (piggyback), or over their shoulder. Use as: rescue, injury transport, \"I\'ve got you\", comedic embarrassment of being carried.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(23, 'Diagonal Clash', 'Both characters arranged diagonally across the frame, weapons or attacks meeting at the center. One top-left, one bottom-right (or vice versa). Use as: sword clash, battle peak, evenly matched fight.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(24, 'Diagonal Chase', 'Both characters arranged diagonally — one ahead (running), one behind (chasing). Both in motion. Use as: pursuit, escape, \"you can\'t outrun me\", chase sequence frame.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(25, 'One Falling, One Catching', 'Character A is falling (from height, collapsing, or knocked). Character B is mid-catch — arms extended, body braced. Dynamic diagonal. Use as: rescue moment, \"I\'ve got you\", emotional save, trust.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(26, 'Split Frame (Left/Right)', 'Frame divided vertically down the middle. Character A on the left, Character B on the right. Each in their own half. Use as: \"meanwhile\", intercut, comparison, two sides of the same coin, rivals.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(27, 'Split Frame (Top/Bottom)', 'Frame divided horizontally. One character on top, one on bottom. Often one reacting while the other acts. Use as: action/reaction intercut, before/after, cause/effect.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(28, 'Foreground/Background Depth', 'Character A sharp in the foreground (large in frame). Character B smaller and softer in the background, visible behind A. Use as: A\'s perspective on B, depth of relationship, \"I\'m watching from here\", layered composition.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(29, 'Mirror Pose (Rivals)', 'Both characters in identical mirrored poses — same stance, same weapon position, same expression. Perfect left-right symmetry. Use as: rivals intro, \"we are the same\", clone fight, matched power.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(30, 'Silhouette Duo', 'Both characters shown as silhouettes against a bright background. No facial detail. Standing together or apart depending on mood. Use as: team reveal, mystery duo, end-of-arc silhouette, friendship confirmed.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1);
INSERT INTO `anivoc_expressions` (`id`, `name`, `description`, `category`, `use_case`, `created_at`, `updated_at`, `is_ingredient`) VALUES
(1, 'The \"Kitsune\" Smile (The Closed-Eye Smile)', 'The classic \"Fox\" expression. Friendly on the surface, unreadable underneath. Facial Visual: Eyes completely closed in upside-down U crescents. Mouth is a gentle, wide curve. Eyebrows are relaxed or slightly raised. Body Posture: Head tilted slightly to the side. Shoulders relaxed. Hands often clasped behind the back or holding a cheek. Context: Genuine happiness, polite refusal, or masking a terrifying threat (The \"Monster\" in human skin). Archetype: The Healer (Taro), The Manipulator, The Mentor.', NULL, NULL, '2026-01-26 23:39:47', '2026-01-26 23:39:47', 1),
(2, 'The \"Jito\" Stare (The Flat Gaze)', 'The half-lidded, unimpressed look of judgment. Facial Visual: Eyelids lowered halfway (dead fish eyes). Pupils visible but bored. Mouth is a straight horizontal line or a tiny dot. Body Posture: Slouching. Arms crossed loosely or hanging limp. Chin tucked in slightly. Context: Listening to an idiot, skepticism, or exhaustion with the situation. Archetype: The Tech Genius (Kaori), The Tsundere, The Cynic.', NULL, NULL, '2026-01-26 23:39:47', '2026-01-26 23:39:47', 1),
(3, 'The \"Doya\" Face (The Smug Gloat)', 'The look of unearned confidence or victory. Facial Visual: Eyebrows arched high/inward. Eyes half-lidded but looking down at the viewer. Mouth curved into a V-shaped smirk (cat mouth) or a one-sided grin. Nose held high. Body Posture: Chest puffed out. Hands on hips (power pose) or arms crossed high on the chest. Head tilted back. Context: \"I told you so,\" winning a game, or showing off a new weapon. Archetype: The Rival, The Brat, The Ace Pilot.', NULL, NULL, '2026-01-26 23:39:47', '2026-01-26 23:39:47', 1),
(4, 'The \"Puku\" Pout (The Balloon Cheeks)', 'Childish frustration or demanding attention. Facial Visual: Cheeks physically puffed out with air (round shape). Eyes wide and staring upward. Mouth is small and puckered. Brows furrowed slightly but not angry. Body Posture: Shoulders hunched up high. Hands clenched into fists at the side or poking fingers together. Context: Being teased, not getting their way, or jealous affection. Archetype: The Childhood Friend, The Little Sister/Brother, The Spirit Companion (Sparklefly).', NULL, NULL, '2026-01-26 23:39:47', '2026-01-26 23:39:47', 1),
(5, 'The \"Hah?\" (The Disgust Tilt)', 'Looking at something like it\'s trash. Facial Visual: Head tilted back, looking down the nose. One eye slightly squinted, the other wide. Mouth curled in a sneer (showing upper teeth). Shadows often heavy under the chin. Body Posture: Leaning away from the subject. Hand waving \"shoo\" or resting on the back of the neck. Context: Encountering an enemy, seeing something gross, or pure arrogance. Archetype: The Villain (Kaelen/Noctura), The Delinquent.', NULL, NULL, '2026-01-26 23:39:47', '2026-01-26 23:39:47', 1),
(6, 'The \"Highlight Loss\" (Dead Eyes)', 'The moment the soul leaves the body. Facial Visual: Eyes are wide open, but the \"highlight\" (the white reflection dot in the pupil) is removed. The iris becomes a flat, dull color. A dark gradient shadow covers the upper half of the eye. Body Posture: Perfectly still. Arms hanging dead at sides. Head straight forward, staring at nothing. Context: Trauma, mind control, realizing a terrible truth, or entering a \"berserk\" state. Archetype: The Tragic Hero (Kai), The Sleeper Agent.', NULL, NULL, '2026-01-26 23:39:47', '2026-01-26 23:39:47', 1),
(7, 'The \"Pupil Tremor\" (The Quake)', 'The brain failing to process reality. Facial Visual: Eyes extremely wide. The iris/pupil is drawn with a \"wobbly\" or jagged line (not a perfect circle) to simulate shaking. Tiny beads of sweat on the temple. Body Posture: Rigid tension. Shoulders hiked up to ears. Hands clutching the head or chest. Context: Terror, extreme shock, seeing a ghost, or being cornered. Archetype: The Victim, The Rookie.', NULL, NULL, '2026-01-26 23:39:47', '2026-01-26 23:39:47', 1),
(8, 'The \"Shadowed Visage\" (Gloom)', 'The classic depression/rage visual shorthand. Facial Visual: Head tilted forward. A heavy, dark gradient shadow covers the face from the nose up. The eyes are either invisible or glowing dots within the shadow. The mouth is a grim line. Body Posture: Slumped forward or standing ominously still. Hands in pockets or clenched fists shaking. Context: \"I am about to kill you,\" grief, or suppressing an emotional breakdown. Archetype: The Avenger (Rin), The Protagonist at their lowest point.', NULL, NULL, '2026-01-26 23:39:47', '2026-01-26 23:39:47', 1),
(9, 'The \"Sanity Slippage\" (The Dutch Smile)', 'When the pressure becomes too much and they snap. Facial Visual: One eye wide open, the other slightly squinted (asymmetry). Eyebrows slanted in opposite directions. Mouth smiling too wide, showing too many teeth. Head tilted at a Dutch Angle. Body Posture: Hand covering half the face (The \"Chuunibyou\" claw), or fingers digging into the scalp. Back arched unnaturally. Context: Manic laughter, villainous breakdown, or using dangerous magic. Archetype: The Corrupted Healer, The Mad Scientist.', NULL, NULL, '2026-01-26 23:39:47', '2026-01-26 23:39:47', 1),
(10, 'The \"Single Tear\" (Silent Resignation)', 'Accepting a sad fate with dignity. Facial Visual: Face is completely neutral or gently smiling. Eyes are soft. A single, distinct tear track runs from one eye down the cheek. No sobbing, no redness. Body Posture: Standing tall. Head held high or looking at the sunset. Hand on heart or reaching out. Context: Saying goodbye, self-sacrifice, or relief after a long battle. Archetype: The Martyr (Eve), The Veteran.', NULL, NULL, '2026-01-26 23:39:47', '2026-01-26 23:39:47', 1),
(11, 'The \"Tsundere\" Flush (The Angry Blush)', 'Defensive embarrassment. \"It\'s not like I did it for you!\" Facial Visual: Heavy vertical blush lines (hatching) across the nose and cheeks. Eyebrows furrowed deeply (angry). Mouth is open, shouting or stammering. Eyes often looking away to the side. Body Posture: Arms crossed tightly over the chest (barrier) or one finger pointing accusatorily. Leaning forward aggressively. Context: Being thanked, being complimented, or getting caught doing something nice. Archetype: The Rival, The Tough Mechanic (Mira).', NULL, NULL, '2026-01-26 23:39:47', '2026-01-26 23:39:47', 1),
(12, 'The \"Doki\" Soften (The Realization)', 'The precise moment a character falls in love or realizes value. Facial Visual: Eyes widen slightly, pupils dilate (larger than normal). The mouth parts slightly as if taking a small breath. Blush is soft and diffuse (airbrushed look), not lines. Eyebrows raised in surprise. Body Posture: Body freezes mid-motion. Hands might drop to the side or slowly raise to touch the chest/heart. Context: Seeing the love interest do something cool, or a sudden moment of intimacy. Archetype: The Protagonist (Eve), The Silent Type.', NULL, NULL, '2026-01-26 23:39:47', '2026-01-26 23:39:47', 1),
(13, 'The \"Red-Ear\" Turn (The Repressed Shy)', 'Trying desperately to maintain composure but failing. Facial Visual: Face tries to remain neutral/stoic, but the Ears are bright red. Avoiding eye contact (looking down or to the far side). Lips pressed together into a thin line. Body Posture: Stiff, robotic movements. Adjusting glasses, a tie, or a hat to hide the face. Turning the back to the camera. Context: A confession, an accidental touch, or an embarrassing memory. Archetype: The Strategist (Kai), The Soldier (Rin).', NULL, NULL, '2026-01-26 23:39:47', '2026-01-26 23:39:47', 1),
(14, 'The \"Sparkle\" Gaze (Admiration)', 'Seeing someone as a hero or idol. Facial Visual: Eyes are huge and shimmering; \"Sparkle\" star glyphs are often visible in the iris. Mouth is a small O or a wide, happy smile. Cheeks are rosy. Body Posture: Leaning in close to the subject. Hands clasped together under the chin (prayer pose) or fists pumped at chest level. Context: Begging for a favor, seeing a cool move, or pure hero worship. Archetype: The Sidekick, The Spirit Companion (Sparklefly).', NULL, NULL, '2026-01-26 23:39:47', '2026-01-26 23:39:47', 1),
(15, 'The \"Steam\" Whiteout (System Crash)', 'Overwhelming embarrassment leading to brain death. Facial Visual: Eyes become blank white circles (no iris). Face is entirely red. Mouth is a wavy line or completely gone. (Optional: Steam clouds venting from head). Body Posture: Rigid, T-posing, or fainting backward stiff as a board. Context: Accidental perverted situations, sudden marriage proposals, or extreme compliments. Archetype: The Innocent, The socially awkward.', NULL, NULL, '2026-01-26 23:39:47', '2026-01-26 23:39:47', 1),
(16, 'The \"Grit\" (Impact Absorption)', 'Taking a hit or pushing limits. Facial Visual: Teeth clenched tight (lines drawn between teeth). One eye squeezed shut, the other wide and twitching. Sweat flying off the face. Nose scrunched up. Body Posture: Head tucked down (chin to chest). Shoulders hunched. Neck muscles (sternocleidomastoid) bulging and defined. Context: Blocking a heavy attack, lifting debris, or enduring pain. Archetype: The Tank, The Shonen Hero.', NULL, NULL, '2026-01-26 23:39:47', '2026-01-26 23:39:47', 1),
(17, 'The \"Battle Roar\" (Primal Scream)', 'Releasing maximum energy. Facial Visual: Mouth wide open (seeing back teeth and tongue). Eyes constricted to tiny pinpoints (insanity/focus). Heavy shading/lines under the eyes and on the forehead. Body Posture: Head thrown back or lunging forward. Neck veins popping. Chest expanded. Context: The final strike, powering up, or a berserker rage. Archetype: The Beast (Noctura), The Berserker.', NULL, NULL, '2026-01-26 23:39:47', '2026-01-26 23:39:47', 1),
(18, 'The \"Tunnel Vision\" (The Sniper)', 'Absolute, cold focus. Facial Visual: Face is completely devoid of emotion (slack). Eyes are unblinking, focusing on a distant point. One eye might be slightly narrowed (aiming). Breathing is invisible. Body Posture: Absolute stillness. \"Statue-like\" stability. Arms locked in position. Context: Lining up a shot, hacking a mainframe under fire, or casting a complex spell. Archetype: The Sniper (Rin), The Hacker (Kaori).', NULL, NULL, '2026-01-26 23:39:47', '2026-01-26 23:39:47', 1),
(19, 'The \"Blood Wipe\" (The Swagger)', 'Confidence after violence. Facial Visual: A smirk or a sharp grin. Eyes half-lidded and confident. A streak of dirt/blood on the cheek. Body Posture: Thumb wiping the corner of the mouth or cheek. Shoulders relaxed/slouched. Weapon resting on the shoulder. Context: \"Is that all you got?\", defeating a minion, or rising from the rubble. Archetype: The Mercenary (Mira), The Villain.', NULL, NULL, '2026-01-26 23:39:47', '2026-01-26 23:39:47', 1),
(20, 'The \"Hollow\" Gasp (Exhaustion)', 'The fight is over, and the adrenaline is gone. Facial Visual: Mouth hanging open, panting heavy breaths. Eyes unfocused (thousand-yard stare). Sweat dripping from the chin. Hair matted to the forehead. Body Posture: Hands on knees (supporting weight) or leaning against a wall. Shoulders heaving up and down rhythmically. Context: Post-battle survival, running out of mana/stamina, or escaping a chase. Archetype: The Survivor, The Human.', NULL, NULL, '2026-01-26 23:39:47', '2026-01-26 23:39:47', 1),
(21, 'The \"Soul Escape\" (Hanyou)', 'When a character is so shocked or tired they die temporarily. Facial Visual: Eyes are blank white circles. Mouth is a ghostly oval. A blue/white \"ghost\" version of the character (ectoplasm) is seen floating out of their mouth. Body Posture: Knees weak, slumping over, or collapsing face-first into the floor. Context: Extreme exhaustion, hearing a terrible pun, or being roasted by a friend. Archetype: The Victim, The Overworked Leader (Kai).', NULL, NULL, '2026-01-26 23:39:47', '2026-01-26 23:39:47', 1),
(22, 'The \"Shark Teeth\" (Aggressive Shout)', 'Comedic rage. All bark, no bite. Facial Visual: Mouth is wide open, but the teeth are drawn as a single jagged zig-zag line (sawtooth pattern). Eyes are white triangles or inverted arcs. Spittle flying. Body Posture: Leaning forward, head gigantic (SD style), fist shaking in the air. Context: Being annoyed by a teammate, yelling at a broken machine, or a \"Tsundere\" snap. Archetype: The Hothead (Rin), The Mechanic.', NULL, NULL, '2026-01-26 23:39:47', '2026-01-26 23:39:47', 1),
(23, 'The \"Waterfall\" Tears (Gag Crying)', 'Over-the-top sadness or pleading. Facial Visual: Eyes are squeezed shut. Two thick, massive streams of water (like fire hoses) are shooting horizontally out of the eyes. Mouth is a wide, wobbly wave. Body Posture: Clinging to someone\'s leg, prostrate on the ground (dogeza), or running away flailing arms. Context: Begging for money/food, apologizing for a mistake, or fake crying to get a way. Archetype: The Mascot (Sparklefly), The Burden.', NULL, NULL, '2026-01-26 23:39:47', '2026-01-26 23:39:47', 1),
(24, 'The \"Dot\" Eyes (The Blank Stare)', 'Total lack of thought or processing. Facial Visual: The detailed anime eyes are replaced by two simple black dots. The mouth is a tiny line or missing entirely. No nose. Body Posture: Perfectly stiff and upright. Standing like a wooden board. Context: Not understanding a complex explanation, silence after a bad joke, or dissociation. Archetype: The Idiot, The Innocent (Taro).', NULL, NULL, '2026-01-26 23:39:47', '2026-01-26 23:39:47', 1),
(25, 'The \"Cat Mouth\" (The :3 Face)', 'Mischief or feigned innocence. Facial Visual: The mouth is drawn in the shape of a 3 or a w (curved lips). Eyes are large and shiny. Body Posture: Hands mimicking paws, or hands behind head. Leaning in playfully. Context: Pranking someone, asking for a treat, or being smugly cute. Archetype: The Trickster, The Hacker (Kaori).', NULL, NULL, '2026-01-26 23:39:47', '2026-01-26 23:39:47', 1),
(26, 'The \"Gaan\" (The Gloom Lines)', 'The classic anime visual for shock or depression. Facial Visual: Eyes go blank or wide. Crucial detail: Vertical blue/purple lines (hatching) descend from the top of the forehead halfway down the face. The skin tone is often paled. Body Posture: Shoulders dropped. Jaw hanging loose. Standing frozen. Context: Realizing you forgot the ammo, hearing bad news, or supreme disappointment. Archetype: The Strategist who failed (Kai), The Comic Relief.', NULL, NULL, '2026-01-26 23:39:47', '2026-01-26 23:39:47', 1),
(27, 'The \"Pinprick\" Pupil (Terror)', 'The fight-or-flight instinct kicking in. Facial Visual: The iris and pupil contract to a tiny, microscopic dot in the center of a large white sclera. The eyes are huge circles. Tiny sweat drops on the skin. Body Posture: Back arched away from the threat. Hands raised defensively but trembling. Context: Seeing a monster (Necro-Titan), facing death, or a jump scare. Archetype: Everyone facing Kaelen/Noctura.', NULL, NULL, '2026-01-26 23:39:47', '2026-01-26 23:39:47', 1),
(28, 'The \"Shadow Mask\" (The Realization)', 'A heavy realization that darkens the mood. Facial Visual: A hard, straight shadow line is cast across the forehead and eyes. We cannot see the eyes clearly, but we see the mouth tight and trembling. Body Posture: Looking down at hands or the floor. Hands clenched so hard the knuckles are white. Context: \"It was me all along,\" \"They are dead,\" or realizing a betrayal. Archetype: The Traitor, The Broken Hero (Rin).', NULL, NULL, '2026-01-26 23:39:47', '2026-01-26 23:39:47', 1),
(29, 'The \"Color Drain\" (Pallor)', 'Blood leaving the face. Facial Visual: The skin tone shifts to a sickly pale grey/blue. The lips lose color. Dark circles appear instantly under the eyes. Sweat pours down the face. Body Posture: Nausea reaction—hand over mouth, or clutching the stomach. Stumbling. Context: Poisoning (Spirit Slag), extreme sickness, or witnessing gore. Archetype: The Rookie, The Sensitive (Taro).', NULL, NULL, '2026-01-26 23:39:47', '2026-01-26 23:39:47', 1),
(30, 'The \"Split\" (Disbelief)', 'The brain rejecting what the eyes see. Facial Visual: One eyebrow shot up high, the other furrowed down. Mouth slightly agape but crooked. Eyes looking in slightly different directions (as if trying to process two things). Body Posture: Taking a half-step back. Head tilted slightly. Hands open in a \"what?\" gesture. Context: Seeing a dead friend walk in, impossible magic, or a plot twist. Archetype: The Detective, The Scientist.', NULL, NULL, '2026-01-26 23:39:47', '2026-01-26 23:39:47', 1),
(31, 'The \"Lumen\" Pulse (Energy Emotion)', 'When a being made of light feels intense emotion. Visual: The entity\'s core brightness flares uncontrollably. Anger: The glow turns hard and jagged (Lens flares). Sadness: The glow dims to a faint ember; the edges become smoky/fading. Joy: The glow pulses rhythmically (strobe effect) and emits \"sparkle\" particles. Context: Sparklefly reacting to Taro\'s mood, or a Spectre warning of danger. Archetype: The Spirit Companion (Sparklefly, Atairukh), The Energy Being.', NULL, NULL, '2026-01-26 23:39:47', '2026-01-26 23:39:47', 1),
(32, 'The \"Aperture\" Squint (Mechanical Focus)', 'The robotic equivalent of narrowing the eyes. Visual: The mechanical iris (camera lens) physically rotates and contracts to a tiny pinhole. The outer ring might rotate clockwise (focusing) or counter-clockwise (relaxing). Audio Visual: Often accompanied by a text description of \"Whir-Click\" or a HUD locking reticle overlay. Context: Gearbit scanning a threat, Kaori\'s cybernetic eye zooming in, or a drone acting suspicious. Archetype: The AI (Gearbit), The Cyborg (Kaori).', NULL, NULL, '2026-01-26 23:39:47', '2026-01-26 23:39:47', 1),
(33, 'The \"Glitch\" Shudder (Data Stress)', 'Pain or confusion for a digital entity. Visual: The hologram or screen tears apart. Chromatic aberration (RGB separation) splits the image. Blocks of pixels vanish or displace horizontally (Databending). The color palette inverts for a split second. Body Posture: The projection flickers in and out of existence. Context: Kaelen suffering a logic error, Gearbit being hacked, or a hologram running out of battery. Archetype: The Hologram, The Corrupted System.', NULL, NULL, '2026-01-26 23:39:47', '2026-01-26 23:39:47', 1),
(34, 'The \"Jagged\" Silhouette (Shadow Aggression)', 'When a fluid entity becomes hostile. Visual: The smooth, smoky outline of the entity suddenly becomes sharp and spiked. What was \"smoke\" becomes \"needles\" or \"blades.\" The eyes (if present) elongate into slanted slits. Body Posture: Expanding in size to loom over the subject. Tentacles/Tendrils lashing out wildly. Context: Shadownip sensing a threat to Rin, or a Void-Beast preparing to strike. Archetype: The Shadow Manifestation (Shadownip), The Elemental.', NULL, NULL, '2026-01-26 23:39:47', '2026-01-26 23:39:47', 1),
(35, 'The \"Icon\" Face (Digital Shorthand)', 'Retro-tech or cute AI communicating simply. Visual: The \"Face\" is a black monitor screen displaying a neon ASCII emote or symbol. Shock: ( ! ) or O_O. Love: <3 or ^__^. Confusion: ? or a spinning hourglass. Death: X_X or \"NO SIGNAL\". Context: Chipster reacting to Kai\'s bad jokes, or background maintenance bots. Archetype: The Mascot Bot (Chipster), The Old Tech.', NULL, NULL, '2026-01-26 23:39:47', '2026-01-26 23:39:47', 1),
(36, 'The \"Menacing\" Aura (JoJo Effect)', 'Raw intimidation made visible. Facial Visual: Face is darkened with heavy shadows. Eyes glow white or colored (often red/gold). A sharp, predatory grin or completely emotionless glare. Visual Effects: Dark, wavy vertical lines (ゴゴゴゴ) radiating from the body. Sometimes kanji characters float in the background. Body Posture: Standing completely still but radiating threat. Shoulders squared. Hands in pockets or arms crossed. Context: A powerful character revealing their true strength, entering battle mode, or warning someone to back off. Archetype: The Final Boss, The Awakened Hero, The Demon King.', NULL, NULL, '2026-01-26 23:39:47', '2026-01-26 23:39:47', 1),
(37, 'The \"Vein Pop\" (Stress Indicator)', 'Visual shorthand for mounting anger or effort. Facial Visual: A prominent cross-shaped or pulsing vein mark (青筋) appears on the temple or forehead. Face may be otherwise calm or twitching with forced smile. Body Posture: Rigid tension. Fists clenching and unclenching. Maintaining forced composure. Context: Being annoyed by an idiot, holding back rage, or straining under physical load. Archetype: The Short-Tempered Leader, The Strict Teacher, The Exhausted Parent Figure.', NULL, NULL, '2026-01-26 23:39:47', '2026-01-26 23:39:47', 1),
(38, 'The \"Eye Gleam\" (Calculated Malice)', 'The flash before the strike. Facial Visual: A sharp white or colored light reflection appears across the eyes, often accompanied by the glasses glare (where glasses become completely white, hiding eyes). Mouth curves into a knowing smirk. Body Posture: Head tilted down slightly, looking up through the brow. Fingers steepled or adjusting glasses. Context: The strategist executing their plan, the villain\'s trap activating, or a character about to reveal crucial information. Archetype: The Chessmaster (Kai), The Manipulator, The Genius.', NULL, NULL, '2026-01-26 23:39:47', '2026-01-26 23:39:47', 1),
(39, 'The \"Dragon Eyes\" (Beast Awakening)', 'When humanity slips away. Facial Visual: Pupils become vertical slits (reptilian). The iris glows or changes to an unnatural color. Teeth may sharpen visibly. Facial features become slightly more angular/feral. Body Posture: Hunched forward predatorily. Fingers curled like claws. Breathing becomes visible vapor. Context: Berserker mode activation, demonic possession, or channeling primal power. Archetype: The Were-creature, The Possessed, The Beast Within (Noctura).', NULL, NULL, '2026-01-26 23:39:47', '2026-01-26 23:39:47', 1),
(40, 'The \"Killing Intent\" Chill', 'The supernatural weight of murderous will. Facial Visual: Face goes completely blank and dead. Eyes become black voids or thin slits. Entire color palette shifts to cold blues/grays. Visual Effects: The victim is shown frozen, often with ice crystals or a cold breath cloud. Perspective warps to show looming threat. Body Posture: The killer is shown from a low angle, towering. The victim is small, trembling, sweating despite the \"cold.\" Context: A master swordsman facing a novice, an assassin revealing themselves, or the moment before execution. Archetype: The Assassin, The Monster (Kaelen), The Veteran Warrior.', NULL, NULL, '2026-01-26 23:39:47', '2026-01-26 23:39:47', 1),
(41, 'The \"Puppy Eyes\" (Irresistible Plea)', 'Maximum cuteness weaponized. Facial Visual: Eyes are enormous and glistening with unshed tears (not crying, just watery). Lower lip trembles or pouts slightly. Eyebrows raised in the center (worried/pleading expression). Often includes light blush. Body Posture: Hands clasped in front of chest or holding the edge of someone\'s sleeve. Slightly hunched, making self smaller. Head tilted down but eyes looking up. Context: Begging for food/money/help, trying to avoid punishment, or genuine desperate plea. Archetype: The Cute Mascot, The Little Sister, The Beggar.', NULL, NULL, '2026-01-26 23:39:47', '2026-01-26 23:39:47', 1),
(42, 'The \"Nya\" (Cat Gesture)', 'Feline playfulness. Facial Visual: One eye closed in a wink, the other wide and bright. Mouth is the classic \"cat mouth\" (w or :3 shape). Tongue might be sticking out slightly. Small fang visible. Body Posture: One or both hands raised to head height with fingers curled to mimic cat paws. Slight lean or bounce. Sometimes includes a head tilt. Context: Playful teasing, being cute on purpose, or literal cat-person behavior. Archetype: The Catgirl/boy, The Playful Trickster, The Idol.', NULL, NULL, '2026-01-26 23:39:47', '2026-01-26 23:39:47', 1),
(43, 'The \"Fumble\" Blush (Clumsy Charm)', 'Embarrassment from one\'s own mistake. Facial Visual: Eyes are spirals or closed in distress. Entire face is red (not just cheeks). Mouth is a wavy line of dismay. Small sweat drops on temples. Body Posture: Hands waving frantically in front of body (defensive gesture). Bowing apologetically or hiding face in hands. Papers/objects scattered around from the fumble. Context: Dropping important documents, tripping in front of a crush, or saying something stupid. Archetype: The Klutz, The Nervous Rookie, The Awkward Genius (Taro).', NULL, NULL, '2026-01-26 23:39:47', '2026-01-26 23:39:47', 1),
(44, 'The \"Headpat Receive\" (Comfort Acceptance)', 'Accepting affection/praise. Facial Visual: Eyes closed in contentment, eyebrows relaxed. Mouth is a small, gentle smile. Soft blush on cheeks. Face is tilted slightly into the hand. Body Posture: Body is relaxed, shoulders dropped. Might lean into the touch. Sometimes hands are clasped at chest. Context: Being comforted after hardship, receiving genuine praise, or bonding moment. Archetype: The Wounded Hero, The Child, The Loyal Companion.', NULL, NULL, '2026-01-26 23:39:47', '2026-01-26 23:39:47', 1),
(45, 'The \"Awawawa\" Panic (Adorable Fluster)', 'Overwhelmed by multiple problems at once. Facial Visual: Eyes are swirls or X\'s. Mouth is wide open with visible panic. Sweat drops flying everywhere. Face may be partially shadowed despite the chaos. Body Posture: Arms flailing wildly in all directions. Running in place or spinning. Objects (papers, tools, creatures) orbiting around them in chaos. Context: Multiple alarms going off, too many tasks, or being swarmed by admirers. Archetype: The Overworked Administrator, The Popular Student, The Overwhelmed Parent.', NULL, NULL, '2026-01-26 23:39:47', '2026-01-26 23:39:47', 1),
(46, 'The \"Tch\" Click (Dismissive Annoyance)', 'Too cool to engage fully. Facial Visual: Eyes looking to the far side, not making contact. One eyebrow slightly raised. Mouth is a small frown or flat line. Minimal expression. Body Posture: Head turned away, showing profile. Hand in pocket or adjusting collar/cuff. Walking away or leaning against wall. Context: Dismissing an inferior opponent, hiding concern behind irritation, or maintaining cool facade. Archetype: The Rival, The Lone Wolf, The Tsundere (Rin).', NULL, NULL, '2026-01-26 23:39:47', '2026-01-26 23:39:47', 1),
(47, 'The \"Hmph\" Huff (Proud Rejection)', 'Aristocratic dismissal. Facial Visual: Eyes closed with eyebrows raised in disdain. Head turned sharply to the side. Nose pointed upward. Small smirk or neutral mouth. Body Posture: Arms crossed high on chest. Back straight. Sometimes includes a hair flip or fan snap. Context: Rejecting an offer, dismissing a commoner, or maintaining noble pride. Archetype: The Noble, The Ojou-sama, The Prideful Rival.', NULL, NULL, '2026-01-26 23:39:47', '2026-01-26 23:39:47', 1),
(48, 'The \"Glasses Adjust\" (Calculation Mode)', 'The thinking pose. Facial Visual: Eyes hidden behind light reflection on glasses (white lenses). Small knowing smile or completely neutral expression. Body Posture: One hand adjusting glasses by the bridge (classic two-finger push) or by the temple. Other hand often on hip or holding a clipboard. Context: About to explain something complex, formulating a plan, or hiding emotions behind intellectual facade. Archetype: The Strategist, The Scientist, The Manipulator (Kai).', NULL, NULL, '2026-01-26 23:39:47', '2026-01-26 23:39:47', 1),
(49, 'The \"Hair Shadow\" (Mysterious Bishounen)', 'The cool character\'s natural state. Facial Visual: One or both eyes are partially obscured by hanging hair. Visible eye is calm and half-lidded. Face is angular and composed. Body Posture: Relaxed but elegant posture. Often shown in profile or three-quarter view. Minimal movement. Context: The mysterious transfer student, the quiet observer, or the tragic backstory holder. Archetype: The Mysterious Stranger, The Tragic Hero, The Lone Wolf.', NULL, NULL, '2026-01-26 23:39:47', '2026-01-26 23:39:47', 1),
(50, 'The \"Thousand Yard Stare\" (Seen Too Much)', 'The weight of experience. Facial Visual: Eyes are dull and unfocused, looking at nothing/everything. No highlight in pupils. Face is neutral but somehow heavy. Slight bags under eyes. Body Posture: Completely still. Often smoking or holding a drink. Sitting slumped or standing at a window. Context: Post-battle reflection, recalling trauma, or the weariness of veterans. Archetype: The War Veteran (Rin), The Survivor, The Jaded Detective.', NULL, NULL, '2026-01-26 23:39:47', '2026-01-26 23:39:47', 1),
(51, 'The \"Hair Rise\" (Power Surge)', 'Energy manifesting physically. Visual: Hair defies gravity, floating upward or whipping dramatically. Individual strands are detailed and dynamic. Sometimes changes color or glows at the tips. Visual Effects: Wind or energy particles swirl upward. Clothing also billows. Ground may crack beneath feet. Body Posture: Arms slightly away from body. Head tilted back. Fists clenching. Aura radiates outward. Context: Powering up, transformation sequence, or breaking through limits. Archetype: The Shonen Hero, The Super Saiyan, The Magical Girl.', NULL, NULL, '2026-01-26 23:39:47', '2026-01-26 23:39:47', 1),
(52, 'The \"Lens Flare\" Eye (Divine/Demonic)', 'Supernatural power activation. Facial Visual: One or both eyes emit bright light (often with a star/cross flare effect). The iris may show a unique symbol or pattern. Rest of face is shadowed by contrast. Body Posture: Head slightly lowered, looking up at target. Often shown from a low angle to emphasize power. Context: Special ability activation, revealing true form, or divine/demonic intervention. Archetype: The Chosen One, The Deity, The Demon (Noctura).', NULL, NULL, '2026-01-26 23:39:47', '2026-01-26 23:39:47', 1),
(53, 'The \"Mask Crack\" (Breaking Point)', 'The facade shattering. Visual: Literal or metaphorical cracks appear across the character\'s face, emanating from one eye or the mouth. The cracks glow or leak darkness/light. Facial Visual: The expression beneath is often the opposite of what was shown before (calm → rage, or smile → despair). Body Posture: Hand reaching up to face. Body trembling. Posture breaking down. Context: Emotional breakdown, revealing true self, or corruption spreading. Archetype: The Fake Hero, The Possessed, The Broken Villain.', NULL, NULL, '2026-01-26 23:39:47', '2026-01-26 23:39:47', 1),
(54, 'The \"Silhouette Reversal\" (Identity Reveal)', 'The dramatic unmasking. Visual: Character is shown only in black silhouette initially. Then light flares from behind/around them, revealing features in high contrast. Often accompanied by cloth/cloak whipping away. Facial Visual: Face emerges from shadow with dramatic lighting—often split lighting (half light/half shadow). Body Posture: Stepping forward into light, or turning to face camera. Dramatic arm gesture (removing mask/hood). Context: The mysterious helper revealing themselves, the villain\'s true identity, or the hero\'s return. Archetype: The Masked Vigilante, The Secret Identity, The Traitor.', NULL, NULL, '2026-01-26 23:39:47', '2026-01-26 23:39:47', 1),
(55, 'The \"Reflection Lie\" (Duality)', 'The inner self vs outer self. Visual: Character\'s reflection in mirror/water/glass shows a different expression or even a different form (demonic, monstrous, or idealized). Facial Visual: Real face is neutral or smiling. Reflection shows true emotion (crying, rage, fear) or true nature. Body Posture: Standing still, looking at or deliberately avoiding the reflection. Context: Internal conflict, hiding true feelings, or foreshadowing transformation. Archetype: The Double Agent, The Cursed, The Split Personality.', NULL, NULL, '2026-01-26 23:39:47', '2026-01-26 23:39:47', 1),
(56, 'The \"Wind Whip\" (Dramatic Tension)', 'Nature emphasizing the moment. Visual: Strong wind suddenly blows through scene. Hair and clothing stream horizontally. Leaves, petals, or papers scatter dramatically. Facial Visual: Eyes narrowed against wind or closed. Expression is serious or determined. Hair covering part of face. Body Posture: Leaning into wind or standing firm against it. Coat/cloak billowing behind dramatically. Context: Tense standoff, moment of decision, or arrival of important character. Archetype: The Rival\'s Entrance, The Challenge Accepted, The Wanderer.', NULL, NULL, '2026-01-26 23:39:47', '2026-01-26 23:39:47', 1),
(57, 'The \"Rainfall Acceptance\" (Melancholy)', 'Letting the rain hide tears. Visual: Character standing in rain, head tilted back or down. Rain streams down face, mixing with or hiding tears. Facial Visual: Eyes closed or open looking at sky. Expression neutral or slightly pained. We can\'t tell if they\'re crying. Body Posture: Arms hanging limp at sides or raised to sky. Standing still while others run for cover. Context: Loss, acceptance of fate, emotional release, or finding peace. Archetype: The Mourner, The Defeated, The Reborn.', NULL, NULL, '2026-01-26 23:39:47', '2026-01-26 23:39:47', 1),
(58, 'The \"Sunset Silhouette\" (Nostalgia)', 'The golden hour of memory. Visual: Character(s) shown in dark silhouette against orange/red sunset sky. High contrast. Often includes long shadows. Facial Visual: Details are minimal—just the outline. Sometimes a small smile visible on the edge. Body Posture: Relaxed, often sitting or standing side-by-side with companions. Peaceful poses. Context: End of adventure, childhood memory, or bittersweet goodbye. Archetype: The Friend Group, The Memory, The Final Scene.', NULL, NULL, '2026-01-26 23:39:47', '2026-01-26 23:39:47', 1),
(59, 'The \"Chibigaki\" (Comedic Background)', 'Environmental chaos reaction. Visual: Character is drawn in super-deformed (SD/chibi) style in background while others continue normally in foreground. Often includes exaggerated action (being tossed around, spinning, flailing). Facial Visual: Simple dot eyes, simple mouth. Pure comedic expression. Body Posture: Being buffeted by wind, waves, explosions. Tumbling or ragdolling. Context: Character experiencing minor disaster while others are oblivious, comedic punishment, or physical comedy. Archetype: The Comic Relief, The Unlucky, The Butt of the Joke.', NULL, NULL, '2026-01-26 23:39:47', '2026-01-26 23:39:47', 1),
(60, 'The \"Spotlight Stand\" (Main Character Energy)', 'Reality acknowledging the protagonist. Visual: A shaft of light (from window, break in clouds, or seemingly nowhere) illuminates only the character while surroundings remain normal or dim. Facial Visual: Face lit from above/front with heroic lighting. Expression confident or determined. Body Posture: Standing tall. Often with hand extended, weapon raised, or making a declaration. Context: Making a stand, giving a speech, or plot armor manifesting visually. Archetype: The Protagonist, The Hero\'s Moment, The Chosen One.', NULL, NULL, '2026-01-26 23:39:47', '2026-01-26 23:39:47', 1),
(61, 'The \"Camera Stare\" (Audience Acknowledgment)', 'Breaking the illusion. Facial Visual: Eyes shift to look directly at viewer/camera while everyone else looks elsewhere. Expression can range from exasperated to conspiratorial. One eyebrow may raise knowingly. Body Posture: Body remains in scene naturally, but head turns slightly toward camera. Sometimes includes a small gesture (shrug, eye roll, thumbs up) meant only for audience. Context: Reacting to another character\'s stupidity, acknowledging absurdity of situation, or sharing a private joke with viewer. Archetype: The Self-Aware Protagonist, The Narrator, The Comic Relief.', NULL, NULL, '2026-01-26 23:39:47', '2026-01-26 23:39:47', 1),
(62, 'The \"Thought Bubble Reaction\" (Visible Internal)', 'When inner thoughts become embarrassingly visible. Facial Visual: Eyes wide in horror, looking up at their own thought bubble. Face goes pale or red. Mouth in shocked O shape or clenched tight. Visual Effects: Thought bubble appears above head with embarrassing thoughts/images. Character visibly tries to swat it away or hide it. Body Posture: Reaching up frantically to grab/dispel the bubble. Backing away from it. Checking if others can see it. Context: Daydreaming about crush when they appear, thinking mean thoughts that manifest, or internal panic becoming external. Archetype: The Awkward Teen, The Telepath losing control, The Comedic Lead.', NULL, NULL, '2026-01-26 23:39:47', '2026-01-26 23:39:47', 1),
(63, 'The \"Narrator Argument\" (Text Box Fight)', 'Fighting with the story itself. Facial Visual: Looking up/around at narration boxes with annoyance or confusion. Mouth open arguing with disembodied voice. Eyebrows furrowed in frustration. Visual Effects: Narration text boxes appear. Character points at them, tries to erase them, or covers them with hands. Body Posture: Gesticulating wildly at the text. Hands on hips in defiant stance. Sometimes jumping to try to reach floating text. Context: Narrator exposing their secrets, correcting their lies, or providing unwanted commentary. Character defending themselves to the reader. Archetype: The Unreliable Narrator, The Fourth-Wall Breaker, The Meta Character.', NULL, NULL, '2026-01-26 23:39:47', '2026-01-26 23:39:47', 1),
(64, 'The \"Panel Break\" (Frame Violation)', 'Escaping the boundaries of reality. Visual Effects: Character\'s body parts extend beyond or break through the panel borders. Cracks appear in the frame. Sometimes they lean on the panel edge. Facial Visual: Smug awareness or desperate escape attempt. Eyes acknowledging the transgression. Body Posture: Climbing out of the panel, reaching into adjacent panels, or pulling the frame wider. Context: Extreme reaction that cannot be contained, comedic escape attempt, or showing god-tier power. Archetype: The Reality Warper, The Trickster God, The Cartoon Character.', NULL, NULL, '2026-01-26 23:39:47', '2026-01-26 23:39:47', 1),
(65, 'The \"Page Turn Anticipation\" (Waiting for Reader)', 'Frozen in anticipation of the reveal. Facial Visual: Expression locked in suspense - mouth open mid-gasp, eyes wide, or dramatic pointing. Completely still. Visual Effects: Speed lines frozen in place. Dramatic background locked. Sometimes TO BE CONTINUED text appears. Body Posture: Dynamic action pose held unnaturally still. Hand extended. Mid-leap or mid-fall. Context: Cliffhanger moment, dramatic reveal about to happen, or character literally waiting for reader to turn page. Archetype: The Cliffhanger Victim, The Dramatic Revealer, The Patient Character.', NULL, NULL, '2026-01-26 23:39:47', '2026-01-26 23:39:47', 1),
(66, 'The \"Flashback Fade\" (Memory Drift)', 'The mind wandering to the past. Facial Visual: Eyes become unfocused and distant, pupils dilated. Gaze directed at nothing. Mouth slightly parted. Expression softens or saddens. Visual Effects: Soft white or sepia overlay beginning at the edges. Background blurs or fades. Sometimes sparkles or film grain appears. Body Posture: Body goes still. Hand might reach out to phantom memory. Head tilts slightly. Context: Triggered by familiar smell/sound/sight. Reminiscing. Trauma response. Nostalgic moment. Archetype: The Veteran, The Orphan, The Reminiscer, The PTSD Sufferer.', NULL, NULL, '2026-01-26 23:39:47', '2026-01-26 23:39:47', 1),
(67, 'The \"Déjà Vu Overlap\" (Time Echo)', 'Experiencing the same moment twice. Visual Effects: Two semi-transparent versions of the same expression overlap slightly offset. Colors may split (chromatic aberration). Echo/ghost trails. Facial Visual: Confusion and disorientation. Eyes trying to focus. Brow furrowed. Slight head shake. Body Posture: Stumbling or touching head. Hand extended as if seeing double. Context: Time loop realization, prophetic vision manifesting, or supernatural time manipulation. Archetype: The Time Traveler, The Seer, The Loop Prisoner.', NULL, NULL, '2026-01-26 23:39:47', '2026-01-26 23:39:47', 1),
(68, 'The \"Photo Freeze\" (Captured Moment)', 'Reality pausing like a photograph. Visual Effects: Character and immediate surroundings freeze in perfect stillness. Color may shift to black & white or sepia. Film grain or photo border appears. Facial Visual: Expression captured mid-emotion - genuine smile, laughter, surprise. Natural and unposed. Body Posture: Casual, natural pose. Often mid-movement. Surrounded by friends/loved ones also frozen. Context: Precious memory being preserved, end of arc/episode, or magical time stop. Archetype: The Memory Keeper, The Photographer, The Time Stopper.', NULL, NULL, '2026-01-26 23:39:47', '2026-01-26 23:39:47', 1),
(69, 'The \"Fast Forward Blur\" (Time Acceleration)', 'Watching time pass rapidly. Visual Effects: Character\'s expression cycles rapidly through multiple emotions as background blurs/streaks. Motion lines everywhere. Facial Visual: Features slightly distorted by speed. Expression changing so fast it blurs together. Body Posture: Standing still while world moves around them, or moving so fast they\'re blurred. Context: Training montage from their POV, waiting impatiently, or time manipulation power. Archetype: The Impatient, The Time Manipulator, The Training Protagonist.', NULL, NULL, '2026-01-26 23:39:47', '2026-01-26 23:39:47', 1),
(70, 'The \"Slow Motion Realization\" (Extended Moment)', 'A split second stretched into eternity. Visual Effects: Everything moves in extreme slow motion. Individual sweat drops frozen mid-air. Dust particles visible. Sound effects drawn out. Facial Visual: Expression slowly morphing from calm to horror/realization. Eyes widening frame by frame. Body Posture: Reaching out desperately but moving too slowly. Every muscle visible in strain. Context: Seeing the bullet/attack coming, realizing terrible truth, or heroic sacrifice moment. Archetype: The Doomed Hero, The Witness, The Awakening.', NULL, NULL, '2026-01-26 23:39:47', '2026-01-26 23:39:47', 1),
(71, 'The \"Ojou-sama Laugh\" (Noble Mockery)', 'The classic drill-hair princess laugh. Facial Visual: Eyes closed in delight (or one open mockingly). Mouth open in elegant laugh. Expression radiating superiority. Body Posture: Hand covering mouth delicately (back of hand, fingers curled). Head tilted back. Other hand on hip or holding fan. Audio Visual: Ohohoho or Hohoho text. Musical notes floating. Context: Mocking social inferiors, responding to compliments, or masking insecurity with arrogance. Archetype: The Ojou-sama, The Rich Girl, The Rival Noble.', NULL, NULL, '2026-01-26 23:39:47', '2026-01-26 23:39:47', 1),
(72, 'The \"Dogeza Desperation\" (Ultimate Apology)', 'The full prostration of absolute submission. Facial Visual: Face pressed to ground (often not visible). If visible: eyes squeezed shut, mouth in grimace of desperation. Body Posture: Entire body flat on ground. Forehead touching floor. Arms extended forward or pressed at sides. Absolute prostration. Context: Begging for forgiveness, extreme apology, absolute submission, or desperate plea. Archetype: The Guilty, The Desperate, The Submissive, The Debtor.', NULL, NULL, '2026-01-26 23:39:47', '2026-01-26 23:39:47', 1),
(73, 'The \"Senpai Notice\" (Hopeful Recognition)', 'The yearning for acknowledgment from upperclassman. Facial Visual: Eyes wide and hopeful, looking upward. Small hopeful smile. Light blush. Eyebrows raised in anticipation. Body Posture: Hands clasped at chest (prayer pose). Leaning forward slightly. Body language open and eager. Visual Effects: Sparkles around head. Flowers in background. Hopeful aura. Context: Waiting for senpai to notice them, hoping for acknowledgment, or seeking approval from superior. Archetype: The Kouhai, The Admirer, The Student, The Junior.', NULL, NULL, '2026-01-26 23:39:47', '2026-01-26 23:39:47', 1),
(74, 'The \"Kouhai Puff\" (Trying to Impress)', 'Attempting to appear mature/capable and failing adorably. Facial Visual: Chest puffed out with pride. Attempting serious/mature expression but looking cute. Small determined frown. Body Posture: Standing extra straight. Chest out. Chin up. Hands on hips or crossed. Trying to look bigger. Visual Effects: Confidence aura attempting to manifest but flickering. Small sweat drops showing the effort. Context: Trying to impress senpai, prove capability, or act mature. Usually undermined by cute appearance or mistake. Archetype: The Eager Kouhai, The Little Sister, The Rookie.', NULL, NULL, '2026-01-26 23:39:47', '2026-01-26 23:39:47', 1),
(75, 'The \"Servant Bow\" (Professional Deference)', 'The perfect butler/maid acknowledgment. Facial Visual: Completely neutral professional expression. Eyes closed or lowered respectfully. Small polite smile. Body Posture: Precise formal bow - hand over heart or crossed at waist. Back straight. Movements elegant and measured. Context: Acknowledging master\'s orders, professional service, or concealing true emotions behind perfect etiquette. Archetype: The Butler, The Maid, The Loyal Servant, The Professional.', NULL, NULL, '2026-01-26 23:39:47', '2026-01-26 23:39:47', 1),
(76, 'The \"Sparkle Taste\" (Transcendent Flavor)', 'When food is so good it becomes a religious experience. Facial Visual: Eyes enormous and sparkling with literal stars, flowers, or light beams. Mouth open in bliss. Cheeks glowing/rosy. Visual Effects: Sparkles radiating from face. Background explodes into flowers, stars, or heavenly light. Sometimes wings appear. Body Posture: Body arched back in ecstasy or leaning forward in reverence. Hands clasped. Sometimes floating. Context: Tasting incredible food, homemade cooking from love interest, or master chef\'s creation. Archetype: The Food Critic, The Gourmand, The Appreciator.', NULL, NULL, '2026-01-26 23:39:47', '2026-01-26 23:39:47', 1),
(77, 'The \"Soul Departure (Food)\" (Delicious Death)', 'Food so good the spirit leaves the body. Facial Visual: Eyes rolled back or closed in bliss. Mouth hanging open. Expression of pure ecstasy. Visual Effects: Translucent ghost/soul floating upward from body. Body remains seated/standing but lifeless. Body Posture: Body slumped in chair or swaying. Arms hanging. Completely limp. Context: First bite of amazing food, nostalgic flavor, or competition-winning dish. Archetype: The Food Lover, The Judge, The Overwhelmed.', NULL, NULL, '2026-01-26 23:39:47', '2026-01-26 23:39:47', 1),
(78, 'The \"Cheek Stuff\" (Greedy Hamster)', 'Hoarding food in cheeks adorably. Facial Visual: Cheeks bulging outward comically (chipmunk/hamster effect). Eyes squeezed into happy crescents. Mouth completely full. Body Posture: Hunched protectively over food. Arms curled around plate. Guarding the feast. Context: Eating enthusiastically, protecting food from others, or storing food like an animal. Archetype: The Big Eater, The Poor Student, The Food Guardian.', NULL, NULL, '2026-01-26 23:39:47', '2026-01-26 23:39:47', 1),
(79, 'The \"Spice Death\" (Too Hot!)', 'The agony of excessive heat/spice. Facial Visual: Eyes bulging, tears streaming. Tongue hanging out. Face bright red. Steam coming from head/mouth. Visual Effects: Literal flames in background. Heat waves visible. Smoke/steam from mouth and ears. Body Posture: Fanning mouth desperately. Grabbing for water. Running in circles. Context: Eating too-spicy food, being tricked with hot sauce, or cultural food challenge. Archetype: The Victim, The Challenger, The Foreigner.', NULL, NULL, '2026-01-26 23:39:47', '2026-01-26 23:39:47', 1),
(80, 'The \"Hunger Collapse\" (Starvation Mode)', 'When hunger becomes a dramatic crisis. Facial Visual: Eyes become spirals or X\'s. Face pale and gaunt. Mouth open weakly. Visual Effects: Soul/ghost partially leaving body. Stomach growling visualized as sound effect text or monster. Body Posture: Collapsed on ground or table. Crawling weakly. Hand reaching toward food desperately. Context: Missing meals, being broke, or after intense training/battle. Archetype: The Poor Student, The Fighter, The Starving Artist.', NULL, NULL, '2026-01-26 23:39:47', '2026-01-26 23:39:47', 1),
(81, 'The \"Hand Cover Smirk\" (Concealed Evil)', 'Hiding the evil grin. Facial Visual: Hand covering lower half of face (mouth and chin). Only eyes visible - often narrowed and gleaming with malice. Body Posture: Relaxed but predatory. Often sitting or leaning. Free hand gesturing casually. Context: Plotting, concealing true intentions, or savoring imminent victory. Archetype: The Manipulator, The Chessmaster Villain, The Traitor.', NULL, NULL, '2026-01-26 23:39:47', '2026-01-26 23:39:47', 1),
(82, 'The \"Throne Slouch\" (Bored Dominance)', 'The ruler too powerful to care. Facial Visual: Utterly bored expression. Eyes half-closed or looking away with disinterest. Small frown or neutral mouth. Body Posture: Slouched carelessly on throne. Head resting on hand. Legs crossed or draped. Body language screaming indifference. Context: Listening to subordinates, dismissing threats, or showing supreme confidence through apathy. Archetype: The Demon King, The Emperor, The Overpowered Villain.', NULL, NULL, '2026-01-26 23:39:47', '2026-01-26 23:39:47', 1),
(83, 'The \"Champagne Tilt\" (Chaos Toast)', 'Celebrating others\' misery. Facial Visual: Elegant smile or smirk. Eyes half-closed in satisfaction. Completely relaxed expression. Body Posture: Holding wine glass delicately. Tilting it toward chaos/destruction. Seated comfortably or standing at window. Context: Watching plan unfold, observing heroes struggle, or celebrating destruction from safety. Archetype: The Mastermind, The Rich Villain, The Spectator.', NULL, NULL, '2026-01-26 23:39:47', '2026-01-26 23:39:47', 1),
(84, 'The \"Monocle Gleam\" (Single Lens Menace)', 'The aristocratic threat. Facial Visual: One eye hidden behind bright white gleaming monocle. Visible eye narrowed. Small knowing smile. Body Posture: Adjusting monocle with one finger. Standing straight with perfect posture. Cane or hand in pocket. Context: Revealing information, making a threat, or showing intellectual superiority. Archetype: The Gentleman Villain, The Mad Scientist, The Aristocrat.', NULL, NULL, '2026-01-26 23:39:47', '2026-01-26 23:39:47', 1);
INSERT INTO `anivoc_expressions` (`id`, `name`, `description`, `category`, `use_case`, `created_at`, `updated_at`, `is_ingredient`) VALUES
(85, 'The \"Finger Bridge\" (Contemplative Evil)', 'The classic Gendo pose. Facial Visual: Lower face obscured behind steepled fingers. Eyes visible above hands - cold and calculating. Small smirk hidden. Body Posture: Seated, leaning forward. Elbows on desk/armrests. Fingers pressed together in bridge/steeple shape. Context: Deep in thought, interrogating, or revealing master plan. Archetype: The Manipulator, The Director, The Evil Genius.', NULL, NULL, '2026-01-26 23:39:47', '2026-01-26 23:39:47', 1),
(86, 'The \"Tattered Determination\" (Heroic Persistence)', 'Still standing despite everything. Facial Visual: Dirt and blood on face. One eye swollen or closed. Determined glare from remaining eye. Teeth gritted or grinning fiercely. Visual Effects: Clothing torn and tattered. Visible wounds. Smoke/steam rising from body. Body Posture: Swaying but standing. Weapon clutched tightly. Refusing to kneel. Context: Final stand, refusing to give up, or protecting someone despite injuries. Archetype: The Shonen Hero, The Guardian, The Last Stand.', NULL, NULL, '2026-01-26 23:39:47', '2026-01-26 23:39:47', 1),
(87, 'The \"One Eye Closed (Injury)\" (Fighting Wounded)', 'Continuing combat despite damage. Facial Visual: One eye forcibly closed from injury (swelling, blood, damage). Other eye blazing with determination. Grimace of pain masked by resolve. Body Posture: Slightly favoring one side. Compensating for reduced vision. Still in fighting stance. Context: Mid-battle injury, losing an eye permanently, or temporary blindness. Archetype: The Wounded Warrior, The Survivor, The Determined.', NULL, NULL, '2026-01-26 23:39:47', '2026-01-26 23:39:47', 1),
(88, 'The \"Blood Drip Grin\" (Savage Joy)', 'Enjoying the fight despite injury. Facial Visual: Wide, almost manic grin. Blood dripping from mouth or forehead. Eyes wild with battle joy. Body Posture: Loose, relaxed despite injuries. Wiping blood with thumb. Laughing. Context: Berserker enjoying combat, finding worthy opponent, or breaking through limits. Archetype: The Battle Maniac, The Berserker, The Blood Knight.', NULL, NULL, '2026-01-26 23:39:47', '2026-01-26 23:39:47', 1),
(89, 'The \"Cracked Armor\" (Defense Breaking)', 'The moment the protection fails. Visual Effects: Visible cracks spreading across armor, shield, or defensive magic. Light bleeding through cracks. Facial Visual: Eyes widening in realization. Sweat appearing. Confident expression cracking into fear. Body Posture: Looking down at damaged protection. Defensive stance weakening. Context: Powerful attack breaking through, defense reaching limit, or invincibility ending. Archetype: The Tank, The Shielded, The Defender.', NULL, NULL, '2026-01-26 23:39:47', '2026-01-26 23:39:47', 1),
(90, 'The \"Victory Collapse\" (Last Strength)', 'Standing just long enough to win. Facial Visual: Relieved smile or grin. Eyes closing. Expression peaceful despite injuries. Body Posture: Knees buckling. Beginning to fall. Weapon dropping from hand. Context: Defeating enemy with last strength, protecting someone until safe, or completing mission before collapse. Archetype: The Hero, The Protector, The Sacrifice.', NULL, NULL, '2026-01-26 23:39:47', '2026-01-26 23:39:47', 1),
(91, 'The \"Wink & Point\" (Classic Idol)', 'The signature idol gesture. Facial Visual: One eye closed in wink. Other eye bright and sparkling. Big smile showing teeth. Body Posture: Pointing directly at viewer/camera. Hip cocked to side. Body in dynamic pose. Visual Effects: Sparkles, stars, or hearts around the gesture. Light rays. Context: Stage performance, photo shoot, or charming fans. Archetype: The Idol, The Performer, The Charmer.', NULL, NULL, '2026-01-26 23:39:47', '2026-01-26 23:39:47', 1),
(92, 'The \"Peace Sign Tilt\" (Cute Pose)', 'The adorable photo pose. Facial Visual: Bright smile. Eyes closed in happy crescents or one winking. Head tilted at angle. Body Posture: V-sign (peace sign) raised near face. Head resting on or near the hand. Context: Taking photos, greeting fans, or being deliberately cute. Archetype: The Idol, The Cute Character, The Influencer.', NULL, NULL, '2026-01-26 23:39:47', '2026-01-26 23:39:47', 1),
(93, 'The \"Microphone Passion\" (Performance Soul)', 'Pouring emotion into the song. Facial Visual: Eyes squeezed shut or staring intensely ahead. Mouth wide open singing. Expression of pure emotion (joy, pain, love). Body Posture: Gripping microphone with both hands or one hand while other reaches out. Body leaning into the performance. Visual Effects: Sound waves visible. Spotlights. Emotion radiating outward. Context: Emotional climax of song, reaching for high note, or connecting with audience. Archetype: The Singer, The Performer, The Artist.', NULL, NULL, '2026-01-26 23:39:47', '2026-01-26 23:39:47', 1),
(94, 'The \"Backstage Collapse\" (Performance Exhausted)', 'The energy drop after the show. Facial Visual: Exhausted relief. Sweat dripping. Small satisfied smile despite tiredness. Body Posture: Slumped against wall or in chair. Arms hanging limp. Still in costume but disheveled. Context: After successful performance, behind the scenes, or dropping the idol facade. Archetype: The Performer, The Hard Worker, The Real Person.', NULL, NULL, '2026-01-26 23:39:47', '2026-01-26 23:39:47', 1),
(95, 'The \"Dance Freeze\" (Choreography Pose)', 'The dramatic dance position. Facial Visual: Intense expression or joyful smile. Eyes focused. Perfectly composed despite dynamic pose. Body Posture: Mid-dance pose - leg extended, arms positioned artistically. Perfect balance. Visual Effects: Motion lines frozen. Ribbons or clothing mid-flutter. Context: Peak moment in choreography, promotional poster pose, or musical number climax. Archetype: The Dancer, The Idol, The Performer.', NULL, NULL, '2026-01-26 23:39:47', '2026-01-26 23:39:47', 1),
(96, 'The \"Possessed Puppet\" (Loss of Control)', 'Being controlled by external force. Visual Effects: Glowing strings, dark tendrils, or mystical chains attached to limbs/body. Body moving unnaturally. Facial Visual: Eyes blank, glowing differently, or fighting for control (one eye normal, one possessed). Mouth slack or forced into smile. Body Posture: Jerky, puppet-like movements. Unnatural angles. Fighting against invisible strings. Context: Mind control, possession, curse activation, or being a literal puppet. Archetype: The Possessed, The Puppet, The Controlled.', NULL, NULL, '2026-01-26 23:39:47', '2026-01-26 23:39:47', 1),
(97, 'The \"Split Personality Switch\" (Instant Change)', 'Complete personality flip mid-scene. Facial Visual: Instant transformation - one frame shy/innocent, next frame confident/evil. Different eye color. Complete expression change. Visual Effects: Flash of light or darkness. Hair may shift. Aura changes completely. Body Posture: Entire posture changes instantly. Slouched to straight, or confident to cowering. Context: Alternate personality emerging, possession taking over, or true nature revealing. Archetype: The Split Personality, The Jekyll/Hyde, The Shapeshifter.', NULL, NULL, '2026-01-26 23:39:47', '2026-01-26 23:39:47', 1),
(98, 'The \"Curse Mark Pulse\" (Affliction Active)', 'The curse responding to emotion. Visual Effects: Magical tattoo/mark glowing brighter. Pulsing with heartbeat. Spreading across skin. Facial Visual: Gritting teeth against pain or power. Eyes glowing same color as mark. Sweat from strain. Body Posture: Hand clutching marked area. Body trembling. Fighting against the power. Context: Curse activating, forbidden power being used, or affliction spreading. Archetype: The Cursed, The Marked One, The Afflicted.', NULL, NULL, '2026-01-26 23:39:47', '2026-01-26 23:39:47', 1),
(99, 'The \"Halo Appearance\" (Divine Manifestation)', 'Showing celestial nature. Visual Effects: Glowing ring/halo appearing above or behind head. Wings of light. Holy aura. Facial Visual: Serene expression. Eyes glowing gently or pure white. Peaceful smile. Body Posture: Arms slightly spread. Floating. Relaxed but radiating power. Context: Angel revealing identity, divine power activation, or achieving enlightenment. Archetype: The Angel, The Saint, The Chosen One.', NULL, NULL, '2026-01-26 23:39:47', '2026-01-26 23:39:47', 1),
(100, 'The \"Corruption Spread\" (Darkness Claiming)', 'Evil/curse visibly taking over. Visual Effects: Black veins/cracks spreading across skin. Darkness oozing from eyes/mouth. Color draining from one side. Facial Visual: Half face normal, half corrupted. Expression of horror or acceptance. Fighting against change. Body Posture: One side of body moving normally, other side jerky/corrupted. Transformation in progress. Context: Succumbing to darkness, virus spreading, or corruption claiming victim. Archetype: The Corrupted, The Infected, The Fallen.', NULL, NULL, '2026-01-26 23:39:47', '2026-01-26 23:39:47', 1),
(101, 'The \"Active Listener\" (Engaged Attention)', 'Showing genuine interest in what\'s being said. Facial Visual: Slight forward lean of the head. Eyes focused on speaker with soft, attentive gaze. Eyebrows occasionally raising in response. Mouth relaxed, slightly parted or in gentle smile. Body Posture: Body oriented toward speaker. Shoulders relaxed. Occasional small nods. Hands resting naturally or making small responsive gestures. Context: Having a meaningful conversation, receiving important information, or showing respect to speaker. Archetype: The Good Friend, The Counselor, The Attentive Student.', 'Dialogue', 'Listening', '2026-02-08 21:08:00', '2026-02-08 21:08:00', 1),
(102, 'The \"Thoughtful Pause\" (Processing Speech)', 'Taking a moment to consider what was said. Facial Visual: Eyes drift slightly upward or to the side. Brow furrows gently in concentration. Mouth closes, sometimes with lips pressed together lightly. Single finger may touch chin or cheek. Body Posture: Slight backward lean. Head tilts at small angle. Hand rises to face in contemplative gesture. Context: Considering a question, processing complex information, or choosing words carefully. Archetype: The Thinker, The Strategist, The Careful Speaker.', 'Dialogue', 'Thinking', '2026-02-08 21:08:00', '2026-02-08 21:08:00', 1),
(103, 'The \"Conversational Smile\" (Warm Engagement)', 'The natural smile during pleasant dialogue. Facial Visual: Genuine smile with eyes slightly crinkled at corners. Mouth curved naturally, showing few or no teeth. Expression warm but not exaggerated. Eyes maintain soft contact. Body Posture: Relaxed, open stance. Body language inviting. Hands may gesture naturally while speaking. Context: Friendly conversation, sharing pleasant news, or casual social interaction. Archetype: The Friend, The Approachable Leader, The Kind Stranger.', 'Dialogue', 'Pleasant', '2026-02-08 21:08:00', '2026-02-08 21:08:00', 1),
(104, 'The \"Explanation Mode\" (Teaching/Sharing)', 'When actively explaining something. Facial Visual: Eyes bright and engaged. Eyebrows raised slightly. Mouth moves expressively with speech. Expression animated but controlled. Body Posture: Hand gestures emphasizing points. Body may lean forward slightly. Fingers counting points or drawing shapes in air. Context: Explaining a plan, teaching something, or sharing important information. Archetype: The Mentor, The Enthusiast, The Expert.', 'Dialogue', 'Explaining', '2026-02-08 21:08:00', '2026-02-08 21:08:00', 1),
(105, 'The \"Agreeable Nod\" (Affirmation)', 'Showing agreement during dialogue. Facial Visual: Gentle smile. Eyes soft and accepting. Small nods accompanying the expression. Eyebrows relaxed or slightly raised in acknowledgment. Body Posture: Head bobbing gently up and down. Body language open. Sometimes accompanied by small mm-hmm gesture. Context: Agreeing with someone, encouraging them to continue, or showing understanding. Archetype: The Supporter, The Team Player, The Understanding Friend.', 'Dialogue', 'Agreement', '2026-02-08 21:08:00', '2026-02-08 21:08:00', 1),
(106, 'The \"Slight Surprise\" (Mild Revelation)', 'A controlled reaction to unexpected information. Facial Visual: Eyes widen slightly. One eyebrow raises fractionally higher than the other. Mouth opens just a bit. Quick, subtle expression. Body Posture: Minimal movement. Perhaps a slight backward lean of the head. Hand might pause mid-gesture. Context: Hearing mildly surprising news, learning something unexpected but not shocking. Archetype: The Composed Professional, The Diplomatic Character.', 'Dialogue', 'Mild Surprise', '2026-02-08 21:08:00', '2026-02-08 21:08:00', 1),
(107, 'The \"Concerned Furrow\" (Gentle Worry)', 'Showing care without alarm. Facial Visual: Eyebrows draw together slightly in the center. Eyes soften with concern. Mouth turns down just at the corners. Head may tilt sympathetically. Body Posture: Leaning slightly toward speaker. Body language open and supportive. Hand may reach out partway. Context: Hearing about someone\'s problem, expressing sympathy, or showing care. Archetype: The Caring Friend, The Healer, The Empath.', 'Dialogue', 'Concern', '2026-02-08 21:08:00', '2026-02-08 21:08:00', 1),
(108, 'The \"Polite Interest\" (Social Engagement)', 'The mask of proper conversation. Facial Visual: Pleasant, neutral expression. Small polite smile. Eyes engaged but not deeply emotional. Controlled, appropriate reactions. Body Posture: Proper posture. Gestures measured and appropriate. Maintaining social distance. Context: Formal conversation, talking with acquaintances, or maintaining professional demeanor. Archetype: The Noble, The Professional, The Diplomat.', 'Dialogue', 'Polite', '2026-02-08 21:08:00', '2026-02-08 21:08:00', 1),
(109, 'The \"Skeptical Tilt\" (Doubtful But Listening)', 'Questioning but not dismissing. Facial Visual: Head tilts to one side. One eyebrow raises higher. Eyes slightly narrowed in thought. Mouth neutral or slightly pursed. Body Posture: Arms may cross loosely. Weight shifts to one leg. Body language showing reservation but engagement. Context: Hearing a dubious claim, not quite convinced, or needing more information. Archetype: The Skeptic, The Scientist, The Detective.', 'Dialogue', 'Skepticism', '2026-02-08 21:08:00', '2026-02-08 21:08:00', 1),
(110, 'The \"Embarrassed Admission\" (Shy Confession)', 'Revealing something uncomfortable. Facial Visual: Light blush on cheeks. Eyes looking away or down. Small nervous smile or grimace. Hand may scratch cheek or back of head. Body Posture: Shoulders hunched slightly inward. Body turning partially away. Defensive but not aggressive posture. Context: Admitting a mistake, confessing something embarrassing, or revealing a secret. Archetype: The Honest Character, The Guilty Party, The Shy Confessor.', 'Dialogue', 'Embarrassment', '2026-02-08 21:08:00', '2026-02-08 21:08:00', 1),
(111, 'The \"Gentle Laugh\" (Soft Amusement)', 'Quiet laughter during conversation. Facial Visual: Eyes closed in crescents or looking down with smile. Mouth curved in genuine smile. Hand might cover mouth lightly. Expression warm and genuine. Body Posture: Shoulders may shake slightly. Head might bow forward a bit. Body language relaxed and happy. Context: Finding something genuinely funny, sharing a laugh with friends, or expressing joy. Archetype: The Friend, The Joyful Character, The Social Butterfly.', 'Dialogue', 'Laughter', '2026-02-08 21:08:00', '2026-02-08 21:08:00', 1),
(112, 'The \"Earnest Plea\" (Sincere Request)', 'Making a heartfelt request. Facial Visual: Eyes wide and honest. Eyebrows raised in the center. Mouth slightly open or in determined line. Expression open and vulnerable. Body Posture: Leaning forward. Hands may be clasped together or reaching out. Body language open and imploring. Context: Asking for help, making an important request, or pleading a case. Archetype: The Determined, The Desperate, The Hopeful.', 'Dialogue', 'Pleading', '2026-02-08 21:08:00', '2026-02-08 21:08:00', 1),
(113, 'The \"Reassuring Calm\" (Soothing Presence)', 'Projecting peace and comfort. Facial Visual: Gentle, steady expression. Eyes soft and warm. Small, comforting smile. Features relaxed and open. Body Posture: Steady, grounded stance. Hands may gesture soothingly. Body language stable and comforting. Context: Calming someone down, providing comfort, or being a steady presence. Archetype: The Healer, The Parent Figure, The Anchor.', 'Dialogue', 'Reassurance', '2026-02-08 21:08:00', '2026-02-08 21:08:00', 1),
(114, 'The \"Frustrated Sigh\" (Contained Irritation)', 'Showing annoyance while remaining composed. Facial Visual: Eyes close or look away briefly. Eyebrows furrow slightly. Mouth exhales visibly. Expression shows restraint. Body Posture: Hand may pinch bridge of nose or run through hair. Shoulders tense then release. Head may shake slightly. Context: Dealing with annoyance, maintaining patience, or expressing mild frustration. Archetype: The Patient Leader, The Tired Mentor, The Exasperated Friend.', 'Dialogue', 'Frustration', '2026-02-08 21:08:00', '2026-02-08 21:08:00', 1),
(115, 'The \"Hopeful Anticipation\" (Positive Expectation)', 'Looking forward to something. Facial Visual: Eyes bright and wide. Small excited smile. Eyebrows raised. Expression eager but controlled. Body Posture: Leaning forward slightly. Hands clasped or fidgeting with excitement. Body language energized. Context: Discussing future plans, anticipating good news, or showing enthusiasm. Archetype: The Optimist, The Dreamer, The Enthusiastic Friend.', 'Dialogue', 'Hope', '2026-02-08 21:08:00', '2026-02-08 21:08:00', 1),
(116, 'The \"Professional Neutral\" (Business Face)', 'The default expression for formal settings. Facial Visual: Completely neutral expression. Eyes alert but not emotional. Mouth in straight line or slight professional smile. Features composed. Body Posture: Perfect posture. Hands at sides or folded. Minimal gestures. Controlled body language. Context: Business meetings, formal presentations, or professional interactions. Archetype: The Executive, The Official, The Professional.', 'Dialogue', 'Professional', '2026-02-08 21:08:00', '2026-02-08 21:08:00', 1),
(117, 'The \"Diplomatic Consideration\" (Political Thought)', 'Carefully weighing words before speaking. Facial Visual: Eyes may close briefly or look distant. Brow slightly furrowed. Mouth neutral. Expression calculating but calm. Body Posture: Hand may stroke chin. Posture remains proper. Head tilts in consideration. Context: Political discussion, negotiation, or careful communication. Archetype: The Diplomat, The Politician, The Negotiator.', 'Dialogue', 'Diplomacy', '2026-02-08 21:08:00', '2026-02-08 21:08:00', 1),
(118, 'The \"Confident Presentation\" (Public Speaking)', 'Projecting authority while speaking. Facial Visual: Steady eye contact. Expression assured but not arrogant. Controlled smile when appropriate. Features strong and clear. Body Posture: Standing tall. Gestures purposeful and controlled. Body language commanding but approachable. Context: Giving presentation, leading meeting, or public speaking. Archetype: The Leader, The Expert, The Presenter.', 'Dialogue', 'Confidence', '2026-02-08 21:08:00', '2026-02-08 21:08:00', 1),
(119, 'The \"Respectful Attention\" (Hierarchical Listening)', 'Showing proper respect to superiors. Facial Visual: Eyes focused on speaker. Expression attentive and respectful. Small acknowledging nods. Features composed. Body Posture: Slightly deferential posture. Body oriented toward speaker. Gestures minimal and appropriate. Context: Receiving orders, listening to superior, or showing professional respect. Archetype: The Subordinate, The Student, The Junior.', 'Dialogue', 'Respect', '2026-02-08 21:08:00', '2026-02-08 21:08:00', 1),
(120, 'The \"Measured Response\" (Controlled Reaction)', 'Maintaining composure while processing. Facial Visual: Minimal visible reaction. Eyes steady. Mouth remains neutral. Only slight micro-expressions. Body Posture: Posture remains unchanged. Hands steady. Body language controlled and professional. Context: Receiving difficult news professionally, maintaining poker face, or staying composed. Archetype: The Professional, The Spy, The Stoic.', 'Dialogue', 'Control', '2026-02-08 21:08:00', '2026-02-08 21:08:00', 1),
(121, 'The \"Casual Grin\" (Relaxed Happiness)', 'Easy-going smile during informal chat. Facial Visual: Lopsided or full grin. Eyes bright and relaxed. Natural, unforced expression. Showing teeth comfortably. Body Posture: Relaxed, loose posture. Hands in pockets or gesturing casually. Body language open and comfortable. Context: Chatting with friends, informal conversation, or relaxed social setting. Archetype: The Friend, The Laid-Back Character, The Casual Cool.', 'Dialogue', 'Casual', '2026-02-08 21:08:00', '2026-02-08 21:08:00', 1),
(122, 'The \"Playful Tease\" (Friendly Mockery)', 'Gentle teasing among friends. Facial Visual: Mischievous smile or smirk. Eyes sparkling with humor. One eyebrow raised playfully. Expression warm despite teasing. Body Posture: Leaning in conspiratorially. Elbow might nudge friend. Body language playful and friendly. Context: Joking with friends, playful banter, or friendly teasing. Archetype: The Jokester, The Best Friend, The Playful Sibling.', 'Dialogue', 'Teasing', '2026-02-08 21:08:00', '2026-02-08 21:08:00', 1),
(123, 'The \"Shared Secret Smile\" (Inside Joke)', 'Acknowledging something only certain people understand. Facial Visual: Knowing smile. Eyes making brief contact with confidante. Small, private expression. Slightly suppressed grin. Body Posture: Subtle body language. Might glance at co-conspirator. Minimal but meaningful gestures. Context: Inside joke, shared secret, or private understanding. Archetype: The Co-Conspirator, The Best Friend, The Insider.', 'Dialogue', 'Shared Secret', '2026-02-08 21:08:00', '2026-02-08 21:08:00', 1),
(124, 'The \"Lazy Drawl\" (Relaxed Speech)', 'Completely at ease, taking time with words. Facial Visual: Half-lidded eyes. Slow, easy smile. Features completely relaxed. Mouth moving languidly. Body Posture: Slouched or leaning back. Arms behind head or draped over furniture. Body completely at ease. Context: Very casual conversation, complete comfort, or lazy afternoon chat. Archetype: The Laid-Back Character, The Cool Guy, The Relaxed Friend.', 'Dialogue', 'Lazy', '2026-02-08 21:08:00', '2026-02-08 21:08:00', 1),
(125, 'The \"Excited Chatter\" (Enthusiastic Sharing)', 'Rapid, energetic conversation. Facial Visual: Eyes wide and bright. Mouth moving quickly. Expression animated and energetic. Features constantly shifting. Body Posture: Leaning forward eagerly. Hands gesturing rapidly. Body language energized and engaged. Context: Sharing exciting news, enthusiastic discussion, or passionate conversation. Archetype: The Enthusiast, The Gossip, The Excited Friend.', 'Dialogue', 'Excitement', '2026-02-08 21:08:00', '2026-02-08 21:08:00', 1),
(126, 'The \"Standard Neutral\" (Baseline Speaking)', 'The most basic talking expression. Facial Visual: Completely neutral, relaxed features. Eyes forward and clear. Mouth in resting position or moving naturally with speech. No strong emotion. Body Posture: Natural, upright posture. Hands at sides or in neutral position. Minimal movement. Context: Default conversation, neutral dialogue, or baseline speaking. Archetype: Any character in neutral dialogue.', 'Neutral', 'Baseline', '2026-02-08 21:08:00', '2026-02-08 21:08:00', 1),
(127, 'The \"Slight Positive\" (Mildly Pleasant)', 'Just a touch above neutral. Facial Visual: Very slight upturn at corners of mouth. Eyes soft and friendly. Overall pleasant but subtle expression. Body Posture: Open, welcoming body language. Posture relaxed and approachable. Context: Polite conversation, friendly interaction, or generally positive mood. Archetype: The Friendly Character, The Approachable Person.', 'Neutral', 'Positive', '2026-02-08 21:08:00', '2026-02-08 21:08:00', 1),
(128, 'The \"Slight Negative\" (Mildly Displeased)', 'Just a touch below neutral. Facial Visual: Very slight downturn at mouth corners. Eyes slightly less open. Subtle tension in features. Body Posture: Slightly more closed body language. Posture indicating mild discomfort or displeasure. Context: Mildly unpleasant conversation, slight discomfort, or minor annoyance. Archetype: The Displeased Character, The Mildly Annoyed.', 'Neutral', 'Negative', '2026-02-08 21:08:00', '2026-02-08 21:08:00', 1),
(129, 'The \"Alert Neutral\" (Focused Attention)', 'Neutral but highly attentive. Facial Visual: Eyes wide and clear. Features neutral but alert. Expression ready and focused. Body Posture: Upright, attentive posture. Body language indicating readiness. Minimal distraction. Context: Important conversation, receiving instructions, or focused listening. Archetype: The Attentive Student, The Alert Professional.', 'Neutral', 'Alert', '2026-02-08 21:08:00', '2026-02-08 21:08:00', 1),
(130, 'The \"Relaxed Neutral\" (Comfortable Baseline)', 'Neutral with complete comfort. Facial Visual: Features soft and relaxed. Eyes calm. Expression peaceful and at ease. Body Posture: Comfortable posture. Body language showing complete relaxation. No tension. Context: Comfortable conversation, safe environment, or at ease dialogue. Archetype: The Comfortable Character, The At-Ease Person.', 'Neutral', 'Relaxed', '2026-02-08 21:08:00', '2026-02-08 21:08:00', 1),
(131, 'The \"Curious Question\" (Genuine Inquiry)', 'Asking with real interest. Facial Visual: Eyes wide with curiosity. Head tilted slightly. Eyebrows raised. Mouth forming question naturally. Body Posture: Leaning forward slightly. Body language open and interested. Gestures inviting response. Context: Asking genuine question, seeking information, or expressing curiosity. Archetype: The Curious, The Student, The Investigator.', 'Question', 'Curiosity', '2026-02-08 21:08:00', '2026-02-08 21:08:00', 1),
(132, 'The \"Rhetorical Raise\" (Knowing Question)', 'Asking a question you already know the answer to. Facial Visual: One eyebrow raised knowingly. Slight smirk. Eyes showing awareness. Expression slightly smug. Body Posture: Confident stance. Arms might cross. Body language assured. Context: Making a point, teaching through questions, or rhetorical questioning. Archetype: The Teacher, The Clever One, The Know-It-All.', 'Question', 'Rhetorical', '2026-02-08 21:08:00', '2026-02-08 21:08:00', 1),
(133, 'The \"Confused Inquiry\" (Seeking Clarification)', 'Not understanding and asking for help. Facial Visual: Brow furrowed. Eyes showing confusion. Mouth uncertain. Head tilted in confusion. Body Posture: Slightly defensive or uncertain posture. Hands might gesture confusion. Body language unsure. Context: Not understanding, needing clarification, or expressing confusion. Archetype: The Confused, The Learner, The Lost.', 'Question', 'Confusion', '2026-02-08 21:08:00', '2026-02-08 21:08:00', 1),
(134, 'The \"Direct Answer\" (Clear Response)', 'Responding with certainty. Facial Visual: Clear, direct expression. Eyes making contact. Mouth speaking with confidence. Features certain. Body Posture: Straightforward posture. Gestures definitive. Body language assured. Context: Answering with certainty, providing clear information, or direct response. Archetype: The Expert, The Confident, The Knowledgeable.', 'Question', 'Direct Answer', '2026-02-08 21:08:00', '2026-02-08 21:08:00', 1),
(135, 'The \"Uncertain Response\" (Hesitant Answer)', 'Not completely sure of the answer. Facial Visual: Eyes uncertain. Mouth hesitant. Features showing doubt. Expression unsure. Body Posture: Fidgeting or uncertain gestures. Body language showing hesitation. Posture less confident. Context: Unsure answer, hedging response, or tentative reply. Archetype: The Uncertain, The Cautious, The Doubtful.', 'Question', 'Uncertain Answer', '2026-02-08 21:08:00', '2026-02-08 21:08:00', 1),
(136, 'The \"Intent Listen\" (Deep Focus)', 'Completely absorbed in listening. Facial Visual: Eyes locked on speaker. Features still and focused. Expression intense with concentration. Minimal blinking. Body Posture: Body completely still. Leaning forward slightly. All attention on speaker. Context: Critical information, important conversation, or deep listening. Archetype: The Student, The Investigator, The Focused.', 'Listening', 'Deep Focus', '2026-02-08 21:08:00', '2026-02-08 21:08:00', 1),
(137, 'The \"Casual Half-Listen\" (Partial Attention)', 'Listening but not fully engaged. Facial Visual: Eyes occasionally drifting. Features relaxed. Nodding occasionally. Expression showing partial engagement. Body Posture: Relaxed posture. Might be doing something else. Body language showing divided attention. Context: Unimportant conversation, multitasking, or casual listening. Archetype: The Busy, The Distracted, The Multitasker.', 'Listening', 'Partial Attention', '2026-02-08 21:08:00', '2026-02-08 21:08:00', 1),
(138, 'The \"Pretend Listen\" (Fake Attention)', 'Looking like you\'re listening but not really. Facial Visual: Neutral expression with occasional nods. Eyes unfocused or distant. Automatic responses. Body Posture: Positioned toward speaker but mind elsewhere. Going through motions. Fake engagement. Context: Boring conversation, unwanted discussion, or polite pretense. Archetype: The Bored, The Polite But Disinterested, The Trapped.', 'Listening', 'Fake Attention', '2026-02-08 21:08:00', '2026-02-08 21:08:00', 1),
(139, 'The \"Critical Listen\" (Analytical Reception)', 'Listening while evaluating. Facial Visual: Eyes slightly narrowed. Brow furrowed in thought. Expression analytical. Features showing judgment. Body Posture: Arms might cross. Posture evaluative. Body language showing assessment. Context: Judging argument, evaluating proposal, or critical analysis. Archetype: The Judge, The Critic, The Analyst.', 'Listening', 'Critical', '2026-02-08 21:08:00', '2026-02-08 21:08:00', 1),
(140, 'The \"Sympathetic Listen\" (Emotional Reception)', 'Listening with empathy. Facial Visual: Eyes soft with emotion. Features showing sympathy. Expression warm and understanding. Mirroring speaker\'s emotion. Body Posture: Open, supportive body language. Leaning in with care. Gestures comforting. Context: Friend sharing problems, emotional conversation, or supportive listening. Archetype: The Empath, The Counselor, The Friend.', 'Listening', 'Empathy', '2026-02-08 21:08:00', '2026-02-08 21:08:00', 1),
(141, 'The \"Group Address\" (Speaking to Multiple)', 'Addressing several people at once. Facial Visual: Eyes scanning across group. Expression engaging everyone. Features animated and inclusive. Body Posture: Open stance facing group. Gestures including everyone. Body language expansive. Context: Group meeting, addressing team, or speaking to crowd. Archetype: The Leader, The Presenter, The Host.', 'Group Dialogue', 'Group Address', '2026-02-08 21:08:00', '2026-02-08 21:08:00', 1),
(142, 'The \"Side Comment\" (Aside to One Person)', 'Speaking to one person while in group. Facial Visual: Eyes focused on specific person. Expression private despite public setting. Features showing selective engagement. Body Posture: Turning slightly toward specific person. Body language excluding others. Intimate despite setting. Context: Private comment in group, whispering aside, or selective communication. Archetype: The Conspirator, The Friend, The Selective.', 'Group Dialogue', 'Private Aside', '2026-02-08 21:08:00', '2026-02-08 21:08:00', 1),
(143, 'The \"Observer Mode\" (Watching Conversation)', 'Watching others talk without participating. Facial Visual: Eyes tracking speakers. Expression neutral or amused. Features relaxed. Not speaking. Body Posture: Slightly back from conversation. Body language observant. Posture comfortable but removed. Context: Watching argument, observing interaction, or choosing not to participate. Archetype: The Observer, The Outsider, The Quiet One.', 'Group Dialogue', 'Observation', '2026-02-08 21:08:00', '2026-02-08 21:08:00', 1),
(144, 'The \"Conversation Join\" (Entering Discussion)', 'Jumping into ongoing conversation. Facial Visual: Expression brightening as speaking begins. Eyes engaging. Features becoming animated. Body Posture: Leaning in from observation position. Hand raising or gesturing to indicate desire to speak. Context: Adding to conversation, interjecting, or joining discussion. Archetype: The Participant, The Joiner, The Contributor.', 'Group Dialogue', 'Joining', '2026-02-08 21:08:00', '2026-02-08 21:08:00', 1),
(145, 'The \"Conversation Exit\" (Leaving Discussion)', 'Politely withdrawing from conversation. Facial Visual: Expression becoming neutral. Eyes disengaging. Features showing polite withdrawal. Body Posture: Leaning back slightly. Body language closing off. Posture indicating departure. Context: Ending participation, excusing self, or withdrawing from discussion. Archetype: The Departing, The Done, The Exiting.', 'Group Dialogue', 'Exiting', '2026-02-08 21:08:00', '2026-02-08 21:08:00', 1),
(146, 'The \"Interrupted Mid-Sentence\" (Cut Off)', 'Being stopped while speaking. Facial Visual: Mouth frozen mid-word. Eyes widening in surprise or annoyance. Expression of being cut off. Body Posture: Hand gesture frozen mid-motion. Body language showing interrupted momentum. Context: Being interrupted, cut off, or stopped mid-speech. Archetype: The Interrupted, The Silenced, The Cut Off.', 'Special States', 'Interruption', '2026-02-08 21:08:00', '2026-02-08 21:08:00', 1),
(147, 'The \"Careful Word Choice\" (Diplomatic Speech)', 'Choosing words very carefully. Facial Visual: Features showing concentration. Eyes thoughtful. Mouth forming words slowly and deliberately. Body Posture: Controlled gestures. Measured movements. Body language careful. Context: Delicate situation, diplomatic conversation, or sensitive topic. Archetype: The Diplomat, The Careful, The Tactful.', 'Special States', 'Careful Speech', '2026-02-08 21:08:00', '2026-02-08 21:08:00', 1),
(148, 'The \"Rapid Fire\" (Quick Speech)', 'Speaking very quickly. Facial Visual: Mouth moving rapidly. Eyes bright and energized. Features animated and fast-moving. Body Posture: Gestures quick and numerous. Body language energetic. Movement rapid. Context: Excited explanation, urgent information, or nervous talking. Archetype: The Excited, The Nervous, The Rapid.', 'Special States', 'Fast Speech', '2026-02-08 21:08:00', '2026-02-08 21:08:00', 1),
(149, 'The \"Slow Revelation\" (Deliberate Disclosure)', 'Revealing something important slowly. Facial Visual: Expression serious and controlled. Eyes watching for reaction. Features measured and deliberate. Body Posture: Still, controlled posture. Gestures minimal and purposeful. Body language careful. Context: Important revelation, careful disclosure, or dramatic announcement. Archetype: The Revealer, The Dramatic, The Controlled.', 'Special States', 'Revelation', '2026-02-08 21:08:00', '2026-02-08 21:08:00', 1),
(150, 'The \"Comfortable Silence\" (Peaceful Quiet)', 'Not speaking but comfortable with it. Facial Visual: Peaceful, content expression. Eyes soft and relaxed. Features showing comfort with silence. Body Posture: Relaxed, at-ease posture. No tension from lack of speech. Body language peaceful. Context: Comfortable with companion, peaceful moment, or no need for words. Archetype: The Content, The Peaceful, The Comfortable.', 'Special States', 'Silence', '2026-02-08 21:08:00', '2026-02-08 21:08:00', 1);
INSERT INTO `anivoc_hand_gestures` (`id`, `name`, `description`, `created_at`, `updated_at`, `is_ingredient`) VALUES
(1, 'Closed Fist (Neutral)', 'All four fingers curled into the palm. Thumb wrapped over the outside of the fingers (index to pinky). Knuckles forward. Clean, simple fist shape. Use as: determination, anger, gripping something invisible, base fist shape.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(2, 'Fist Bump Ready', 'Closed fist, thumb on the outside, extended forward toward another fist. Arm slightly bent. Knuckles facing the target. Use as: camaraderie, \"let\'s go\", team moment, casual agreement.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(3, 'Fist Against Wall/Surface', 'Closed fist pressed against a vertical surface — wall, desk, door. Knuckles in contact. Arm extended. Use as: frustration, anger, \"damn it\", impact aftermath, barely holding back.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(4, 'Trembling Fist', 'Closed fist visibly shaking. Same shape as neutral fist but with motion lines or vibration marks around it. Use as: rage building, holding back violence, emotional overflow, \"I\'m going to...\".', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(5, 'Open Palm Forward (Stop)', 'Hand fully open, all five fingers together and extended. Palm facing the viewer/target. Fingers together, thumb slightly apart. Use as: \"stop\", \"wait\", blocking, barrier gesture.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(6, 'Open Palm Upward (Offering)', 'Hand open, palm facing up. Fingers slightly relaxed. Arm extended forward or at waist height. Use as: offering something, \"please\", presenting, open-handed peace.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(7, 'Open Hand Spread (Surprise)', 'All five fingers splayed wide apart. Palm open. Fingers fanned out maximally. Use as: shock, \"what?!\", surprise, horror reaction, \"no way\".', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(8, 'Relaxed Open Hand', 'Palm open, fingers slightly curled inward in a natural resting position. Not stiff, not spread. Loose and casual. Use as: idle hand, mid-gesture transition, natural hanging position.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(9, 'Index Finger Point', 'Index finger fully extended straight forward. Other three fingers curled into palm. Thumb tucked or resting against middle finger. The classic \"you\" point. Use as: accusation, identification, \"that one\", challenge.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(10, 'Index Finger Up (One)', 'Index finger extended straight up toward the sky. Other fingers closed. Thumb tucked. Use as: \"number one\", \"wait one moment\", \"I have a point\", attention-getting.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(11, 'Two Fingers Up (Peace / V-Sign)', 'Index and middle fingers extended upward, spread in a V shape. Ring, pinky, and thumb closed into palm. Use as: peace sign, victory, photo pose, \"two\" count.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(12, 'Index Finger at Lips (Shh)', 'Index finger extended and pressed vertically against the center of the lips. Other fingers curled into palm. Arm bent at elbow. Use as: \"be quiet\", secret, shushing, playful silence.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(13, 'Index Finger Tap (on chin/cheek)', 'Index finger extended, lightly tapping against the chin or cheek. Other fingers loosely curled. Elbow supported by the other hand. Use as: thinking, \"hmm\", playful consideration, teasing.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(14, 'Index Finger Wag', 'Index finger extended and slightly curved — mid-wag motion. Other fingers closed. Finger angled side to side. Use as: scolding, \"no no no\", disapproval, playful warning.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(15, 'Thumbs Up', 'Closed fist with thumb extended upward. Knuckles facing forward. Clean, unambiguous positive gesture. Use as: approval, \"good\", \"OK\", encouragement, confirmation.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(16, 'Thumbs Down', 'Closed fist with thumb extended downward. Knuckles facing forward. Use as: disapproval, rejection, \"nope\", verdict, comedic dismissal.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(17, 'Thumbs Up and Down (Both Hands)', 'Both fists raised — one thumb up, one thumb down. Side by side or at different heights. Use as: conflicted decision, \"pros and cons\", weighing options, comedic indecision.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(18, 'Gripping Collar/Lapel', 'Fingers hooked into the fabric at the collar or lapel of another character\'s outfit. Knuckles tight. Arm extended forward. Use as: confrontation, \"talk\", intimidation, pulling someone close.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(19, 'Gripping Wrist', 'Hand wrapped around another character\'s wrist. Thumb on top, fingers underneath. Firm hold. Use as: \"stop\", restraint, leading someone, desperate hold, trust moment.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(20, 'Gripping Own Sleeve/Arm', 'Hand clutching the opposite arm\'s sleeve near the elbow or forearm. Fingers bunched into fabric. Use as: nervousness, self-comfort, holding back emotion, anxiety tell.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(21, 'Weapon Grip (Sword/Staff — One Hand)', 'Hand wrapped firmly around a cylindrical grip. Fingers fully closed around the handle. Thumb on the side. Wrist straight and locked. Use as: weapon ready, combat stance, holding weapon at rest.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(22, 'Weapon Grip (Two-Handed)', 'Both hands on a single weapon handle. Top hand with fingers forward, bottom hand with fingers curling under. Hands spaced apart on the grip. Use as: heavy weapon stance, two-handed sword, power grip, chopping stance.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(23, 'Hand on Cheek', 'Open palm resting against one cheek. Fingers at the temple, fingertips near the eye. Head slightly tilted into the hand. Use as: thinking, listening, dreamy/romantic pose, \"hmm\".', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(24, 'Hand Covering Eyes', 'Open palm pressed flat over both eyes. Fingers spread slightly. Arm extended from shoulder. Use as: \"I can\'t look\", embarrassment, hiding tears, horror.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(25, 'Fingers Through Hair (Frustrated)', 'Hand raked into the hair, fingers spread and gripping. Fingers visible between strands. Wrist bent. Hair slightly disheveled. Use as: frustration, stress, \"ugh\", running out of patience.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(26, 'Tucking Hair Behind Ear', 'One hand with index finger and thumb gently pushing a strand of hair behind the ear. Other fingers loosely curled. Delicate motion. Use as: nervous habit, flirting, idol gesture, idle tell.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(27, 'Chin Rest on Fist', 'Closed fist resting under the chin, supporting the head. Elbow on a surface or supported by the other arm. Head tilted slightly. Use as: boredom, waiting, lazy thinking, \"talk faster\".', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(28, 'Glasses Push (Two Fingers)', 'Index and middle finger on the bridge of the glasses, pushing them up the nose. Other fingers loosely curled. Precise, deliberate motion. Use as: calculation mode, character signature, \"let me think\", intellectual pose.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(29, 'Steepled Fingers', 'Both hands with fingertips touching — index to index, middle to middle, etc. Palms open, fingers arched. Thumbs may touch below. Use as: contemplation, villain planning, \"interesting\", manipulation, Gendo pose.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(30, 'Covering Smirk (Back of Hand)', 'Back of one hand raised in front of the mouth, covering the lower face. Fingers curled slightly. Wrist elegant. Use as: concealed laughter, ojou-sama laugh, aristocratic amusement, hiding a smirk.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(31, 'Claw Gesture (Chuunibyou)', 'One hand raised with fingers curled into a claw shape — all fingers bent at the second knuckle. Wrist slightly bent. Dramatic pose. Use as: \"evil\" pose, chuunibyou energy, playful villain, dramatic power gesture.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(32, 'Cat Paw (Nya Hands)', 'Both hands raised to chest height with fingers curled inward loosely — mimicking animal paws. Wrists slightly bent. Cute, animal-like. Use as: cat-person behavior, nya pose, playful cute gesture, idol variant.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(33, 'Jazz Hands', 'Both hands raised at head height with fingers spread wide and slightly curled/wiggling. Palms facing forward. Showmanship pose. Use as: performance, \"ta-da!\", comedic reveal, sarcastic enthusiasm.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(34, 'Thumbs Against Cheeks (Stretching)', 'Both thumbs pressed against cheeks, pulling the skin sideways slightly. Fingers wrapped around the jaw. Playful face-stretch. Use as: comedic face-making, \"look at me\", playful distortion, silly moment.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(35, 'Finger Gun', 'One hand in a gun shape — index finger and thumb extended at 90 degrees, other fingers curled into palm. Aimed forward. Wink often accompanies. Use as: playful greeting, \"got you\", casual charm, idol signature.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1);
INSERT INTO `anivoc_lighting` (`id`, `name`, `description`, `created_at`, `updated_at`, `is_ingredient`) VALUES
(1, 'The \"Rim Light Hero\" (Heroic Silhouette)', 'Bright outline around character in darkness. Visual Description: Character primarily in shadow/darkness but with bright glowing outline around their entire silhouette. Light source behind or around them creates halo effect. Interior details minimal, emphasis on heroic shape. Technical Details: Rim Width (thin precise line to thick glowing aura), Rim Color (white pure, gold divine, blue cool hero, warm colors passionate hero), Interior Lighting (usually very dark, maybe key facial features lit), Background (typically dark to maximize contrast). Lighting Setup: Strong backlight with little to no front light. Emotional Tone: Heroic, mysterious, powerful, silhouette against darkness, hope in darkness. Common Contexts: Hero emerging from shadows, dramatic entrance, standing against evil, sunset hero shots, power reveals. Character Archetypes: The Mysterious Hero, The Dark Knight, The Protector, The Silhouette Badass. Time/Setting: Any time, but especially effective at dawn/dusk, in dark spaces, or backlit by explosions.', '2026-01-27 00:02:04', '2026-01-27 00:02:04', 1),
(2, 'The \"Half-Face Shadow\" (Duality Split)', 'Vertical line dividing face between light and dark. Visual Description: Character\'s face split vertically with one side fully lit, the other in deep shadow. Creates stark division down center of face. The shadow side can hide or reveal the eye depending on intent. Technical Details: Division Line (sharp edge vs soft gradient transition), Shadow Depth (complete black vs dark but detailed), Eye Treatment (both visible, or shadow side eye hidden/glowing), Symmetry (perfect vertical split or slight angle). Lighting Setup: Strong side lighting (90° angle), blocking opposite side. Emotional Tone: Internal conflict, duality, moral ambiguity, hidden nature, two sides of personality. Common Contexts: Moral dilemmas, revealing dual nature, internal struggle, villain/hero moments, dramatic decisions. Character Archetypes: The Conflicted, The Anti-Hero, The Double Agent, The Split Personality, The Morally Gray. Color Coding: Warm light/cool shadow = passion vs reason, Blue light/warm shadow = cold exterior/warm heart, Red/blue = opposing forces.', '2026-01-27 00:02:04', '2026-01-27 00:02:04', 1),
(3, 'The \"Under-Light Villain\" (Sinister Shadows)', 'Lit from below creating upward shadows. Visual Description: Light source from below the face (flashlight under chin effect), casting shadows upward. Makes eye sockets dark, nose cast shadow upward, creates unnatural and threatening appearance. Reverses normal lighting psychology. Technical Details: Shadow Direction (all shadows cast upward), Eye Treatment (eyes can be shadowed pits or glowing from within), Intensity (harsh lighting creates strong contrast), Color (often sickly green, cold blue, or hellish red/orange). Lighting Setup: Light source below face level pointing up. Emotional Tone: Evil, unnatural, threatening, sinister, wrong, horror, madness. Common Contexts: Villain reveals, horror moments, madness, demonic possession, telling scary stories, evil monologues. Character Archetypes: The Villain, The Mad Scientist, The Demon, The Horror, The Storyteller (scary tale). Cultural Note: Universal horror/villain lighting, plays on primal fear of unnatural shadow direction.', '2026-01-27 00:02:04', '2026-01-27 00:02:04', 1),
(4, 'The \"Top-Down Spotlight\" (Judgment Light)', 'Single harsh light from directly above. Visual Description: Strong light coming straight down from above, like interrogation spotlight. Creates hard shadows under eyes, nose, chin. Shoulders receive light, but neck area in shadow. Creates oppressive, vulnerable feeling. Technical Details: Shadow Pattern (dark eye sockets, pronounced nose shadow, harsh cheekbones), Coverage (can be narrow spotlight or wider overhead sun), Intensity (usually harsh and bright), Background (often dark, emphasizing isolation). Lighting Setup: Overhead light source, 90° from above. Emotional Tone: Judgment, interrogation, pressure, exposure, nowhere to hide, being watched, guilt. Common Contexts: Interrogation scenes, confession moments, divine judgment, guilt visualization, courtroom drama, being caught. Character Archetypes: The Accused, The Guilty, The Interrogated, The Judged, The Exposed. Psychological Effect: Creates vulnerability, as if judged from above.', '2026-01-27 00:02:04', '2026-01-27 00:02:04', 1),
(5, 'The \"Chiaroscuro Drama\" (Rembrandt Lighting)', 'Strong light/dark contrast with triangle of light on shadow side. Visual Description: Dramatic lighting with most of face in shadow except for a triangle of light on the cheek of the shadow side (under eye). Creates depth and drama. Classical painting technique adapted for anime. Technical Details: Key Feature (triangle of light on shadow-side cheek), Light Ratio (strong contrast between lit and shadow sides), Detail Level (shadow side still has subtle detail visible), Angle (light typically 45° above and to side of face). Lighting Setup: Single light source at 45° angle (both horizontal and vertical). Emotional Tone: Dramatic, artistic, contemplative, serious, depth of character, classical beauty. Common Contexts: Dramatic conversations, character depth moments, serious declarations, artistic scenes, photography. Character Archetypes: The Complex Character, The Contemplative, The Serious, The Dramatic Lead. Artistic Heritage: Named after Rembrandt\'s painting technique, signals quality/artistry.', '2026-01-27 00:02:04', '2026-01-27 00:02:04', 1),
(6, 'The \"Backlighting Silhouette\" (Mystery Figure)', 'Character as dark shape against bright background. Visual Description: Character completely in shadow/silhouette with bright light source behind them. Details obscured, only shape visible. Creates mystery and emphasizes form. Can reveal only eyes glowing from within darkness. Technical Details: Silhouette Completeness (total black vs some rim lighting), Background Brightness (moderate glow to blinding white), Eye Treatment (completely dark or eyes glowing through), Edge Quality (sharp defined edge vs soft halation). Lighting Setup: Strong backlight with no fill light. Emotional Tone: Mystery, dramatic entrance, power reveal, unknown threat, impressive presence, intimidation. Common Contexts: Mysterious character entrance, door/window entries, identity concealment, dramatic reveals, power displays. Character Archetypes: The Mystery Figure, The Arriving Power, The Unknown Threat, The Dramatic Entrance. Reveal Technique: Often precedes lighting change that reveals identity.', '2026-01-27 00:02:04', '2026-01-27 00:02:04', 1),
(7, 'The \"Glow From Within\" (Inner Light)', 'Character emitting their own light. Visual Description: Character themselves is the light source, glowing from within. Skin, eyes, markings, or entire body emits light. Illuminates their surroundings. Shows supernatural or emotional state. Technical Details: Glow Source (eyes only, specific markings, entire body), Glow Color (power type - blue=ice, red=fire, white=pure, etc.), Intensity (subtle inner glow to blinding radiance), Effect on Environment (illuminates nearby objects/people). Lighting Setup: Character is primary light source. Emotional Tone: Power, supernatural, transcendence, emotion made visible, inner truth revealed, divine/demonic. Common Contexts: Power-ups, transformations, emotional peaks, divine/demonic revelation, magical abilities active. Character Archetypes: The Powered, The Transformed, The Emotional Peak, The Divine/Demonic, The Energy Being. Color Psychology: White/Gold = Divine/pure/heroic, Red = Rage/demonic/fire, Blue = Cold/calm/ice/magic, Purple = Forbidden power/corruption, Green = Nature/poison/sickness.', '2026-01-27 00:02:04', '2026-01-27 00:02:04', 1),
(8, 'The \"Venetian Blind Stripes\" (Film Noir Bars)', 'Parallel light/shadow stripes across face. Visual Description: Light filtering through venetian blinds, prison bars, or similar creates horizontal or vertical stripes of light and shadow across character\'s face and body. Classic noir aesthetic. Technical Details: Stripe Direction (usually horizontal blinds or vertical bars), Spacing (narrow stripes vs wide bands), Coverage (just face or entire body), Contrast (harsh black/white or softer gradation). Lighting Setup: Light through slats/bars creating regular shadow pattern. Emotional Tone: Trapped, noir mystery, caged, shadows of past, imprisonment (literal or metaphorical), detective story. Common Contexts: Detective offices, prison scenes, trapped feelings, film noir homage, shadowy investigations, moral imprisonment. Character Archetypes: The Detective, The Prisoner, The Trapped, The Noir Protagonist, The Investigator. Genre Association: Strong film noir and detective story connection.', '2026-01-27 00:02:04', '2026-01-27 00:02:04', 1),
(9, 'The \"Soft Diffused Beauty\" (Glamour Light)', 'Soft, even lighting with minimal shadows. Visual Description: Gentle, diffused lighting that wraps around the face softly. Minimal harsh shadows, even light distribution. Creates smooth, beautiful appearance. Often with soft glow or bloom effect. Technical Details: Shadow Softness (extremely soft shadow transitions), Highlights (gentle, not blown out), Coverage (even, flattering distribution), Effects (optional soft glow, slight bloom, gentle rim light). Lighting Setup: Large soft light source or multiple fill lights, diffusion material. Emotional Tone: Beauty, gentleness, romance, idealization, peace, innocence, purity, dreamlike. Common Contexts: Romantic moments, beauty shots, dream sequences, idealized memories, peaceful scenes, first love. Character Archetypes: The Love Interest, The Beautiful, The Innocent, The Idealized, The Dreamed-Of. Technical Purpose: Hides imperfections, creates ethereal quality.', '2026-01-27 00:02:04', '2026-01-27 00:02:04', 1),
(10, 'The \"Harsh Reality Light\" (Unflattering Truth)', 'Bright, harsh, unflattering lighting revealing flaws. Visual Description: Bright, hard lighting that creates harsh shadows and reveals every detail unflinchingly. Opposite of glamour light. Shows reality without beautification. Can be overhead fluorescent or harsh direct sun. Technical Details: Harshness (strong, hard shadows), Detail Level (every line and flaw visible), Shadow Depth (dark, pronounced shadows), Color (often cool fluorescent or extremely bright harsh sun). Lighting Setup: Hard direct light, often overhead or direct sun. Emotional Tone: Harsh reality, unflinching truth, exhaustion, no illusions, mundane, unglamorous, exposed. Common Contexts: Revealing character\'s true state, exhaustion scenes, morning-after scenes, harsh reality checks, interrogations. Character Archetypes: The Exhausted, The Exposed, The Realistically Portrayed, The Truth-Faced. Narrative Purpose: Shows reality without romantic filter.', '2026-01-27 00:02:04', '2026-01-27 00:02:04', 1),
(11, 'The \"Golden Hour Warmth\" (Sunset/Sunrise)', 'Warm orange-gold light of early morning or late afternoon. Visual Description: Everything bathed in warm orange, gold, and amber tones. Long shadows. Soft, flattering light. Creates nostalgic, warm atmosphere. Lens flare common. Sky gradients from yellow to orange to pink. Technical Details: Color Temperature (very warm 2000-3000K equivalent), Shadow Length (long shadows due to low sun angle), Sky Treatment (gradient of warm colors), Rim Lighting (golden rim light on edges). Lighting Setup: Low-angle sun (within 1-2 hours of sunrise/sunset). Emotional Tone: Nostalgia, warmth, peace, endings, beginnings, hope, melancholy beauty, precious moments. Common Contexts: Peaceful endings, nostalgic flashbacks, romantic moments, end of day reflections, precious memories. Time Associations: Sunrise = New beginnings/hope/awakening, Sunset = Endings/nostalgia/day\'s end/farewells. Cultural Significance: Universally beautiful time, photography \"magic hour\".', '2026-01-27 00:02:04', '2026-01-27 00:02:04', 1),
(12, 'The \"Noon Overhead Harsh\" (Midday Intensity)', 'Bright overhead sun creating harsh top-down lighting. Visual Description: Extremely bright, high-contrast lighting from directly overhead. Short, dark shadows directly beneath objects. Squinting common. Hot, intense atmosphere. Colors can be washed out or hyper-saturated. Technical Details: Shadow Direction (directly downward, very short), Intensity (maximum brightness), Contrast (extreme light/dark areas), Color (can wash out colors or intensify them). Lighting Setup: Sun at zenith (noon). Emotional Tone: Intensity, heat, harshness, high energy, confrontation, no escape, exposed, relentless. Common Contexts: Desert scenes, summer heat, intense confrontations, nowhere to hide, peak moments, exhaustion. Atmospheric Effects: Heat shimmer, intense shadows, sweat emphasized. Psychological Impact: Oppressive, relentless, no relief.', '2026-01-27 00:02:04', '2026-01-27 00:02:04', 1),
(13, 'The \"Blue Hour Melancholy\" (Twilight Cool)', 'Cool blue-purple light of pre-dawn or post-sunset. Visual Description: Soft blue-purple ambient light when sun is below horizon but sky still illuminated. Peaceful, melancholic atmosphere. Colors muted but visible. Street lights and artificial lights begin appearing. Technical Details: Color Temperature (cool blue 6000-8000K equivalent), Ambient Quality (diffused, directionless light), Contrast (low contrast, soft shadows), Artificial Light Mix (beginning to see interior lights through windows). Lighting Setup: Sun below horizon by 4-8°, before sunrise or after sunset. Emotional Tone: Melancholy, contemplation, transition, between states, peaceful sadness, quiet moments. Common Contexts: Quiet contemplation, transitional moments, melancholic scenes, peaceful sadness, between day and night. Time Associations: Pre-dawn = Anticipation/quiet before awakening, Post-sunset = Day ending/settling into night. Photographer\'s Term: \"Blue hour\" is cherished time for atmospheric shots.', '2026-01-27 00:02:04', '2026-01-27 00:02:04', 1),
(14, 'The \"Moonlight Silver\" (Night Luminescence)', 'Silvery-blue moonlight illuminating night scene. Visual Description: Cool silver-blue light from moon. Less intense than sunlight but sufficient for visibility. Creates mysterious, ethereal atmosphere. Long shadows. Stars visible. Monochromatic feeling possible. Technical Details: Color (silver, blue-white, cool tones), Intensity (subtle compared to daylight), Shadow Quality (soft but visible shadows), Contrast (can desaturate colors, push toward monochrome). Lighting Setup: Full or near-full moon as primary light source. Emotional Tone: Mystery, romance, eeriness, magic, solitude, nighttime wonder, ethereal beauty. Common Contexts: Night scenes, romantic encounters, mysterious meetings, supernatural events, solitary moments. Genre Associations: Romance, horror, supernatural, mystery. Cultural Symbolism: Moon = feminine, emotion, mystery, transformation.', '2026-01-27 00:02:04', '2026-01-27 00:02:04', 1),
(15, 'The \"Midday Shade Relief\" (Sheltered Coolness)', 'Cool shadowed area contrasting with bright sunlight. Visual Description: Character in shaded area (under tree, building, umbrella) while background is harsh bright sunlight. Cool, blue-tinted shadows contrasting with hot bright areas. Relief from intensity. Technical Details: Shadow Color (blue-tinted from skylight ambient), Contrast (sharp line between shade and sun), Temperature Difference (cool shaded area vs hot bright area), Detail (more visible detail in shaded area than bright area). Lighting Setup: Overhead sun with object blocking direct light, blue sky as fill light. Emotional Tone: Relief, respite, contemplation, escape from intensity, peaceful break, hidden from harsh world. Common Contexts: Taking shelter from heat, private conversations away from crowd, contemplative breaks, hiding. Symbolic Use: Retreat from harshness, finding peace, temporary escape. Physical Sensation: Viewer can almost feel the temperature difference.', '2026-01-27 00:02:04', '2026-01-27 00:02:04', 1),
(16, 'The \"Overcast Flat\" (Cloudy Day Even)', 'Soft, directionless light from overcast sky. Visual Description: Even, flat lighting with no strong shadows. Entire sky acts as one giant soft light source. Colors appear muted. No dramatic contrast. Can feel neutral or depressing depending on context. Technical Details: Shadow Quality (minimal to no visible shadows), Light Direction (appears to come from everywhere equally), Color (slightly desaturated, cool tones), Contrast (very low contrast). Lighting Setup: Complete cloud cover acting as giant diffusion. Emotional Tone: Neutral, melancholy, gloomy, depression, mundane, realistic, undramatic, waiting. Common Contexts: Depressed mood scenes, mundane daily life, waiting periods, emotional numbness, before rain. Narrative Uses: Neutral (realistic daily life), Negative (depression/gloom/emptiness), Anticipation (before storm breaks). Lack of Shadows: Unusual, can feel \"off\" or unnatural.', '2026-01-27 00:02:04', '2026-01-27 00:02:04', 1),
(17, 'The \"Storm Darkness\" (Pre-Storm Gloom)', 'Dark, greenish, ominous light before storm. Visual Description: Unnaturally dark for daytime with possible greenish or yellow tint. Heavy clouds blocking most light. Everything has ominous quality. Wind effects visible. Occasional lightning flash. Technical Details: Color Tint (green, yellow, or dark grey), Darkness Level (darker than normal overcast), Contrast (low except during lightning flashes), Dynamic (flickering with lightning). Lighting Setup: Storm clouds blocking sun, scattered light through clouds. Emotional Tone: Ominous, threatening, anticipation, dread, nature\'s power, danger approaching, tension. Common Contexts: Before disasters, tension building, nature\'s wrath, villain approaching, ominous moments. Lightning Integration: Sudden bright flashes provide dramatic punctuation. Symbolism: Storm = conflict, chaos, change, danger.', '2026-01-27 00:02:04', '2026-01-27 00:02:04', 1),
(18, 'The \"Firelight Flicker\" (Warm Dancing Light)', 'Orange flickering light from fire source. Visual Description: Warm orange-yellow light that moves and flickers constantly. Creates dancing shadows. Intimate, primal feeling. Lights only nearby area, darkness beyond. Colors shift from orange to deep red. Technical Details: Color Range (yellow-orange-red shifting), Movement (constant flickering and movement), Range (limited light spread, dark beyond), Shadow Movement (shadows dance and shift). Lighting Setup: Fire (campfire, torch, fireplace) as light source. Emotional Tone: Primal, intimate, storytelling, warmth in darkness, survival, camaraderie, ancient. Common Contexts: Campfire scenes, intimate conversations, storytelling, survival situations, cave scenes, pre-electric settings. Psychological Effect: Primal comfort, gathering place, protection against darkness. Cultural Association: Ancient human experience of fire as light and safety.', '2026-01-27 00:02:04', '2026-01-27 00:02:04', 1),
(19, 'The \"Artificial Fluorescent\" (Office/Facility Cold)', 'Cool, flat, slightly green-tinted fluorescent light. Visual Description: Cool-toned, slightly green or blue-tinted light. Flat and even but harsh. Unflattering to skin tones. Creates sterile, institutional feeling. Slight flicker possible. Technical Details: Color Temperature (cool 4000-5000K, slight green tint), Quality (flat but harsh), Shadow (minimal, multiple sources create overlapping soft shadows), Skin Rendering (unflattering, can look pale or sickly). Lighting Setup: Overhead fluorescent fixtures in grid pattern. Emotional Tone: Institutional, sterile, mundane, depressing, office life, artificial, unnatural, bureaucracy. Common Contexts: Office scenes, hospitals, schools, government buildings, bureaucratic settings, sterile facilities. Psychological Impact: Draining, artificial, removed from nature. Modern Life Symbol: Represents modern institutional/corporate existence.', '2026-01-27 00:02:04', '2026-01-27 00:02:04', 1),
(20, 'The \"Neon Night Glow\" (Urban Night Colors)', 'Multiple colored neon lights creating vibrant night atmosphere. Visual Description: Various colored neon signs and lights (pink, blue, green, purple) illuminating night scene. Colors reflect off wet surfaces. High contrast between bright neon and dark shadows. Cyberpunk aesthetic common. Technical Details: Color Variety (multiple saturated colors - pink, blue, cyan, purple, green), Reflections (colors reflect off wet pavement, puddles), Contrast (extreme darks and bright colored lights), Movement (often includes animated signs, traffic lights). Lighting Setup: Multiple colored artificial light sources (neon, LED, signs). Emotional Tone: Urban energy, nightlife, modernity, alienation, excitement, cyberpunk, lonely crowds. Common Contexts: City night scenes, urban exploration, nightlife, cyberpunk settings, modern alienation. Genre Association: Strongly associated with cyberpunk, urban drama, night life stories. Cultural Context: Represents modern urban experience, particularly East Asian cities.', '2026-01-27 00:02:04', '2026-01-27 00:02:04', 1),
(21, 'The \"Lens Flare Divine\" (Bright Hope Rays)', 'Bright light rays streaming through, suggesting divinity or hope. Visual Description: Bright light rays (god rays, crepuscular rays) streaming through breaks in clouds, forest canopy, or windows. Creates ethereal, heavenly effect. Lens flare and glow around light source. Particles visible in beams. Technical Details: Ray Pattern (radial beams from source), Particle Visibility (dust, mist, or light particles visible in beams), Glow (halation and bloom around light source), Contrast (beams clearly defined against darker surroundings). Lighting Setup: Strong point light source with atmosphere to scatter light, creating visible beams. Emotional Tone: Divine, hope, heavenly, salvation, spiritual, miraculous, blessing, transcendence. Common Contexts: Divine interventions, hope arriving, spiritual moments, miraculous events, prayers answered, heavenly visions. Symbolic Meaning: Light from above = divine presence, hope, salvation. Cultural Universal: Across cultures, heavenly light represented this way.', '2026-01-27 00:02:04', '2026-01-27 00:02:04', 1),
(22, 'The \"Single Shaft Spotlight\" (Isolated Focus)', 'Single narrow beam illuminating character in darkness. Visual Description: Narrow beam of light from above or single direction, illuminating character while everything else is in darkness. Creates isolation and focus. Can suggest spotlight, interrogation, or divine attention. Technical Details: Beam Width (narrow, precise circle or oval), Edge Quality (sharp defined edge or soft falloff), Darkness Level (everything outside beam is very dark or black), Character Placement (usually centered in light). Lighting Setup: Single focused spot light with no fill, high contrast. Emotional Tone: Isolation, focus, judgment, performance, exposure, being watched, solitude, divine attention. Common Contexts: Interrogations, performances, confessions, isolation, divine judgment, stage moments, crucial decisions. Multiple Meanings: Stage = Performance/being on display, Judgment = Being watched/evaluated, Divine = Chosen/special attention, Isolation = Alone in darkness.', '2026-01-27 00:02:04', '2026-01-27 00:02:04', 1),
(23, 'The \"Rainbow Prism Split\" (Hope & Diversity)', 'Light split into rainbow spectrum. Visual Description: Light passing through prism, water droplets, or crystals splits into visible rainbow spectrum. Creates magical, hopeful effect. Colors separate and visible. Often after rain or with crystal objects. Technical Details: Color Separation (full spectrum visible - ROYGBIV), Pattern (can be traditional arc or light rays splitting), Clarity (distinct color bands vs blended gradient), Scale (small prism effect to full rainbow arc). Lighting Setup: White light passing through refractive material (prism, water, crystal). Emotional Tone: Hope, magic, wonder, promise, diversity, beauty from simplicity, after the storm. Common Contexts: After rain, crystal magic, hope after darkness, promises, magical moments, wonder. Symbolic Meanings: Rainbow after storm = Hope/promise, Prism split = Hidden beauty revealed, Spectrum = Diversity/completeness. Cultural Association: Universal symbol of hope and promise.', '2026-01-27 00:02:04', '2026-01-27 00:02:04', 1),
(24, 'The \"Eclipse Darkness\" (Unnatural Shadow)', 'Sudden unnatural darkness during daytime. Visual Description: Day suddenly becoming dark as if night, but with unnatural quality. Thin rim of light around shadowed sun/moon. Stars visible during day. Ominous, apocalyptic feeling. Colors muted, strange quality to light. Technical Details: Light Level (day to twilight/night level), Rim Light (bright rim around eclipsed body), Color Quality (unnatural tint, muted colors), Shadow Direction (unchanged from before eclipse). Lighting Setup: Eclipse blocking sun while maintaining some ambient light. Emotional Tone: Ominous, apocalyptic, unnatural, prophecy, bad omen, cosmic significance, doom. Common Contexts: Prophecies, apocalyptic events, villain ascension, cosmic alignments, bad omens, world-changing moments. Cultural Significance: Across cultures, eclipses seen as ominous or significant. Psychological Impact: Primal unease at daytime darkness.', '2026-01-27 00:02:04', '2026-01-27 00:02:04', 1),
(25, 'The \"Stained Glass Colored\" (Sacred Color Projection)', 'Colored light through stained glass creating colored shadows. Visual Description: Light passing through stained glass creates colored patterns and shadows on surfaces and characters. Multiple colors create patchwork effect. Deeply associated with churches and sacred spaces. Technical Details: Color Patches (multiple distinct colored areas), Pattern (often geometric or figurative - religious imagery), Movement (colors shift as sun/character moves), Intensity (saturated colors when sun strong, subtle when dim). Lighting Setup: Strong light source (sun) passing through colored glass. Emotional Tone: Sacred, spiritual, religious, holy, contemplative, blessing, divine presence, peace. Common Contexts: Churches, temples, religious moments, spiritual contemplation, sacred spaces, blessings. Cultural Association: Strong Western church association, but also temples and sacred architecture globally. Emotional Effect: Creates sense of sacred space, spiritual atmosphere.', '2026-01-27 00:02:04', '2026-01-27 00:02:04', 1),
(26, 'The \"Candle Glow Intimate\" (Close Personal Light)', 'Soft warm light from candles in darkness. Visual Description: Small warm light source(s) creating intimate pool of light in darkness. Faces lit from below/side by candle. Warm orange-yellow glow. Gentle, flickering. Intimate distance. Everything beyond is darkness. Technical Details: Light Source Size (small points - candles), Color (warm yellow-orange), Flicker (gentle movement), Range (very limited spread), Intimacy (lights only immediate area, close faces). Lighting Setup: One or few candles as primary light, darkness beyond. Emotional Tone: Intimacy, romance, secrecy, quiet, private, vulnerable, traditional, pre-electric nostalgia. Common Contexts: Romantic dinners, secret meetings, power outages, period settings, intimate confessions, private moments. Psychological Effect: Creates bubble of intimacy, shutting out world beyond light. Cultural Nostalgia: Pre-electric lighting, simpler times.', '2026-01-27 00:02:04', '2026-01-27 00:02:04', 1),
(27, 'The \"Bioluminescent Glow\" (Natural Magic Light)', 'Glowing from natural sources—fireflies, fungi, sea life. Visual Description: Cool colored glow (usually blue, green, cyan) from living sources. Multiple small lights or larger glowing areas. Magical, fantastical atmosphere. Gentle pulsing possible. Against darkness. Technical Details: Color (blues, greens, cyans, occasionally yellow-green), Pattern (many small points like fireflies or larger glowing masses like fungi/plankton), Intensity (subtle glow, not bright), Movement (fireflies move, plankton swirls, fungi static). Lighting Setup: Bioluminescent organisms as light source. Emotional Tone: Magic, wonder, natural beauty, fantastical, otherworldly, gentle, mysterious beauty. Common Contexts: Fantasy forests, night beaches with bioluminescent plankton, fairy encounters, magical environments. Natural Sources: Fireflies (yellow-green, pulsing), Bioluminescent plankton (blue, in water), Glowing fungi (green-blue, on trees). Fantasy Association: Strongly associated with fairy/magical environments.', '2026-01-27 00:02:04', '2026-01-27 00:02:04', 1),
(28, 'The \"Lightsaber Glow\" (Weapon Light Source)', 'Glowing weapon illuminating wielder\'s face. Visual Description: Brightly glowing weapon (lightsaber, energy sword, magical blade) held near character, illuminating their face with colored light. Face lit from unusual angle by weapon. Color indicates character type/allegiance. Technical Details: Glow Color (varies by character/weapon - blue, red, green, purple, etc.), Face Illumination (under-lighting from weapon position), Intensity (bright enough to be primary light source), Environmental Glow (nearby surfaces also colored by weapon). Lighting Setup: Bright glowing weapon as primary or significant light source. Emotional Tone: Power, readiness, determination, cool factor, heroic or villainous (depending on color), combat ready. Common Contexts: Pre-battle stances, dramatic character reveals, power-up moments, hero/villain confrontations. Color Psychology: Blue = Hero/calm/justice, Red = Villain/rage/danger, Green = Wise/balanced, Purple = Rare/unique/grey morality. Iconic Status: Made famous by Star Wars, now anime staple.', '2026-01-27 00:02:04', '2026-01-27 00:02:04', 1),
(29, 'The \"Aurora Borealis Sky\" (Celestial Light Show)', 'Northern/Southern lights creating magical sky colors. Visual Description: Flowing, undulating curtains of colored light in night sky. Usually green, but can be pink, purple, blue. Creates magical, otherworldly atmosphere. Reflects on snow or water. Characters silhouetted against it. Technical Details: Colors (green most common, also pink, purple, yellow, blue), Movement (flowing, undulating, dancing), Sky Coverage (partial to full sky), Reflection (on snow/water surfaces), Character Positioning (often silhouetted). Lighting Setup: Natural aurora phenomenon or magical equivalent. Emotional Tone: Wonder, magic, natural majesty, otherworldly, cosmic beauty, awe, cold beauty. Common Contexts: Northern/arctic settings, magical phenomena, cosmic events, wonder moments, natural majesty, fantasy worlds. Scientific Reality: Actual natural phenomenon adds authenticity. Symbolic Use: Nature\'s magic, cosmic connection, wonder of natural world. Fantasy Adaptation: Often used for magical events, dimensional rifts, cosmic power displays.', '2026-01-27 00:02:04', '2026-01-27 00:02:04', 1),
(30, 'The \"God Ray Revelation\" (Divine Light Shafts)', 'Dramatic light shafts breaking from above suggesting divine presence, revelation, or heavenly blessing. Visual Description: Dramatic shafts of light breaking through clouds, ceiling, or other barriers from above creating volumetric beams. Often with visible particles in beams. Suggests divine presence, revelation, or heavenly blessing descending. Technical Details: Light Source (Always from above suggesting heaven or divine origin), Beam Quality variations (Sharp defined beams equals dramatic theatrical effect, Soft diffused beams equals gentle peaceful presence, Multiple parallel beams equals heavenly choir effect, Single focused beam equals divine spotlight from above), Visible Particles (Dust or particles visible in beams emphasizing three-dimensional volume), Breaking Through (Light dramatically breaking through clouds, holes in ceiling, windows, forest canopy). Symbolic Meanings: Divine presence or direct intervention, Heaven reaching down to earth, Revelation or truth revealed, Blessing or divine favor, Hope from above, Spiritual moment, Answered prayer, Grace descending. Psychological Effect: Awe, divine presence felt, hope, revelation, blessing, spiritual connection, wonder, grace, transcendence. Common Contexts: Divine interventions, Revelation moments, Character receiving blessing, Spiritual awakenings, Church or temple scenes, Answered prayers, Miraculous moments, Religious experiences, Transcendent scenes. Cultural Significance: Universal symbol of divine presence across virtually all religions worldwide. Natural Phenomenon: Based on real atmospheric phenomenon called crepuscular rays or god rays. Genre: Fantasy, spiritual, religious, epic, transcendent anime.', '2026-02-01 12:17:52', '2026-02-01 12:17:52', 1),
(31, 'The \"Neon Glow\" (Urban Artificial Light)', 'Artificial neon lighting creating cyberpunk urban technological atmosphere with reflections. Visual Description: Bright artificial neon lights in pinks, cyans, greens creating urban, technological, cyberpunk atmosphere. Often reflected dramatically in wet surfaces multiplying effect. Technical Details: Color Palette and Meanings (Hot pink or magenta equals nightlife and pleasure districts, Cyan or blue equals technology and cold corporations, Green equals alien, toxic, or tech, Purple equals mysterious luxury), Reflection (Neon often reflected in wet pavement, glass, puddles doubling visual impact), High Contrast (Extreme contrast with dark surroundings and shadows), Flicker (Sometimes flickering or buzzing for dystopian deteriorating feel), Multiple Sources (Usually multiple competing neon sources). Symbolic Meanings: Urban modernity, Technology dominance over nature, Artificial life, Cyberpunk future vision, Nightlife and vice, Corporate control, Alienation in crowds, Seedy underbelly. Psychological Effect: Urban energy, alienation despite crowds, modernity, artificial, cool temperature, technological, seedy, futuristic, corporate dystopia. Common Contexts: Cyberpunk settings, Urban night scenes, Red light districts, Future cities, Technology themes, Modern alienation, Corporate dystopia, Nightlife, Detective noir. Blade Runner Legacy: Heavily influenced by Blade Runner aesthetic establishing cyberpunk visual language. Akira Pioneer: Akira perfected anime neon lighting in Neo-Tokyo sequences. Genre: Cyberpunk, sci-fi, urban, noir, technological anime. Rain Enhancement: Rain and wet streets intensify neon reflections dramatically.', '2026-02-01 12:17:52', '2026-02-01 12:17:52', 1),
(32, 'The \"Bioluminescence\" (Natural Glow)', 'Organic glowing light from living creatures or plants creating natural magical atmosphere. Visual Description: Soft glowing light emanating from living things including fireflies, glowing plants, sea creatures, or spirits. Creates natural, magical, organic, enchanted feel. Technical Details: Light Sources (Fireflies equals summer nostalgia and magic, Glowing plants equals fantasy or alien worlds, Sea creatures equals underwater mysterious, Spirits or souls equals supernatural), Color typically blue, green, yellow-green, or white, Quality soft and gentle with pulsing or steady glow, Intensity always dim to moderate never harsh or artificial. Symbolic Meanings: Natural magic exists, Life force made visible, Wonder and beauty in nature, Spirits or souls visible, Nature hidden mystery, Innocence, Summer memories and nostalgia. Psychological Effect: Wonder, magic, nostalgia especially for childhood summers, beauty, peace, natural mystery, innocence, enchantment, organic. Common Contexts: Fantasy forests, Summer night scenes especially nostalgic, Underwater sequences, Spirit encounters, Magical natural realms, Nostalgic moments, Natural wonder, Enchanted places. Studio Ghibli: Ghibli uses extensively in Princess Mononoke, Nausicaa, creating signature magical natural aesthetic. Romantic Association: Fireflies particularly strongly associated with romance and summer nostalgia in Japanese culture. Genre: Fantasy, supernatural, nostalgic, nature, environmental anime.', '2026-02-01 12:17:52', '2026-02-01 12:17:52', 1),
(33, 'The \"Lens Flare\" (Camera Awareness)', 'Deliberate lens flare effect acknowledging camera presence despite being animation. Visual Description: Bright light source creating visible lens flare including hexagonal shapes, light streaks across frame, acknowledging camera presence despite being drawn animation. Technical Details: Flare Types (Hexagonal aperture shapes, Light streaks across frame, Halo around light source, Rainbow spectrum dispersion), Causes (Sun, explosions, bright lights, energy blasts, divine light, intense power), Placement (Streaks across frame from light source direction), Intensity (Subtle accent to overwhelming screen-filling effect). Symbolic Meanings: Intense brightness, Realism effect in animation, Energy or power intensity, Beautiful light celebrated, Camera or eye presence acknowledged, Modern aesthetic choice, Cinematic quality. Psychological Effect: Realism, intensity, beauty, power, modern, cinematic, epic scale, visual interest, light celebrated. Common Contexts: Sunrise and sunset scenes, Explosions, Power releases and energy attacks, Epic moments, Cinematic scenes, Energy attacks, Beautiful lighting moments, Divine light. Intentional Choice: Always intentional in animation unlike accidental in photography, artistic choice. Modern Influence: J.J. Abrams overuse in live-action influenced modern anime adoption. Genre: Action, sci-fi, epic, cinematic, power-display anime. Celebration: Celebrates light itself as beautiful element.', '2026-02-01 12:17:52', '2026-02-01 12:17:52', 1),
(34, 'The \"Magical Particle Glow\" (Fantasy Light)', 'Glowing magical particles floating and providing gentle illumination in fantasy scenes. Visual Description: Glowing particles whether magical, spiritual, or energy floating in air and providing gentle ambient illumination. Creates magical, otherworldly, enchanted atmosphere. Technical Details: Particle Types (Sparkles equals magic and joy, Motes equals spirits or souls, Energy equals power or aura visible, Pollen-like equals nature magic), Color (Often white, gold, blue, or character-specific signature colors), Movement (Floating gently, swirling in currents, dancing playfully), Density (Few scattered to overwhelming swarms). Symbolic Meanings: Magic present in air, Spiritual energy visible, Life force, Power made visible, Enchantment active, Divine presence, Wonder, Sacred space. Psychological Effect: Magic real, wonder, enchantment, spiritual, power, beauty, otherworldly, mystical, sacred, joyful. Common Contexts: Magic casting, Spiritual realms, Enchanted locations, Power displays, Magical girl transformation sequences, Sacred spaces, Magical environments, Fantasy worlds. Practical Use: Also adds visual interest to dialogue scenes in magical settings. Magical Girl Essential: Absolutely essential element of magical girl transformation and power sequences. Genre: Fantasy, magical girl, supernatural, spiritual, enchanted anime. Atmosphere: Creates magical atmosphere even in mundane scenes.', '2026-02-01 12:17:52', '2026-02-01 12:17:52', 1),
(35, 'The \"Lightning Flash\" (Momentary Revelation)', 'Brief lightning flash revealing scene momentarily creating drama and sudden visibility. Visual Description: Sudden lightning flash briefly illuminating dark scene for 1-3 frames, revealing what darkness was hiding. Creates drama, reveals threats, emphasizes storm atmosphere. Technical Details: Duration (Usually only 1-3 frames for shock), Revelation (Shows exactly what darkness was hiding), Color (Blue-white typically), Shadow (Creates harsh dramatic shadows briefly), Timing (Often precisely synced with thunder sound). Symbolic Meanings: Sudden revelation, Hidden threat revealed briefly, Nature power, Dramatic moment emphasized, Truth flash, Danger emphasized, Shock. Psychological Effect: Shock, revelation, drama, nature power felt, fear, tension, sudden visibility then darkness again, unsettling. Common Contexts: Storm scenes, Horror scare moments, Threat reveals, Dramatic confrontations, Truth revelations, Power of nature, Suspense building, Stalker reveals. Horror Technique: Common horror technique for jump scares and revealing threats. Stroboscopic: Multiple rapid flashes create stroboscopic unsettling disorienting effect. Genre: Horror, thriller, drama, action, suspense anime. Natural: Uses natural phenomenon for dramatic effect.', '2026-02-01 12:17:52', '2026-02-01 12:17:52', 1),
(36, 'The \"Holographic Light\" (Digital/Virtual)', 'Holographic or digital light effects showing technology, virtual reality, or digital spaces. Visual Description: Light with digital or holographic quality including scan lines, pixelation, translucent projections. Shows technology, virtual reality, digital spaces, or simulations. Technical Details: Characteristics (Visible scan lines, Slight transparency or translucence, Digital artifacts, Blue or cyan tint common, Geometric patterns), Stability (Often slightly unstable or flickering suggesting digital), Projection (Light from projectors, screens, holographic displays). Symbolic Meanings: Technology and computers, Virtual reality, Digital space or cyberspace, Artificial construct, Future tech, Simulation, Information, Non-physical. Psychological Effect: Technological, artificial, futuristic, digital, virtual, information, modern, simulated, non-real. Common Contexts: Holographic displays, Virtual reality sequences, Computer interfaces, Sci-fi technology, Digital spaces, Future tech, Information displays, Cyberspace, Simulations. Ghost in the Shell: Major influence on digital lighting aesthetics in anime. Modern Relevance: Increasingly common as VR becomes reality in real world. Genre: Sci-fi, cyberpunk, technology-focused, virtual reality anime. Non-Physical: Emphasizes non-physical nature of digital information.', '2026-02-01 12:17:52', '2026-02-01 12:17:52', 1),
(37, 'The \"Campfire Circle\" (Intimate Group Light)', 'Campfire providing warm intimate lighting for group bonding and storytelling. Visual Description: Campfire or similar central light source illuminating small group sitting in circle around it. Creates warm, intimate, storytelling, bonding atmosphere. Technical Details: Light Quality (Warm orange-red glow, Flickering and dynamic, Illuminates faces from below, Creates community circle), Face Lighting (Faces lit from below creating intimacy), Surrounding Darkness (Darkness beyond circle emphasizes intimacy and isolation), Dancing Shadows (Shadows dance from flame movement). Symbolic Meanings: Community and bonds, Intimacy and sharing, Storytelling tradition ancient, Survival together, Warmth in darkness, Primitive human connection, Safety in numbers, Team bonding. Psychological Effect: Intimacy, warmth, community, bonding, safety together, storytelling, primitive connection, togetherness, survival. Common Contexts: Camping scenes, Group bonding, Storytelling moments, Survival situations, Team building, Night conversations, Intimate group moments, Strategy discussions. Primitive Connection: Connects to primitive human bonding around fire throughout history. Storytelling Tradition: Traditional storytelling lighting setup across cultures. Genre: Adventure, survival, team, bonding-focused, camping anime. Circle: Circle formation emphasizes equality and inclusion.', '2026-02-01 12:17:52', '2026-02-01 12:17:52', 1),
(38, 'The \"Spotlight Interrogation\" (Harsh Examination)', 'Single harsh spotlight in darkness for interrogation, examination, or performance pressure. Visual Description: Single harsh spotlight on character in otherwise complete dark space. Creates interrogation, examination, or stage performance pressure atmosphere. Technical Details: Light (Single hard source, Harsh shadows created, Sharp circle or beam, Often from directly above), Surrounding (Complete darkness beyond spot), Character (Isolated and exposed), Shadow (Deep black shadows, extreme high contrast). Symbolic Meanings: Under examination, Exposed and vulnerable, Interrogation, Truth demanded, Performance pressure, Isolation, Intense scrutiny, Judgment. Psychological Effect: Exposure, vulnerability, pressure, interrogation, isolation, scrutiny, spotlight pressure, judgment, trapped. Common Contexts: Interrogation scenes, Stage performances, Confession moments, Under intense scrutiny, Truth seeking, Psychological pressure, Exposed vulnerability, Trials, Auditions. Film Noir: Classic noir interrogation lighting technique. Theater: Also suggests theatrical spotlight pressure and performance anxiety. Genre: Thriller, psychological, detective, crime, performance anime. Nowhere to Hide: Character has nowhere to hide, fully exposed.', '2026-02-01 12:17:52', '2026-02-01 12:17:52', 1),
(39, 'The \"Aurora Borealis\" (Natural Wonder)', 'Northern lights creating ethereal magical natural wonder atmosphere. Visual Description: Aurora borealis northern lights with flowing curtains of colored light in night sky. Creates magical, ethereal, natural wonder, rare beauty atmosphere. Technical Details: Colors (Green most common, also pink, purple, blue in nature), Movement (Flowing like curtains, dancing, wave-like), Intensity (Soft glow to brilliant display), Sky Dominance (Dominates entire night sky), Reflection (Often reflected in snow, ice, water below). Symbolic Meanings: Natural wonder and beauty, Magic is real, Northern mystique, Beauty and awe, Rare precious moment, Nature power and mystery, Otherworldly, Divine natural display. Psychological Effect: Wonder, awe, magic real, beauty, natural mystery, ethereal, rare beauty witnessed, transcendent, spiritual. Common Contexts: Northern settings, Magical moments, Romantic confession or kiss scenes, Natural wonder, Spiritual moments, Rare beauty, Transcendent experiences, Perfect moments. Romantic Use: Often used for romantic confession or first kiss scenes creating perfect moment. Makoto Shinkai: Your Name and other Shinkai films use aurora-like effects beautifully. Genre: Romance, fantasy, natural wonder, spiritual, atmospheric anime. Rare: Emphasizes rarity and specialness of moment.', '2026-02-01 12:17:52', '2026-02-01 12:17:52', 1),
(40, 'The \"Flashback Overexposure\" (Memory Brightness)', 'Overexposed washed-out lighting for idealized nostalgic memories shown through rose-colored glasses. Visual Description: Memories shown with overexposed blown-out lighting making everything slightly too bright with white highlights blooming. Creates idealized, dreamlike, nostalgic quality suggesting rose-colored memory. Technical Details: Overexposure (Highlights blown out, Soft overall feel, Slightly washed out, Dreamy quality), Warm Color Tint (Often warm tint added), Detail Loss (Some detail lost in highlights), Soft Edges (Edges soft with slight glow). Symbolic Meanings: Idealized memory, Rose-colored glasses, Dreamlike past, Better than reality was, Nostalgic glow, Fading memory, Golden days remembered, Unreliable memory. Psychological Effect: Nostalgia, idealization of past, dreamlike, soft, gentle, rose-colored, bittersweet, memory not reality, longing. Common Contexts: Flashback sequences, Memory scenes, Nostalgia moments, Idealized past, Character remembering, Lost times mourned, Innocent past, Before tragedy. Unreliable Narrator: Suggests memory may be idealized or unreliable, not objective truth. Contrast: Often contrasted with darker harsher present showing loss. Genre: Drama, memory-focused, nostalgic, coming-of-age, loss anime. Psychology: Reflects how human memory actually works, idealizing past.', '2026-02-01 12:17:52', '2026-02-01 12:17:52', 1),
(41, 'The \"Isolation Cold Blue\" (Loneliness Visual)', 'Cold blue lighting emphasizing isolation, loneliness, and depression visually. Visual Description: Character lit with cold blue light often from single source, surrounded by darkness or empty shadow. Emphasizes isolation, loneliness, depression, disconnection. Technical Details: Color Temperature (Very cool, 7000K or higher), Quality (Often harsh or unflattering to face), Surrounding (Dark or empty space around character isolating them), Source (Often from TV, phone screen, window, or other artificial light). Symbolic Meanings: Isolation and loneliness, Depression, Cold emotional state, Disconnection from world, Technology isolation, Emptiness, Social withdrawal, Alone. Psychological Effect: Loneliness, isolation, cold emotionally, depression, disconnection, sadness, emptiness, withdrawn, alienation. Common Contexts: Isolation scenes, Depression visualization, Loneliness, Late night alone, Technology addiction isolation, Emotional distance, Social withdrawal, Modern alienation, Hikikomori. Modern Life: Often combined with technology light from TV, phone, computer emphasizing modern isolation. Contrast: Contrasts sharply with warm social gathering lighting showing what is missing. Genre: Psychological, drama, modern life, isolation, depression anime. Technology: Associates isolation with technology use.', '2026-02-01 12:17:52', '2026-02-01 12:17:52', 1);
INSERT INTO `anivoc_lighting` (`id`, `name`, `description`, `created_at`, `updated_at`, `is_ingredient`) VALUES
(42, 'The \"Romantic Warm Glow\" (Love Scene Light)', 'Warm soft flattering lighting for romantic moments creating intimacy and beauty. Visual Description: Soft, warm, flattering lighting for romantic scenes. Often golden hour, candlelight, or warm interior creating intimate beautiful romantic atmosphere. Technical Details: Color Temperature (Warm, 2500-3500K range), Quality (Soft, flattering, gentle on faces), Direction (Usually soft and diffused from multiple directions), Moderate Intensity (Creating intimacy not harsh), Practical Sources (Sunset, candles, warm lamps, firelight, string lights). Symbolic Meanings: Love and romance, Intimacy, Beauty, Warm feelings, Connection, Perfect moment, Tenderness, Magic of love. Psychological Effect: Romance, warmth, intimacy, beauty, love, connection, tender, gentle, perfect, magical, soft. Common Contexts: Romantic scenes, Love confessions, Kiss scenes, Intimate moments, Dates, Tender moments, Connection scenes, First love. Deliberately Flattering: Intentionally flattering lighting to make characters appear most beautiful. Practical Sources: Often mimics golden hour or candlelight natural romantic light sources. Genre: Romance, shoujo, slice-of-life, love-focused anime. Beauty: Emphasizes beauty of characters and moment.', '2026-02-01 12:17:52', '2026-02-01 12:17:52', 1),
(43, 'The \"Anger Red Wash\" (Rage Visualization)', 'Scene washing with red light during anger or rage visualizing emotional state. Visual Description: Scene washes with red light or strong tint during anger, rage, or violent moments. Can be subtle tint to overwhelming wash. Shows internal emotional state made visible externally. Technical Details: Intensity Range (10% subtle tint to 80% overwhelming red wash), Source (Often no realistic source, pure emotional coloring), Pulsing (Sometimes pulses with heartbeat or anger building), Spread (Can affect whole scene or just around angry character), Building (Often builds as anger intensifies). Symbolic Meanings: Anger and rage, Violence coming, Bloodlust, Seeing red literally, Loss of control, Primal emotion, Danger imminent, Berserker mode. Psychological Effect: Anger, rage, violence, danger, loss of control, primal, intense, threatening, overwhelming emotion. Common Contexts: Rage moments, Berserker mode activation, Intense anger, Violence, Loss of control, Bloodlust, Primal fury, Extreme emotion, Breaking point. Subjective: Often represents character subjective experience not objective reality. Warning: Warns viewer of dangerous emotional state and potential violence. Genre: Action, shounen, violent, intense, battle anime. Escalation: Often escalates with anger level.', '2026-02-01 12:17:52', '2026-02-01 12:17:52', 1),
(44, 'The \"Hope Morning Light\" (Optimism Visual)', 'Bright morning light emphasizing hope, new beginnings, and optimism visually. Visual Description: Bright, clear, fresh morning light often streaming through windows or curtains. Emphasizes hope, new beginning, optimism, fresh start, tomorrow coming. Technical Details: Quality (Clear, bright, fresh, clean), Color (Clean white or slight warm tint), Direction (Often horizontal morning sun angle), Brightness (Bright but not harsh), Window Light (Often through window showing new day dawning). Symbolic Meanings: Hope and optimism, New beginning, Fresh start, Tomorrow coming, Renewal, Clean slate, Life continuing, Awakening, Second chance. Psychological Effect: Hope, optimism, new beginning, fresh, clean, renewal, energy, morning, awakening, tomorrow. Common Contexts: After dark times, New beginnings, Morning after trauma, Recovery starting, Hope restored, Fresh start, Awakening moments, Surviving night, Tomorrow arrived. Window Symbolism: Window with curtains particularly symbolic of opening to receive new day. Contrast: Often strongly contrasted with previous dark night scenes showing survived. Genre: Hopeful, recovery, uplifting, survival, resilient anime. Promise: Morning light promises new day and new chances.', '2026-02-01 12:17:52', '2026-02-01 12:17:52', 1),
(45, 'The \"Despair Shadow\" (Depression Darkness)', 'Character in shadow or darkness representing despair, depression, and giving up. Visual Description: Character sitting or standing in heavy shadow or darkness, face often obscured or partially hidden in shadow. Represents despair, depression, giving up, defeat. Technical Details: Coverage (Character partially or fully engulfed in shadow), Face Often Obscured (Face in shadow, eyes particularly often hidden), Surrounding Darkness (Darkness surrounding and isolating character), Heavy Quality (Heavy, oppressive shadow), Minimal Light (Little to no light reaching character). Symbolic Meanings: Despair and depression, Giving up, Lost in darkness, No hope visible, Emotional darkness, Isolation, Defeat, Paralysis. Psychological Effect: Despair, depression, hopelessness, darkness, defeat, isolation, lost, heavy, paralyzed, given up. Common Contexts: Depression scenes, Despair moments, Defeat, Giving up, Lost hope, Trauma response, Dark emotional state, Breakdown, Surrender. Eyes Hidden: Eyes often hidden in shadow emphasizing disconnection from world and others. Static Character: Often static, unmoving character emphasizing emotional paralysis and defeat. Genre: Psychological, dark, trauma, depression, heavy drama anime. Weight: Shadow has visual weight, pressing down on character.', '2026-02-01 12:17:52', '2026-02-01 12:17:52', 1),
(46, 'The \"Jealousy Green Tint\" (Envy Visual)', 'Green tint during jealousy or envy moments visualizing being green with envy. Visual Description: Scene or character takes on green tint during jealousy or envy moments. Literally visualizes the expression and emotion of being green with envy. Technical Details: Green Tint (Green color wash or tint applied), Intensity (Subtle hint to obvious wash), Focus (Often specifically on jealous character), Yellow-Green (Typically yellow-green shade), Brief (Often brief flash rather than sustained). Symbolic Meanings: Jealousy and envy, Green with envy made literal, Coveting what others have, Resentment, Wanting what cannot have, Negative emotion, Bitterness, Comparison pain. Psychological Effect: Jealousy, envy, resentment, negative, wanting, coveting, bitterness, comparison, inadequacy. Common Contexts: Jealousy moments, Envy visualization, Romantic jealousy, Coveting, Resentment, Comparison pain, Negative emotions, Competition, Social comparison. Idiom Origin: Based directly on green with envy idiom making it literal visual. Brief Flash: Often brief flash rather than sustained throughout scene. Genre: Romance, drama, comedy, school, competition anime. Universal: Jealousy green recognized across cultures through idiom.', '2026-02-01 12:17:52', '2026-02-01 12:17:52', 1),
(47, 'The \"Joy Sparkle\" (Happiness Light)', 'Sparkling bright lighting for joy and happiness literally brightening with emotion. Visual Description: Scene brightens with sparkles, increased brightness, warm glow during moments of joy or happiness. Literally brightens with positive emotion visually. Technical Details: Elements (Sparkles, Increased overall brightness, Warm glow, Soft focus), Warm Color (Warm, golden, bright tones), Moderate to High Intensity, Duration (Usually sustained through entire happy moment). Symbolic Meanings: Joy and happiness, Delight, Wonderful moment, Bliss, Magic of happiness, Perfect moment, Pure joy, Celebration. Psychological Effect: Joy, happiness, delight, wonderful, bliss, warmth, magic, perfection, celebration, positivity. Common Contexts: Happy moments, Joy expressions, Wonderful experiences, Success celebrations, Happy endings, Blissful moments, Pure happiness, Victory, Love realized. Shoujo Common: Particularly common in shoujo manga and anime visual language. Sparkles Meaning: Sparkles emphasize magical quality of happiness and joy. Genre: Romance, comedy, shoujo, slice-of-life, uplifting anime. Literal: Makes abstract happiness literally visible as light and sparkles.', '2026-02-01 12:17:52', '2026-02-01 12:17:52', 1),
(48, 'The \"Fear Harsh Contrast\" (Terror Lighting)', 'Harsh high-contrast lighting for fear and terror creating unsettling atmosphere. Visual Description: Harsh lighting creating extreme contrast with deep blacks, bright highlights, minimal mid-tones. Creates unsettling, frightening, nightmare atmosphere. Technical Details: Extremely High Contrast, Deep Shadows (Impenetrable blacks), Harsh Highlights (Bright harsh highlights), Few Mid-tones (Minimal or no mid-tones), Unusual Angles (Often unusual unsettling angles). Symbolic Meanings: Fear and terror, Threat and danger, Unknown lurking in shadows, Harsh reality, Unsettling atmosphere, Nightmare quality, Paranoia, Dread. Psychological Effect: Fear, terror, unsettling, threatening, harsh, dangerous, nightmare, anxiety, dread, paranoia. Common Contexts: Horror scenes, Fear moments, Threats, Nightmares, Terror, Danger, Suspense, Stalking, Paranoia, Psychological horror. German Expressionism: Based on German Expressionist film lighting techniques. Shadow Fear: What lurks unseen in shadows creates fear and paranoia. Genre: Horror, thriller, psychological horror, suspense anime. Discomfort: Intentionally creates visual discomfort and unease.', '2026-02-01 12:17:52', '2026-02-01 12:17:52', 1),
(49, 'The \"Calm Even Light\" (Peace Visual)', 'Even balanced calm lighting for peaceful moments showing tranquility and stability. Visual Description: Even, well-balanced lighting with no harsh contrasts or dramatic elements. Creates calm, peaceful, balanced, stable atmosphere. Technical Details: Even Balance (Even illumination throughout), Low to Moderate Contrast, Soft Gentle (Soft, gentle, non-harsh), Neutral or Slightly Warm Color, Steady Stability (Steady, unchanging, stable). Symbolic Meanings: Peace and calm, Balance, Stability, Tranquility, Normal peaceful life, Contentment, Serenity, Harmony. Psychological Effect: Peace, calm, balance, tranquility, stability, contentment, normal, serene, harmony, safe. Common Contexts: Peaceful moments, Calm scenes, Daily life, Contentment, Stability, Balance restored, Tranquility, Normal life, Safety, Home. Contrast Function: Often contrasts with dramatic lighting in action scenes showing difference. Slice-of-Life: Common in slice-of-life anime showing peaceful daily life as beautiful. Genre: Slice-of-life, peaceful, calm, iyashikei anime. Nothing Dramatic: Deliberately avoids drama showing peace is valuable.', '2026-02-01 12:17:52', '2026-02-01 12:17:52', 1),
(50, 'The \"Excitement High Key\" (Energy Brightness)', 'Bright high-key lighting for excitement and energy creating positive atmosphere. Visual Description: Bright, high-key lighting with minimal shadows, lots of light, bright saturated colors. Creates energetic, exciting, positive, youthful atmosphere. Technical Details: Very Bright Overall, Minimal Shadows, Heavy Fill Light, Bright Saturated Colors, Low Contrast (Bright throughout). Symbolic Meanings: Excitement and energy, Positivity, Fun and joy, Vitality, Optimism, Youthful energy, Celebration, Enthusiasm. Psychological Effect: Excitement, energy, positivity, fun, joy, vitality, optimism, enthusiasm, youth, celebration. Common Contexts: Exciting moments, Celebrations, Fun scenes, Energetic sequences, Positive moments, Youth, Parties, Festivals, Success. Commercial Aesthetic: Similar to commercial advertising lighting creating positive associations. Music Videos: Often mimics music video bright energetic aesthetics. Genre: Comedy, slice-of-life, youth, energetic, idol, sports anime. Positive: Emphasizes positive energy and fun.', '2026-02-01 12:17:52', '2026-02-01 12:17:52', 1);
INSERT INTO `anivoc_motion_impact` (`id`, `name`, `description`, `created_at`, `updated_at`, `is_ingredient`) VALUES
(1, 'The \"Action Streak\" (Speed Trail)', 'The classic multiple overlapping afterimages showing rapid movement. Visual Description: Multiple semi-transparent copies of the moving object/character layered in sequence along the path of motion. Each copy slightly faded, creating a \"strobe effect\" trail. Usually 3-7 copies visible. Technical Details: Spacing (closer together = faster motion), Opacity (front image solid, trailing 100% → 70% → 40% → 20%), Optional distortion on trailing images. Variants: Clean Streak (precise copies), Blur Streak (softer, motion-blurred), Color Shift Streak (trailing copies shift color hot to cold), Particle Streak (copies breaking into particles). Context: Fast punches, quick dodges, speed-based powers, superhuman movement, bullet-time perspectives. Power Level Indicator: More streaks = faster movement. Sound Association: Whoosh, Swish, Shing.', '2026-01-27 00:02:03', '2026-01-27 00:02:03', 1),
(2, 'The \"Motion Blur Trail\" (Smear Animation)', 'Single elongated streak behind moving object. Visual Description: The moving object is stretched/smeared in the direction opposite to its movement, creating a tapered trail. Not multiple copies—one distorted image. Often includes color gradation along the trail. Technical Details: Length proportional to speed, tapered from solid object to thin point, can include horizontal lines suggesting speed. Variants: Simple Smear (solid color), Textured Smear (lines or patterns in blur), Glow Smear (luminous trail for energy-based), Particle Dispersion (trail breaking into fragments). Context: Objects in flight, swinging weapons, quick turns, energy projectiles, supersonic movement. Power Level Indicator: Length and intensity = speed/power. Sound Association: Zoom, Fwoosh, Vwoom.', '2026-01-27 00:02:03', '2026-01-27 00:02:03', 1),
(3, 'The \"Speed Lines\" (Radial Motion Lines)', 'Straight lines radiating from vanishing point showing relative motion. Visual Description: Parallel lines (or lines converging to a point) drawn on background to show motion through space. Lines move in opposite direction to object\'s movement. Can be black on white or white on black. Technical Details: Density (more lines = faster motion), Thickness varies from thin to thick, Direction (horizontal, vertical, diagonal). Variants: Horizontal Speed Lines (left/right), Vertical Speed Lines (up/down), Converging (moving toward viewer), Diverging (moving away), Curved Speed Lines (following curved path). Context: Running, flying, vehicles, camera tracking fast movement, establishing speed. Power Level Indicator: Density and length = speed. Sound Association: Whoooosh (sustained).', '2026-01-27 00:02:03', '2026-01-27 00:02:03', 1),
(4, 'The \"Zip Line\" (Trajectory Path)', 'Single line showing the path taken. Visual Description: A single bold line tracing the exact path the object/character took through space. Can be solid or dashed. Often used to show impossible or complex trajectories. Technical Details: Style can be solid, dashed, dotted, or glowing. Color usually contrasts with background. Complexity: straight, curved, zigzag, spiral, or impossible angles. Variants: Straight Zip (direct path), Zigzag Zip (multiple direction changes), Spiral Zip (rotating path), Ricochet Zip (bouncing trajectory), Impossible Zip (physics-defying path - mid-air direction change). Context: Tracking projectile path, showing complex movement, ricochet effects, teleportation paths. Power Level Indicator: Complexity of path = skill/power. Sound Association: Ziiip, Zing.', '2026-01-27 00:02:03', '2026-01-27 00:02:03', 1),
(5, 'The \"Sonic Boom Cone\" (Supersonic Break)', 'Visual representation of breaking the sound barrier. Visual Description: Cone-shaped pressure wave emanating from the object, often white or light-colored. Can include ring-shaped shockwaves expanding outward. Distortion effects around the cone edge. Technical Details: Cone extending behind moving object, concentric rings expanding from breakthrough point, air/background warping at edges, vapor/energy/air pressure particles. Variants: Clean Cone (pure white pressure cone), Ring Boom (expanding ring shockwaves), Energy Boom (colored energy instead of air pressure), Vapor Cone (realistic vapor condensation). Context: Supersonic flight, extremely fast punches, power-up acceleration, missiles/projectiles. Power Level Indicator: Size and intensity = speed achieved. Sound Association: BOOM, CRACK, BANG.', '2026-01-27 00:02:03', '2026-01-27 00:02:03', 1),
(6, 'The \"Impact Flash\" (Point of Contact Burst)', 'Bright white/colored explosion at collision point. Visual Description: Bright burst of light (usually white, yellow, or element-colored) at the exact point where two forces meet. Can be circular, star-shaped, or irregular. Often completely obscures the impact point momentarily. Technical Details: Size proportional to impact force. Shape: circle, star, irregular burst, or cross. Color: white (generic), yellow (fire/energy), blue (ice/magic), red (critical hit). Duration: single frame or brief sequence. Variants: White Flash (standard), Star Flash (critical/super effective hit), Cross Flash (dramatic clash), Expanding Flash (impact spreading), Colored Element Flash (magic/elemental). Context: Punches landing, swords clashing, projectile hits, critical hits, power clashes. Power Level Indicator: Brightness and size = impact force. Sound Association: KRAK, WHAM, CLASH.', '2026-01-27 00:02:03', '2026-01-27 00:02:03', 1),
(7, 'The \"Shockwave Rings\" (Radial Force Wave)', 'Concentric circles expanding from impact point. Visual Description: Multiple circular rings expanding outward from the impact center. Rings can be thin lines or thick bands. Usually distort the air/background as they expand. Often combined with impact flash. Technical Details: Ring Count (2-5 rings typical, more = stronger), Equal spacing or accelerating outward, Background warping along ring edge, Rings fade as they expand. Variants: Ground Shockwave (rings on ground surface only), Air Pressure Wave (spherical expanding wave), Directional Blast (semi-circular wave in one direction), Multiple Source Waves (waves from multiple impact points interfering). Context: Powerful impacts, explosions, sonic attacks, ki blasts landing, earthquakes. Power Level Indicator: Ring size and number = force magnitude. Sound Association: BOOM, THOOM, VWOOM.', '2026-01-27 00:02:03', '2026-01-27 00:02:03', 1),
(8, 'The \"Crack Pattern\" (Surface Fracture)', 'Spider-web cracks radiating from impact. Visual Description: Network of cracks spreading from impact point, usually in spider-web or lightning-bolt pattern. Shows on ground, walls, or barriers. Cracks can be surface-level or deep fissures. Technical Details: Density (more cracks = stronger), Depth (thin lines vs wide gaps), Propagation (static or animated spreading), Chunks lifting or falling from surface. Variants: Surface Crack (thin web of cracks), Deep Fissure (wide gaps revealing depth), Shattering (surface about to completely break), Spreading Crack (animated propagation), Glow Crack (light/energy bleeding through). Context: Ground-shattering impacts, breaking barriers, wall damage, shield cracking, limit breaking. Power Level Indicator: Crack depth and spread = impact power. Sound Association: CRACK, KRSH, CRUMBLE.', '2026-01-27 00:02:03', '2026-01-27 00:02:03', 1),
(9, 'The \"Debris Cloud\" (Particulate Explosion)', 'Cloud of dust, smoke, or particles exploding outward. Visual Description: Mass of particles (dust, smoke, debris, water droplets, energy) exploding outward from impact in all directions or directionally. Obscures the impact area temporarily. Technical Details: Density (thin wisps to completely opaque), Particle Size (fine dust to large chunks), Direction (omnidirectional or directional blast), Composition varies by material. Variants: Dust Cloud (ground impact, earth material), Smoke Plume (fire/explosion impacts), Water Spray (liquid impacts), Energy Dispersion (magical/energy impacts), Mixed Debris (chunks and dust combined). Context: Ground impacts, explosions, destruction, dramatic entrances, dust settling reveals. Power Level Indicator: Cloud size and density = impact force. Sound Association: CRASH, BOOM, WHOOSH.', '2026-01-27 00:02:03', '2026-01-27 00:02:03', 1),
(10, 'The \"Impact Distortion\" (Reality Warp)', 'Space/air visibly warping from force. Visual Description: The background and air around the impact point visibly distorts, bends, or ripples. Similar to heat shimmer but more pronounced. Shows pure force affecting space itself. Technical Details: Distortion Type (radial warp, directional push, compression, ripple), Intensity (subtle shimmer to extreme warping), Area (localized or widespread), Duration (momentary flash or sustained). Variants: Heat Shimmer (thermal distortion), Air Pressure Warp (compressed air visible), Space Distortion (reality-bending force), Ripple Effect (wave propagating through space), Lens Distortion (gravity/force bending light). Context: Extreme power impacts, reality-warping attacks, dimensional effects, gravity manipulation. Power Level Indicator: Severity of distortion = power level. Sound Association: VWOOM, WHOOM (often bass-heavy).', '2026-01-27 00:02:03', '2026-01-27 00:02:03', 1),
(11, 'The \"Spin Trail\" (Circular Afterimage)', 'Spiral or circular trails showing rotation. Visual Description: Curved afterimage trails following a spinning object or character. Can be complete circles, spirals, or arced segments. Multiple layers possible for complex spins. Technical Details: Pattern (spiral for continuous rotation, arc for partial, helix for 3D spiral), Layer Count (single loop to multiple overlapping spirals), Color (solid or gradating along path), Tightness (tight spiral vs loose curves). Variants: Single Spin Arc (one rotation visible), Multi-Spin Spiral (continuous spinning motion), Vertical Spin (wheel/cartwheel motion), Drill Spiral (tight corkscrew pattern), Figure-8 Pattern (complex aerial maneuvers). Context: Spinning attacks, aerial acrobatics, tornado effects, drill attacks, figure skating moves. Power Level Indicator: Tightness and speed of spiral = rotation speed. Sound Association: VWING, SPINNING, WHORL.', '2026-01-27 00:02:03', '2026-01-27 00:02:03', 1),
(12, 'The \"Vortex Lines\" (Suction/Rotation Force)', 'Lines spiraling inward or outward showing rotational force. Visual Description: Lines following spiral paths either converging to center (suction) or diverging from center (explosion). Creates sense of rotational pull or push. Can be smooth curves or sharp angular spirals. Technical Details: Direction (inward pulling, outward pushing, bidirectional chaos), Speed (line spacing indicates rotation speed), Layers (2D spiral or 3D vortex), Density (sparse lines to dense pattern). Variants: Suction Vortex (lines spiraling inward), Explosive Spiral (lines spiraling outward), Tornado Column (vertical rotating vortex), Whirlpool (horizontal water vortex), Energy Spiral (glowing rotating energy). Context: Tornado attacks, black holes, portals, vortex weapons, water whirlpools, summoning circles. Power Level Indicator: Tightness of spiral and speed = suction/force strength. Sound Association: VWOOOOOOP, WHORL, SWIRL.', '2026-01-27 00:02:03', '2026-01-27 00:02:03', 1),
(13, 'The \"Orbit Trail\" (Circular Path)', 'Objects orbiting around a central point. Visual Description: One or more objects following circular paths around a center, leaving trails. Can be planetary orbit-like, tight circles, or complex orbital patterns. Trails show the path taken. Technical Details: Path Shape (perfect circle, ellipse, irregular orbit), Object Count (single to multiple satellites), Trail Length (short segments to complete circles), Speed Variation (uniform or varying). Variants: Planet Orbit (celestial body orbiting), Weapon Orbit (swords/projectiles circling caster), Debris Orbit (fragments circling impact point), Energy Ring (power orbiting character), Multi-Body Orbit (multiple objects in synchronized orbits). Context: Orbital weapons, planetary scenes, magic circles, energy manipulation, debris fields. Power Level Indicator: Number of orbiting objects and orbit speed = power. Sound Association: Hmmmmm (sustained hum), VWING.', '2026-01-27 00:02:03', '2026-01-27 00:02:03', 1),
(14, 'The \"Arc Swing\" (Weapon Trail)', 'Curved line following weapon swing path. Visual Description: Bold curved line showing the arc of a weapon swing. Often glowing or colored differently from the weapon. Can include afterimages of the weapon along the arc. Technical Details: Arc Shape (horizontal slash, vertical cut, diagonal sweep, full circle), Visual Style (solid line, gradient, glowing energy, wind effect), Width (thin line to wide swath), Persistence (momentary or lingering effect). Variants: Sword Arc (clean cutting line), Energy Blade Arc (glowing energy trail), Wind Slash (air pressure visible), Full Circle Slash (360° rotation attack), Multi-Hit Arc (multiple overlapping arcs). Context: Sword slashes, scythe swings, staff spins, any melee weapon arc attack. Power Level Indicator: Arc length and glow intensity = cutting power. Sound Association: SLASH, SWISH, SHING.', '2026-01-27 00:02:03', '2026-01-27 00:02:03', 1),
(15, 'The \"Rolling Thunder\" (Ground Roll)', 'Object rolling with rotation indicators. Visual Description: Object rolling along ground with visual indicators of rotation - curved motion lines, rotation marks, or the object shown in multiple rotational positions. Often includes ground impact effects. Technical Details: Rotation Marks (curved arrows or lines on object), Ground Contact (dust, sparks, or impact marks where it touches), Speed Indicators (lines trailing the roll), Bounce (optional lift-off and re-impact). Variants: Smooth Roll (continuous rolling motion), Bouncing Roll (skipping along surface), Accelerating Roll (building speed), Boulder Roll (large object crushing path), Barrel Roll (aerial rolling maneuver). Context: Dodging by rolling, boulder attacks, barrel rolls, tumbling, spherical objects. Power Level Indicator: Speed and size of rolling object = momentum. Sound Association: RUMBLE, THUD-THUD-THUD.', '2026-01-27 00:02:03', '2026-01-27 00:02:03', 1),
(16, 'The \"Multi-Hit Flash\" (Rapid Strike Sequence)', 'Series of impact flashes showing multiple rapid hits. Visual Description: Multiple impact flashes appearing in rapid sequence, often overlapping. Shows consecutive hits landing faster than eye can follow. Can include numerical indicators (Hit counter). Technical Details: Flash Count (2-3 for combo to dozens for rapid barrage), Pattern (linear sequence, circular pattern, random placement), Timing (simultaneous or rapid sequential), Size Variation (same size or escalating). Variants: Double Impact (one-two punch combo), Rush Barrage (dozens of rapid hits), Combo Chain (sequential power-up combo), Omnidirectional Assault (hits from all angles), Finishing Blow Sequence (building to final strike). Context: Martial arts combos, rapid-fire attacks, speed-based assaults, finishing move sequences. Power Level Indicator: Number of hits and flash intensity = total damage. Sound Association: ORAORAORAORA, rapid THWAK-THWAK-THWAK.', '2026-01-27 00:02:03', '2026-01-27 00:02:03', 1),
(17, 'The \"Piercing Lance\" (Penetration Effect)', 'Sharp impact showing penetration rather than collision. Visual Description: Sharp, elongated impact effect showing an object piercing through rather than bouncing off. Often includes a thin bright line extending through the target, entry and exit points marked. Technical Details: Penetration Line (bright line through target), Entry Flash (bright burst at entry point), Exit Flash (often larger burst at exit), Distortion (space warping along penetration line). Variants: Clean Pierce (straight through with minimal damage), Explosive Exit (large exit wound effect), Beam Pierce (energy beam penetration), Multi-Pierce (multiple penetration points), Drill Pierce (spinning penetration with spiral effect). Context: Spear attacks, bullets, laser beams, drilling attacks, armor-piercing hits. Power Level Indicator: Penetration depth and exit size = piercing power. Sound Association: SHING, PIERCE, SKEWER.', '2026-01-27 00:02:03', '2026-01-27 00:02:03', 1),
(18, 'The \"Reflect Burst\" (Deflection Impact)', 'Impact showing attack being deflected/reflected. Visual Description: Angled impact flash with projectile/energy bouncing off at angle. Shows glancing blow rather than direct hit. Often includes sparks or energy ricocheting off in new direction. Technical Details: Angle (incoming and outgoing trajectory visible), Spark Effect (particles flying off at deflection point), Shield Glow (defending surface glowing at impact), Trajectory Change (clear before/after path shown). Variants: Perfect Reflect (clean bounce at mirror angle), Deflect Scatter (attack dispersing in multiple directions), Shield Block (impact absorbed by barrier), Parry Flash (weapon-on-weapon deflection), Energy Redirect (beam bent to new direction). Context: Blocking attacks, parrying, deflecting projectiles, force field impacts, perfect defense. Power Level Indicator: Size of deflection burst = attack power blocked. Sound Association: KLANG, PING, DEFLECT.', '2026-01-27 00:02:03', '2026-01-27 00:02:03', 1),
(19, 'The \"Clash Stalemate\" (Equal Force Collision)', 'Two equal forces meeting with neither winning. Visual Description: Large symmetrical impact effect at the meeting point of two forces. Often shows both attacks stopped dead, energy or force radiating outward equally in all directions. Extended duration compared to regular impact. Technical Details: Symmetry (impact effect is balanced/symmetrical), Duration (held moment, not instant flash), Energy Output (power radiating outward from center), Struggle Lines (visual indicators of straining). Variants: Beam Clash (two energy beams meeting), Blade Lock (swords pressed together), Fist Clash (punches meeting mid-air), Power Struggle (extended test of strength), Explosion Stalemate (two explosions canceling each other). Context: Hero vs villain clash, rivals evenly matched, test of strength, dramatic standoff. Power Level Indicator: Size of clash effect and struggle duration = combined power. Sound Association: CLAAAANG, sustained KSSSSHHH.', '2026-01-27 00:02:03', '2026-01-27 00:02:03', 1),
(20, 'The \"Overkill Devastation\" (Excessive Force)', 'Impact that far exceeds what was necessary. Visual Description: Massive, over-the-top impact effect that continues well beyond the initial hit. Multiple types of effects layered together. Shows complete destruction of target and surrounding area. Technical Details: Layering (multiple effect types combined), Scale (far larger than target requires), Duration (extended destruction sequence), Aftermath (crater, wasteland, or complete erasure). Variants: Crater Impact (massive crater formation), Mushroom Cloud (nuclear-scale explosion), Disintegration (target erased from existence), Landscape Erasure (entire area destroyed), Dimensional Tear (space itself damaged). Context: Final attacks, showing overwhelming power difference, overkill, dramatic finishers. Power Level Indicator: Destruction scale and effect duration = power excess. Sound Association: BOOOOOOOM (extended), OBLITERATE.', '2026-01-27 00:02:03', '2026-01-27 00:02:03', 1),
(21, 'The \"Launch Burst\" (Initial Acceleration)', 'Explosive start of movement from stationary. Visual Description: Burst of energy/force behind character/object as they suddenly accelerate from stillness. Often includes ground cracking, dust kicking up, or launching platform damage. Condensed motion lines radiating from starting point. Technical Details: Burst Direction (opposite to movement direction), Ground Damage (footprints, cracks, or crater at launch point), Condensed Lines (short, dense speed lines at origin), Expanding Lines (lines extending as movement progresses). Variants: Ground Launch (kicking off from surface), Propulsion Burst (rocket/jet propulsion), Energy Explosion Launch (magical/energy-based takeoff), Spring Launch (compressed energy release), Catapult (external force launching). Context: Race starts, charging into battle, rocket takeoff, jumping, power-up activation. Power Level Indicator: Burst size and ground damage = acceleration force. Sound Association: BOOM, BLAST OFF, LAUNCH.', '2026-01-27 00:02:03', '2026-01-27 00:02:03', 1),
(22, 'The \"Skid Halt\" (Sudden Stop)', 'Visual representation of rapid deceleration. Visual Description: Character/object coming to sudden stop with forward-leaning posture, skid marks on ground, dust/debris pushed forward, and motion lines showing momentum fighting the stop. Body continues forward while feet stop. Technical Details: Skid Marks (lines on ground showing sliding), Debris Wave (dust/gravel pushed forward), Lean Angle (body angled forward from momentum), Brake Effect (visual indication of stopping force). Variants: Ground Skid (feet dragging/sliding on surface), Controlled Stop (precise deceleration), Crash Stop (uncontrolled halt with tumbling), Air Brake (sudden stop mid-flight), Emergency Stop (instant halt - physics-defying). Context: Last-minute stops, dodging, arrival at destination, catching oneself, emergency braking. Power Level Indicator: Skid distance and debris = speed before stop. Sound Association: SCREECH, SKRT, HALT.', '2026-01-27 00:02:03', '2026-01-27 00:02:03', 1),
(23, 'The \"Mid-Air Pivot\" (Direction Change)', 'Changing direction impossibly while airborne. Visual Description: Character changing direction mid-flight with impossible physics. Shows motion lines changing angle, burst of energy/force at pivot point, body contorting to new direction. Original trajectory line crossed by new trajectory. Technical Details: Pivot Burst (small explosion/flash at turn point), Crossed Paths (old and new trajectory lines visible), Body Twist (anatomically impossible rotation shown), Secondary Launch (new acceleration from nothing). Variants: 90° Turn (right angle direction change), U-Turn (complete reversal), Spiral Turn (corkscrew direction change), Multi-Pivot (multiple direction changes - air dashing), Teleport Fake (turn so fast it looks like teleportation). Context: Aerial combat, superhuman reflexes, video game physics, magical flight, momentum manipulation. Power Level Indicator: Angle sharpness and speed maintained = power. Sound Association: VWIP, REDIRECT, sharp TURN.', '2026-01-27 00:02:03', '2026-01-27 00:02:03', 1),
(24, 'The \"Acceleration Burst\" (Speed Increase)', 'Sudden increase in already-fast movement. Visual Description: Character already in motion suddenly accelerates further with burst of increased effects. Motion lines become denser, afterimages increase, glow intensifies, or new visual effects layer on top of existing ones. Technical Details: Effect Intensification (all motion indicators amp up), Color Shift (often shift to warmer colors - yellow/white hot), Additional Effects (new elements added to motion visual), Scale Increase (existing effects grow larger/more intense). Variants: Gear Shift (distinct transition to higher speed tier), Turbo Boost (brief maximum acceleration), Breaking Limit (surpassing previous maximum), Momentum Build (gradual acceleration increase), Super Mode (power-up acceleration). Context: Second wind, power-up mid-battle, vehicle turbo, surpassing limits, clutch moment. Power Level Indicator: Intensity increase = power gain. Sound Association: VWOOOM, BOOST, ACCELERATE.', '2026-01-27 00:02:03', '2026-01-27 00:02:03', 1),
(25, 'The \"Drag Resistance\" (Fighting Friction)', 'Visual of struggling against resistance while moving. Visual Description: Character moving but showing strain against opposing force. Motion lines point in direction of travel but are irregular or turbulent. Resistance effects like air pressure waves, water drag, or energy friction visible. Technical Details: Opposing Force (visual showing what\'s resisting), Strain Indicators (gritted teeth, muscle strain, energy glow), Turbulence (chaotic motion lines around character), Breakthrough Moments (resistance effects shattering). Variants: Water Drag (moving through liquid), Wind Resistance (fighting air pressure), Gravity Drag (pushing against intense gravity), Energy Field (moving through hostile magic/energy), Time Resistance (moving through slowed time). Context: Moving through difficult terrain, fighting against hostile forces, time manipulation resistance. Power Level Indicator: Resistance intensity overcome = strength/willpower. Sound Association: STRAINING, PUSH, RESIST.', '2026-01-27 00:02:03', '2026-01-27 00:02:03', 1),
(26, 'The \"Teleport Displacement\" (Instant Movement)', 'Visual for appearing/disappearing without travel. Visual Description: Character disappearing from one location and appearing in another without visible travel. Departure shows implosion/fading effect. Arrival shows materialization/explosion effect. Original position often has lingering afterimage. Technical Details: Departure Effect (fade, implode, dissolve, scatter), Arrival Effect (fade in, explode, coalesce, gather), Particle Type (light, shadow, element-specific, digital), Sound (often visual sound effect of VWIP or POOF). Variants: Clean Teleport (simple fade out/in), Particle Teleport (body scatters/reforms as particles), Shadow Step (vanish into/emerge from shadows), Dimensional Rip (tear reality to step through), Digital Phase (pixelate out/in - tech-based). Context: Teleportation abilities, instant transmission, phase shifting, dimensional travel. Power Level Indicator: Distance traveled and effect intensity = teleport power. Sound Association: VWIP, BLINK, PHASE.', '2026-01-27 00:02:03', '2026-01-27 00:02:03', 1),
(27, 'The \"Phase Through\" (Intangibility)', 'Passing through solid objects. Visual Description: Character passing through solid object with transparency effect. The passing-through portion becomes semi-transparent or ghost-like. Ripple effects on the surface being penetrated. Both character and object remain intact. Technical Details: Transparency (character becomes translucent during passage), Ripple Effect (surface shows ripples like water), Duration (brief moment or sustained intangibility), Visual Style (ghost-like, digital, shadow-form, energy-state). Variants: Ghost Phase (spectral transparency), Dimensional Shift (briefly in different dimension), Molecular Pass (atoms passing between atoms), Shadow Merge (becoming shadow to pass through), Energy State (converting to energy form). Context: Intangibility powers, ghost abilities, phase shifting, dimensional manipulation. Power Level Indicator: Object density passed through = power level. Sound Association: WHOOSH, PHASE, (often minimal sound).', '2026-01-27 00:02:03', '2026-01-27 00:02:03', 1);
INSERT INTO `anivoc_scale_perspective` (`id`, `name`, `description`, `created_at`, `updated_at`, `is_ingredient`) VALUES
(1, 'The \"Chibi Shrink\" (Super-Deformed Comedy)', 'Character becomes tiny and cute for comedy or vulnerability showing emotional state. Visual Description: Character rendered as super-deformed miniature version with huge head (often 1:1 or 2:1 head-to-body ratio compared to normal 1:7), simplified features, tiny body. Usually appears 1/4 to 1/2 normal size relative to environment. Technical Details: Proportions (Head-to-body ratio 1:1 to 1:3 versus normal 1:7, Eyes become huge and simplified, Limbs shortened and simplified, Overall cute aesthetic), Size Reduction (Character appears 25-50% of normal height in frame), Detail Level (Significantly simplified features, cute rather than realistic, minimal anatomical detail), Movement Quality (Often bouncy, exaggerated, cute movements, physics don\'t apply normally). Psychological Effect: Cuteness response triggered, comedy recognized, harmlessness conveyed, vulnerability shown, non-threatening, approachable. Emotional Meaning: Comedy moment occurring, embarrassment expressed, cute reaction shown, vulnerability displayed, powerlessness felt, child-like state, pouting or begging, not to be taken seriously in this moment. Common Contexts: Comedy moments and reactions, Embarrassment scenes, Pouting or begging, Powerless situations, Cute appeals to others, Background comedy while main action continues, Tsundere reactions, Anger that isn\'t threatening. Style Origins: Originated from manga space-saving technique to show reactions without full panel, evolved into expressive emotional tool. Transition: Can snap between chibi and normal size instantly with no transition, audience accepts this. Ensemble Chibi: Sometimes entire cast goes chibi for comedy sequences or ending credits. Genre Prevalence: Universal in anime across genres, more prominent in comedy and slice-of-life. Cultural Note: Uniquely anime convention, not typically used in Western animation.', '2026-01-27 09:51:56', '2026-01-27 09:51:56', 1),
(2, 'The \"Giant Looming\" (Intimidation Scale)', 'Antagonist shown enormously large compared to hero showing power imbalance. Visual Description: Villain or threat rendered much larger than actual size difference would realistically suggest. Hero shown tiny in comparison at bottom of frame. Camera angle from below emphasizes towering imposing presence. Technical Details: Size Exaggeration (Antagonist rendered 2-10x larger than realistic proportions would dictate), Camera Angle (Low angle looking up at antagonist from ground level), Hero Position (Small figure, often at bottom third or quarter of frame), Shadow Usage (Antagonist shadow can dwarf hero completely), Detail Distribution (Antagonist highly detailed and imposing, hero simplified or small), Perspective Tricks (Forced perspective making distance seem less, Wide-angle lens distortion effect simulated, Hero in foreground still appears dwarfed). Psychological Effect: Intimidation and fear, overwhelming odds felt, powerlessness, David versus Goliath dynamic, \"how can I possibly win\" feeling. Emotional Meaning: Overwhelming threat faced, power imbalance stark, insurmountable obstacle, intimidation tactics, fear of superior force, questioning ability to win, facing the impossible. Common Contexts: First villain encounter establishing threat, Power difference demonstration, Hopeless situations, Boss reveals in games or battles, Intimidation scenes, Before hero power-up moment, Establishing stakes. Reversal Effect: Hero growing larger or villain shrinking equals power shift, tables turning. Literal Giants: Sometimes represents actual size difference with giants, but effect still exaggerated. Shadow Domination: Often villain shadow alone dwarfs hero before villain fully visible. Genre: Especially common in shonen battle anime, action, dark fantasy.', '2026-01-27 09:51:56', '2026-01-27 09:51:56', 1),
(3, 'The \"Ant View\" (Extreme Low Perspective)', 'Viewing from ground level making everything tower above showing vulnerability. Visual Description: Camera positioned at ground or floor level (0-6 inches height) looking up. Everything towers above creating vulnerable, small, overwhelmed feeling. Feet, furniture, people become giants from this perspective. Technical Details: Camera Height (Literally floor or ground level, 0-6 inches maximum), Vertical Exaggeration (Vertical lines converge dramatically upward toward vanishing point), Horizon Placement (Very low in frame or completely absent), Scale Reference (Small objects like pebbles or grass blades in foreground for scale), Perspective Effects (Extreme foreshortening of vertical elements, Ceiling or sky dominates upper frame, Legs and feet dominate if people present, Everything seems impossibly tall). Psychological Effect: Vulnerability and powerlessness, childhood perspective, being overwhelmed, insignificance, primal fear of being small. Emotional Meaning: Powerless and at mercy of others, vulnerable position, child-like helpless perspective, overwhelmed by world, insignificant and small, scared and threatened, at mercy of giants, defeated perspective. Common Contexts: Child point-of-view scenes, Powerless moments, Shrinking scenarios, Defeated or collapsed character view looking up, Insect or small creature POV, Vulnerable emotional states, After being knocked down, Fear visualization. Size Categories from this view: Normal people become towering giants, Furniture becomes architectural structures, Small details become landscape features. Recovery Shot: Rising camera angle equals character getting up, regaining power and agency. Empathy Tool: Puts viewer in physically vulnerable position creating empathy for character state. Genre: Common across genres for vulnerability moments, particularly effective in psychological, horror, drama.', '2026-01-27 09:51:56', '2026-01-27 09:51:56', 1),
(4, 'The \"Titan Reveal\" (Scale Pull-Back)', 'Camera pulls back revealing true massive scale hidden by initial framing. Visual Description: Scene starts focused on detail or character at seemingly normal comfortable scale, then camera pulls back and back, progressively revealing subject is actually enormous - mountain-sized creature, giant mech, massive structure. Creates surprise and awe through delayed revelation. Technical Details: Initial Frame (Detail shown at comfortable relatable scale, hides true scope), Pull-Back Method (Continuous camera movement orbiting out, or Series of progressive cuts moving further back), Revelation (True scale revealed through context - tiny people, known-size objects for comparison), Duration (Typically 3-10 seconds for maximum impact, can be longer for truly massive subjects), Scale Indicators (Tiny people or vehicles for scale comparison, Comparison to buildings or mountains, Shadow cast over landscape, Multiple stages of zoom-out needed to show full scale). Psychological Effect: Awe and wonder, shock at true scale, dread if threatening, sublime terror, insignificance of self, power recognition. Emotional Meaning: Overwhelming scale beyond imagination, awe at size, terror if threatening, \"we are doomed\" realization if enemy, sublime beauty or horror, godlike presence, impossible to comprehend fully. Common Contexts: Kaiju or giant monster reveals, Massive mech unveilings, Ancient colossus awakening, Spaceship scale reveals, Natural wonder discoveries, \"Final boss\" introductions, Establishing shots of massive structures, Ancient ruins true scale. Timing Strategy: Delayed revelation builds suspense and maximizes impact versus showing immediately. Sound Design: Often accompanied by increasingly distant or echoing sounds emphasizing scale. Attack on Titan: Made this technique iconic with progressive Titan reveals showing true terrifying scale. Genre: Particularly effective in mecha, kaiju, epic fantasy, science fiction anime.', '2026-01-27 09:51:56', '2026-01-27 09:51:56', 1),
(5, 'The \"Forced Perspective\" (Size Illusion)', 'Using perspective tricks to exaggerate size differences beyond reality. Visual Description: Deliberately manipulating perspective to make size differences more extreme than reality - small character very close to camera, large character further away but positioned to seem even larger through alignment. Creates dramatic size contrast. Technical Details: Near-Far Positioning (Small subject placed close to camera, Large subject positioned far but carefully aligned), Lens Choice (Wide-angle distortion effect exaggerates depth and size differences), Alignment (Subjects aligned to maximize apparent size difference, careful staging), Focus (Often selective focus emphasizing size difference, depth of field used strategically), Classic Tricks (Hand in foreground appearing to dwarf distant person, Small character appearing to be held in large character palm, Objects manipulated to appear larger or smaller than reality, Careful staging to create illusion). Psychological Effect: Power dynamic emphasized dramatically, visual trickery (acknowledged or hidden), dramatic contrast heightened, symbolic relationships made literal. Emotional Meaning: Power imbalance visualized, manipulation if revealed as trick, dramatic emphasis on relationship, visual metaphor for power dynamic, size representing importance or dominance. Common Contexts: Power dynamic visualization between characters, Metaphorical size relationships made visual, Comedy tricks and sight gags, Intimidation scenes, Parent-child relationship emphasis, Capturing or holding smaller character, Size-based humor. Reveal: Sometimes revealed as deliberate trick by character, sometimes maintained as visual truth. Lord of the Rings Influence: Famous forced perspective use in live-action Hobbit scenes, anime adapts principle. Meta Usage: Can be revealed as character using perspective trick within story. Genre: Comedy, action, drama - versatile technique across genres. Staging Required: Requires careful spatial planning and staging unlike pure size manipulation.', '2026-01-27 09:51:56', '2026-01-27 09:51:56', 1),
(6, 'The \"Fish Bowl Distortion\" (Wide-Angle Exaggeration)', 'Fish-eye or wide-angle lens effect making foreground huge, background tiny. Visual Description: Extreme wide-angle (fish-eye) lens distortion effect. Objects in foreground become disproportionately large, background shrinks dramatically. Curved distortion at frame edges. Creates dynamic, energetic, or disorienting feeling. Technical Details: Distortion Type (Barrel distortion - straight lines curve outward), Size Gradient (Extreme size difference from front to back of frame), Curved Lines (Horizontal and vertical lines curve, especially at frame edges), Center Focus (Center of frame relatively undistorted, distortion increases toward edges), Distortion Effects (Face close to camera appears huge with exaggerated features, Background compressed and tiny, Frame edges curved creating bubble effect, Depth dramatically exaggerated). Psychological Effect: Energy and dynamism, disorientation, comedy emphasis, invasion of personal space, in-your-face intensity, aggressive. Emotional Meaning: Energetic and dynamic moment, aggressive confrontation, in-your-face intensity, disorienting experience, comedic exaggeration, personal space invasion, overwhelming presence, reality distortion. Common Contexts: Comedy close-ups for exaggerated reactions, Energetic action sequences, Aggressive confrontations, Disorientation scenes, POV shots when peering or spying, Exaggerated reactions, Dynamic movement emphasis, Intense personal moments. Comedy Use: Often used for exaggerated comic reactions, surprise, shock faces. Action Use: Adds dynamism and energy to action sequences, punch impacts. Skateboard Video Influence: Borrowed from extreme sports video aesthetics. Genre: Particularly common in comedy, action, sports anime. Visual Impact: Creates memorable, eye-catching frames that stand out.', '2026-01-27 09:51:56', '2026-01-27 09:51:56', 1),
(7, 'The \"Doll House\" (God\'s Eye Overhead)', 'Viewing scene from directly above as if looking into dollhouse showing strategic view. Visual Description: Camera positioned directly overhead looking straight down at scene. Scene appears as miniature or dollhouse layout. Characters become small figures in architectural space. Creates detached, strategic, or omniscient feeling. Technical Details: Angle (Perfectly overhead at 90 degrees from ground plane), Framing (Often shows entire room or area as complete layout), Character View (Top of heads, characters simplified when viewed from directly above), Shadows (Important for depth perception, cast directly beneath subjects), Visual Effect (Flattened perspective appearance, Architectural or strategic view, Characters appear as game pieces, Patterns and spatial relationships clearly visible). Psychological Effect: Detachment from action, strategic viewpoint, fate or god perspective, characters as pawns in larger game, pattern recognition, omniscient perspective. Emotional Meaning: Detached observation from above, strategic planning view, fate or destiny perspective, characters as pieces in larger game, pattern of events visible, omniscient god-view, removed from immediate emotion. Common Contexts: Strategic planning scenes, Showing spatial relationships clearly, Fate or destiny moments, Establishing scene geography and layout, Showing choreography patterns, Transitions between scenes or locations, Tactical overview, Game or chess metaphor. Board Game Aesthetic: Characters become pieces in game, emphasizing strategy or fate controlling them. Wes Anderson Influence: Influenced by similar symmetrical overhead shots in live-action films. Transition Use: Often used for clean elegant scene transitions. Genre: Effective across genres - particularly in strategic, mystery, fate-themed narratives. Clarity: Provides spatial clarity impossible from other angles.', '2026-01-27 09:51:56', '2026-01-27 09:51:56', 1),
(8, 'The \"Giant Eye\" (Macro Close-Up)', 'Extreme close-up making single eye fill entire frame showing intense focus. Visual Description: Single eye fills entire frame (70-100%), showing extreme detail - iris patterns, reflections, blood vessels. Rest of face cropped out. Creates intensity, focus, examination, or intimidation through radical close-up. Technical Details: Framing (Eye occupies 70-100% of frame space), Detail Level (Extreme detail visible - iris patterns and colors, reflections showing what character sees, blood vessels and texture, individual eyelashes), Pupil State (Dilation state communicates emotion - fear equals dilated, focus equals constricted), Reflection (Often shows reflection of scene or other character in eye surface), Detail Emphasis (Iris detail and color patterns prominent, Pupil size indicating emotional state, Reflections telling parallel story, Highlights and shadow creating depth). Psychological Effect: Intensity and focus, scrutiny, soul-gazing, intimidation, intimate examination, window to soul, determination visible. Emotional Meaning: Intense focus on something, soul visible in eyes, intimidation tactic, intimate moment, examination or scrutiny, truth visible in eyes, determination and resolve, \"looking into their soul\", realization dawning. Common Contexts: Determination moments before action, Recognizing someone important, Intense emotional moments, Intimidation tactics, Soul-gazing between characters, Realization moments, \"Eyes meeting\" significant scenes, Seeing truth or deception, Internal resolve forming. Reflection Story: What is reflected in eye tells parallel story to main scene. Pupil Size Meaning: Emotional state readable from pupil dilation - fear, attraction, focus. Cultural: \"Eyes are window to soul\" universal belief across cultures. Genre: Particularly effective in psychological, drama, thriller anime. Intimacy: Creates intense intimacy between character and viewer.', '2026-01-27 09:51:56', '2026-01-27 09:51:56', 1),
(9, 'The \"Crowd Density\" (Mass Through Repetition)', 'Making crowds feel massive through repetition and scale tricks suggesting thousands. Visual Description: Crowds shown as mass of repeated figures filling frame to horizon. Uses repetition, depth layers, and scale to create sense of massive numbers - suggests thousands from hundreds of drawn figures. Technical Details: Repetition (Same character designs repeated with minor variations), Depth Layers (Foreground detailed with individual characters, Middle ground moderate detail, Background simplified masses, Far distance barely detailed suggestions), Perspective (Figures progressively shrinking into distance), Density (Packed composition with little negative space), Visual Tricks (Detailed foreground figures drawing eye, Simplified background masses, Atmospheric perspective with fading into distance, Strategic placement suggesting continuation beyond frame edges). Psychological Effect: Overwhelming numbers, individual lost in mass, movement power, collective force, \"can\'t fight this many\", conformity pressure. Emotional Meaning: Overwhelming mass of people, individual insignificance, collective power, impossible to fight so many, movement or army strength, conformity and group, lost in crowd. Common Contexts: Army or military scenes, Mass movements or protests, Overwhelming enemy numbers, Festival or crowd scenes, Showing scale of civilization, Individual versus system, Mob scenes, Population density. Efficiency: Visual technique suggests thousands without needing to draw thousands individually. Akira: Famous for extremely detailed crowd scenes in Neo-Tokyo showing urban density. Movement: Moving crowd creates wave or flow effect emphasizing collective power. Genre: Effective in military, political, urban, epic fantasy anime. Scale: Creates sense of scale for cities, armies, movements.', '2026-01-27 09:51:56', '2026-01-27 09:51:56', 1),
(10, 'The \"Isolation Distance\" (Vast Space Between)', 'Showing emotional distance through physical space between characters. Visual Description: Two characters separated by vast empty space in frame. Extreme distance between them emphasizes emotional distance, disconnection, or impossible gap to bridge. Negative space becomes meaningful storytelling element. Technical Details: Composition (Characters positioned at opposite edges or ends of frame), Negative Space (Large empty area between them becomes focal point), Size (Often both shown small in larger environment emphasizing distance), Depth (Can be lateral at same depth, or front-to-back distance), Compositional Variations (Both at frame edges looking away from each other, One foreground one background with vast distance between, Both small in vast landscape, Separated by physical barrier with space emphasizing separation). Psychological Effect: Loneliness despite proximity, disconnection felt, unbridgeable gap sensed, isolation even when together, emotional distance made physical. Emotional Meaning: Emotional distance visualized, disconnection and inability to reach each other, growing apart, unbridgeable gap between them, loneliness despite proximity, communication breakdown, impossible to cross distance. Common Contexts: Relationship deterioration, Communication breakdown, Growing apart over time, Misunderstanding and conflict, After argument or fight, Emotional walls between people, Impossible love, Separation and loss, Alienation. Reversal: Characters moving closer together equals reconciliation, connection restored. Physical Metaphor: Physical space in frame directly represents emotional space between characters. Silence: Often accompanied by silence or minimal dialogue emphasizing gulf. Genre: Particularly powerful in drama, romance, psychological anime. Visual Poetry: Simple visual composition communicates complex emotional state.', '2026-01-27 09:51:56', '2026-01-27 09:51:56', 1),
(11, 'The \"Cathedral Ceiling\" (Overwhelming Architecture)', 'Showing architecture so large it dwarfs characters emphasizing power and grandeur. Visual Description: Architecture such as cathedral, throne room, or ancient ruins shown at overwhelming scale. Ceilings impossibly high, characters tiny at bottom of frame. Emphasizes grandeur, power display, or ancient majesty through architectural scale. Technical Details: Vertical Emphasis (Strong vertical lines drawing eye upward toward ceiling), Character Placement (Usually positioned in bottom third of frame appearing very small), Convergence (Vertical lines converging dramatically upward), Light Quality (Often dramatic light from above through stained glass or ceiling openings), Architectural Features (Towering columns reaching far overhead, Vaulted ceilings impossibly high, Massive statues dwarfing people, Endless hallways extending into distance, Giant doorways emphasizing human smallness). Psychological Effect: Awe and wonder, insignificance of individual, power and wealth display, ancient grandeur, divine scale, intimidation through architecture. Emotional Meaning: Human insignificance before power, power on display through architecture, ancient majesty and history, divine or royal authority, overwhelming grandeur, intimidation through scale, humbling before greatness. Common Contexts: Throne rooms and royal courts, Cathedrals and temples, Ancient ruins and monuments, Villain lairs, Divine realms, Royal audiences, Power displays, Religious or sacred spaces. Historical Basis: Based on real architectural intimidation tactics used in cathedrals and palaces throughout history. Echo Effect: Often includes echoing sounds emphasizing vast space. Power Statement: Architecture itself statement of ruler or god power over subjects. Genre: Common in fantasy, historical, religious-themed anime. Cultural: Gothic cathedral influence, Eastern palace architecture.', '2026-01-27 09:51:56', '2026-01-27 09:51:56', 1),
(12, 'The \"Cityscape Vista\" (Urban Immensity)', 'Showing city scale from high vantage point emphasizing urban vastness. Visual Description: City viewed from high point such as rooftop, tower, or aircraft. Buildings extend to horizon in all directions. Shows urban sprawl, civilization scale, or character small place in metropolis. Technical Details: Vantage Point (High elevation looking down and outward), Depth (Multiple layers of buildings receding to horizon), Detail Gradient (Foreground detailed, middle ground moderate, distance simplified), Atmosphere (Haze or atmospheric perspective in distance), Visual Elements (Layer upon layer of buildings, Lights at night showing millions of windows, Streets as grid patterns, Landmarks for orientation, Atmospheric haze adding depth). Psychological Effect: Urban vastness, civilization scale felt, individual lost in mass, connection or isolation paradox, modern life complexity. Emotional Meaning: Urban immensity, lost in the city, civilization scope, connection to millions or isolation among millions, modern life, individual insignificance, teeming humanity. Common Contexts: Establishing city setting, Character contemplation of life, Urban isolation themes, Showing civilization scale, \"Lost in the city\" moments, Cyberpunk establishing shots, Metropolis scope, Modern alienation. Day versus Night: Day shows vastness and complexity; Night shows million lights creating either connection or isolation feeling. Blade Runner and Akira Influence: Iconic city vistas from these films established visual language. Character Scale: Character often shown as small silhouette against city emphasizing scale contrast. Genre: Essential in cyberpunk, urban drama, modern psychological anime.', '2026-01-27 09:51:56', '2026-01-27 09:51:56', 1),
(13, 'The \"Mountain Range Infinity\" (Natural Grandeur)', 'Mountains extending endlessly showing nature eternal scale and journey scope. Visual Description: Mountain ranges extending to horizon, layer upon layer receding into distance. Shows nature timeless grandeur, journey scope, or human insignificance before natural world. Technical Details: Layering (Multiple mountain ridges at different distances creating depth), Atmospheric Perspective (Progressive blue tint and haze in distance), Scale (Foreground mountains huge and detailed, distant mountains progressively smaller), Character Inclusion (Often small figure for scale comparison), Visual Progression (Foreground with detailed texture, Middle ground with moderate detail, Background as silhouettes with blue haze, Far distance as barely visible layers). Psychological Effect: Nature grandeur and power, timelessness, journey scope felt, human insignificance, sublime beauty, humility before nature. Emotional Meaning: Nature eternal scale, journey magnitude ahead, human smallness, sublime beauty, timeless perspective, overwhelming task, ancient world predating humanity. Common Contexts: Journey beginnings, Showing quest scope, Nature majesty, Contemplative moments, Challenge visualization, Epic quest settings, Spiritual journeys, Adventure establishing shots. Spiritual Association: Mountains often represent spiritual journeys, enlightenment paths, challenges to overcome. Challenge Metaphor: Visual metaphor for size of challenge ahead, mountains to climb. Studio Ghibli: Master of natural grandeur showing respect for nature scale and beauty. Genre: Common in adventure, fantasy, journey narratives. Cultural: Mountain pilgrimage tradition in Eastern culture.', '2026-01-27 09:51:56', '2026-01-27 09:51:56', 1),
(14, 'The \"Starfield Infinity\" (Cosmic Scale)', 'Space shown with endless stars emphasizing cosmic scale and human insignificance. Visual Description: Deep space with countless stars, galaxies, nebulae. Character or ship shown impossibly tiny against infinite cosmos. Emphasizes cosmic insignificance or wonder at universe scale. Technical Details: Depth (Multiple layers of stars - near, middle distance, far), Variety (Stars of different sizes, colors brightness levels), Subject Scale (Ship or character impossibly small in frame), No Reference (No normal scale references, only cosmic elements), Cosmic Elements (Distant galaxies, Nebulae clouds, Dense star fields, Cosmic phenomena like supernovae, Absolute blackness between stars). Psychological Effect: Cosmic insignificance, infinite wonder, existential perspective, isolation or connection to cosmos, awe, humility. Emotional Meaning: Human insignificance in cosmos, infinite wonder, existential contemplation, cosmic loneliness or unity with universe, perspective shift, smallness, connection to infinite. Common Contexts: Space opera establishing shots, Existential moments, Showing cosmic scope, Isolation in space, Wonder moments, Perspective shifts, Philosophical scenes, Contemplating existence. Philosophy: Often accompanies philosophical dialogue about existence, meaning, humanity place in universe. 2001 Space Odyssey Influence: Kubrick space scale and isolation influenced anime space scenes. Sound: Often complete silence emphasizing void, or vast echoing sounds. Genre: Essential in space opera, science fiction, philosophical anime. Scale: Ultimate scale contrast - human versus infinite universe.', '2026-01-27 09:51:56', '2026-01-27 09:51:56', 1),
(15, 'The \"Ocean Horizon\" (Endless Blue)', 'Ocean extending to horizon showing vastness, isolation, or peaceful infinity. Visual Description: Ocean filling frame to horizon line. Character on small boat or floating, surrounded by endless water. Shows isolation, vastness, being adrift, or peaceful infinity depending on treatment. Technical Details: Horizon Line (Usually positioned in upper third emphasizing water expanse), Subject (Small boat, person, or object for scale), Texture (Water surface texture showing scale), Sky (Often large sky portion showing openness), Water States (Calm water equals peaceful, meditative, alone with thoughts; Rough water equals struggle, nature power, vulnerability; Mist equals mystery, liminal space between states). Psychological Effect: Vastness felt, isolation, peace or fear, adrift sensation, infinity, contemplation, vulnerability. Emotional Meaning: Isolation in vastness, being adrift literally or metaphorically, peaceful infinity or terrifying endlessness, contemplation, human smallness, journey, vulnerability before nature. Common Contexts: Sea journey scenes, Isolation visualization, Contemplative moments, Survival scenarios at sea, Peaceful meditation, Lost or adrift feelings, Liminal space between places, Life journey metaphors. Dual Nature: Can be peaceful meditative infinity, or terrifying vast indifference and vulnerability. Sound: Often minimal sound - water sounds, wind, silence emphasizing isolation. Literary Influence: \"Old Man and the Sea\" type narratives, sea as life metaphor. Genre: Effective in survival, journey, contemplative, psychological anime. Symbolism: Ocean often symbolizes unconscious mind, unknown, life journey.', '2026-01-27 09:51:56', '2026-01-27 09:51:56', 1),
(16, 'The \"Tree Cathedral\" (Nature\'s Architecture)', 'Ancient forest with trees like cathedral columns showing nature sacred grandeur. Visual Description: Ancient forest with massive tree trunks like cathedral columns. Canopy far above like vaulted ceiling. Shafts of light through leaves creating god rays. Shows nature grandeur and sacred quality. Technical Details: Vertical Lines (Massive straight trunks like architectural columns), Height (Canopy far above, trees towering overhead), Light (Dappled light from above, god rays through leaves), Scale (Character small at base of giant ancient trees), Natural Cathedral (Tree trunks function as columns, Canopy functions as vaulted ceiling, Light shafts like stained glass effect, Forest floor as cathedral nave). Psychological Effect: Nature majesty, sacred natural space felt, ancient wisdom, peace, respect for nature, spiritual connection, humility. Emotional Meaning: Nature sacred grandeur, ancient wisdom in trees, spiritual space, respect for nature, peace and tranquility, timeless beauty, connection to something greater. Common Contexts: Spiritual journeys, Ancient forests, Spirit encounters, Contemplative moments, Nature respect themes, Sacred natural spaces, Environmental messages, Miyazaki-style reverence. Studio Ghibli Signature: Ghibli sacred forest spaces showing deep respect for nature. Shinto Influence: Japanese sacred forest tradition, spirits dwelling in ancient trees. Sound: Often wind through leaves, silence, birdsong, reverent quiet. Genre: Fantasy, spiritual, environmental anime. Cultural: Sacred grove tradition across many cultures. Environmentalism: Often carries environmental protection message.', '2026-01-27 09:51:56', '2026-01-27 09:51:56', 1),
(17, 'The \"Ruins Vastness\" (Civilization Lost)', 'Ancient ruins showing scale of lost civilization and impermanence. Visual Description: Massive ancient ruins extending vast distances. Broken architecture still towering impressively. Nature reclaiming structures. Shows civilization former grandeur now fallen, impermanence of human works. Technical Details: Architecture (Broken but still massive structures), Nature Reclamation (Vegetation growing over and through ruins), Scale (Ruins dwarf modern characters exploring them), Depth (Ruins extending to horizon showing former extent), Ruin Elements (Toppled columns still huge, Partial walls still towering, Broken statues still recognizable, Stairways leading nowhere, Nature taking back space). Psychological Effect: Fallen grandeur felt, impermanence of civilization, history weight, melancholy, adventure beckoning, humility, mortality of societies. Emotional Meaning: \"How the mighty have fallen\", impermanence of civilization, history weight, mystery of past, melancholy beauty, adventure beckons, warning about pride, mortality. Common Contexts: Ancient civilization discoveries, Impermanence themes, Historical mysteries, Adventure beginnings, Apocalyptic futures, Archaeological scenes, Exploring forgotten places, Warning about current civilization. Philosophy: \"Ozymandias\" theme - all empires fall, pride precedes fall. Adventure: Ruins equal adventure, discovery, treasure, mystery to uncover. Warning: Sometimes functions as warning about current civilization fate. Genre: Adventure, fantasy, post-apocalyptic, historical anime. Melancholy: Beautiful melancholy of fallen greatness.', '2026-01-27 09:51:56', '2026-01-27 09:51:56', 1),
(18, 'The \"Underground Cavern\" (Subterranean Vastness)', 'Massive underground caverns showing hidden world scale beneath surface. Visual Description: Enormous underground caverns with ceiling far above or invisible in darkness. Vast space underground. Stalactites and stalagmites, underground lakes, bioluminescence. Shows hidden world existing beneath known surface. Technical Details: Vertical Space (Ceiling invisible or barely visible far above), Depth (Multiple levels descending into earth), Lighting (Limited creating mystery and wonder), Scale Indicators (Small character, light sources, geological formations), Cavern Features (Massive stalactite and stalagmite formations, Underground water bodies, Crystal formations, Bioluminescent life, Ancient carved or natural spaces). Psychological Effect: Hidden world wonder, going deep physically and metaphorically, mystery, primordial space, discovery, awe. Emotional Meaning: Hidden world beneath surface, depths unexplored, mystery and unknown, primordial ancient space, going deep as journey inward metaphor, discovery of hidden realm. Common Contexts: Underground adventures, Hidden worlds beneath surface, Journey to depths, Treasure hunts, Underworld entrances, Dwarven or underground realms, Cave exploration, Descent narratives. Symbolism: Underground often represents subconscious mind, hidden truths, journey inward, primordial origins. Light Sources: Limited light creates mystery, drama, wonder through partial revelation. Journey Down: Often represents psychological descent into self or past. Genre: Fantasy, adventure, psychological anime. Primordial: Ancient primordial feeling, predating surface world.', '2026-01-27 09:51:56', '2026-01-27 09:51:56', 1),
(19, 'The \"Sky Realm\" (Floating Architecture)', 'Floating islands or cities showing magical impossible scale defying physics. Visual Description: Cities or structures floating in sky among clouds. Impossible architecture defying gravity. Shows magical world, freedom from earth bounds, fantasy grandeur made real. Technical Details: Floating Elements (Islands, buildings, entire structures suspended in sky), Clouds (Surrounding, below floating structures, or penetrating them), Connections (Bridges, chains, or visible magic connecting floating pieces), Scale (Often enormous structures floating impossibly), Fantasy Architecture (Inverted waterfalls falling upward, Floating gardens and forests, Cloud-piercing towers, Impossibly balanced structures, Visible magic keeping structures aloft). Psychological Effect: Wonder and awe, magic is real, freedom from earthly limits, fantasy grandeur, impossible made possible, imagination realized. Emotional Meaning: Wonder at magic made real, freedom from earthly physical bounds, fantasy grandeur achieved, impossible made possible, reaching for and achieving sky, transcendence, limitless possibility. Common Contexts: Fantasy worlds, Magical realms, Utopian societies, Divine or celestial realms, Magic demonstration, Ultimate achievement of civilization, Transcendent spaces, Impossible made real. Castle in the Sky: Studio Ghibli \"Castle in the Sky\" archetypal floating realm. Freedom Symbol: Sky realms represent freedom, transcendence, breaking earthly bonds. Magic Required: Floating architecture proves magic exists, impossible by physics. Genre: Essential in fantasy, magical, utopian anime. Wonder: Designed to evoke childlike wonder and imagination.', '2026-01-27 09:51:56', '2026-01-27 09:51:56', 1),
(20, 'The \"Microscopic Realm\" (Tiny World Huge)', 'Entering microscopic world where small becomes enormous showing hidden complexity. Visual Description: Microscopic environment shown at enormous scale - bacteria as monsters, cells as landscapes, water droplets as oceans. Shows familiar world at radically unfamiliar scale revealing hidden complexity. Technical Details: Scale Inversion (Microscopic elements rendered huge and imposing), Detail (Extreme detail of tiny structures normally invisible), Perspective (Character now tiny in this normally invisible world), Biology (Biological structures function as architecture and landscape), Micro Elements (Cells as terrain and landscape, Bacteria as creatures, Blood vessels as rivers, Molecular structures visible, Surface tension effects on water). Psychological Effect: Wonder at hidden world, unfamiliar familiar, everything is relative, hidden complexity everywhere, new perspective. Emotional Meaning: World within world, hidden complexity in everything, scale is relative concept, wonder in tiny invisible realm, life at all levels and scales, new perspective on reality. Common Contexts: Shrinking scenarios, Science fiction adventures, Educational sequences, Body invasion plots for medical drama, Perspective shift narratives, Showing hidden worlds, Scientific wonder. Fantastic Voyage Influence: Classic \"Fantastic Voyage\" shrinking journey established trope. Science Wonder: Shows scientific microscopic world beauty and complexity. Relativity: Everything depends on scale and perspective, no absolute size. Genre: Science fiction, educational, adventure anime. Educational: Can serve educational purpose showing microscopic reality.', '2026-01-27 09:51:56', '2026-01-27 09:51:56', 1),
(21, 'The \"Growing Threat\" (Progressive Size Increase)', 'Threat progressively growing larger showing escalating danger and losing control. Visual Description: Antagonist or threat shown progressively larger across scenes or within single scene. Starts normal-sized, grows to tower over heroes. Shows escalating danger, power increase, or entity losing control and growing beyond bounds. Technical Details: Progression (Series of shots showing incremental size increase), Rate (Can be gradual steady expansion or explosive sudden growth), Comparison (Same reference objects showing growth progression), Peak (Often crescendo moment of maximum size before confrontation), Growth Patterns (Steady continuous expansion, Staged power-ups in distinct phases, Explosive sudden growth spurt, Continuous slow inflation, Pulsing growth getting bigger with each pulse). Psychological Effect: Escalating threat felt, losing control, growing fear, unstoppable force, desperation increasing, \"this is getting worse\" realization. Emotional Meaning: Threat escalating beyond control, losing control of situation or self, growing beyond bounds, \"this is getting worse\", unstoppable force, fear increasing proportionally, stakes rising. Common Contexts: Boss battles with multiple phases, Kaiju emergence and growth, Power corruption spreading visually, Rage physically increasing size, Transformation sequences, Exponential threats, \"Final form\" reveals, Escalation visualization. Visual Storytelling: Size directly equals danger level, growing size equals growing stakes and desperation. Phases: Boss battles often have 3-5 distinct growing phases showing escalation. Desperation Parallel: Heroes desperation and effort grows proportionally with threat size. Breaking Limits: Villain visually breaking their own limits, going beyond. Genre: Essential in shonen battle, kaiju, action anime.', '2026-01-27 09:51:56', '2026-01-27 09:51:56', 1),
(22, 'The \"Shrinking Defeat\" (Size Loss/Deflation)', 'Character shrinking showing power loss, defeat, or deflation to true weak state. Visual Description: Character progressively shrinking in size. Powerful being reduced to small weak form. Shows power loss, defeat, deflation both literal and emotional, or returning to true weak state. Technical Details: Progression (Series showing size decrease stages), Rate (Can be gradual deflation or sudden collapse), End State (Small, weak, vulnerable final form), Comparison (Environment staying same scale showing shrinkage clearly), Details Lost (Character becomes simpler as they shrink, less imposing), Shrinking Contexts (Power running out or depleted, Transformation time limit ending, Defeat revealing weakness, Curse or magic effect, True weak form revealed, Air or power escaping like deflation). Psychological Effect: Deflation literal and emotional, power loss felt, vulnerability revealed, pathetic, defeat, reversal, weakness exposed. Emotional Meaning: Power gone completely, deflation and defeat, weakness revealed, \"is that all you were?\", vulnerability exposed, true pathetic self shown, humiliation. Common Contexts: Villain defeats revealing true weakness, Power time limits expiring, Transformation endings, Magic wearing off, True form reveals showing actually weak, Balloon or pufferfish deflation, Comedy deflation of ego. Comedy Use: Can be comedic showing puffed up ego deflating literally. Pathetic Imagery: Often includes pathetic whimpering, confusion, vulnerability. Relief Moment: Can be relief if threatening villain shrinks to harmless. Vulnerability: Small size equals now defenseless and at mercy. Genre: Common across action, comedy, drama anime.', '2026-01-27 09:51:56', '2026-01-27 09:51:56', 1),
(23, 'The \"Size Swap\" (Role Reversal Scale)', 'Hero and villain swap sizes showing complete power shift and tables turned. Visual Description: Scene where hero was small and villain was large becomes completely inverted - hero now towers imposingly, villain now small and vulnerable. Power dynamic visually reversed through size swap showing tables turned. Technical Details: Reversal (Direct inversion of earlier size relationship), Staging (Often similar composition to earlier scene but roles swapped), Emphasis (Clear visual parallel to earlier intimidation scene), Triumph Moment (Hero growth or villain reduction marking turning point), Reversal Triggers (Hero power-up moment, Villain power loss, Physical transformation, Metaphorical shift made literal and visual, Magic reversal, True power revealed). Psychological Effect: Satisfaction at reversal, power shift felt, tables turned, justice served, role reversal thrill, comeuppance, vindication. Emotional Meaning: Tables turned completely, power shift complete, \"now you know how it feels\", justice or revenge, role reversal, satisfying payback, vindication. Common Contexts: Climactic power-up moments, Revenge moments, Justice served, True power reveals, Character growth visualization, Turning point battles, Underdog triumph, Power shift moments. Mirror Composition: Often deliberately mirrors earlier intimidation scene for maximum impact. Dialogue Echo: May include echoed dialogue from earlier scene with roles reversed. Satisfaction: Highly satisfying narrative moment for audience. Visual Metaphor: Size literally shows who has power now, no ambiguity. Genre: Essential payoff moment in shonen, action, justice-themed anime.', '2026-01-27 09:51:56', '2026-01-27 09:51:56', 1),
(24, 'The \"Transformation Scale\" (Power-Up Size Change)', 'Character growing larger during power-up transformation showing power increase visually. Visual Description: During transformation sequence, character grows larger through muscular expansion, height increase, or overall enlargement. Size increase directly represents and visualizes power increase. Technical Details: Growth Type (Muscular expansion - hulking out, Height growth - stretching upward, Overall mass increase, Specific body parts growing like weapons or wings, Staged growth in multiple distinct phases), Rate (Can be explosive instant or gradual expansion), Glow Effects (Often accompanied by energy glow or aura), Clothing (Clothes strain, tear dramatically, or magically adjust to new size), Transformation Patterns (Progressive muscle inflation, Vertical stretching, Mass accumulation, Phased multi-stage growth). Psychological Effect: Power increase felt viscerally by viewer, intimidation, awesome power display, escalation, \"getting serious\", limit breaking. Emotional Meaning: Power increasing dramatically, \"getting serious now\", limits breaking, true form revealing, power unleashed, escalation, hidden strength shown, transformation. Common Contexts: Power-up transformation sequences, \"True form\" reveals, Rage transformations, Final form sequences, Limit breaking moments, Super modes activation, Berserker transformations, Hidden power unleashing. Shonen Staple: Core trope in shonen battle anime showing power levels. Size Equals Power: Visual shorthand where bigger automatically equals stronger. Clothes Destruction: Often includes dramatic clothing damage or destruction. Energy Display: Usually combined with energy aura effects for emphasis. Genre: Defining element of battle shonen, action, superhero anime.', '2026-01-27 09:51:56', '2026-01-27 09:51:56', 1),
(25, 'The \"Chibi-Normal Snap\" (Comedy Scale Shift)', 'Instant switch between chibi and normal size for pure comedy effect. Visual Description: Character instantly switches between super-deformed tiny chibi form and normal size, often multiple times in quick succession. Pure comedy effect with no logic required. Technical Details: Instant Switch (No transition, immediate snap between sizes), Frequency (Can switch multiple times within seconds), Triggers (Emotional reactions, comedy beats, rapid mood changes), Contrast (Maximum contrast between tiny-cute and normal proportions), Switch Triggers (Embarrassment causes shrink to chibi, Anger snaps to normal to yell, Indignation as chibi rage, Pleading as chibi puppy-dog eyes, Recovered dignity returns to normal). Psychological Effect: Comedy and humor, whiplash humor from rapid changes, emotional volatility shown physically, visual gag, absurdity. Emotional Meaning: Emotional instability shown comedically, vulnerability and strength switches, comedy through visual contrast, physical manifestation of mood swings, not serious. Common Contexts: Comedy sequences, Tsundere reactions, Rapid emotional changes, Slapstick moments, Embarrassment-anger cycles, Chibi arguments, Mood swing visualization, Romance comedy reactions. No Logic Required: Doesn\'t follow any physical logic, pure visual comedy convention. Genre: Most common in comedy, slice-of-life, romantic comedy anime. Audience Expectation: Viewers don\'t question it, fully accepted anime convention. Cultural: Uniquely anime comedic device.', '2026-01-27 09:51:56', '2026-01-27 09:51:56', 1),
(26, 'The \"Imposing Silhouette\" (Backlit Size Exaggeration)', 'Character backlit to appear larger and more imposing than reality through shadow. Visual Description: Character shown in silhouette against bright background, making them appear larger, more imposing, more threatening than actual size. Shadow and backlighting exaggerate presence. Technical Details: Backlighting (Strong light from behind character), Silhouette (Character rendered as dark imposing shape), Size Exaggeration (Appears 20-50% larger than reality), No Detail (Face and features obscured, only imposing shape visible), Lighting Setup (Door or window light behind, Sun backlighting, Fire or explosion behind, Dramatic reveal lighting). Psychological Effect: Intimidation felt, mystery, imposing presence, threat sensed, authority, dramatic impact, fear. Emotional Meaning: Intimidating entrance, mysterious figure, imposing presence, threat arriving, authority, dramatic reveal, power before details shown. Common Contexts: Dramatic entrances, Authority figures arriving, Mysterious strangers, Intimidation moments, Backlit doorways, Sunset arrivals, Villain reveals, Power demonstrations. Reveal: Often followed by lighting change revealing true appearance creating secondary impact. Western Film Reference: Classic Western \"stranger arrives\" shot influenced this. Power Suggestion: Suggests power and threat before showing any details. Genre: Effective across genres - particularly in action, mystery, western-influenced anime. Doorway: Doorway backlighting particularly common and effective.', '2026-01-27 09:51:56', '2026-01-27 09:51:56', 1),
(27, 'The \"Child\'s Eye Giant\" (Adult Through Child Perspective)', 'Adults shown as giants from child character low point-of-view showing vulnerability. Visual Description: From child character perspective at low eye-level (3-4 feet), normal-sized adults appear as towering giants. Child sees mostly legs and torsos. Shows vulnerability, power imbalance, childhood fear or wonder. Technical Details: Camera Height (Child eye-level at 3-4 feet height), Adult Framing (Often cut off at top, heads out of frame or far above), Foreshortening (Adults bodies dramatically foreshortened), Child in Frame (Small child in foreground for scale), Child POV Elements (Adults tower impossibly high, See mostly legs and waists, Faces far above and intimidating, World designed for bigger people, Everything out of reach). Psychological Effect: Vulnerability felt, powerlessness, childhood fear or wonder, adult world intimidating, seeking protection or fearing adults. Emotional Meaning: Child vulnerability, powerlessness in adult world, adult world intimidating and overwhelming, seeking protection or fearing adults, giant world, dependency. Common Contexts: Childhood flashbacks, Child protagonist scenes, Abuse or trauma visualization, Parent-child dynamics, Wonder through child eyes, Fear of adults, Vulnerable moments, Coming-of-age. Emotional Valence: Can be positive (protective giants, wonder) or negative (intimidating, frightening adults). Empathy Tool: Puts adult viewer in child vulnerable position creating empathy. Studio Ghibli: Miyazaki frequently uses child perspective showing their view of world. Genre: Effective in coming-of-age, family drama, trauma-focused anime.', '2026-01-27 09:51:56', '2026-01-27 09:51:56', 1);
INSERT INTO `anivoc_scale_perspective` (`id`, `name`, `description`, `created_at`, `updated_at`, `is_ingredient`) VALUES
(28, 'The \"Mech Scale Staging\" (Pilot Reveal Size Contrast)', 'Showing mech or robot scale by revealing tiny human pilot inside cockpit. Visual Description: Enormous mech or robot shown imposing and powerful, then cut to tiny human pilot inside cockpit. Creates dramatic scale contrast showing how massive the mech truly is. Technical Details: External Shot (Mech shown at imposing scale), Cut to Cockpit (Human pilot tiny surrounded by controls), Scale Indicators (Pilot size versus cockpit shows mech true scale), Technology (Complex controls dwarf pilot), Staging Sequence (1. Mech exterior imposing, 2. Cut to pilot interior showing tiny human, 3. Back to exterior with new perspective, 4. Viewer understands true scale). Psychological Effect: Awe at scale, human controlling massive power, technology magnitude, pilot vulnerability despite power. Emotional Meaning: Human controlling massive power, technology scale and complexity, awesome machinery, pilot vulnerability inside power, scale contrast, man and machine. Common Contexts: Mech anime establishing shots, Giant robot reveals, Pilot introduction scenes, Scale demonstration, Vulnerability despite power, Technology showcase, Human-machine interface. Gundam Legacy: Established by Gundam franchise as essential mech anime technique. Vulnerability: Tiny pilot emphasizes vulnerability despite massive mech power. Scale Understanding: Helps viewer grasp otherwise incomprehensible scale. Genre: Essential and defining element of mech anime genre.', '2026-01-27 09:51:56', '2026-01-27 09:51:56', 1),
(29, 'The \"Crowd Lift Elevation\" (Collective Power Visual)', 'Single character lifted or elevated by crowd showing collective support and triumph. Visual Description: Character physically lifted above crowd through crowd surfing, carried on shoulders, or raised on platform. Shows collective support, being raised up by community, elevation through others. Technical Details: Character Position (Above crowd, elevated 6-10 feet), Crowd Below (Supporting, raising, celebrating), Height (Character significantly elevated above ground), Perspective (Often from character elevated POV looking down, or external showing elevation), Elevation Contexts (Victory celebrations, Community support, Leader emerging, Being chosen or selected, Triumph moments, Revolutionary fervor). Psychological Effect: Triumph felt, community support, elevation literal and metaphorical, being lifted up by others, collective power, belonging. Emotional Meaning: Supported by community, lifted up by others, triumph, collective celebration, chosen one, power of many, belonging, achievement recognized. Common Contexts: Victory celebrations, Revolutionary moments, Community support scenes, Leader coronations, Sports victories, Triumph over adversity, Collective achievement, Being chosen. Literal Rise: Character literally lifted equals metaphorically raised, elevated in status, supported. Community Power: Shows strength of collective over individual. Perspective Shift: Character gains new elevated perspective literally and metaphorically. Genre: Sports, revolutionary, community-focused anime. Cultural: Victory parade, leader coronation traditions.', '2026-01-27 09:51:56', '2026-01-27 09:51:56', 1),
(30, 'The \"Horizon Line Character\" (Tiny Figure Vast Landscape)', 'Single tiny character against vast landscape, nearly invisible showing insignificance or determination. Visual Description: Character rendered so small in vast landscape they are almost invisible - tiny dot on horizon line. Shows insignificance, vastness, loneliness, or journey scope. Requires viewer to search for tiny character. Technical Details: Character Size (Occupies less than 1% of frame), Landscape Dominance (95%+ of frame is environment), Horizon Placement (Often character positioned on horizon line itself), Search Factor (Viewer must actively search to find character), Landscape Types (Desert - tiny against dunes, Ocean - speck on water, Mountain - dot on peak or slope, Plains - figure in vastness, Snow - barely visible in white). Psychological Effect: Insignificance of individual, loneliness, vastness overwhelming, journey scope, human smallness, persistence despite odds. Emotional Meaning: Human insignificance, alone in vastness, journey magnitude, loneliness, persistence despite smallness, one person versus world, determination. Common Contexts: Journey beginnings, Isolation moments, Post-apocalyptic wandering, Spiritual quests, Showing scope of challenge, Lone survivor scenarios, Pilgrimage, Existential moments. Movement: Often includes slow movement across vast space emphasizing journey. Persistence: Small figure still moving equals determination despite impossible odds. Existential: Raises questions of meaning and purpose in vast indifferent universe. Genre: Journey, post-apocalyptic, existential, epic fantasy anime. Visual Poetry: Simple powerful image communicating complex themes.', '2026-01-27 09:51:56', '2026-01-27 09:51:56', 1),
(31, 'The \"David vs Goliath\" (Size Mismatch Combat)', 'Small hero fighting enormous opponent with extreme size difference emphasizing underdog status. Visual Description: Combat between characters with massive size difference - small hero versus giant enemy. Emphasizes underdog status, impossible odds, requiring speed and smarts over raw strength to prevail. Technical Details: Size Ratio (Often 1:10 or greater size difference), Framing (Both in frame simultaneously showing stark size difference), Movement (Small character faster, more agile, precise; Large character powerful, slow, destructive), Impact (Large character attacks massive and destructive; Small character attacks precise), Combat Dynamics (Small equals fast, agile, precise strikes; Large equals powerful, slow, destructive; Small targets weak points; Large has overwhelming brute power; Speed versus strength dynamic). Psychological Effect: Underdog thrill, impossible odds, courage emphasized and admired, brain over brawn, hope against hopelessness. Emotional Meaning: Underdog courage, impossible odds to overcome, brain over brawn, speed over power, determination versus size, hope, resourcefulness. Common Contexts: Boss battles, Kaiju fights, Giant slaying, Proving worth despite size, Classic hero journey moment, Overcoming impossible odds, Skill versus power. Biblical Reference: Named after David and Goliath archetype from Bible story. Victory Method: Small character must use intelligence, speed, finding weak points rather than direct power. Attack on Titan: Built entire premise on this size mismatch dynamic. Genre: Essential in action, shonen, kaiju, heroic fantasy anime. Underdog Appeal: Universal appeal of underdog overcoming larger opponent.', '2026-01-27 09:51:56', '2026-01-27 09:51:56', 1),
(32, 'The \"Hand Comparison\" (Scale Reference Gesture)', 'Characters comparing hand sizes showing size, age, or relationship difference intimately. Visual Description: Two characters hold hands up comparing sizes - adult hand dwarfing child hand, or revealing size difference between characters. Intimate personal scale comparison. Technical Details: Framing (Close-up focused on hands), Overlap (Hands touching or overlapping for direct comparison), Size Contrast (Clear size difference visible), Focus (Often soft focus background, hands in sharp focus), Emotional Contexts (Parent-child bonding, Growth comparison then versus now, Size difference acknowledgment, Intimacy and connection, Protection promise, Age difference emphasis). Psychological Effect: Intimacy, protection dynamic, growth awareness, connection, vulnerability and safety, care relationship. Emotional Meaning: Protection offered or accepted, growth over time, connection between characters, size difference equals care dynamic, vulnerability and safety, relationship. Common Contexts: Parent-child scenes, Protective moments, Romance with size difference, Growth flashbacks showing child versus adult hands, Promise gestures, Age difference relationships, Bonding moments. Time Passage: Often used to show child grown to adult through hand comparison. Protection Symbol: Large hand represents protection, small hand represents being protected. My Neighbor Totoro: Iconic hand comparison scenes in Ghibli films. Genre: Family, drama, romance, coming-of-age anime. Intimacy: Simple gesture creates intimate emotional moment.', '2026-01-27 09:51:56', '2026-01-27 09:51:56', 1),
(33, 'The \"Shadow Overcast\" (Ominous Shadow Scale)', 'Character shadow dwarfing another showing threat, power difference, or protection. Visual Description: One character shadow falls over another character, with shadow much larger than realistic. Shows power imbalance, threat, or protection through shadow scale manipulation. Technical Details: Shadow Size (Exaggerated larger than realistic proportions), Coverage (Shadow covers or engulfs smaller character), Light Source (Positioned to maximize dramatic shadow), Expression (Often cannot see face, only imposing shadow), Shadow Meanings (Threat - ominous shadow engulfing vulnerable character; Protection - comforting shadow covering protectively; Power - shadow showing true power level; Presence - shadow announces arrival before character visible). Psychological Effect: Threat or protection felt, power presence, ominous or comforting depending on context, anticipation. Emotional Meaning: Under someone shadow literally (threat or protection), power presence felt before seen, ominous arrival, covered or protected, dominated or sheltered. Common Contexts: Villain arrivals, Protective moments with parent shadow, Power reveals, Intimidation, \"Living in father shadow\" visualization, Authority figure arrival, Dominance display. Ambiguous: Can be threatening or comforting depending entirely on context and relationship. Arrival: Shadow arrives before character fully visible building anticipation. Symbolism: \"Living in someone shadow\" idiom made literal and visual. Genre: Effective across genres - thriller, family drama, action anime. Metaphor: Shadow as metaphor for influence, protection, or domination.', '2026-01-27 09:51:56', '2026-01-27 09:51:56', 1),
(34, 'The \"Stair Height Difference\" (Elevation Advantage)', 'Characters on different stair levels showing hierarchy and power dynamic. Visual Description: Characters positioned at different heights on stairs creating height and power difference. Higher character looks down, lower character looks up. Shows hierarchy, power dynamic, social structure. Technical Details: Height Difference (Multiple steps between characters creating significant elevation difference), Eye Level (Higher character eyes above lower character eyes), Perspective (Camera can emphasize or minimize difference strategically), Positioning (Strategic placement for maximum hierarchical effect), Hierarchical Positions (Higher equals authority, power, judgment position; Lower equals subordinate, pleading, receiving judgment; Equal same step equals equals meeting; Ascending equals rising to meet or challenge). Psychological Effect: Hierarchy made visible, power imbalance, judgment from above, looking up to authority, striving upward. Emotional Meaning: Social or power hierarchy made visible, looking down on or up to someone, authority and subordinate, judgment from above, striving to reach higher level. Common Contexts: Throne room approaches, School hierarchies, Social class visualization, Power confrontations, Elevation seeking, Court scenes, Social climbing visualization, Hierarchy display. Symbolic Ascent: Climbing stairs represents seeking to reach someone level or status. Throne Rooms: Often deliberately incorporate stairs for this hierarchical effect. Confrontation: Characters meeting on same step equals equal confrontation, neither above. Genre: Drama, political, school, hierarchical society anime. Architecture: Stairs as architectural tool for showing power structure.', '2026-01-27 09:51:56', '2026-01-27 09:51:56', 1),
(35, 'The \"Doorway Frame\" (Threshold Scale)', 'Character filling doorway frame showing imposing presence and blocked passage. Visual Description: Large or imposing character perfectly filling doorway frame, body blocking passage completely. Shows imposing presence, authority, or functioning as barrier. Small character seeing this feels intimidated. Technical Details: Frame Filling (Character occupies 70-90% of doorway space), Backlight (Often backlit from room behind creating silhouette), POV (Usually from smaller character perspective looking up), Blocking (Clearly blocking passage, must get past this person), Doorway Symbolism (Blocked passage and transition, Authority controlling access, Imposing presence, Threshold guardian, Must deal with this person to proceed). Psychological Effect: Intimidation, authority felt, blocked path, must confront this person, barrier, challenge. Emotional Meaning: Imposing authority, path blocked, must confront this person, guardian of threshold, intimidation, challenge to overcome, barrier. Common Contexts: Authority figures blocking way, Bouncers and guards, Parent blocking child, Confrontation setups, \"You shall not pass\" moments, Barrier characters, Entrance denial, Challenge presentation. Threshold: Door represents transition point, figure blocking prevents transition or demands confrontation. Western Film: Classic Western saloon entrance shot influenced this. Narrative Block: Physical blocking equals narrative obstacle to overcome. Genre: Action, drama, authority-themed anime. Symbolic: Doorway as liminal space, threshold between states.', '2026-01-27 09:51:56', '2026-01-27 09:51:56', 1),
(36, 'The \"Carrying Scale\" (One Carrying Another)', 'Size difference shown through one character carrying another showing care or power. Visual Description: One character carrying another through princess carry, piggyback, shoulder carry. Shows size difference, strength difference, or care dynamic through carrying action. Technical Details: Carry Type (Princess or bridal carry, Piggyback, Shoulder carry, Fireman carry), Size Contrast (Carrier larger or stronger, carried smaller or weaker), Effort (Ease or strain of carrying tells relationship story), Position (Carried character position shows relationship dynamic), Carry Type Meanings (Princess or Bridal equals romance, rescue, care; Piggyback equals playful, friendship, youth; Shoulder equals victory, triumph, celebration; Fireman equals emergency, urgent rescue). Psychological Effect: Care and protection, strength shown, vulnerability accepted, trust, intimacy, power dynamic. Emotional Meaning: Protection offered or accepted, strength caring for weakness, rescue, care, vulnerability and strength dynamic, trust, intimacy, relationship. Common Contexts: Rescue scenes, Romantic moments, Injury care, Victory celebrations, Playful friend moments, Protection display, Trust demonstration, Strength showing. Romance Trope: Princess carry equals classic romance moment in anime. Size Dynamic: Usually though not always larger carries smaller emphasizing difference. Trust: Being carried represents trusting carrier completely with vulnerability. Genre: Romance, action, adventure, friendship anime. Intimacy: Physical closeness creates intimate moment.', '2026-01-27 09:51:56', '2026-01-27 09:51:56', 1),
(37, 'The \"Sitting/Standing\" (Verticality Power)', 'One character sitting, another standing showing power dynamic through height. Visual Description: One character seated (often lower status, vulnerable, or relaxed position) while another stands (authority, active, or threatening position). Height difference creates power dynamic. Technical Details: Height Difference (Standing character eyes above seated character), Position (Seated equals lower, vulnerable position), Camera Angle (Can emphasize or minimize difference strategically), Context Determines Meaning (threatening or protective, authority or service), Dynamic Types (Authority standing over seated equals intimidation, questioning; Protector standing over seated equals protection, guarding; Visitor standing, host seated equals social dynamic; One seated by choice, other must stand equals power display). Psychological Effect: Power imbalance, vulnerability or relaxation, authority or threat, service or dominance, hierarchy. Emotional Meaning: Power dynamic showing who has control, vulnerability, authority presence, threat or protection, social hierarchy, dominance or service. Common Contexts: Interrogation scenes, Office or boss dynamics, Protective standing guard, Social visits, Throne rooms with seated authority, Power displays, Service situations, Confrontations. Reversal: Powerful figure seated on throne while others stand actually shows ultimate power - throne exception. Throne Exception: Seated on throne represents ultimate authority, others standing are subjects. Japanese Culture: Sitting positions (seiza, etc.) carry specific cultural meanings about respect and hierarchy. Genre: Drama, thriller, political, workplace anime.', '2026-01-27 09:51:56', '2026-01-27 09:51:56', 1),
(38, 'The \"Head Pat Height\" (Affection Height Difference)', 'Taller character patting shorter character head showing affection and relationship. Visual Description: Taller character able to comfortably pat shorter character head. Shows height difference, affection, and often protective or mentoring relationship through simple gesture. Technical Details: Height Difference (Significant enough for easy head access without bending), Hand Position (On top of head, gentle touch), Recipient Reaction (Varies from pleased to annoyed to embarrassed), Context (Affectionate, not condescending usually), Relationship Types (Older or younger sibling, Mentor and student, Romantic with height difference couples, Parent and child, Senior and junior). Psychological Effect: Affection, comfort, hierarchy acknowledged but gentle, care, praise, protectiveness, warmth. Emotional Meaning: Affection shown, comfort given, \"you did well\" praise, protective care, gentle hierarchy, praise and approval, warmth, care. Common Contexts: Comfort moments, Praise giving, Romantic affection, Sibling care, Post-victory acknowledgment, Mentoring moments, Reassurance, Approval display. Cultural Note: Common and accepted gesture in anime and manga, less common in Western media. Reception: Can be comforting, annoying, or embarrassing to recipient depending on relationship and context. Moe Trope: Strongly associated with \"cute\" moments and moe aesthetic. Genre: Slice-of-life, romance, comedy, family anime. Gentleness: Despite height difference, gesture is gentle not dominating.', '2026-01-27 09:51:56', '2026-01-27 09:51:56', 1),
(39, 'The \"Crowd Towering\" (Individual vs Mass)', 'Single character facing towering crowd or army showing overwhelming odds. Visual Description: Individual character facing massive crowd or army that towers through sheer numbers. Character small in frame, crowd fills most space. Shows individual versus collective, one against many. Technical Details: Character Size (Small portion of frame, 10-20%), Crowd Mass (Fills majority of frame, extends to horizon), Vertical Stacking (Crowd members stacked in depth creating wall), Perspective (Character POV looking at crowd, or external showing both), Crowd Configurations (Army arrayed equals military threat; Mob surrounding equals overwhelming, trapped; Audience before equals performing, speaking; Wall of bodies equals impassable obstacle). Psychological Effect: Overwhelming odds, individual courage, impossibility, determination or fear, insignificance versus collective, bravery. Emotional Meaning: One against many, overwhelming odds, courage against impossible numbers, \"how can I face this?\", determination, individual versus collective, bravery or foolishness. Common Contexts: Battle speeches before armies, One warrior against army, Performance anxiety visualization, Revolutionary moments, Impossible odds visualization, Facing the masses, Lone stand, Speaking to multitudes. Courage Display: Facing crowd anyway despite overwhelming numbers equals ultimate courage. Speech Moment: Often precedes or follows rallying speech to crowd or army. Braveheart Parallel: Similar to famous live-action battle speech scenes. Genre: Historical, military, revolutionary, sports anime. Individual: Emphasis on individual courage or foolishness versus collective.', '2026-01-27 09:51:56', '2026-01-27 09:51:56', 1),
(40, 'The \"Perspective Rotation Reveal\" (Hidden Scale)', 'Camera rotates revealing true scale hidden by initial clever framing. Visual Description: Camera angle initially hides true scale through clever framing. As camera rotates, changes angle, or pulls back, true massive or tiny scale is progressively revealed. Creates surprise through perspective shift and delayed revelation. Technical Details: Initial Angle (Strategic framing hiding true scale), Rotation (Camera orbits, tilts, or pulls back revealing), Revelation (True scale revealed progressively through context), Timing (Timed for maximum surprise impact, typically 3-8 seconds), Reveal Types (Larger than expected - initially seems normal sized; Smaller than expected - initially seems imposing; More numerous than expected - one revealed to be many; Different context - scale completely recontextualized). Psychological Effect: Surprise and shock, revelation, scale shock, expectations subverted, \"wait what?\" moment, awe or horror. Emotional Meaning: \"Wait, what?\" surprise, surprise at true scale, expectations deliberately subverted, hidden truth revealed, perspective was deceiving, reality different than appeared. Common Contexts: Monster reveals showing true size, Army size reveals, Miniature reveals showing was actually tiny, True scope revelations, Perspective tricks revealed, Scale surprises, Deceptive initial framing, Twist reveals. Cinematography: Requires very careful shot planning and staging. Impact: Creates memorable impactful \"wow\" moments. Subversion Tool: Deliberately tricks viewer expectations for effect. Genre: Mystery, thriller, action, horror anime. Surprise: Built entirely on surprising viewer with hidden truth.', '2026-01-27 09:51:56', '2026-01-27 09:51:56', 1);
INSERT INTO `anivoc_scene_functions` (`id`, `name`, `slug`, `description`, `anime_notes`, `is_active`, `priority`, `created_at`, `updated_at`) VALUES
(1, 'Teaser / Cold Open', 'teaser_cold_open', 'Short opening beat before titles that hooks the audience — can be visual, comedic or suspenseful.', 'Common in anime TV and films: sometimes an OP preface or dramatic cold open.', 1, 1, '2026-01-31 13:19:44', '2026-01-31 13:19:44'),
(2, 'Prologue', 'prologue', 'Background context or mythic setup that precedes the main dramatic spine.', 'Often used in fantasy anime to establish lore.', 1, 2, '2026-01-31 13:19:44', '2026-01-31 13:19:44'),
(3, 'Act-Opening', 'act_opening', 'Scene that launches or re-establishes an act with new momentum.', '', 1, 3, '2026-01-31 13:19:44', '2026-01-31 13:19:44'),
(4, 'Act-Closing / Cliffhanger', 'act_closing_cliff', 'Ends an act on a question or reversal to propel the narrative.', 'Essential for episodic anime serialization; marks eyecatch placement.', 1, 2, '2026-01-31 13:19:44', '2026-01-31 13:19:44'),
(5, 'Epilogue', 'epilogue', 'Aftermath/closing sequence that wraps loose ends or shows consequences.', 'Used to close emotional arcs after climactic sakuga.', 1, 3, '2026-01-31 13:19:44', '2026-01-31 13:19:44'),
(6, 'Establishing Shot / Scene', 'establishing', 'Orients time/place, sets locale and mood.', 'Important for anime world design: panorama, establishing plate for 2.5D parallax.', 1, 1, '2026-01-31 13:19:44', '2026-01-31 13:19:44'),
(7, 'Set-Up / Plant', 'setup_plant', 'Plants items or facts that will matter later (plant-and-payoff).', 'Mark for later automated cross-references.', 1, 1, '2026-01-31 13:19:44', '2026-01-31 13:19:44'),
(8, 'Inciting Incident', 'inciting_incident', 'Event that creates the central problem/goal and launches the protagonist.', '', 1, 1, '2026-01-31 13:19:44', '2026-01-31 13:19:44'),
(9, 'Complication', 'complication', 'Introduces an obstacle that complicates the character goal.', '', 1, 2, '2026-01-31 13:19:44', '2026-01-31 13:19:44'),
(10, 'Pinch Point', 'pinch_point', 'Reminder scene of antagonistic force to increase pressure.', '', 1, 2, '2026-01-31 13:19:44', '2026-01-31 13:19:44'),
(11, 'Midpoint / Reversal', 'midpoint_reversal', 'A scene that changes the story direction with a revelation or commitment.', '', 1, 1, '2026-01-31 13:19:44', '2026-01-31 13:19:44'),
(12, 'Crisis / Dark Night', 'crisis_dark', 'Protagonist faces apparent defeat; stakes peak before decision.', '', 1, 1, '2026-01-31 13:19:44', '2026-01-31 13:19:44'),
(13, 'Climax / Showdown', 'climax_showdown', 'Decisive confrontation resolving principal conflict.', 'Sakuga-heavy in anime; flag for stunt/sakuga resources.', 1, 1, '2026-01-31 13:19:44', '2026-01-31 13:19:44'),
(14, 'Resolution / Payoff', 'resolution_payoff', 'Executes consequences of the climax and resolves core questions.', '', 1, 2, '2026-01-31 13:19:44', '2026-01-31 13:19:44'),
(15, 'Expository (Dramatized)', 'expository_dramatized', 'Conveys necessary background or rules but dramatized rather than an info-dump.', 'Prefer dramatized form; mark long-exposition for rewrite.', 1, 3, '2026-01-31 13:19:44', '2026-01-31 13:19:44'),
(16, 'Info-Dump (to avoid)', 'info_dump', 'Heavy background delivered as non-dramatic exposition; flagged as risky.', 'Auto-flag for editorial review.', 1, 4, '2026-01-31 13:19:44', '2026-01-31 13:19:44'),
(17, 'Reveal / Revelation', 'reveal', 'Critical secret/fact becomes known (twist or expected).', 'Good marker for audience impact analytics.', 1, 1, '2026-01-31 13:19:44', '2026-01-31 13:19:44'),
(18, 'Confession / Disclosure', 'confession', 'Character verbally acknowledges truth; catalyzes action or reversal.', '', 1, 2, '2026-01-31 13:19:44', '2026-01-31 13:19:44'),
(19, 'Briefing / Planning', 'briefing_planning', 'Characters exchange intelligence and plan an action.', 'Common in sci-fi and action-anime; mark for storyboard beats.', 1, 3, '2026-01-31 13:19:44', '2026-01-31 13:19:44'),
(20, 'Demonstration / Proof-of-Concept', 'demo_proof', 'Scene shows a capability, technology or rule that justifies later stakes.', 'Useful for fantasy power-systems and mecha specs.', 1, 2, '2026-01-31 13:19:44', '2026-01-31 13:19:44'),
(21, 'Action → Reaction Pair', 'action_reaction', 'Two-part structure where an action is immediately followed by consequence.', 'Useful to tag paired frames for editorial continuity.', 1, 2, '2026-01-31 13:19:44', '2026-01-31 13:19:44'),
(22, 'Linking / Bridge', 'bridge', 'Short interstitial scene connecting two larger beats, used to maintain continuity or show passage.', 'Often lower priority for coverage.', 1, 3, '2026-01-31 13:19:44', '2026-01-31 13:19:44'),
(23, 'Temporal Montage / Passage of Time', 'montage_time', 'Compressed sequence showing progress (training, travel, seasons).', 'Anime-specific: training montage, school-year montage.', 1, 2, '2026-01-31 13:19:44', '2026-01-31 13:19:44'),
(24, 'Transition / Segue', 'transition_seg', 'Short scene smoothing tonal or spatial cuts.', 'Include eyecatch/OP/ED considerations.', 1, 3, '2026-01-31 13:19:44', '2026-01-31 13:19:44'),
(25, 'Character Introduction', 'character_intro', 'Scene focused on presenting a character’s core traits and status.', 'Mark for cast posters and character cards.', 1, 1, '2026-01-31 13:19:44', '2026-01-31 13:19:44'),
(26, 'Character Beat', 'character_beat', 'Small, defining moments that reveal personality or values.', 'High-value for merch and social clips.', 1, 2, '2026-01-31 13:19:44', '2026-01-31 13:19:44'),
(27, 'Arc Milestone', 'arc_milestone', 'Scene marking measurable change in a character arc (decision or breakthrough).', '', 1, 1, '2026-01-31 13:19:44', '2026-01-31 13:19:44'),
(28, 'Interior / Introspection', 'interior_introspection', 'Quiet, interior scene showing emotional processing.', 'Often uses POV, close-up, silence; good for score cues.', 1, 2, '2026-01-31 13:19:44', '2026-01-31 13:19:44'),
(29, 'Mirror Scene', 'mirror_scene', 'Two scenes that mirror each other to highlight growth or contrast.', 'Flag both scenes to enable automated \"compare\" reels.', 1, 3, '2026-01-31 13:19:44', '2026-01-31 13:19:44'),
(30, 'Romantic / Intimacy', 'romantic_intimacy', 'Establishes or changes romantic relationship (can be intimate or tender).', 'Handle content flags for explicitness; anime-specific: \"moe\" beats.', 1, 2, '2026-01-31 13:19:44', '2026-01-31 13:19:44'),
(31, 'Reunion', 'reunion', 'Characters meet after separation, charged with unresolved emotion.', '', 1, 2, '2026-01-31 13:19:44', '2026-01-31 13:19:44'),
(32, 'Breakup / Separation', 'breakup', 'Scene that delineates an ending of relationship.', '', 1, 2, '2026-01-31 13:19:44', '2026-01-31 13:19:44'),
(33, 'Reconciliation / Forgiveness', 'reconciliation', 'Resolves interpersonal tension; often cathartic.', '', 1, 2, '2026-01-31 13:19:44', '2026-01-31 13:19:44'),
(34, 'Domestic / Slice-of-Life', 'domestic_slice', 'Everyday life scenes that ground characters and reveal small stakes.', 'Crucial for anime slice-of-life pacing.', 1, 3, '2026-01-31 13:19:44', '2026-01-31 13:19:44'),
(35, 'Confrontation', 'confrontation', 'Direct clash between opposing forces — verbal or physical.', 'Flag for coverage and stunt planning.', 1, 1, '2026-01-31 13:19:44', '2026-01-31 13:19:44'),
(36, 'Interrogation', 'interrogation', 'Focused scene extracting information under pressure.', '', 1, 3, '2026-01-31 13:19:44', '2026-01-31 13:19:44'),
(37, 'Negotiation / Deal', 'negotiation_deal', 'Bargaining scene with possible plot pivots.', '', 1, 3, '2026-01-31 13:19:44', '2026-01-31 13:19:44'),
(38, 'Stakes Ratchet', 'stakes_ratcheting', 'Scene that intentionally escalates consequences and pressure.', 'Useful for trailer selection.', 1, 1, '2026-01-31 13:19:44', '2026-01-31 13:19:44'),
(39, 'Bottle / Pressure Cooker', 'bottle_scene', 'Single-location, intensifying tension (e.g., trapped interior).', 'High editorial value for pacing.', 1, 2, '2026-01-31 13:19:44', '2026-01-31 13:19:44'),
(40, 'Set-Piece / Spectacle', 'setpiece_spectacle', 'Large choreographed sequence designed as a highlight (action, dance, disaster).', 'Anime note: sakuga sequences, cinematic mech battles.', 1, 1, '2026-01-31 13:19:44', '2026-01-31 13:19:44'),
(41, 'Action Beat (Fight/Chase)', 'action_beat', 'Discrete action moment with clear rhythm and coverage needs.', 'Flag for stunts, VFX and sakuga.', 1, 1, '2026-01-31 13:19:44', '2026-01-31 13:19:44'),
(42, 'Heist Sequence', 'heist_sequence', 'Multistage plan→execution→escape sequence.', '', 1, 2, '2026-01-31 13:19:44', '2026-01-31 13:19:44'),
(43, 'Chase', 'chase_scene', 'Movement-based pursuit with escalating obstacles.', 'Often cross-cuts and dynamic staging.', 1, 1, '2026-01-31 13:19:44', '2026-01-31 13:19:44'),
(44, 'Rescue / Extraction', 'rescue_extraction', 'Retrieval mission raising moral or temporal stakes.', '', 1, 2, '2026-01-31 13:19:44', '2026-01-31 13:19:44'),
(45, 'Showcase / Stunt', 'showcase_stunt', 'Sequence that displays physical or animation virtuosity.', 'Direct tie to marketing and festival clips.', 1, 1, '2026-01-31 13:19:44', '2026-01-31 13:19:44'),
(46, 'Comic Relief', 'comic_relief', 'Light scene to relieve tension and reset audience mood.', 'Anime-specific: chibi gag or visual gag sequence.', 1, 3, '2026-01-31 13:19:44', '2026-01-31 13:19:44'),
(47, 'Running Gag / Callback', 'running_gag', 'Recurrent joke motif for cumulative humor.', 'Mark occurrences for subtitle/localization notes.', 1, 4, '2026-01-31 13:19:44', '2026-01-31 13:19:44'),
(48, 'Tone-Reset', 'tone_reset', 'Short scene to recalibrate mood after extreme beats.', '', 1, 3, '2026-01-31 13:19:44', '2026-01-31 13:19:44'),
(49, 'Flashback', 'flashback', 'Retrospective scene revealing past events relevant to present stakes.', 'Tag for color/palette changes and matte transitions.', 1, 2, '2026-01-31 13:19:44', '2026-01-31 13:19:44'),
(50, 'Flashforward / Prefigure', 'flashforward', 'Jump ahead to show consequence or future state.', '', 1, 3, '2026-01-31 13:19:44', '2026-01-31 13:19:44'),
(51, 'Dream / Fantasy', 'dream_sequence', 'Subjective, symbolic scene that reveals interiority or wish-fulfillment.', '', 1, 3, '2026-01-31 13:19:44', '2026-01-31 13:19:44'),
(52, 'Vision / Hallucination', 'vision_hallucination', 'Unreliable moment complicating objective perception.', '', 1, 3, '2026-01-31 13:19:44', '2026-01-31 13:19:44'),
(53, 'Voice-Over / Narration', 'voice_over', 'Scenes structured with character commentary or framing voice.', '', 1, 3, '2026-01-31 13:19:44', '2026-01-31 13:19:44'),
(54, 'Epistolary / Records', 'epistolary', 'Story told via documents, letters, texts or recordings.', 'Useful for montage-style exposition.', 1, 3, '2026-01-31 13:19:44', '2026-01-31 13:19:44'),
(55, 'Montage (Functional)', 'montage_functional', 'Sequence of images advancing story efficiently (training, travel).', 'Mark in/out points for music and cuts.', 1, 2, '2026-01-31 13:19:44', '2026-01-31 13:19:44'),
(56, 'Parallel Montage / Cross-Cut', 'parallel_montage', 'Interleaving simultaneous sequences to build tension or compare.', '', 1, 1, '2026-01-31 13:19:44', '2026-01-31 13:19:44'),
(57, 'Match Cut', 'match_cut', 'Visual rhyme linking disparate scenes by composition or action.', 'High editorial value.', 1, 2, '2026-01-31 13:19:44', '2026-01-31 13:19:44'),
(58, 'World-Building / Tour', 'worldbuilding_tour', 'Introduces institutions, geography and cultural rules of setting.', 'Important for anime fantasy/scifi world maps and lore.', 1, 2, '2026-01-31 13:19:44', '2026-01-31 13:19:44'),
(59, 'Procedural / Institutional', 'procedural', 'Repetitive institutional work (police, medical, school) that structures the world.', 'Useful to define recurring beats.', 1, 3, '2026-01-31 13:19:44', '2026-01-31 13:19:44'),
(60, 'Crowd / Mass Event', 'crowd_event', 'Festivals, riots, rallies that show scale or social dynamics.', 'Often VFX-heavy for background population.', 1, 2, '2026-01-31 13:19:44', '2026-01-31 13:19:44'),
(61, 'Master / Coverage', 'coverage_master', 'Main continuous take designed to be covered with additional angles.', 'Tag required coverage types: wide, two-shot, singles, inserts.', 1, 1, '2026-01-31 13:19:44', '2026-01-31 13:19:44'),
(62, 'Insert / Cutaway', 'insert_cutaway', 'Short shot focusing on object or reaction to clarify continuity.', '', 1, 2, '2026-01-31 13:19:44', '2026-01-31 13:19:44'),
(63, 'Pickup / Patch', 'pickup_scene', 'Small scene shot after principal photography to fix continuity or strengthen story.', '', 1, 3, '2026-01-31 13:19:44', '2026-01-31 13:19:44'),
(64, 'VFX Required', 'vfx_required', 'Flags scenes that need digital effects or plates.', 'Set to 1 for planning; tie to VFX pipeline.', 1, 1, '2026-01-31 13:19:44', '2026-01-31 13:19:44'),
(65, 'Practical Effects / Stunt Required', 'practical_stunt', 'Flags scenes requiring practical stunts or effects.', '', 1, 1, '2026-01-31 13:19:44', '2026-01-31 13:19:44'),
(66, 'ADR / Dialogue Replacement', 'adr_required', 'Likely to need later dialogue looping.', 'Useful for voice-heavy anime; mark lines.', 1, 2, '2026-01-31 13:19:44', '2026-01-31 13:19:44'),
(67, 'SFX / Foley Heavy', 'sfx_heavy', 'Scenes needing extensive sound design and foley.', '', 1, 2, '2026-01-31 13:19:44', '2026-01-31 13:19:44'),
(68, 'Music Cue / Leitmotif Anchor', 'music_cue', 'Scene designed to carry a specific scoring motif.', 'Label with cue-name for composer.', 1, 1, '2026-01-31 13:19:44', '2026-01-31 13:19:44'),
(69, 'Silent / Intertitle', 'silent_intertitle', 'Silent beats or scenes using text for information.', 'Classic anime effect: intertitles/kanji slates.', 1, 3, '2026-01-31 13:19:44', '2026-01-31 13:19:44'),
(70, 'Mystery / Clue Scene', 'mystery_clue', 'Plants clues or performs detection work; used in mystery anime.', '', 1, 2, '2026-01-31 13:19:44', '2026-01-31 13:19:44'),
(71, 'Horror / Fright Beat', 'horror_fright', 'Designed to build dread — slow reveals and isolation.', 'Use for sound design and timing of scares.', 1, 2, '2026-01-31 13:19:44', '2026-01-31 13:19:44'),
(72, 'Rom-Com Meet Cute', 'romcom_meetcute', 'Initial romantic encounter with comedic/serendipitous beats.', 'Common anime trope; tag for montage/musical beats.', 1, 2, '2026-01-31 13:19:44', '2026-01-31 13:19:44'),
(73, 'Tableau / Ensemble', 'ensemble_tableau', 'Multi-character scene showing group dynamics.', 'Useful to mark blocking complexity.', 1, 2, '2026-01-31 13:19:44', '2026-01-31 13:19:44'),
(74, 'Courtroom / Political Arena', 'courtroom_politics', 'Institutional arena for rhetoric and spectacle.', '', 1, 3, '2026-01-31 13:19:44', '2026-01-31 13:19:44'),
(75, 'Goal-Oriented Scene', 'goal_oriented', 'Scene built around a character objective, obstacle and outcome.', 'Preferred engineering pattern for automated validators.', 1, 1, '2026-01-31 13:19:44', '2026-01-31 13:19:44'),
(76, 'Obstacle Scene', 'obstacle_scene', 'Primary function is to prevent goal attainment and generate conflict.', '', 1, 1, '2026-01-31 13:19:44', '2026-01-31 13:19:44'),
(77, 'Decision / Choice', 'decision_scene', 'Character must choose a path — often a hinge moment.', 'Priority candidate for trailer selection.', 1, 1, '2026-01-31 13:19:44', '2026-01-31 13:19:44'),
(78, 'Payoff Scene', 'payoff_scene', 'Delivers consequence of earlier plant; must feel earned.', 'Auto-link to plants where possible.', 1, 1, '2026-01-31 13:19:44', '2026-01-31 13:19:44'),
(79, 'False Resolution / Fakeout', 'false_resolution', 'Appears to resolve but sets up further complication.', '', 1, 2, '2026-01-31 13:19:44', '2026-01-31 13:19:44'),
(80, 'Theme Statement', 'theme_statement', 'Scene that articulates the central theme directly or symbolically.', 'High value for festival synopses and catalogue notes.', 1, 2, '2026-01-31 13:19:44', '2026-01-31 13:19:44'),
(81, 'Catharsis', 'catharsis', 'Emotional release where audience/character attains relief.', 'Often placed late act; mark for score and color timing.', 1, 1, '2026-01-31 13:19:44', '2026-01-31 13:19:44'),
(82, 'Moral Dilemma', 'moral_dilemma', 'Scene testing character ethics; defines moral core.', '', 1, 2, '2026-01-31 13:19:44', '2026-01-31 13:19:44'),
(83, 'OP (Opening) Sequence', 'op_opening', 'Title sequence / opening credits; usually stylized and music-driven.', 'Mark in/out for branding; includes eyecatch placement rules.', 1, 1, '2026-01-31 13:19:44', '2026-01-31 13:19:44'),
(84, 'ED (Ending) Sequence', 'ed_ending', 'Closing credits sequence; often thematically reflective.', 'Tag for credit crawl timing and song edit.', 1, 2, '2026-01-31 13:19:44', '2026-01-31 13:19:44'),
(85, 'Eyecatch / Interstitial Card', 'eyecatch', 'Short interstitial (often TV anime) between acts/segments.', 'Important for episodic structure and ad breaks.', 1, 2, '2026-01-31 13:19:44', '2026-01-31 13:19:44'),
(86, 'Sakuga / Animation Peak', 'sakuga_peak', 'Sequence with exceptional animation virtuosity (keyframe artistry).', 'Flag for high animation budget and marketing reels.', 1, 1, '2026-01-31 13:19:44', '2026-01-31 13:19:44'),
(87, 'Chibi / Gag Short', 'chibi_gag', 'Cartoonishly simplified comedic beat, often for relief.', 'Used in extras and post-credit vignettes.', 1, 3, '2026-01-31 13:19:44', '2026-01-31 13:19:44'),
(88, 'Animation Gag / Visual Kake', 'animation_gag', 'Short visual gag relying on timing and animation.', 'Useful for social clip extraction.', 1, 3, '2026-01-31 13:19:44', '2026-01-31 13:19:44'),
(89, 'Sound Cue Plate / VO, SFX Anchor', 'sound_anchor', 'Short scene fragment used as anchor for VO or key SFX.', 'Helps sound editors with temp stitching.', 1, 3, '2026-01-31 13:19:44', '2026-01-31 13:19:44');
INSERT INTO `anivoc_shot_pacing` (`id`, `name`, `description`, `created_at`, `updated_at`, `is_ingredient`) VALUES
(1, 'Flash — Impact White', '1-2 frames. Pure white or bright color flash at the moment of impact. The audience feels the hit before processing it. No character detail visible — just light. Use as: punch landing, explosion onset, bullet impact, power surge peak.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(2, 'Flash — Negative Inversion', '1-2 frames. Colors invert completely for a single frame. Disorienting and visceral. Often accompanies a massive hit or reality-breaking moment. Use as: impact frame (sakuga), shock beat, \"the world just changed\" punctuation.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(3, 'Flash — Single Frame Detail', '1 frame. A single critical detail shown for barely a heartbeat — a face, a weapon, a symbol. The audience may not consciously register it but it plants information. Use as: foreshadowing plant, subliminal reveal, horror glimpse, dream fragment.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(4, 'Beat — Reaction Cut', '12-24 frames. Cut to a character\'s face for their reaction. Just long enough to read the expression — shock, amusement, anger, realization. Then cut away. Use as: punctuation after dialogue or action, comedic timing, emotional confirmation.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(5, 'Beat — Action Snapshot', '12-24 frames. A single dynamic action frozen or shown in rapid sequence. The pose itself carries the information — a strike, a dodge, a catch. Use as: combat beat, key moment in a fight, \"that was cool\" frame.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(6, 'Beat — Dialogue Line', '24-48 frames. One character delivers a single line. Camera on their face or a medium shot. Just enough time for the line to land. Use as: standard dialogue pacing, one-liner, quick exchange in a conversation.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(7, 'Beat — Insert Detail', '12-24 frames. Quick cut to a prop, object, or environmental detail. Provides information without dwelling. Use as: weapon check, clock glance, important object reveal, environmental storytelling.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(8, 'Beat — Comedic Punch', '12-36 frames. The punchline frame in a comedic sequence. Held just long enough for the joke to land — the chibi reaction, the face, the absurd result. Use as: gag payoff, slapstick result, comedic beat punctuation.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(9, 'Hold — Emotional Beat', '48-96 frames. A character\'s face or body held on screen during an emotionally significant moment. The audience needs time to read the full expression and let it sink in. Use as: revelation, grief, determination, love confession landing.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(10, 'Hold — Tension Stare', '48-120 frames. Two characters locked in a stare. No dialogue. The silence IS the content. Held long enough to become uncomfortable. Use as: standoff, duel setup, \"say something\" moment, power dynamic assertion.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(11, 'Hold — Environment Read', '48-96 frames. The audience is meant to actually take in the environment — its scale, detail, mood. Not just a flash of \"oh we\'re in a city\" but a real look. Use as: new location introduction, atmosphere establishment, beauty shot.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(12, 'Hold — Aftermath Stillness', '60-120 frames. The moment after something big happened. Everything is quiet. Dust settling. Characters breathing. The audience processes what just occurred. Use as: post-battle silence, after an explosion, after a reveal.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(13, 'Hold — Character Reveal', '60-120 frames. A new or transformed character is shown for the first time in their full glory. The camera stays on them long enough for the audience to take in every detail. Use as: villain reveal, hero transformation complete, new ally introduction.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(14, 'Linger — Pillow Shot (Ma)', '120-240 frames. A static shot of the environment with no characters — or characters as tiny elements. Pure atmosphere. The anime tradition of \"ma\" (間) — meaningful silence/pause. Use as: scene transition, mood establishment, breathing room between intense beats.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(15, 'Linger — Monologue Hold', '120-200 frames. Camera stays on a character\'s face while they deliver a longer speech or internal monologue. The expression shifts subtly during the hold. Use as: character moment, villain speech, hero\'s resolve speech, emotional confession.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(16, 'Linger — Sunset / Goodbye', '150-240 frames. The classic farewell or bittersweet moment held on screen. Two characters in silhouette, or one looking at the horizon. The audience needs time to feel it. Use as: end of arc, goodbye scene, nostalgia beat, \"things will never be the same\".', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(17, 'Linger — Power Build', '120-180 frames. A character powering up. Energy gathering, aura intensifying, the buildup before the strike. Held long enough to feel the mounting pressure. Use as: transformation sequence, charge-up, \"here it comes\" anticipation.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(18, 'Sustain — Long Take Walk', '240-480 frames. An unbroken shot following a character through an environment. No cuts. The audience follows their journey in real time. Use as: character introduction, \"one continuous night\", establishing normalcy before chaos.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(19, 'Sustain — Silent Standoff', '300-480 frames. Two characters face each other for an extended period of silence. Neither moves. The tension builds and builds. Use as: duel before the first strike, \"I know what you did\" confrontation, maximum dramatic weight.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(20, 'Sustain — Contemplation', '240-360 frames. A single character in a static or near-static shot, thinking. The audience sits with them. No action, no dialogue. Just presence. Use as: character alone with their thoughts, pre-decision moment, weight of the world on shoulders.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(21, 'Pattern — Escalating Cuts', 'A sequence where each successive shot is shorter than the last. Starts at Hold tier, moves to Beat tier, ends at Flash tier. The audience feels acceleration and mounting intensity without consciously counting frames. Use as: battle climax buildup, chase sequence peak, \"it\'s happening NOW\" sequence.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(22, 'Pattern — Beat-Hold-Beat', 'Quick reaction (Beat) → held emotional moment (Hold) → quick resolution (Beat). The Hold in the middle is where the audience actually processes the emotion. The Beats on either side give it context. Use as: standard emotional scene structure, dialogue exchange with weight.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(23, 'Pattern — Linger-Flash Contrast', 'A long, slow, quiet shot (Linger) suddenly interrupted by a Flash-tier cut. Maximum contrast in pacing. The slow shot makes the Flash hit harder. Use as: ambush, jump scare, sudden revelation during a calm moment, \"out of nowhere\" event.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(24, 'Pattern — Staccato Montage', 'Rapid sequence of Beat-tier cuts, all roughly the same length. Creates a rhythmic, almost musical feeling. No single shot dominates. Use as: training montage, time passing, parallel action, \"a lot happened\" summary.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1),
(25, 'Pattern — Breath (Reset)', 'After a high-intensity sequence (Flash/Beat tier rapid cuts), a single Hold or Linger shot is inserted. The audience exhales. Pacing resets to normal. Use as: post-battle pause, comedic beat after action, \"okay, we survived\" moment.', '2026-02-01 00:00:00', '2026-02-01 00:00:00', 1);
INSERT INTO `anivoc_symbolic_objects` (`id`, `name`, `description`, `created_at`, `updated_at`, `is_ingredient`) VALUES
(1, 'The \"Broken Mirror\" (Shattered Identity/Relationship)', 'Shattered mirror or reflection showing fragmented identity or irreparably broken bonds. Visual Description: Mirror shown cracking, shattering, or already broken into pieces. Reflection fragments across shards. Character sees fragmented self or relationship symbolically shattered through broken glass. Technical Details: Breakage Patterns (Slow crack spreading equals gradual breakdown, Sudden dramatic shatter equals traumatic break, Single crack equals first damage appearing, Web pattern equals complete breakdown imminent), Reflection Treatment (Character reflection fragments across pieces showing fractured self), Sound Design (Often emphasized crack or shatter sound for impact), Aftermath (Pieces falling, scattered fragments on ground). Symbolic Meanings: Broken identity and shattered sense of self, Relationship irreparably broken and cannot be fixed, Self-image destroyed, Multiple fractured selves or personalities, Cannot go back to being whole, Truth shattered, Point of no return crossed. Psychological Effect: Brokenness, irreparable damage felt, fragmentation, loss of wholeness, identity crisis, permanence of damage. Common Contexts: Identity crisis moments, Relationship endings and breakups, Self-discovery of dark truths, Traumatic revelations, Breakdown moments, Multiple personality reveals, Loss of self. Variations: Mirror intact but reflection shows different person equals lost true self; Mirror slowly repairing itself equals healing process (rare and powerful); Multiple mirrors showing different fractured selves. Cultural Context: Universal symbol of brokenness, also references Japanese tradition of broken mirror in separated lovers story (kagami). Permanence: Breaking mirror often represents permanent irreversible change, cannot return to before this moment. Genre: Particularly powerful in psychological, drama, identity-focused anime.', '2026-01-27 12:22:12', '2026-01-27 12:22:12', 1),
(2, 'The \"Falling Leaf\" (Passage of Time/Melancholy)', 'Single leaf drifting downward showing inexorable time passing or melancholic contemplative mood. Visual Description: Single leaf, often autumn colored, falling slowly, drifting, floating down through frame. Camera often follows gentle descent. Creates melancholic, contemplative, peaceful yet sad atmosphere. Technical Details: Leaf Type and Color (Autumn leaf in orange or red equals seasonal change and ending, Cherry blossom petal equals Japanese specific meaning of impermanence, Dead brown leaf equals death and decay, Green leaf equals life ending prematurely), Movement (Slow drift, spiraling, gentle fall, almost floating), Camera (Often follows leaf down in slow tracking shot, meditation on descent), Landing (Where leaf lands can add additional meaning to scene). Symbolic Meanings: Time passing inexorably and unstoppably, Autumn of life approaching, Melancholy and wistfulness, Natural cycle of life and death, Gentle sadness and acceptance, Something ending naturally, Transience and impermanence of life (mono no aware). Psychological Effect: Melancholy, contemplation, peaceful sadness, acceptance of impermanence, time awareness, gentle mortality. Common Contexts: Character contemplation and reflection, Seasonal transitions especially autumn, Aging themes, Peaceful endings and deaths, Time passage montages, Melancholic moments, Natural life cycles, Philosophical moments. Cherry Blossom Specific: In Japanese cultural context, falling sakura petals carry additional specific meanings of fleeting beauty, impermanence concept of mono no aware, precious because temporary. Speed Meaning: Slow fall equals peaceful acceptance; Fast fall equals more abrupt ending. Quantity: Single leaf equals specific moment; Many leaves equals general passage of time, season. Genre: Universal across genres but particularly in contemplative, slice-of-life, drama anime.', '2026-01-27 12:22:12', '2026-01-27 12:22:12', 1),
(3, 'The \"Red Thread\" (Fate/Destiny Bond)', 'Red string or thread connecting characters showing fated destined connection that cannot be broken. Visual Description: Red thread, string, or ribbon visually connecting two characters, sometimes literally visible in world, sometimes metaphorical overlay only viewers see. Shows fated unbreakable connection. Technical Details: Visibility (Literal thread characters can see and interact with, Metaphorical overlay only viewers see showing fate, Thread appears and disappears at significant moments), Connection Points (Usually tied to fingers, wrists, or hearts of characters), Thread State indicating relationship (Taut thread equals strong active connection, Tangled equals complicated relationship, Fraying equals connection weakening, Cut or severed equals fate broken - very dramatic). Symbolic Meanings: Fate binding two people together, Destined love or connection, Unbreakable bond between souls, Red string of fate legend, Soul mates connected across time and space, Destiny that cannot be escaped, Meant to be together. Psychological Effect: Romance, destiny felt, inevitability, connection beyond choice, fate, meant to be, predestination. Common Contexts: Romance anime especially, Fate and destiny themes, Soul mate reveals, Character deep connections, Supernatural romance, Prophecy fulfillment, Reincarnation stories, Past life connections. Cultural Origin: Ancient Chinese and Japanese legend of red thread connecting destined partners, tied by gods at birth, cannot be broken regardless of distance or time. Modern Use: Sometimes deliberately subverted in modern anime showing fate can be changed or chosen. Visual Metaphor: May not be literal visible thread but red visual line or connection shown cinematically. Genre: Romance, supernatural romance, fate-themed, reincarnation anime.', '2026-01-27 12:22:12', '2026-01-27 12:22:12', 1),
(4, 'The \"Broken Chain\" (Freedom/Breaking Free)', 'Chain breaking or being shattered showing liberation, escape, and freedom achieved. Visual Description: Chain shown breaking, snapping, being shattered into pieces. Character breaking free from literal or metaphorical chains and bonds. Moment of liberation and empowerment. Technical Details: Break Type and Meaning (Character breaks it themselves equals claiming freedom actively, Chain rusts and breaks equals time weakens oppressive bonds, Someone else breaks it equals liberation given by another, Explosive dramatic break equals violent freedom), Chain Type (Literal shackles equals physical imprisonment, Metaphorical chains equals psychological bonds and trauma, Social chains equals societal expectations and norms), Aftermath (Chain pieces falling away, new freedom of movement, liberation moment). Symbolic Meanings: Breaking free from oppression, Liberation from bonds both physical and psychological, Freedom finally achieved, Escaping painful past, Breaking free from societal expectations, Psychological liberation, No longer bound by anything. Psychological Effect: Liberation, freedom, empowerment, escape, breaking bonds, independence, self-determination, power reclaimed. Common Contexts: Escape sequences, Character growth breakthrough moments, Breaking from traumatic past, Psychological liberation, Social constraint breaking, Prison escapes literal or metaphorical, Coming-of-age freedom, Revolution moments. Sound Design: Emphasized breaking sound, often dramatic and echoing. Slow Motion: Often shown in slow motion for maximum emotional emphasis and impact. Multiple Chains: Breaking multiple chains simultaneously equals complete total liberation from all bonds. Genre: Action, psychological, coming-of-age, revolutionary anime. Empowerment: One of most empowering visual symbols in anime vocabulary.', '2026-01-27 12:22:12', '2026-01-27 12:22:12', 1),
(5, 'The \"Extinguished Flame\" (Death/Ending)', 'Candle, fire, or flame going out showing death, life ending, or final conclusion. Visual Description: Flame whether candle, fire, or lamp shown being extinguished, going out, dying. Light fading into darkness. Represents life ending, death, hope lost, or final absolute conclusion. Technical Details: Extinguishing Method indicating type of death (Wind blows it out equals natural peaceful death, Someone deliberately blows it out equals deliberate ending or murder, Burns out completely equals life fully spent and exhausted, Crushed or snuffed equals violent sudden end), Flame Type (Candle flame equals individual life, Torch equals hope and light, Fire equals passion and spirit, Lamp equals consciousness), Darkness After (Darkness following extinguishing emphasizes finality and permanence). Symbolic Meanings: Death of character, Life ending, Hope extinguished completely, Spirit dying or broken, Passion lost, Era ending, Light going out of world, Consciousness fading, Soul departing. Psychological Effect: Finality, death, ending, darkness, loss, extinguishing of life or hope or light, permanence, conclusion. Common Contexts: Death scenes, Character giving up completely, Hope lost, Era endings, Final moments, Spirit breaking, Loss of passion for life, Surrender, Defeat accepted. Powerful Reversal: Flame being relit equals hope returning, resurrection, second chance, renewed spirit (very powerful when done). Multiple Flames: Many flames going out simultaneously equals mass death, collective loss, catastrophe. Buddhist Influence: Nirvana literally means \"extinguishing\" in Sanskrit, so can have spiritual enlightenment meaning in context. Genre: Drama, tragedy, war, dark fantasy anime. Universal: One of most universal death symbols across cultures.', '2026-01-27 12:22:12', '2026-01-27 12:22:12', 1),
(6, 'The \"Dropped Photo\" (Lost Memory/Relationship)', 'Photograph falling or being dropped showing lost connection, abandoned memory, or severed relationship. Visual Description: Photograph shown falling through air, being dropped deliberately or accidentally, or lying abandoned on ground. Often photo shows character with someone else in happier times. Represents lost relationship, abandoned memory, severed connection, or past let go. Technical Details: Fall Type indicating meaning (Deliberate drop equals active rejection, Accidental drop equals unintended loss, Slow melancholic fall equals sadness, Photo lands face down equals rejection of memory itself), Photo Content (Usually shows happier past times, creating painful contrast with present), Photo State (Pristine photo equals recent loss, Worn photo equals old loss carried long time, Torn photo equals actively destroyed relationship). Symbolic Meanings: Lost relationship cannot be recovered, Abandoned memory, Past deliberately let go, Connection severed, Better times lost forever, Cannot go back, Relationship ending symbolically, Discarding someone from life. Psychological Effect: Loss, nostalgia mixed with pain, sadness, letting go, severed bonds, past irretrievable, grief, moving on. Common Contexts: Breakup scenes, Memory loss, Moving on moments, Abandonment, Death of relationship, Letting go of past, Rejection, Cutting ties with someone. Photo Retrieved: Someone picking photo back up equals not ready to let go, or someone else preserving memory when original person cannot. Torn Photo: More violent than simply dropped, shows active deliberate destruction of memory and relationship. Wind Carries Away: Photo blown away by wind equals loss beyond anyone control, fate taking it. Genre: Drama, romance, tragedy, memory-focused anime. Nostalgia: Creates powerful nostalgic pain through visual contrast.', '2026-01-27 12:22:12', '2026-01-27 12:22:12', 1),
(7, 'The \"Wilting Flower\" (Decay/Dying Beauty)', 'Flower wilting, dying, or losing petals showing beauty fading, vitality draining, or death approaching. Visual Description: Once-beautiful flower shown wilting, dying, steadily losing petals. Beauty and life visibly fading away. Often represents dying character, fading beauty, youth passing, or relationship decay. Technical Details: Wilting Stages (Petals drooping equals decline beginning, Color fading from vibrant equals vitality leaving, Petals falling one by one equals active dying process, Completely dried and dead equals death complete), Flower Type carrying specific meaning (Rose equals love or passion dying, Cherry blossom equals fleeting beauty in Japanese context, Lily equals purity being corrupted, White flower equals innocence lost), Context (Often shown in vase, held in hand, or at memorial). Symbolic Meanings: Beauty fading with time, Death approaching, Love dying and relationship ending, Youth passing away, Vitality and life force draining, Innocence corrupted, Natural inevitable decay, Mortality visualized. Psychological Effect: Melancholy, mortality awareness, fading, decay, loss of beauty, death approaching, sadness, impermanence. Common Contexts: Character dying or terminal illness, Aging themes, Love fading and relationships ending, Beauty lost to time, Innocence corrupted or lost, Time relentless passage, Memorials and graves, Corruption spreading. Reverse Meaning: Flower blooming has opposite meaning of life, growth, awakening (see later entry). Speed: Rapid wilting equals sudden death or decay; Slow wilting equals gradual decline. Victorian Flower Language: Different specific flowers carry particular meanings in floriography tradition. Genre: Drama, tragedy, romance, coming-of-age anime. Beauty: Particularly associated with tragic beauty aesthetic.', '2026-01-27 12:22:12', '2026-01-27 12:22:12', 1),
(8, 'The \"Cracked Mask\" (False Self Breaking)', 'Mask cracking or breaking showing facade crumbling and true authentic self finally emerging. Visual Description: Mask whether literal or metaphorical shown cracking, breaking, or falling away in pieces. Facade crumbling, revealing true face and self beneath. Truth can no longer be hidden or contained. Technical Details: Crack Pattern (Single crack equals first break in carefully maintained facade, Web of cracks equals complete breakdown imminent, Pieces actively falling away equals facade crumbling right now, Half mask falls away equals partial truth revealed), What Lies Beneath Mask (True face revealed at last, Emptiness or void beneath - horror revelation, Another mask beneath - layers upon layers of lies, Real genuine emotions finally visible). Symbolic Meanings: Facade breaking down, True self emerging finally, Cannot maintain lie anymore, Social mask crumbling, Truth forcing its way out, Authenticity emerging, Breakdown of false constructed identity, Exhaustion of pretense. Psychological Effect: Revelation, truth emerging, breakdown, authenticity, facade failing, real self exposed finally, vulnerability, collapse of pretense. Common Contexts: Identity reveals, Breakdown moments, Truth emerging despite efforts, Exhaustion of pretense, Villain true nature reveals, Character growth moments, Psychological breaking point, Cannot maintain act anymore. Japanese Cultural Context: Tatemae (public facade) versus honne (true feelings) culturally significant dichotomy in Japanese society. Literal versus Metaphorical: Can be actual physical mask or purely visual metaphor for psychological facade. Voluntary versus Involuntary: Character removing mask voluntarily versus mask breaking involuntarily equals very different meanings about agency and choice. Genre: Psychological, drama, thriller, mystery anime.', '2026-01-27 12:22:12', '2026-01-27 12:22:12', 1),
(9, 'The \"Shattered Glass/Window\" (Barrier Broken)', 'Glass or window shattering dramatically showing barrier broken, boundary crossed, violence erupting, or breakthrough achieved. Visual Description: Glass window, door, or surface shown shattering explosively. Barrier broken, boundary definitively crossed, violence erupting, or breakthrough finally achieved. Almost always shown in dramatic slow-motion. Technical Details: Shatter Type and Direction (Explosive outward equals breakthrough from inside, Inward shattering equals invasion or violation, From impact equals violence and force, Spontaneous without cause equals psychological break), Glass Type (Window equals barrier to outside world, Glass door equals threshold crossed, Mirror has different symbolism - see entry number one, Glass wall equals invisible barrier finally broken), Slow Motion (Almost always shown in dramatic slow motion for maximum impact). Symbolic Meanings: Barrier broken at last, Boundary crossed - point of no return, Violence erupting, Breakthrough achieved, Safety shattered, Illusion broken, Invisible barrier made visible through breaking, Change that cannot be undone. Psychological Effect: Violence, breakthrough, barrier breaking, safety lost, boundary crossed, dramatic irreversible change, shock, liberation or violation. Common Contexts: Action sequences and violence, Breakthrough moments, Violence suddenly erupting, Barrier breaking, Dramatic entrances, Psychological breakthroughs, Safety violated, Escape sequences, Revolution moments. Slow Motion Usage: Almost always shown in slow motion for dramatic impact and emphasis. Sound Design: Emphasized shattering sound, often echoing and reverberating. Physics Exaggeration: Anime often exaggerates glass quantity and spread pattern for dramatic effect beyond realism. Genre: Action, psychological thriller, drama, horror anime. Violence: Strong association with violence and violation.', '2026-01-27 12:22:12', '2026-01-27 12:22:12', 1),
(10, 'The \"Torn Letter/Document\" (Broken Communication/Promise)', 'Letter or document being torn showing communication severed, promise broken, or words destroyed. Visual Description: Letter, document, or paper shown being torn, ripped up into pieces, or already discovered in pieces. Communication rejected, promise broken, words destroyed and made meaningless. Relationship ending symbolically through destroyed words. Technical Details: Tearing Method (Slow deliberate tear equals painful rejection, Angry violent ripping equals furious rejection and rage, Precise cutting with scissors equals cold calculated rejection, Already torn when discovered equals past break being discovered), Document Type (Love letter equals romantic rejection, Contract equals broken promise or agreement, Photo with letter equals complete total rejection, Legal document equals official severing of bond). Symbolic Meanings: Communication rejected and refused, Promise broken and void, Relationship ending definitively, Words meaningless now, Contract void, Message destroyed, Cannot take back what is destroyed, Severing of bond. Psychological Effect: Rejection, finality, broken promises, severed communication, words destroyed, relationship ending, pain of rejection, permanence of break. Common Contexts: Rejection scenes, Breakups and relationship endings, Broken promises revealed, Refusing communication, Contract breaking, Betrayal, Cutting ties with someone, Divorce or separation. Pieces Scattering: Torn pieces often shown drifting away, scattered on ground - words literally scattered to wind, cannot be recovered. Attempted Repair: Character trying desperately to piece letter back together equals attempting to salvage relationship (usually proves futile). Burning Alternative: Sometimes letter burned instead of torn equals even more final and complete destruction, reduced to ashes. Genre: Drama, romance, tragedy, betrayal-focused anime. Finality: Emphasizes finality and irreversibility of decision.', '2026-01-27 12:22:12', '2026-01-27 12:22:12', 1),
(11, 'The \"Umbrella Share\" (Intimacy/Protection)', 'Two people sharing single umbrella showing intimacy, romance, or one person protecting another. Visual Description: Two characters positioned under single umbrella together creating intimate shared space. Classic intimacy and romance symbol. One person may hold umbrella sheltering both, or both hold it together sharing burden. Technical Details: Sharing Type indicating relationship (One person holds umbrella sheltering other equals protection and care, Both hold umbrella together equals equal partnership, Umbrella tilted to cover other person more equals sacrifice for loved one, Struggling to fit under one umbrella equals comedy or awkwardness), Weather Context (Usually rain but sometimes snow or harsh sun), Physical Distance (How close they must stand reveals intimacy level and comfort), Camera Angle (Often filmed from behind showing silhouettes under umbrella dome). Symbolic Meanings: Intimacy and closeness, Protection and care for another, Sharing burden together, Romance blooming, Willing to get wet for other person, Private intimate space created in public, Partnership and cooperation, Warmth despite cold rain. Psychological Effect: Intimacy, romance, warmth despite cold rain outside, protection, partnership, closeness, care, sheltering. Common Contexts: Romance development, Protective moments, Intimacy establishment, Confession scenes, First romantic moments, Partnership symbolism, Caring for someone. Japanese Cultural Specific: Aiaigasa (love-love umbrella) - drawing two names under umbrella is romantic symbol, cultural significance in Japan. Comedy Version: Fighting over umbrella, both getting wet anyway, awkward close proximity creating comedy. One Person Wet: One person deliberately getting wet to shelter other more completely equals sacrifice, deep care, putting other first. Genre: Romance, slice-of-life, drama anime. Universal: Recognized intimacy symbol across cultures.', '2026-01-27 12:22:12', '2026-01-27 12:22:12', 1),
(12, 'The \"Phone Not Answered\" (Rejection/Distance)', 'Ringing phone ignored or not answered showing deliberate rejection, emotional distance, or severed communication. Visual Description: Phone ringing, vibrating, or showing accumulating missed calls. Character deliberately ignores it, or phone rings completely unanswered. Shows rejection, emotional distance, avoidance, or severed communication. Technical Details: Phone State (Persistent ringing equals desperate attempt to reach someone, Multiple missed calls accumulating equals ongoing sustained rejection, Looking at phone but not answering equals deliberate conscious choice to avoid, Phone placed face-down equals complete rejection of communication), Context (Knowing who is calling equals deliberate avoidance of specific person, Unknown caller equals mystery or fear, Phone silenced equals complete cutoff from world). Symbolic Meanings: Rejection of communication and connection, Emotional distance from others, Deliberately avoiding someone, Relationship severed, Cannot face the conversation, Cut off from world by choice, Alone by choice not circumstance, Ghosting someone. Psychological Effect: Rejection, loneliness, distance, avoidance, severed connection, isolation, inability to face situation, withdrawal. Common Contexts: Relationship deterioration, Avoiding confrontation, Emotional shutdown and withdrawal, Breaking away from someone, Depression isolation, Guilt avoidance, Ghosting visualization, Unable to face reality. Modern Symbol: Specifically modern technology symbol, evolved from older symbols like letters or telegrams left unopened. Reversal: Character finally answering phone after many calls equals breakthrough, reconnection, ready to face situation at last. Missed Call Pile: Many many missed calls shown visually equals either desperate attempts to reach, or extent of isolation. Genre: Drama, romance, psychological, modern life anime. Technology: Reflects modern communication anxiety.', '2026-01-27 12:22:12', '2026-01-27 12:22:12', 1),
(13, 'The \"Back-to-Back\" (Distance Despite Proximity)', 'Two characters sitting or standing back-to-back showing emotional distance despite physical proximity. Visual Description: Two characters positioned back-to-back, not looking at each other despite being physically very close. Shows emotional distance, communication breakdown, conflict, or inability to face each other. Technical Details: Position Type (Sitting back-to-back equals settled into distance, Standing back-to-back equals active maintenance of distance, Slight lean backward equals still unconsciously seeking connection, Rigid posture equals complete emotional wall erected), Distance Paradox (Physical proximity but maximum emotional distance), Camera Treatment (Often camera splits them visually with focus, framing, or lighting emphasizing separation). Symbolic Meanings: Emotional distance despite physical proximity, Communication breakdown, Conflict without resolution, Together but fundamentally separate, Cannot or will not face each other, Invisible wall between them, Relationship strain, Stubborn maintenance of distance. Psychological Effect: Distance felt, conflict, inability to communicate, together but apart paradox, emotional walls, stubbornness, isolation despite proximity. Common Contexts: After arguments, Relationship strain, Communication failure, Stubborn conflict neither will resolve, Growing apart, Inability to reconcile, Cold war between characters, Mutual avoidance. Resolution: Characters turning to face each other equals breakthrough moment, reconciliation, wall breaking down at last. Touching: Backs still touching equals vestigial physical connection despite emotional distance - not completely severed yet. Camera Split: Often camera frames them in separate halves of screen despite being physically together. Genre: Drama, romance, relationship-focused anime. Irony: Ironic proximity despite distance.', '2026-01-27 12:22:12', '2026-01-27 12:22:12', 1),
(14, 'The \"Held Hand\" (Connection/Promise)', 'Hands holding, clasping, or reaching for each other showing connection, promise, support, or bond. Visual Description: Two characters hands shown holding, clasping, reaching desperately for each other. Can be gentle or desperate. Shows connection, promise, support, or unbreakable bond between people. Technical Details: Hold Type indicating relationship (Gentle fingers intertwined equals romantic intimacy, Firm grasp equals promise and determination, Desperate clutch equals fear of losing connection, Reaching but not quite touching yet equals separated but trying to connect), Context (Hand pulling someone up equals saving and helping, Hand offered equals support offered, Hands together in prayer position equals unity, One hand wrapped protectively in both equals protection and care). Symbolic Meanings: Connection between people, Promise made and kept, Support and help offered, Will not let go, Unity and bond, Protection and care, Commitment to each other, Anchor in storm. Psychological Effect: Connection, promise, security, unity, support, care, commitment, warmth, anchoring, safety, bond. Common Contexts: Promise scenes, Rescue moments, Romance development, Support giving, Unity demonstrations, Protective moments, Commitment displays, Preventing someone from falling. Letting Go: Hand slipping away despite efforts equals losing connection, failure to save, forced separation, unbearable loss. Cultural Significance: Hand-holding significance varies by culture; in some Asian cultures considered very significant romantic gesture, not casual. Close-Up: Often shown in intimate extreme close-up to emphasize importance and connection. Genre: Romance, drama, action, adventure anime. Universal: Universal gesture of connection across all cultures.', '2026-01-27 12:22:12', '2026-01-27 12:22:12', 1),
(15, 'The \"Gift Unopened/Rejected\" (Rejection/Distance)', 'Gift left unopened, returned, or rejected showing emotional rejection beyond just rejecting object. Visual Description: Gift shown unopened and ignored, deliberately returned, or refused. Represents rejection not just of physical object but of giver feelings, care, or relationship itself. Technical Details: Gift State (Sitting unopened equals ignored or rejected, Physically returned to giver equals active deliberate rejection, Thrown away equals harsh cruel rejection, Sits untouched for long time equals uncertainty, distance, cannot accept), Beautiful Wrapping (Often beautifully wrapped emphasizing care and effort put in, making rejection more painful), Gift Type (Valentine chocolate equals romantic rejection, Birthday gift equals relationship rejection, Apology gift equals forgiveness refused, Expensive gift equals completely rejecting person regardless of effort). Symbolic Meanings: Feelings rejected not just gift, Relationship refused, Emotional distance maintained, Not ready to accept care, Hurt too deep to accept, Cannot accept kindness, Emotional wall maintained at all costs, Pride preventing acceptance. Psychological Effect: Rejection, pain, distance, emotional walls, unable to accept care, hurt, closed off from others, isolation by choice. Common Contexts: Romantic rejection, Apology refused, Cannot accept kindness due to trauma, Depression isolation, Maintaining distance deliberately, Hurt too deep to forgive, Pride preventing acceptance of help, Self-punishment through rejection. Gift Opened Later: Gift finally opened later in story equals coming around, acceptance, emotional walls finally breaking, growth. Gift Giver Reaction: Often show gift giver seeing rejection, emphasizing pain of rejection beyond just recipient. Japanese Cultural Context: Gift-giving culturally very significant in Japan, making rejection carry heavy social weight. Genre: Romance, drama, psychological anime. Pain: Emphasizes pain of rejection for both parties.', '2026-01-27 12:22:12', '2026-01-27 12:22:12', 1),
(16, 'The \"Scarf/Jacket Sharing\" (Warmth/Care)', 'One character giving their jacket or scarf to another showing care, warmth, and attention. Visual Description: Character removes their own jacket or scarf and places it on another character who is shivering, cold, or in need. Classic care and protection gesture showing noticing and attending to another needs. Technical Details: Giving Method (Draping over shoulders equals gentle care, Wrapping around carefully equals intimate care, Throwing it at them equals tsundere \"not because I care\" version, Character notices later they are wearing it equals secret care), Recipient State (Usually cold, shivering, wet, or otherwise visibly in need), Giver Sacrifice (Left in shirt sleeves, visibly sacrificing own comfort for another). Symbolic Meanings: Care and concern for wellbeing, Warmth both literal and emotional, Protection and sheltering, Sacrifice own comfort for another, Intimacy through wearing someone clothes and scent, Notice and attention to needs, Kindness and thoughtfulness, Non-verbal care. Psychological Effect: Warmth, care, protection, kindness, being noticed, intimacy, sacrifice for another, gentleness, thoughtfulness. Common Contexts: Romance development, Caring moments, Character showing hidden kind side, Cold weather scenes, Protection display, Noticing needs others miss, Tsundere character development showing they care, First romantic gesture. Smell and Scent: Often mention recipient smelling like the person who gave jacket creating intimacy through scent. Reluctance: Recipient reluctant to accept but eventually does equals accepting care, letting walls down. Keeping Item: Recipient keeping jacket or scarf longer than functionally needed equals treasuring connection and person. Genre: Romance, slice-of-life, drama anime. Warmth: Literal and emotional warmth combined.', '2026-01-27 12:22:12', '2026-01-27 12:22:12', 1),
(17, 'The \"Distance on Bench\" (Emotional Distance Visualization)', 'Characters sitting on same bench with noticeable space between showing emotional distance made physical. Visual Description: Two characters sitting on same bench but with significant noticeable space between them. Physical distance directly represents and visualizes emotional distance between them. Technical Details: Distance Amount (Opposite ends of bench equals maximum distance possible while still together, One seat space between equals uncomfortable distance, Just slightly apart equals slight but significant distance, Sitting together with no space equals contrast showing no distance), Body Language (Turned away from each other, looking in different directions emphasizes emotional distance further), Camera (Often wide shot showing full bench to emphasize empty space between them). Symbolic Meanings: Emotional distance visualized physically, Relationship strain, Uncomfortable proximity, Cannot close the gap, Awkwardness between them, Growing apart, Space needed between them, Together but separate. Psychological Effect: Distance felt, discomfort, strain, awkwardness, gap unable to close, apart despite together, tension, separation. Common Contexts: After arguments, Awkward moments, Growing apart over time, First meeting discomfort, Cannot connect, Relationship strain, Communication breakdown, Incompatibility. Resolution: Characters moving closer together on bench, closing physical gap equals emotional breakthrough, distance closing, reconciliation. Public Setting: Bench in public park or space equals cannot fully express feelings, constrained by public nature. Camera Movement: Camera often pans across empty space between them, emphasizing gap they cannot close. Genre: Romance, drama, relationship anime. Visual: Makes emotional distance visually concrete and measurable.', '2026-01-27 12:22:12', '2026-01-27 12:22:12', 1),
(18, 'The \"Matching Object\" (Connection/Belonging)', 'Two or more characters with matching or complementary objects showing connection, bond, or belonging together. Visual Description: Two or more characters shown possessing matching or complementary objects such as keychains, charms, bracelets, or other tokens. Shows connection, bond, promise, or belonging together as pair or group. Technical Details: Object Type (Split charm that fits together equals complementary souls, Matching pair equals equality and partnership, Set pieces equals group belonging and identity, Friendship bracelets equals promises made), Discovery (Often one character discovers other has been keeping matching item all along), Reveal Timing (Sometimes revealed at significant emotional moment for maximum impact). Symbolic Meanings: Bond between people, Belonging together, Promise kept over time, Thinking of each other, Connection maintained across distance, Partners or group identity, Matching souls, Not alone. Psychological Effect: Connection, belonging, bond, promise kept, unity, partners, identity, warmth, inclusion, remembered. Common Contexts: Friendship promises, Romance tokens, Group belonging and team identity, Separation before long journeys, Reunion recognition, Secret connection, Team unity, Childhood promises kept. Lost Item: One character losing their matching item equals connection threatened, fear of losing bond. Reunion: Seeing matching item after long separation equals emotional reunion moment, proof connection maintained. Japanese Cultural: Omamori matching charms culturally significant in Japanese tradition, protective charms. Genre: Romance, friendship, adventure, team anime. Promise: Physical proof of promise or connection.', '2026-01-27 12:22:12', '2026-01-27 12:22:12', 1),
(19, 'The \"Doorway Distance\" (Threshold Unable to Cross)', 'Character standing in doorway unable to step through showing barrier, hesitation, or not belonging. Visual Description: Character standing in doorway threshold, frozen, unable or unwilling to step through. Threshold represents barrier they psychologically cannot or will not cross. Door frame physically divides them from interior space. Technical Details: Position (Standing frozen in doorway equals hesitation and fear, Hand on door frame equals considering but cannot commit, One foot tentatively in equals torn between worlds, Looking in from outside equals unable to enter that world), Camera Framing (Often frames character perfectly in doorway, neither fully inside nor outside), Lighting Contrast (Inside versus outside lighting dramatically different emphasizing divide and barrier). Symbolic Meanings: Unable to cross threshold, Not belonging in that space, Cannot enter that world or life, Hesitation and fear paralyzing, Barrier either literal or emotional, Outsider looking in, Not invited or welcome, Fear of commitment or change. Psychological Effect: Exclusion, hesitation, fear, unable to cross, not belonging, threshold anxiety, barrier, frozen, outsider status. Common Contexts: Cannot enter someone life, Social exclusion, Fear of commitment, Not belonging anywhere, Outsider status, Unable to return home, Threshold of major change, Paralyzed by fear. Finally Entering: Character finally stepping through threshold equals breakthrough, acceptance, overcoming fear, commitment, belonging achieved. Door Frame as Prison: Frame itself becomes symbolic barrier and prison of own hesitation. Invitation: Someone from inside inviting them in equals acceptance offered, belonging given, permission to enter. Genre: Drama, psychological, romance, coming-of-age anime. Liminal: Character stuck in liminal threshold space.', '2026-01-27 12:22:12', '2026-01-27 12:22:12', 1),
(20, 'The \"Two Mugs/Cups\" (Companionship/Loss)', 'Two mugs or cups shown together or one sitting alone showing companionship or devastating absence. Visual Description: Two mugs or cups shown together (companionship, partnership, routine intimacy) or single mug sitting alone with obvious empty space where second should be (loss, absence, loneliness). Technical Details: Together Configuration (Side by side equals equality and partnership, Different but matching equals complementary, Steam rising from both equals warmth and life, Matching set equals established routine), Alone Configuration (One mug with obvious space for second equals absence and loss, Second mug sitting unused equals waiting and hope, Second mug removed from frame entirely equals gone forever), Setting (Usually kitchen table or coffee shop emphasizing domestic routine). Symbolic Meanings: Companionship and partnership (together) or Loss and absence (alone), Daily ritual shared or lost, Ordinary intimacy of daily life, Presence or absence made concrete, Routine broken, Morning ritual disrupted, Empty chair at table, Domestic intimacy. Psychological Effect: Companionship warmth (together) or absence pain (alone), routine comfort or disruption, together or alone, intimate or lonely, everyday closeness or loss. Common Contexts: Morning routine scenes, Companionship moments, Loss and absence after death, Relationship endings, Moving in together or apart, Daily life intimacy, Routine establishment or disruption, Loneliness visualization. Coffee Shop Setting: Often seen in coffee shop or kitchen settings emphasizing routine and daily ritual. Two Together Meaning: Symbol of comfortable domestic intimacy, shared routines, companionship in ordinary moments. One Alone Power: Powerful symbol of absence and loss, especially if routine was previously established showing contrast. Genre: Slice-of-life, romance, drama, loss-focused anime. Everyday: Makes extraordinary emotions through ordinary objects.', '2026-01-27 12:22:12', '2026-01-27 12:22:12', 1),
(21, 'The \"Blooming Flower\" (Growth/Awakening)', 'Flower opening or blooming showing growth, awakening, coming alive, or reaching full potential. Visual Description: Flower shown opening, blooming, petals unfurling gracefully. Often shown in time-lapse or emphasized slow motion. Shows character growing, awakening to life or love, coming truly alive, or reaching full potential. Technical Details: Bloom Stages (Bud tight equals potential still unrealized, Petals beginning to open equals awakening starting, Half bloom equals transformation actively in progress, Full glorious bloom equals potential completely realized and peak reached), Flower Type carrying specific meaning (Rose equals love awakening, Cherry blossom equals Japanese beauty and potential realized, Lotus equals spiritual awakening and purity, Sunflower equals turning toward light and truth), Speed Treatment (Time-lapse rapid bloom equals transformation compressed, Real-time bloom equals natural gradual growth process). Symbolic Meanings: Growth and development, Awakening to life or love or truth, Coming alive and vibrant, Potential being realized, Beauty emerging from bud, Innocence awakening, Reaching full bloom and peak, Life force. Psychological Effect: Hope, growth, awakening, life, beauty emerging, potential realized, optimism, vitality, renewal. Common Contexts: Character growth breakthrough moments, Awakening to love and romance, Coming of age moments, Spiritual awakening, Spring and renewal, Recovery from trauma, Finding true self, Transformation completing. Opposite: Wilting flower from Volume 1 - direct contrast showing decay versus growth, death versus life. Light Combination: Often combined with sunrise or light for double symbolism of awakening and new beginning. Sound: Sometimes accompanied by gentle uplifting music emphasizing beauty and growth. Genre: Romance, coming-of-age, spiritual, healing anime. Universal: Flower blooming as growth symbol crosses all cultures.', '2026-01-27 15:44:38', '2026-01-27 15:44:38', 1),
(22, 'The \"Butterfly Emergence\" (Transformation Complete)', 'Butterfly emerging from cocoon showing complete transformation achieved and metamorphosis realized. Visual Description: Butterfly emerging from chrysalis, spreading wings for first time, taking first flight. Shows complete successful transformation, metamorphosis fully achieved, becoming new self. Technical Details: Emergence Stages (Cocoon cracking equals transformation completing final stage, Emerging wet and vulnerable equals new self first appearance, Wings spreading and drying equals revealing new beautiful form, First flight equals transformation complete and functional), Butterfly Type (Colorful butterfly equals beautiful successful transformation, White butterfly equals pure transformation, Specific species may carry particular cultural meaning), Context (Character often watches butterfly or is directly compared to butterfly transformation). Symbolic Meanings: Complete successful transformation, Metamorphosis achieved, Becoming entirely new self, Leaving old self completely behind, Freedom to fly at last, Beauty emerging from struggle in cocoon, Rebirth into new form, No longer caterpillar. Psychological Effect: Transformation, freedom, rebirth, beauty from struggle, hope, new beginning, liberation, achievement, emergence. Common Contexts: Character transformation complete, Coming out of protective shell, Overcoming trauma successfully, Finding and becoming true self, Liberation moments, Rebirth after darkness, Metamorphosis visualization, Identity fully realized. Cocoon: Cocoon shown earlier in story represents transformation in progress, isolation period. Flight: First tentative flight equals testing new self, embracing change, learning new capabilities. Cultural: Butterfly as symbol of soul, transformation, rebirth across many cultures worldwide. Genre: Transformation, coming-of-age, psychological, magical girl anime.', '2026-01-27 15:44:38', '2026-01-27 15:44:38', 1),
(23, 'The \"Seed Planted\" (Potential/New Beginning)', 'Seed being planted showing potential, hope for future, or new beginning intentionally started. Visual Description: Seed shown being planted carefully in soil, watered, tended with care. Represents potential waiting to be realized, hope for future, new beginning, investment in growth and tomorrow. Technical Details: Planting Act (Deliberate careful planting equals intentional new beginning, Child planting equals innocence and hope, Two people planting together equals shared future, Careful tending afterward equals nurturing potential), Seed Type (Tree seed equals long-term growth and patience, Flower seed equals beauty to come, Food plant seed equals sustenance and survival, Specific plant carries meaning), Follow-up (Often shown sprouting later in story showing growth realized). Symbolic Meanings: Potential and possibility, New beginning intentionally started, Hope for future, Investment in growth, Faith in tomorrow, Nurturing something precious, Long-term thinking and patience, Planting future. Psychological Effect: Hope, potential, future orientation, optimism, new beginnings, patience, faith in tomorrow, nurturing, investment. Common Contexts: New beginning moments, Hope after darkness and despair, Investment in future, Teaching next generation, Relationship beginnings, Post-war recovery and rebuilding, Environmental themes, Faith in tomorrow. Time Factor: Seed represents patience - seed takes time to grow, cannot rush. Care Requirement: Seed requires ongoing care and attention equals commitment to future and growth. Sprouting Later: Seed shown sprouting later equals hope realized, growth happening, investment paying off. Genre: Hopeful, environmental, rebuilding, coming-of-age anime. Patience: Teaches patience and faith in unseen growth.', '2026-01-27 15:44:38', '2026-01-27 15:44:38', 1),
(24, 'The \"Opening Door/Window\" (New Possibilities)', 'Door or window opening showing new possibilities, opportunities, or hope entering life. Visual Description: Door or window shown opening, often with bright light streaming in from outside. Shows new possibilities opening, opportunities arising, hope entering, or entering new phase of life. Technical Details: Opening Method (Character actively opens equals taking action and initiative, Opens itself mysteriously equals fate or destiny, Bursts open suddenly equals sudden unexpected opportunity, Slow gradual open equals gradual revelation and change), Light (Usually bright hopeful light streams in from outside), View Beyond (What is visible beyond door matters greatly), Type Distinction (Door opening equals major life change or threshold, Window opening equals new perspective or fresh air, Multiple doors equals many possibilities available). Symbolic Meanings: New possibilities opening up, Opportunities arising and available, Entering entirely new phase, Hope and future accessible, Perspective change, New world becoming accessible, Breakthrough achieved, Freedom from confinement. Psychological Effect: Hope, opportunity, new possibilities, optimism, change, adventure, future, potential, liberation, fresh start. Common Contexts: New opportunities arising, Major life changes and transitions, Perspective shifts, Hope returning after darkness, Leaving past behind, Adventure beginning, Breakthrough moments, Escape from confinement. Light Streaming: Light streaming in equals enlightenment, hope, positivity, truth, divine. Contrast: Often shown from dark confined room to bright open outside. Opposite: Closing door represents ending versus opening representing beginning. Genre: Hopeful, adventure, coming-of-age, transformation anime.', '2026-01-27 15:44:38', '2026-01-27 15:44:38', 1),
(25, 'The \"Hatching Egg\" (Birth/New Life)', 'Egg hatching showing birth, new life emerging, or potential becoming reality at last. Visual Description: Egg shown cracking, hatching, new life struggling to emerge. Shows birth, new beginning, potential becoming reality, something new entering world. Technical Details: Hatching Process (First crack equals beginning of emergence, Breaking through shell equals struggle to be born, Full emergence equals birth achieved, First vulnerable moments equals new life fragility), What Hatches (Bird equals freedom and flight, Dragon equals power unleashed, Phoenix equals rebirth from destruction, Unknown creature equals mystery revealed, Specific creature carries meaning), Struggle (Struggle to hatch emphasized equals growth and birth require effort). Symbolic Meanings: Birth and new life, Potential finally realized, Breaking free from shell, New beginning, Vulnerability of new life, Struggle required to be born, What was hidden now revealed, Emergence. Psychological Effect: Birth, new life, potential realized, breaking free, hope, new beginning, wonder, vulnerability, struggle rewarded. Common Contexts: Actual births literal or metaphorical, Character rebirths and transformations, New persona emerging, Breaking free from constraints, Monster or creature reveals, New power awakening, Transformation completing, Beginning of life. Struggle Emphasis: Struggle to hatch shown equals important lesson that growth requires effort, cannot be rushed. Protection: Egg carefully protected before hatching equals necessary gestation and protection period. First Moments: Vulnerable first moments emphasized equals fragility of new beginnings. Genre: Birth, transformation, monster, new beginning anime.', '2026-01-27 15:44:38', '2026-01-27 15:44:38', 1);
INSERT INTO `anivoc_symbolic_objects` (`id`, `name`, `description`, `created_at`, `updated_at`, `is_ingredient`) VALUES
(26, 'The \"Rising Sun\" (New Day/Hope)', 'Sun rising over horizon showing new day beginning, new start, or hope emerging from darkness. Visual Description: Sun shown rising over horizon, darkness steadily giving way to light. Shows new day dawning, new beginning, hope emerging after darkness, renewal. Technical Details: Rise Stages (Pre-dawn dim light equals hope approaching, First light breaking equals hope emerging, Sun breaking horizon equals new day definitively beginning, Fully risen sun equals hope fully realized), View Context (Rising over ocean equals vast limitless new beginning, Rising over mountains equals overcoming obstacles, Rising through window equals personal renewal, After long darkness equals hope after deep despair), Color (Golden and orange light equals warmth, life, hope, vitality). Symbolic Meanings: New day beginning, New beginning and fresh start, Hope after darkness and despair, Light overcoming darkness, Renewal and rebirth, Surviving the long night, Tomorrow always comes, Never give up hope. Psychological Effect: Hope, renewal, new beginning, optimism, light after darkness, survival, perseverance rewarded, morning. Common Contexts: After dark traumatic times, New beginning moments, Survival scenes after ordeal, Hope restored after loss, Morning after trauma or grief, Recovery beginning, New life phase starting, Never giving up. Universal: Sunrise as ultimate hope symbol crosses all cultures worldwide. Color Psychology: Golden orange light creates warmth, life, hope feelings. Opposite: Sunset represents ending versus sunrise representing beginning. Genre: Hopeful, survival, recovery, new beginning anime. Promise: Sunrise promises new day will come no matter how dark night.', '2026-01-27 15:44:38', '2026-01-27 15:44:38', 1),
(27, 'The \"Sprouting Plant\" (Growth Visible)', 'Plant sprouting from soil showing growth becoming visible and progress made tangible. Visual Description: Small plant sprouting, pushing through soil, first leaves visible above ground. Shows growth happening and becoming visible, potential becoming reality, persistence paying off. Technical Details: Growth Stages (Breaking through soil equals overcoming obstacles, First leaves visible equals growth becoming visible, Growing progressively taller equals steady progress, Multiple leaves developing equals flourishing), Plant Type (Tree seedling equals long-term sustained growth, Flower equals beauty emerging, Food plant equals sustenance and life, Specific plant carries meaning), Context (Often follows seed planting shown earlier creating narrative arc). Symbolic Meanings: Growth becoming visible at last, Potential realized and visible, Persistence paying off, Breaking through obstacles, Progress visible and tangible, Life force, Development, Investment returning. Psychological Effect: Growth, progress, hope realized, persistence rewarded, life, potential visible, encouragement, validation. Common Contexts: Character growth becoming visible, Progress shown tangibly, After patient waiting rewarded, Hope materializing concretely, Recovery progress visible, Teaching paying off, Investment returning, Care rewarded. Time Passage: Sprouting shows significant time has passed since planting, growth takes time. Care Implied: Sprouting implies someone cared for seed equals nurturing paying off. Fragility: Sprout still fragile equals growth requires continued care and protection, not finished. Genre: Growth, nurturing, patience, hopeful anime. Reward: Visual reward for faith and patience invested.', '2026-01-27 15:44:38', '2026-01-27 15:44:38', 1),
(28, 'The \"Breaking Cocoon\" (Transformation In Progress)', 'Cocoon cracking and breaking showing transformation actively happening right now. Visual Description: Cocoon cracking, breaking, being shed in pieces. Shows transformation actively in progress, old self being left behind, struggling to become something new. Technical Details: Breaking Process (First cracks appearing equals transformation starting, Active breaking and struggling equals effort required, Shedding pieces equals leaving old self behind, Almost free equals nearly complete but not yet), Context (Character often in metaphorical cocoon representing isolation or transformation period), Timing (Represents middle of transformation, not yet complete - vulnerable liminal state). Symbolic Meanings: Transformation actively in progress, Breaking free from constraints, Leaving old self behind, Struggle to transform, Almost there but not complete, Shedding old constraints, Metamorphosis active, Liminal state. Psychological Effect: Transformation, struggle, breaking free, almost there, hope, effort required, change in progress, vulnerability. Common Contexts: Mid-transformation sequences, Breaking from past, Isolation period ending, Change in progress, Struggling to change, Almost breakthrough, Metamorphosis, Vulnerability during change. Struggle Emphasis: Transformation requires effort and struggle, not easy or instant process. Isolation: Cocoon often represents necessary isolation period for transformation to occur. Not Complete: Transformation not yet complete equals vulnerability, fragility, still in process. Genre: Transformation, coming-of-age, psychological, magical girl anime. Process: Emphasizes transformation as process, not instant change.', '2026-01-27 15:44:38', '2026-01-27 15:44:38', 1),
(29, 'The \"First Step\" (Journey Beginning)', 'Character foot taking first step into new world or journey showing commitment made. Visual Description: Character foot shown taking first deliberate step into new area, across threshold, onto new path. Shows journey beginning, commitment made, point of no return crossed. Technical Details: Step Type (Hesitant tentative step equals uncertain beginning, Confident firm step equals determined beginning, Forced reluctant step equals reluctant beginning, Running eager step equals enthusiastic beginning), Threshold (Often shown crossing visible threshold or boundary), Camera (Often intimate close-up on foot, then pulls back to wider reveal), Destination (What they are stepping toward matters greatly to meaning). Symbolic Meanings: Journey beginning, Commitment made and acted upon, Point of no return crossed, Taking decisive action, Leaving safety and comfort, Adventure starting, Decision enacted physically, Cannot go back now. Psychological Effect: Beginning, commitment, determination, courage, leaving comfort zone, adventure, point of no return, agency. Common Contexts: Journey beginnings, Leaving home for first time, Major life decisions enacted, Adventure starting, Commitment moments, Crossing thresholds literal and metaphorical, No turning back moments, Taking initiative. Threshold: Physical threshold represents psychological threshold being crossed. Sound: Often emphasized footstep sound for dramatic impact. Point of No Return: First step represents commitment made, cannot easily go back. Genre: Adventure, journey, coming-of-age, quest anime. Agency: Represents character taking active agency and control.', '2026-01-27 15:44:38', '2026-01-27 15:44:38', 1),
(30, 'The \"Phoenix Rising\" (Rebirth from Destruction)', 'Phoenix rising from ashes showing rebirth from complete destruction, stronger than before. Visual Description: Phoenix or phoenix-like imagery rising from flames or ashes. Shows rebirth from total destruction, rising from complete ruin, emerging stronger from suffering. Technical Details: Imagery (Literal phoenix bird with flame wings, Phoenix-like flames surrounding character, Character rising from destruction site, Fire wings spreading dramatically), Context (Always after destruction, defeat, or severe trauma), Flames (Fire represents both destruction and purification or rebirth - dual symbolism), Rising (Movement always upward - rising from low point). Symbolic Meanings: Rebirth from complete destruction, Rising from ashes, Stronger from suffering endured, Cannot be permanently destroyed, Renewal through fire and trial, Immortal spirit, Comeback from impossible, Triumph over destruction. Psychological Effect: Rebirth, resurrection, strength from suffering, hope from utter despair, immortality, power, triumph, invincibility. Common Contexts: After total defeat, Rising from trauma, Comeback moments, Rebirth after death literal or metaphorical, Stronger from suffering, Immortal characters, Triumph over destruction, Refusing to stay down. Mythology: References ancient phoenix mythology of death by fire and rebirth from ashes. Fire Symbolism: Dual symbolism of fire as both destruction and purification or rebirth. Power Increase: Often character more powerful after phoenix rebirth than before. Genre: Action, supernatural, comeback, triumph anime. Hope: Ultimate symbol of hope and resilience - cannot be kept down.', '2026-01-27 15:44:38', '2026-01-27 15:44:38', 1),
(31, 'The \"Ticking Clock\" (Urgency/Deadline)', 'Clock ticking or shown in close-up creating urgency, showing deadline approaching, or time pressure mounting. Visual Description: Clock shown ticking, close-up on moving hands, second hand movement emphasized. Creates urgency, shows deadline inexorably approaching, time running out. Technical Details: Visual Treatment (Extreme close-up on clock face, Second hand movement emphasized dramatically, Ticking sound made prominent and loud, Specific time shown clearly), Clock Type (Wall clock equals public shared time, Pocket watch equals personal time, Digital countdown equals precision, Bomb timer equals extreme life-or-death urgency), Speed Manipulation (Sometimes shown accelerating unnaturally to emphasize urgency building). Symbolic Meanings: Time running out inexorably, Deadline approaching, Urgency and pressure mounting, Cannot stop time, Racing against clock, Limited time remaining, Countdown, Mortality. Psychological Effect: Urgency, pressure, anxiety, time running out, deadline stress, racing feeling, tension, panic. Common Contexts: Deadline scenes, Bomb countdowns, Racing against time, Limited time offers, Death approaching, Competition time limits, Urgency creation, Time pressure. Sound Design: Ticking often made loud, prominent, anxiety-inducing, overwhelming. Intercut: Often intercut rapidly with action sequences to heighten tension dramatically. Clock Stopping: Clock stopping equals time up, deadline passed, too late. Genre: Thriller, action, suspense, deadline-driven anime. Universal: Clock as time pressure symbol crosses all cultures.', '2026-01-27 15:44:38', '2026-01-27 15:44:38', 1),
(32, 'The \"Stopped Clock\" (Time Frozen/Trauma)', 'Clock stopped at specific time showing time frozen at trauma moment or inability to move forward. Visual Description: Clock shown stopped at specific significant time, hands not moving. Shows time frozen at exact moment of trauma, time standing still, or moment preserved forever. Technical Details: Stopped Time (Specific time shown, often narratively significant), Condition indicating cause (Stopped cleanly equals deliberate stopping, Broken or shattered equals violent traumatic stop, Battery dead equals natural end, Frozen mid-tick equals supernatural or metaphorical), Context (Often at trauma site, abandoned place, or showing character frozen moment). Symbolic Meanings: Time frozen at specific moment, Trauma moment preserved forever, Time stood still, Cannot move forward from moment, Moment captured forever, Stuck in past, Time of death, Paralyzed by past. Psychological Effect: Frozen, trauma, stuck, cannot move on, time stood still, preservation, haunting, paralysis, trapped. Common Contexts: Trauma sites, Exact time of death, Abandoned places frozen in time, Cannot move on from past, Frozen moments, Disaster scenes, Stuck in past psychologically, PTSD visualization. Specific Time: Time shown often narratively significant - time of death, disaster, trauma moment. Contrast: Frozen clock versus moving clocks equals past versus present, stuck versus moving forward. Starting Again: Clock starting to tick again equals moving forward at last, healing beginning, time flowing again. Genre: Trauma, psychological, horror, mystery anime. Haunting: Particularly haunting symbol of being trapped.', '2026-01-27 15:44:38', '2026-01-27 15:44:38', 1),
(33, 'The \"Old Photograph\" (Frozen Past)', 'Faded or aged photograph showing past captured forever, nostalgia, or memory preserved. Visual Description: Old, faded, yellowed, or aged photograph. Shows past captured and frozen, better times remembered, nostalgia, memory, or what was lost forever. Technical Details: Photo Condition (Faded equals very distant past, Sepia tone equals nostalgia, Torn or damaged equals troubled or painful past, Pristine but old equals carefully treasured memory), Content (Usually shows happier times creating painful contrast), Context (Held by character equals actively remembering, On wall equals past displayed, Found accidentally equals discovering past, Hidden away equals buried memory). Symbolic Meanings: Past captured forever, Better times remembered, Nostalgia, Memory preserved, What was lost, Cannot go back, History, Frozen moment, Before tragedy. Psychological Effect: Nostalgia, loss, memory, past, longing, bittersweet, melancholy, treasure, grief, remembering. Common Contexts: Nostalgia moments, Remembering past, Loss of past, Family history, Before tragedy contrast, Character background, Treasured memories, What was lost. Age Degree: Degree of aging and fading shows how distant past is. Compare Present: Often compared to present showing dramatic change and loss. Damage: Damaged photo equals damaged past or troubled memory. Genre: Drama, family, historical, memory-focused anime. Bittersweet: Creates powerful bittersweet nostalgia.', '2026-01-27 15:44:38', '2026-01-27 15:44:38', 1),
(34, 'The \"Hourglass\" (Finite Time)', 'Hourglass with sand falling showing finite time, mortality, or time slipping away inexorably. Visual Description: Hourglass with sand steadily inevitably falling, running out. Shows finite time, mortality awareness, inevitability, or time slipping away beyond control. Technical Details: Sand Level indicating time remaining (Full top chamber equals plenty of time remaining, Half equals midpoint, Nearly empty equals running out, Empty equals time completely up), Flow (Steady inevitable fall cannot be stopped), Type (Clear glass equals visible time passage, Ornate equals precious time, Large equals significant time span measured), Can Be Flipped (Flipping hourglass equals renewal, second chance, time reset). Symbolic Meanings: Finite limited time, Mortality, Time slipping away, Inevitability, Cannot stop time, Life span, Deadline, Hourglass of life, Sand of time. Psychological Effect: Mortality awareness, time passing, finite life, inevitability, melancholy, awareness, pressure, contemplation. Common Contexts: Mortality themes, Time limits, Life span visualization, Aging, Deadline approaches, Cannot stop time, Philosophical moments, Contemplating death. Flip for Renewal: Flipping hourglass equals renewal, second chance, time reset, rebirth. Empty Last Grain: Last grain of sand falling equals critical final moment, last breath. Classic Symbol: Classic memento mori symbol reminding of mortality. Genre: Philosophical, mortality, deadline, contemplative anime. Meditation: Invites meditation on time and mortality.', '2026-01-27 15:44:38', '2026-01-27 15:44:38', 1),
(35, 'The \"Worn Object\" (Age and History)', 'Worn, aged, well-used object showing passage of time, history, or long endurance. Visual Description: Object visibly worn, aged, used extensively over long time. Shows time relentless passage, history and stories, long use and service, or endurance. Technical Details: Wear Signs (Fading equals very long time passed, Scratches and dents equals hard use, Polish from handling equals loving care, Visible repairs equals preserved despite age), Object Type (Childhood toy equals past, Work tool equals long service, Book equals much reading, Clothing equals long worn), Context (Often contrasted with new version showing change). Symbolic Meanings: Time passing, History and accumulated stories, Long use and service, Endurance through time, Loved over time, Age and wisdom, Survival, Loyalty. Psychological Effect: Nostalgia, time passage, history, endurance, treasure, age, value of old things, respect, memory. Common Contexts: Treasured possessions, Long-held items, Family heirlooms, Time passage visualization, Character history, Endurance proof, Value of old things, Loyalty. Care Despite Wear: Well-worn but carefully maintained equals treasured despite or because of age. Contrast New: Often shown next to new version showing passage of time. Stories in Wear: Wear patterns tell stories of use and history. Genre: Family, historical, nostalgia, slice-of-life anime. Respect: Creates respect for endurance and history.', '2026-01-27 15:44:38', '2026-01-27 15:44:38', 1),
(36, 'The \"Calendar Page\" (Time Marking)', 'Calendar page being torn off or day marked showing time passing or important day. Visual Description: Calendar page being torn off, day crossed out, or date circled. Shows time passing, important day approaching, or marking moments in time. Technical Details: Action Type (Tearing pages rapidly equals time passing montage, Circling date equals important day, Crossing out day equals day completed, Final page equals time running out), Calendar Type (Wall calendar equals public shared time, Desk calendar equals personal time, Countdown calendar equals anticipation building), Marking Method (Red circle equals very important, X equals completed, Countdown numbers equals urgency). Symbolic Meanings: Time passing, Day marked as significant, Important date, Counting down to event, Daily routine, Anticipation building, Time progressing, Ritual. Psychological Effect: Time passing, routine, anticipation, marking time, progress, waiting, deadline approaching, ritual. Common Contexts: Time passage montages, Countdown to event, Daily routine, Waiting for specific date, Marking important day, Time progressing, Deadline tracking, Anticipation. Rapid Montage: Rapid calendar pages tearing equals time passing quickly in montage. Circled Date: Date circled in red equals important upcoming event creating anticipation. Final Page: Last page of calendar year equals end of period, transition. Genre: Slice-of-life, deadline, anticipation, routine anime. Ritual: Represents daily ritual of marking time.', '2026-01-27 15:44:38', '2026-01-27 15:44:38', 1),
(37, 'The \"Pocket Watch\" (Personal Time/Legacy)', 'Pocket watch often heirloom showing personal time, legacy object, or connection to past person. Visual Description: Pocket watch, often old or heirloom quality. Shows personal intimate time, connection to past person through object, legacy, or treasured possession with history. Technical Details: Condition (Still working equals connection alive, Stopped at specific time equals frozen at meaningful moment, Engraved with message or name equals personalized, Worn from handling equals long treasured), Usage (Checked for time equals awareness, Held emotionally equals connection, Given to another equals passing legacy, Found equals discovering past), Chain (Often attached to chain showing it was carried). Symbolic Meanings: Personal intimate time, Legacy object passed down, Connection to past person, Treasured possession with story, Memory of giver, Time is personal not public, Inheritance, Father to son tradition. Psychological Effect: Legacy, connection across time, treasure, memory, personal time, inheritance, emotional object, continuity. Common Contexts: Inherited objects, Memory of deceased, Legacy moments, Time checking, Character treasures, Passing down to next generation, Emotional anchors, Family tradition. Engraving: Often engraved with meaningful message or name creating personal connection. Given Before: Often given before death, journey, or separation creating poignancy. Contrast: Personal pocket watch versus public wall clock. Genre: Family, legacy, historical, emotional anime. Connection: Creates connection across generations.', '2026-01-27 15:44:38', '2026-01-27 15:44:38', 1),
(38, 'The \"Music Box\" (Preserved Moment/Memory)', 'Music box playing showing preserved moment in time, memory through music, or connection to past. Visual Description: Music box shown playing, often old or precious. Shows moment preserved in music, memory triggered by specific melody, or connection to past through sound. Technical Details: Playing (Character winds it equals deliberately activating memory, Plays on own equals haunting past, Slowing down equals fading memory or running down, Broken equals damaged past or memory), Song (Specific melody triggers specific vivid memory), Condition (Pristine equals treasured carefully, Worn equals long loved, Broken or damaged equals damaged past). Symbolic Meanings: Preserved moment in time, Connection to past through music, Childhood treasure, Someone remembered through melody, Moment captured in song, Haunting past, Innocence preserved, Lullaby. Psychological Effect: Nostalgia, memory, melancholy, treasure, past, innocence, bittersweet, haunting, comfort. Common Contexts: Memory trigger moments, Childhood objects, Treasured possessions, Haunting moments, Character background, Emotional anchors, Loss reminders, Comfort objects. Specific Song: Specific melody strongly connects to specific memory or person. Winding Act: Act of winding music box equals choosing to remember, activating memory. Slowing Music: Music slowing down equals memory fading, time running out, loss. Genre: Nostalgia, childhood, memory, emotional anime. Trigger: Powerful memory trigger through sound.', '2026-01-27 15:44:38', '2026-01-27 15:44:38', 1),
(39, 'The \"Childhood Toy\" (Innocent Past)', 'Childhood toy showing innocent past, nostalgia, or lost innocence preserved in object. Visual Description: Childhood toy, often worn from love or carefully preserved. Shows innocent past, nostalgia for childhood, lost innocence, or preserved memory of who you were. Technical Details: Condition (Well-worn equals much loved in childhood, Pristine equals carefully preserved, Broken equals damaged past, Repaired equals trying to preserve memory), Type (Stuffed animal equals comfort object, Action figure equals hero worship, Doll equals innocence, Game or toy equals play), Context (Still kept as adult equals treasured past, Found in storage equals discovered past, Given away equals letting go, Carried always equals clinging to past). Symbolic Meanings: Innocent past, Childhood nostalgia, Lost innocence, Comfort object, Simpler times, Who you were before, Preserved memory, Inner child. Psychological Effect: Nostalgia, innocence, comfort, past, childhood, bittersweet, treasure, melancholy, longing, remembering. Common Contexts: Childhood memories, Lost innocence, Comfort seeking, Character background revelation, Nostalgia moments, Growing up themes, Letting go of past, Clinging to childhood. Worn From Love: Well-worn condition equals was much loved, very important. Adult Keeping: Adult still keeping childhood toy equals maintaining connection to innocent self. Letting Go: Giving away childhood toy equals growing up, moving on, accepting adulthood. Genre: Coming-of-age, nostalgia, childhood, psychological anime. Innocence: Represents lost or preserved innocence.', '2026-01-27 15:44:38', '2026-01-27 15:44:38', 1),
(40, 'The \"Faded Letter\" (Past Communication)', 'Old faded letter showing past communication, memory preserved in words, or message from gone person. Visual Description: Old, faded letter, often yellowed or worn from time. Shows past communication preserved, memory in written words, or message from someone now gone. Technical Details: Condition (Yellowed paper equals age and time, Worn from reading many times equals treasured, Faded ink equals very distant past, Torn edges equals fragile with age), Content (Often contains loving or important message), Context (Kept carefully equals treasured, Re-read repeatedly equals seeking comfort, Found accidentally equals discovering past, Hidden away equals protecting memory). Symbolic Meanings: Past communication, Words from gone person, Memory preserved in writing, Message across time, Treasured words, Connection to past, Cannot reply anymore, One-way communication now, Last words. Psychological Effect: Nostalgia, loss, treasure, memory, connection across time, bittersweet, longing, grief, comfort. Common Contexts: Lost loved ones, Old relationships, Historical connections, Treasured messages, Cannot contact anymore, Memory preservation, Words that last beyond person, Love letters. Re-reading: Character re-reading repeatedly equals seeking comfort from past, connection to gone person. Condition From Reading: Worn from many readings equals frequently returned to for comfort. One-Way: Cannot reply anymore equals permanent separation, one-way communication. Genre: Romance, loss, historical, memory anime. Permanence: Words outlast person who wrote them.', '2026-01-27 15:44:38', '2026-01-27 15:44:38', 1),
(41, 'The \"Falling Feather\" (Angel/Loss/Purity)', 'White feather drifting down showing angel presence, soul departing, or purity and grace. Visual Description: White feather floating down, drifting gently through air. Shows angel presence, soul departing from body, purity, or gentle loss with grace. Technical Details: Color Significance (White equals purity and angel, Black equals dark angel or death, Colored feather may carry specific meaning), Movement (Slow gentle drift, Spiraling descent, Floating gracefully), Context (After death equals soul departing body, From sky equals angel presence, Landing gently equals peaceful transition), Quantity (Single feather equals specific soul or angel, Multiple feathers equals divine presence). Symbolic Meanings: Angel presence, Soul departing body, Purity and innocence, Gentle peaceful death, Heaven calling soul, Lightness of spirit, Grace in death, Divine touch. Psychological Effect: Peace, loss, angel, purity, gentle, ethereal, spiritual, grace, sadness mixed with beauty, transcendence. Common Contexts: Death scenes, Angel presence, Peaceful departures, Pure characters dying, Spiritual moments, Soul visibly leaving body, Heavenly connection, Divine intervention. Cultural: Angels and feathers symbol across Western and some Asian traditions. Contrast: Lightness of feather contrasts dramatically with weight of death. Catching: Character catching falling feather equals connection to departed soul, receiving message. Genre: Spiritual, death, angelic, peaceful anime. Beauty: Makes death beautiful and gentle rather than harsh.', '2026-01-27 15:44:38', '2026-01-27 15:44:38', 1),
(42, 'The \"White Flowers at Grave\" (Memorial/Death)', 'White flowers placed at grave or memorial showing death, respectful memory, and mourning. Visual Description: White flowers, often lilies or chrysanthemums, placed carefully at grave, memorial, or death site. Shows respect for dead, memory honored, mourning ritual. Technical Details: Flower Type (White lily equals purity in death, Chrysanthemum equals death in Japanese culture, White rose equals pure love remembered forever), Placement (At gravestone equals memorial, At death site equals marking place, Fresh flowers equals recently placed, Wilting flowers equals time passed since visit), Context (Character placing equals active remembering, Already there equals others remember too, Many flowers equals well-loved person). Symbolic Meanings: Death memorial, Respect for dead, Memory honored, Mourning and grief, Pure remembrance, Life after death honored, Not forgotten, Love continuing. Psychological Effect: Mourning, respect, memory, loss, tribute, honor, grief, remembrance, continuing love, ritual. Common Contexts: Graveside scenes, Memorial visits, Death anniversaries, Mourning rituals, Respect paying, Not forgetting dead, Grief expression, Continuing bonds. Cultural Significance: White flowers specifically for death in many Asian cultures including Japan. Fresh Flowers: Fresh flowers indicate continuing care, memory, visits, love beyond death. Quantity: Number of flowers may carry specific significance or show how many remember. Genre: Death, mourning, memorial, family anime. Ritual: Important mourning and remembrance ritual.', '2026-01-27 15:44:38', '2026-01-27 15:44:38', 1),
(43, 'The \"Closed Book\" (Story Ended)', 'Book closing or closed showing story definitively ended, chapter finished, or life concluded. Visual Description: Book shown closing, being closed deliberately, or already closed. Shows story definitively ended, chapter finished completely, life concluded, or ending achieved and accepted. Technical Details: Closing Action (Character closes it equals accepting end, Slow deliberate close equals reluctant end, Firm decisive close equals definitive end, Final page shown before close equals conclusion visible), Book Type (Personal diary equals personal story, Novel equals fiction ended, Photo album equals memories concluded, History book equals era ended, Life book metaphor). Symbolic Meanings: Story definitively ended, Life concluded, Chapter finished completely, Narrative complete, No more to write, Final page turned, The End, Acceptance of ending, Closure. Psychological Effect: Finality, ending, conclusion, completion, closure, acceptance, finale, done, peace with ending, resolution. Common Contexts: Story endings, Life conclusions, Chapter endings, Accepting endings, Narrative conclusions, Series finales, Death metaphors, Closure moments, Moving on. Final Page: Often show final page or words before closing book for emphasis. Sound: Closing book sound can be emphasized for finality. Life as Book: Common metaphor of life as book or story being written. Genre: Meta, conclusive, finale, acceptance anime. Metaphor: Powerful metaphor for any ending or conclusion.', '2026-01-27 15:44:38', '2026-01-27 15:44:38', 1),
(44, 'The \"Empty Shoes\" (Absence/Death)', 'Empty shoes left behind showing devastating absence, someone gone forever, or death. Visual Description: Shoes shown empty with no feet in them, left behind. Shows absence, someone gone and not returning, death, or person missing. Technical Details: Placement (Neatly placed side by side equals planned departure or peaceful death, Scattered or fallen equals sudden departure or violence, At doorway equals never returned home, At bedside equals death in sleep, At edge equals suicide), Type (Child small shoes equals young death tragedy, Work shoes equals life interrupted, Special shoes equals identity, Worn shoes equals life lived), Condition (Pristine equals recent, Dusty equals time passed, Weathered equals long abandoned). Symbolic Meanings: Absence and devastating loss, Death, Person gone forever, Cannot walk anymore, Empty space left, Life interrupted, Someone missing, Never coming back, Stopped journey. Psychological Effect: Absence, loss, death, empty, gone, haunting, missing, void, stopped, tragic, finality. Common Contexts: Death scenes, Absence visualization, Missing persons, Suicide sites, Life interrupted, Memorial moments, Ghost stories, Abandonment, Tragedy. Japanese Cultural: Removing shoes before entering culturally significant making empty shoes powerful. Haunting: Empty shoes particularly haunting symbol of absence. Size: Shoe size tells story - child shoes especially tragic. Genre: Death, tragedy, loss, horror, memorial anime. Concrete: Makes abstract absence concrete and visible.', '2026-01-27 15:44:38', '2026-01-27 15:44:38', 1),
(45, 'The \"Last Candle\" (Final Light)', 'Single remaining candle lit while others extinguished showing last light, final hope, or end approaching. Visual Description: Single candle remaining lit while others around it are extinguished, or last candle burning down. Shows last hope, final light in darkness, or end approaching inevitably. Technical Details: Candle State (Still tall equals time remaining, Short and low equals nearly gone, Flickering dangerously equals struggling to survive, Burning steady equals determined resistance), Context (Only one left among many equals isolation, Others recently extinguished equals companions lost, Burning down equals time running out, Wind threatens it equals danger to last hope), Flame (Flame size and stability indicate hope strength). Symbolic Meanings: Last light in darkness, Final hope remaining, End approaching, Sole survivor, Resistance continuing, Time running out, Last stand, Alone but not giving up, Final beacon. Psychological Effect: Last hope, ending approaching, final light, determination, isolation, time running out, resistance, courage, desperation. Common Contexts: Last hope moments, Sole survivors, Time running out, Final stands, Endings approaching, Resistance despite overwhelming odds, Last light in darkness, Refusing to give up. Extinguishing: Candle finally going out equals end, death, hope lost completely. Protecting: Character desperately protecting flame equals preserving last hope. Wind: Wind threatening candle equals danger to last hope, forces trying to extinguish. Genre: Dark, desperate, last stand, resistance anime. Symbol: Powerful symbol of desperate hope.', '2026-01-27 15:44:38', '2026-01-27 15:44:38', 1),
(46, 'The \"Setting Sun\" (Day Ending/Life Fading)', 'Sun setting below horizon showing day ending, life fading away, or era concluding. Visual Description: Sun shown setting below horizon, light steadily fading. Shows day ending, life fading away, era concluding, or entering twilight years. Technical Details: Setting Stages (Afternoon light equals decline beginning, Golden hour equals beautiful ending, Touching horizon equals end imminent, Below horizon equals ended completely), Color (Often orange and red creating melancholic beauty), View (Ocean sunset equals vast ending, Mountain sunset equals peaceful natural end, City sunset equals life continues for others), Light Quality (Fading light creating long shadows and twilight). Symbolic Meanings: Day ending, Life fading away, Era concluding, Twilight years, Beautiful ending, Time running out, Darkness coming, Mortality, Last light, Peaceful end. Psychological Effect: Ending, melancholy, beauty, fading, twilight, peace, conclusion, mortality, bittersweet, acceptance. Common Contexts: Life endings, Era conclusions, Peaceful deaths, Reflective moments, Day ending, Character departures, Final scenes, Mortality contemplation, Twilight years. Beauty Despite: Often beautiful despite representing ending - finding beauty in mortality. Opposite: Sunrise represents beginning versus sunset representing ending. Twilight: Brief twilight period before darkness represents liminal time. Genre: Contemplative, mortality, peaceful ending, reflective anime. Universal: Sunset as ending symbol crosses all cultures.', '2026-01-27 15:44:38', '2026-01-27 15:44:38', 1),
(47, 'The \"Broken Necklace/Jewelry\" (Bond Severed)', 'Necklace or jewelry breaking showing bond severed, protection lost, or connection ended. Visual Description: Necklace, bracelet, ring, or jewelry shown breaking, snapping, falling off, or discovered broken. Shows bond severed, protection lost, or connection definitively ended. Technical Details: Break Type (Snaps under stress equals breaking point reached, Violently torn off equals forceful severing, Falls off naturally equals natural ending, Found already broken equals discovered past break), Jewelry Type (Necklace equals connection broken, Ring equals commitment or marriage broken, Bracelet equals bond severed, Charm or amulet equals protection lost), Significance (Often gift from important person now lost). Symbolic Meanings: Bond severed completely, Connection broken, Protection lost, Relationship ended, Gift rejected or lost, Commitment broken, Death of giver, Curse or protection broken, Tie cut. Psychological Effect: Loss, severing, broken bond, unprotected, connection lost, relationship ended, grief, vulnerability, separation. Common Contexts: Relationship endings, Death of giver, Protection failing, Bonds breaking, Commitments broken, Gifts from deceased, Symbolic breaking, Curse breaking, Separation. Slow Motion: Often shown in dramatic slow motion emphasizing moment. Pieces Falling: Pieces falling away equals bond scattered, irreparable damage. Desperate Retrieve: Desperate attempt to catch falling pieces equals trying desperately to save bond. Genre: Romance, tragedy, loss, relationship anime. Finality: Emphasizes finality of severed bond.', '2026-01-27 15:44:38', '2026-01-27 15:44:38', 1),
(48, 'The \"Final Letter\" (Last Words)', 'Final letter being written or found showing last words, goodbye, or final message from departed. Visual Description: Letter being written knowing it is final communication, or final letter found after death. Shows last words, final goodbye, final message that cannot be answered. Technical Details: Writing (Careful deliberate writing equals thoughtful goodbye, Shaking hand equals deep emotion, Pausing frequently equals difficulty finding words, Final signature equals finished and final), Finding (Addressed to specific person equals meant for them, Unsealed equals never finished or rushed, Tear stains visible equals emotional writing, Hidden equals meant to be found later), Content (Usually contains love, apology, explanation, or important final message). Symbolic Meanings: Last words spoken, Final goodbye, Death letter, Suicide note, Legacy message, Cannot say in person, Final communication, One-way conversation, Love expressed finally, Truth revealed. Psychological Effect: Finality, grief, last words, goodbye, loss, weight of final message, cannot respond or ask questions, closure or lack thereof. Common Contexts: Death scenes, Suicide, Before dangerous mission, Final goodbyes, Cannot say in person, Legacy letters, Last communications, Unfinished business, Truth revealed after death. Reading: Character reading final letter equals receiving last message, cannot reply. Unfinished: Letter left unfinished equals sudden death, ran out of time. Keeping Forever: Recipient keeping letter forever equals treasuring last words. Genre: Death, tragedy, war, final goodbye anime. Weight: Carries tremendous emotional weight as final communication.', '2026-01-27 15:44:38', '2026-01-27 15:44:38', 1),
(49, 'The \"Funeral Incense\" (Ritual Ending)', 'Incense burning at funeral or memorial showing ritual respect, soul ascending, and finality. Visual Description: Incense burning at funeral, memorial service, or altar. Shows ritual respect for dead, final goodbye ritual, spiritual journey of soul, or ongoing memorial. Technical Details: Incense Type (Stick incense equals individual offering, Coil incense equals continuous remembrance, Smoke rising equals soul ascending to heaven), Setting (Altar equals memorial space, Graveside equals burial ritual, Home shrine equals ongoing remembrance and ancestor worship), Action (Lighting incense equals honoring dead, Smoke rising equals prayers ascending, Burning down completely equals ritual time passing, Multiple sticks equals multiple mourners). Symbolic Meanings: Ritual respect for dead, Soul ascending to heaven, Final goodbye ritual, Prayers for dead, Buddhist tradition, Memorial and remembrance, Honoring deceased, Spiritual journey, Continuing bonds. Psychological Effect: Respect, ritual, finality, spiritual, memorial, grief expressed ritually, tradition, peace, acceptance, connection. Common Contexts: Funeral scenes, Memorial services, Buddhist death rituals, Ancestor worship, Honoring dead, Spiritual moments, Death rituals, Continuing remembrance, Annual memorials. Cultural Significance: Strong Buddhist tradition in Japanese culture, deeply meaningful. Smoke: Smoke carries prayers and soul to heaven in belief. Continuous: Some incense burns continuously at shrines showing eternal remembrance. Genre: Death ritual, Buddhist, memorial, cultural anime. Sacred: Sacred ritual connecting living and dead.', '2026-01-27 15:44:38', '2026-01-27 15:44:38', 1),
(50, 'The \"Scattered Ashes\" (Final Release)', 'Ashes being scattered showing final release, ultimate freedom, or return to nature cycle. Visual Description: Cremated ashes shown being scattered into wind, water, or earth. Wind carrying them away, water dispersing them, or earth receiving them. Shows final release, freedom in death, return to nature. Technical Details: Location Significance (Sea or ocean equals return to vastness, Mountain peak equals return to heights and freedom, Garden or forest equals return to earth and nature, Wind scattered equals complete freedom everywhere), Method (Slow reverent release equals respect, Cast to wind equals freedom, Poured to water equals flowing away, Buried in earth equals return to soil), Dispersal (Ashes spreading, dissolving, disappearing, becoming part of everything). Symbolic Meanings: Final release and freedom, Freedom in death, Return to nature cycle, No grave binding soul, Scattered everywhere therefore everywhere, Becoming part of world, Ultimate freedom, Dissolution, Cycle completed. Psychological Effect: Release, freedom, peace, return to nature, letting go completely, dissolution, acceptance, finality, transcendence. Common Contexts: Cremation conclusions, Final wishes honored, Return to nature, Freedom in death, No binding grave desired, Spiritual release, Letting go completely, Becoming one with nature. Wind and Water: Elements carrying ashes away equals complete release from earthly bonds. Everywhere: Being scattered everywhere equals becoming part of everything, omnipresent in nature. Choice: Often deceased specific wish showing they chose freedom over grave. Genre: Death, freedom, nature, spiritual, peaceful anime. Liberation: Ultimate liberation from physical form and earthly bonds.', '2026-01-27 15:44:38', '2026-01-27 15:44:38', 1);
INSERT INTO `anivoc_transitions` (`id`, `name`, `description`, `created_at`, `updated_at`, `is_ingredient`) VALUES
(1, 'The \"Iris Wipe\" (Circle Close/Open)', 'Circular transition that closes or opens like a camera iris. Visual Description: Circular shape that either contracts to close a scene (iris out) or expands to reveal a new scene (iris in). Can be centered on important element or character. Creates vintage/classic film feeling. Technical Details: Direction (Iris Out closing to point or Iris In opening from point), Center Point (can be centered on character, object, or screen center), Speed (quick snap or slow dramatic close), Edge Quality (sharp circle or soft feathered edge). Timing: Usually 0.5-2 seconds. Emotional Effect: Focus on specific element, vintage charm, comedic end, finality, spotlight effect. Common Contexts: Comedy endings, focusing on reaction, old-fashioned storytelling, episode endings, dramatic emphasis. Narrative Uses: Iris Out on character\'s face = Their POV/reaction important, Iris In on location = Revealing new place, Snap Iris = Comic timing/sudden end. Cultural Association: Silent film era, Looney Tunes endings, classic animation. Variation: Can use star, heart, or custom shapes for specific effects.', '2026-01-27 00:02:04', '2026-01-27 00:02:04', 1),
(2, 'The \"Wipe Curtain\" (Sliding Scene Transition)', 'One scene slides away like a curtain revealing the next. Visual Description: Previous scene slides off screen in a direction (left, right, up, down, diagonal) as new scene slides in from opposite direction. Can have hard edge or push previous scene out. Technical Details: Direction (left, right, up, down, diagonal), Edge Type (hard cut, soft dissolve edge, or geometric shape edge), Speed (quick wipe 0.3s to slow dramatic 2s), Pattern (can be straight, zigzag, or complex shape). Timing: 0.3-2 seconds typically. Emotional Effect: Dynamic movement, connection between scenes, energy, forward momentum, deliberate transition. Common Contexts: Location changes, time jumps, perspective switches, action to action, training montages. Directional Meanings: Left-to-Right = Forward progress/Western reading, Right-to-Left = Flashback/reverse/Eastern reading, Top-to-Bottom = Descent/passage of time/weight, Bottom-to-Top = Rising/hope/elevation. Variations: Clock Wipe (rotating arm like clock hand), Diagonal Wipe (dynamic, action-oriented), Venetian Blind (multiple parallel wipes). Star Wars Famous: Made iconic by Star Wars scene transitions.', '2026-01-27 00:02:04', '2026-01-27 00:02:04', 1),
(3, 'The \"Shatter Cut\" (Breaking Glass Transition)', 'Scene breaks like glass into the next scene. Visual Description: Current scene fractures and shatters like glass, pieces flying away to reveal next scene beneath or between cracks. Creates dramatic, violent, or breakthrough feeling. Technical Details: Crack Pattern (radial from impact point or overall pattern), Fragment Behavior (pieces fall, fly outward, or dissolve), Reveal Method (new scene visible between cracks or beneath), Sound Integration (glass breaking sound effect common). Timing: 0.5-1.5 seconds for shatter effect. Emotional Effect: Violent break, reality shattering, breakthrough, dramatic reveal, world changing, illusion breaking. Common Contexts: Reality revelations, breaking illusions, violent emotional breaks, flashback interruptions, awakening moments. Symbolic Meanings: Shattered Mirror = Identity/self-image broken, Shattered Window = Barrier broken, Shattered Screen = Fourth wall break/simulation revealed. Variation Types: Impact Shatter (from specific point outward), Overall Crack (entire scene cracks at once), Slow Crack Spread (tension building before shatter). Psychological Impact: Jarring, shocking, emphasizes dramatic change.', '2026-01-27 00:02:04', '2026-01-27 00:02:04', 1),
(4, 'The \"Split Screen Convergence\" (Joining Paths)', 'Multiple split screens merge into single unified scene. Visual Description: Screen divided into sections showing different characters/locations, then divisions dissolve or sections zoom/move together to become single scene where they meet. Technical Details: Initial Split (2-way vertical/horizontal to 4-way or more), Merge Method (lines dissolve, sections zoom together, or slide together), Timing Sync (often shows simultaneous actions before merge), Final Unity (all characters/elements now in same scene). Timing: Split can hold 2-10 seconds before merge (0.5-1s). Emotional Effect: Parallel paths converging, destiny meeting, team assembly, multiple perspectives uniting. Common Contexts: Characters traveling to same destination, team gathering, phone conversations meeting in person, parallel story convergence. Narrative Functions: Show Simultaneous Actions (building tension/excitement), Character Assembly (team coming together), Cause-Effect (action in one split affects another). Phone Conversation Specific: Classic for showing both sides of call before meeting. Resolution: When splits merge, represents unity/meeting achieved.', '2026-01-27 00:02:04', '2026-01-27 00:02:04', 1),
(5, 'The \"Kaleidoscope Rotation\" (Fragmented Spin)', 'Scene breaks into kaleidoscope pattern that rotates to new scene. Visual Description: Current scene fragments into repeated geometric pattern (like kaleidoscope), rotates, and pattern resolves into new scene. Creates psychedelic, magical, or dream-like transition. Technical Details: Pattern Type (triangular, hexagonal, or custom geometric repetition), Rotation (60°, 90°, 180°, or full 360°), Symmetry (radial symmetry around center point), Resolution (pattern coalesces back into coherent image). Timing: 1-2 seconds for full rotation and resolution. Emotional Effect: Disorientation, magic, transformation, psychedelic, dream logic, reality shifting. Common Contexts: Magical transformations, drug/poison effects, entering dream world, reality warping, magical portals. Associated Genres: Magical girl transformations, psychedelic sequences, dream episodes. Color Treatment: Often enhanced saturation or shifted colors during effect. Symbolism: Fragmentation and reconstruction = transformation, change of state.', '2026-01-27 00:02:04', '2026-01-27 00:02:04', 1),
(6, 'The \"Page Flip\" (Book/Manga Turn)', 'Scene transitions like turning pages of a book or manga. Visual Description: Scene appears to be on page that flips/turns to reveal next scene on next page. Can flip like book (vertical axis) or calendar (top tear). Often includes page texture. Technical Details: Flip Direction (book page right to left or left to right, calendar top to bottom), Page Texture (can show paper texture, edges, slight curl), Flip Speed (quick snap or slow deliberate turn), Back Side (can show reverse of page or immediate new scene). Timing: 0.5-1.5 seconds per page turn. Emotional Effect: Storybook feeling, narrative progression, chapter ending, controlled pacing, meta-awareness. Common Contexts: Narrated stories, flashbacks, educational sequences, story-within-story, breaking into chapters. Variations: Manga Page Turn (right to left with manga panel aesthetics), Photo Album (multiple photos on page), Calendar Tear (daily progression shown). Narrative Meta: Acknowledges story-being-told nature. Pacing Tool: Slows transition, gives viewer moment to process.', '2026-01-27 00:02:04', '2026-01-27 00:02:04', 1),
(7, 'The \"Spiral Transition\" (Vortex Scene Change)', 'Scene spirals away/inward while new scene spirals in/outward. Visual Description: Current scene spirals inward to center point and disappears while new scene spirals outward from same point, or vice versa. Creates vortex, tunnel, or whirlpool effect. Technical Details: Direction (inward spiral sucked in or outward spiral emerging), Rotation (clockwise or counterclockwise), Center Point (can be center of screen or off-center significant point), Distortion (scene can stretch/warp as it spirals). Timing: 0.7-2 seconds for complete spiral transition. Emotional Effect: Dizzying, magical, portal travel, time travel, being pulled/pushed, vortex of change. Common Contexts: Time travel, portal transitions, falling into memories, being sucked into other world, transformation sequences. Directional Meanings: Inward Spiral = Being pulled in/descending/going deeper, Outward Spiral = Emerging/ascending/expanding. Physics Association: Whirlpool, tornado, black hole, portal. Combination: Often combined with color shifts during spiral.', '2026-01-27 00:02:04', '2026-01-27 00:02:04', 1),
(8, 'The \"Puzzle Pieces\" (Assembling Scene)', 'New scene assembles from pieces like jigsaw puzzle. Visual Description: Next scene appears in fragments/pieces that slide, fall, or fade into place, building complete image. Can start random or organized. Creates assembly/construction feeling. Technical Details: Piece Shape (jigsaw puzzle shapes, rectangles, irregular fragments), Assembly Order (random, organized left-to-right/top-down, or revealing specific element first), Movement (pieces slide in, fall into place, or fade in), Final Lock (pieces settling into final position). Timing: 1-3 seconds depending on piece count. Emotional Effect: Mystery assembling, understanding forming, pieces coming together, construction, revelation. Common Contexts: Mysteries being solved, memories reforming, understanding dawning, plans coming together. Narrative Metaphor: Literal \"pieces coming together\". Variations: Important Element First (reveals focus then context), Scattered Assembly (chaotic understanding), Methodical Build (logical progression). Reverse Effect: Can also show scene breaking into puzzle pieces to transition out.', '2026-01-27 00:02:04', '2026-01-27 00:02:04', 1),
(9, 'The \"Expanding Frame\" (Growing Window)', 'Small frame/window expands to fill screen with new scene. Visual Description: New scene starts as small rectangle, circle, or shape that grows to fill entire screen, replacing previous scene. Like zooming into photo or expanding window. Technical Details: Initial Shape (rectangle, circle, or custom shape), Starting Size (small thumbnail to medium window), Expansion (smooth growth to fullscreen), Starting Position (center, corner, or position of relevant object). Timing: 0.5-1.5 seconds expansion time. Emotional Effect: Zooming into detail, focusing attention, importance of this scene, diving deeper, commitment to new perspective. Common Contexts: Flashbacks, focusing on photographs/screens, entering memories, revealing details, POV shifts. Common Uses: Photo Expansion (flashback from photograph), Screen Expansion (entering digital world), Window Expansion (focusing on view outside), Memory Expansion (entering recalled memory). Reverse Effect: Scene can shrink to transition out. Attention Direction: Naturally draws eye to expanding element.', '2026-01-27 00:02:04', '2026-01-27 00:02:04', 1),
(10, 'The \"Curtain Reveal\" (Theater Curtain)', 'Theatrical curtains part or close for scene change. Visual Description: Stage curtains (usually red velvet) either close to end scene or part to reveal new scene. Can open horizontally (splitting center) or rise vertically. Creates theatrical, performative feeling. Technical Details: Curtain Type (horizontal split parting center or vertical rise lifting up), Curtain Style (classic red velvet or styled to match show aesthetic), Speed (slow dramatic reveal or quick snap open), Completion (curtains fully offscreen or visible at edges). Timing: 1-3 seconds for full open/close. Emotional Effect: Theatrical, performance beginning/ending, dramatic reveal, meta-theatrical awareness, showmanship. Common Contexts: Show-within-show, breaking into performance, meta moments, chapter endings, dramatic reveals. Narrative Meaning: Curtain Opening = Show/story beginning/revelation, Curtain Closing = End/intermission/conclusion. Color Symbolism: Red curtains = classic theater, other colors for specific moods. Meta-Commentary: Acknowledges performative nature of storytelling.', '2026-01-27 00:02:04', '2026-01-27 00:02:04', 1),
(11, 'The \"Clock Wipe\" (Time Passage Indicator)', 'Clock hand sweeps around like wipe, indicating time passing. Visual Description: Wipe transition where the wipe edge follows circular path like clock hand sweeping. Often includes actual clock imagery or time indicators. Shows passage of time while transitioning. Technical Details: Start Position (usually 12 o\'clock position), Sweep Direction (clockwise forward time or counterclockwise backward time), Completeness (can be full 360° or partial sweep), Clock Imagery (may include actual clock face or just circular wipe pattern). Timing: 0.5-2 seconds for sweep, depending on time passage indicated. Emotional Effect: Time passing, hours/days passing, temporal progression, waiting, countdown. Common Contexts: Time skips, showing hours passing, deadline approaching, waiting periods, daily routines. Time Amount Indicated: Quarter turn (90°) = Hours, Half turn (180°) = Half day, Full turn (360°) = Full day/cycle, Multiple turns = Days/weeks. Direction Meaning: Clockwise = Moving forward in time, Counterclockwise = Flashback/going back. Combination: Often combined with changing light (day to night) or calendar pages.', '2026-01-27 00:02:04', '2026-01-27 00:02:04', 1),
(12, 'The \"Calendar Flip\" (Days/Months Passing)', 'Calendar pages flip rapidly showing time progression. Visual Description: Calendar pages tear away or flip rapidly, with dates visible, showing passage of days, weeks, or months. Pages can blow away, fall, or dissolve. Classic time-passing indicator. Technical Details: Page Style (wall calendar, desk calendar, or date cards), Flip Speed (slow for days to rapid blur for months/years), Detail Level (specific dates visible or just blur of passing), Movement (pages fly away, fall down, or flip in place). Timing: 1-3 seconds typically, longer for more time passing. Emotional Effect: Time flying, montage feeling, waiting period, progression, routine passage. Common Contexts: Training montages, waiting periods, showing time between events, seasonal changes, aging. Variation Types: Slow Flip (days passing, specific dates matter), Rapid Blur (weeks/months passing quickly), With Scenes (calendar flips between scene snippets), Seasonal Progression (calendar with seasonal imagery). Cultural Variation: Western calendars, Eastern calendars, or universal date displays. Combination: Often with other time indicators (clock, seasons, aging).', '2026-01-27 00:02:04', '2026-01-27 00:02:04', 1),
(13, 'The \"Seasonal Transition\" (Nature\'s Time Passage)', 'Same location shown through different seasons to indicate time. Visual Description: Same scene/location shown with seasonal changes - spring blossoms to summer green to autumn leaves to winter snow - indicating months passing. Emphasizes nature\'s cycle. Technical Details: Season Count (can show 2, 3, or all 4 seasons), Transition Style (fade, dissolve, wipe, or morph between seasons), Speed (quick flashes or held moments for each season), Constancy (same camera angle/framing showing change). Timing: 2-5 seconds showing multiple seasons. Emotional Effect: Time\'s passage, nature\'s cycle, change and constancy, melancholy, life\'s progression. Common Contexts: Time skips, relationship development over time, training periods, waiting, life changes. Seasonal Associations: Spring = New beginnings/youth/hope, Summer = Peak/energy/fullness, Autumn = Change/melancholy/maturity, Winter = Ending/death/rest/waiting. Emotional Depth: More poetic and melancholic than calendar flip. Visual Poetry: Beautiful way to show time\'s passage.', '2026-01-27 00:02:04', '2026-01-27 00:02:04', 1),
(14, 'The \"Sun/Moon Cycle\" (Day/Night Rapid Cycle)', 'Sun and moon rapidly cycle across sky showing time passing. Visual Description: Sun rises, arcs across sky, sets, moon rises, arcs across, sets, repeat. Shows day/night cycles rapidly. Sky colors change accordingly. Shadows rotate with sun position. Technical Details: Speed (single cycle one day to many rapid cycles weeks/months), Sky Colors (full color progression dawn/day/dusk/night), Shadow Movement (shadows rotate around fixed point following sun), Cloud Movement (time-lapse cloud movement). Timing: 2-5 seconds for single cycle, longer for multiple. Emotional Effect: Time flying, relentless passage, routine, cycles of life, persistence, waiting. Common Contexts: Long waits, training montages, construction time-lapse, recovery periods, persistent effort. Mathematical Precision: Shows exact passage of time (X days/nights). Character State: Often shows character in same position throughout, emphasizing persistence or stasis. Combination: Often combined with other changes (growth, construction progress, seasonal changes).', '2026-01-27 00:02:04', '2026-01-27 00:02:04', 1),
(15, 'The \"Aging Morph\" (Character Age Progression)', 'Character\'s appearance morphs through ages to show time. Visual Description: Character\'s face/body morphs through different ages - child to teen to adult to elderly - showing years passing in seconds. Face stays centered while features age. Technical Details: Age Stages (can show 2-7+ different ages), Morph Style (smooth blend or discrete jumps), Speed (slow deliberate emphasizing each age or quick long time span), Consistency (same angle, expression changes with age). Timing: 3-8 seconds depending on age range shown. Emotional Effect: Life passing, mortality, growth, time\'s effect, life journey, poignant reflection. Common Contexts: Life flashbacks, \"what if\" scenarios, showing character\'s full life, memory sequences, mortality reflection. Emotional Weight: Often bittersweet or melancholic. Reverse Effect: Can show aging backward (regression, remembering youth). Photo Album Variation: Can jump between photos at different ages instead of smooth morph.', '2026-01-27 00:02:04', '2026-01-27 00:02:04', 1),
(16, 'The \"Time-Lapse Build\" (Construction/Growth Progression)', 'Building being constructed or plant growing rapidly. Visual Description: Shows progression of construction (building going up) or growth (plant sprouting, growing, blooming) in rapid time-lapse. Indicates weeks/months passing through progress. Technical Details: Subject Type (building construction, plant growth, art creation, any progressive process), Frame Rate (stop-motion style jumps or smooth time-lapse), Progress Stages (shows beginning, middle stages, completion), Movement (workers moving quickly, sun cycling, shadows changing). Timing: 3-10 seconds depending on project scope. Emotional Effect: Progress, persistence, growth, achievement, effort paying off, time\'s creative power. Common Contexts: Training results, construction projects, artistic creation, recovery/healing, relationship building. Metaphorical Use: Building Construction = Building relationship/organization/life, Plant Growth = Character growth/natural development, Art Creation = Skill development/creative process. Satisfaction: Completion provides satisfaction/payoff. Background Detail: Often used as background while other story continues.', '2026-01-27 00:02:04', '2026-01-27 00:02:04', 1),
(17, 'The \"Reverse Rewind\" (Time Running Backward)', 'Action plays in reverse showing time going backwards. Visual Description: Scene plays in reverse - water flowing backward, people walking backward, objects un-breaking, smoke being sucked back in. Shows time literally reversing or flashback beginning. Technical Details: Reverse Speed (real-time reverse, fast reverse, or slow-motion reverse), Completeness (partial rewind or full scene reversal), End Point (can stop at flashback point or continue to beginning), Visual Clarity (obvious it\'s reverse unnatural or smooth enough to seem forward at first). Timing: Varies greatly, 2 seconds to full scene length. Emotional Effect: Flashback starting, do-over, turning back time, undoing, regret, second chance, time manipulation. Common Contexts: Entering flashbacks, time manipulation powers, \"what if\" scenarios, regret visualization, rewinding to explain. Narrative Uses: Flashback Entry (rewinding to show what happened before), Time Powers (character actually reversing time), Explanation (rewinding to show missed detail), Do-Over (showing alternative action). Sound Design: Often includes reverse sound effects or silence. Visual Markers: May include reverse motion lines, counter-clockwise indicators.', '2026-01-27 00:02:04', '2026-01-27 00:02:04', 1),
(18, 'The \"Freeze Frame Progression\" (Stopped Moments Sequence)', 'Series of frozen moments showing progression through time. Visual Description: Sequence of still freeze-frames, each showing a different moment in time, creating flipbook effect. Like photo sequence or security camera snapshots. Shows progression in discrete moments. Technical Details: Frame Count (3-20+ freeze frames), Hold Time (each frame holds 0.1-0.5 seconds), Progression (can be linear time progression or thematic/emotional progression), Frame Style (can include photo borders, timestamp, or be clean frames). Timing: 2-10 seconds total depending on frame count. Emotional Effect: Memory snapshots, significant moments, photo album feeling, documentary style, analytical perspective. Common Contexts: Showing relationship progression, investigation/analysis, memory sequences, photo albums, documentary style. Variations: Photo Album Style (with photo frames/borders), Security Footage (with timestamps, grainy quality), Flipbook Style (hand-drawn animation feel), Memory Flashes (quick emotional snapshots). Pacing Effect: Slows time, emphasizes specific moments. Analytical Distance: Creates slight emotional distance, viewing from outside.', '2026-01-27 00:02:04', '2026-01-27 00:02:04', 1),
(19, 'The \"Slow-Motion Bridge\" (Extended Moment Link)', 'Critical moment plays in slow-motion bridging to next scene. Visual Description: Action slows dramatically - falling object, expression changing, impact happening - stretched in time as next scene begins fading in or as voiceover bridges to new scene/time. Technical Details: Slow-Motion Degree (50% speed to extreme slow 1000fps look), Duration (2-5 seconds of slow-motion), Audio Treatment (sound pitched down, muted, or replaced with music/narration), Overlap (next scene can fade in while slow-motion continues). Timing: The critical moment stretched + overlap period. Emotional Effect: Importance emphasized, time suspended, critical realization, dramatic weight, moment of truth. Common Contexts: Life-changing moments, critical realizations, impacts/consequences, beautiful moments extended, emotional peaks. Narrative Function: Emphasize Importance (this moment matters deeply), Allow Processing (give viewer time to register), Create Beauty (make moment aesthetically powerful), Bridge Times (connect cause to distant effect). Audio Bridge: Often narration or music carries across time gap. Emotional Bridge: Connects emotional states across time.', '2026-01-27 00:02:04', '2026-01-27 00:02:04', 1),
(20, 'The \"Flash Forward Glimpse\" (Future Moment Preview)', 'Brief flash of future scene before returning to present. Visual Description: Quick flash (1-3 frames to full second) of future scene, then return to present. Flash can be clear or obscured/filtered. Creates anticipation or dramatic irony. Technical Details: Duration (single frame to 2 seconds), Clarity (crystal clear or filtered/obscured/partial), Frequency (single flash or repeated glimpses), Treatment (can be washed out, high contrast, or color-shifted). Timing: Flash is brief, return to present maintains flow. Emotional Effect: Anticipation, dread, dramatic irony, destiny glimpse, prophecy, motivation, warning. Common Contexts: Prophetic visions, foreshadowing, dramatic irony, motivation moments, destiny reveals, death flags. Narrative Purposes: Foreshadowing (hint at what\'s coming), Prophecy (character sees future), Dramatic Irony (audience knows what character doesn\'t), Motivation (future goal shown). Clarity Strategy: Clear = Audience understands fully (dramatic irony), Obscured = Mystery maintained until it happens. Emotional Manipulation: Creates anticipation or dread while maintaining present narrative.', '2026-01-27 00:02:04', '2026-01-27 00:02:04', 1),
(21, 'The \"Match Cut Shape\" (Visual Echo)', 'Similar shapes in consecutive scenes create seamless transition. Visual Description: Object or shape in Scene A transitions to similar shape in Scene B. Circle to circle, vertical line to vertical line, face to face. Creates visual continuity and elegant flow. Technical Details: Shape Matching (similar shapes, sizes, positions in frame), Transition Method (direct cut, brief dissolve, or morph), Precision (can be exact match or suggestive similarity), Movement (can include matching movement direction/speed). Timing: Usually direct cut (0 frames) or very brief dissolve. Emotional Effect: Elegant, smooth, connecting disparate elements, visual poetry, thematic linking. Common Examples: Moon to plate/ball/face, Coffee cup to tunnel/portal, Door to door, Eye to eye, Tower to tower/person standing. Narrative Purpose: Thematic Link (connect related ideas visually), Smooth Flow (elegant scene transition), Visual Metaphor (create meaning through juxtaposition), Time/Location (change setting while maintaining composition). Famous Example: \"2001: A Space Odyssey\" bone to spacecraft. Planning Required: Must be storyboarded/planned in advance.', '2026-01-27 00:02:04', '2026-01-27 00:02:04', 1),
(22, 'The \"Match Cut Action\" (Continued Movement)', 'Action continues across scene change - same movement in different context. Visual Description: Character performs action in Scene A (raising hand, turning head, falling) and continues exact same motion in Scene B but different time/place. Movement provides continuity. Technical Details: Action Type (any continuous motion - walking, reaching, turning, falling), Timing Match (motion speed and position must match precisely), Transition Point (cut happens mid-motion), Context Change (time, place, or both change while motion continues). Timing: Invisible cut during motion. Emotional Effect: Seamless flow, time/space fluidity, dream logic, connecting parallel moments, poetic transition. Common Examples: Character reaches for object, hand continues reaching in new scene; Person falling, continues falling in flashback/different place; Walking motion continues from one location to another; Turning head continues turn across time jump. Narrative Uses: Time Jump (continue action across time gap), Location Change (same action, new place), Parallel Moments (show similarity across different contexts), Memory Flow (present action triggers matching memory). Execution Challenge: Requires precise matching of motion and timing.', '2026-01-27 00:02:04', '2026-01-27 00:02:04', 1),
(23, 'The \"Match Cut Sound\" (Audio Bridge)', 'Sound continues across scene change creating continuity. Visual Description: Scene changes but sound from Scene A continues into Scene B before transitioning. Creates audio bridge. Can be diegetic (from scene) or non-diegetic (music/narration). Technical Details: Sound Type (dialog, sound effect, music, ambient sound), Overlap Duration (0.5-5 seconds of overlap), Volume Treatment (can fade or continue at same level), Source Reveal (may reveal sound actually belongs to Scene B). Timing: Visual cut with audio overlap. Emotional Effect: Smooth transition, connecting scenes through sound, disorienting then clarifying, playful editing. Common Examples: Character says \"Yes!\" in Scene A, revealed to be answering different question in Scene B; Alarm sound continues from dream to waking; Music from radio continues as time/place changes; Scream continues into scene of different character screaming. Types: J-Cut (audio from Scene B comes in before visual), L-Cut (audio from Scene A continues after visual cut), Sound Bridge (ambiguous sound belongs to both scenes). Clever Technique: Can create jokes or smooth transitions.', '2026-01-27 00:02:04', '2026-01-27 00:02:04', 1),
(24, 'The \"Match Cut Color\" (Chromatic Continuity)', 'Dominant color continues from scene to scene. Visual Description: Scenes transition while maintaining same dominant color. Red scene to red scene, blue to blue. Color provides visual continuity and can create thematic connection. Technical Details: Color Element (can be entire scene tone, specific object, or lighting color), Transition Type (direct cut or brief dissolve), Color Prominence (dominant to subtle), Thematic Use (color often carries meaning). Timing: Usually direct cut. Emotional Effect: Visual flow, thematic connection, emotional continuity, color symbolism, aesthetic cohesion. Common Examples: Blood red to red sunset, Blue water to blue sky, Fire orange to sunset orange, Green forest to green eyes. Color Symbolism: Red = Passion/blood/danger/love, Blue = Sadness/calm/cold/distance, Green = Nature/envy/sickness/life, Yellow/Gold = Hope/wealth/divine, Purple = Mystery/royalty/magic. Narrative Connection: Color can thematically link scenes. Aesthetic Cohesion: Creates beautiful visual flow.', '2026-01-27 00:02:04', '2026-01-27 00:02:04', 1),
(25, 'The \"Echo Transition\" (Repeated Action)', 'Same action repeated in different contexts showing connection. Visual Description: Specific action (gesture, phrase, ritual) shown in Scene A, then repeated in Scene B in different context, showing parallel, evolution, or ironic contrast. Technical Details: Action Type (physical gesture, spoken phrase, ritual action), Framing (often similar camera angle/composition), Repetition Type (exact replica, variation, or ironic inversion), Contexts (different times, characters, or circumstances). Timing: Each instance full action, transition between them varies. Emotional Effect: Parallel drawing, evolution showing, contrast highlighting, theme reinforcing, poetic repetition. Common Examples: Character performs gesture as child, again as adult (growth); Hero does action, villain does same (parallel); Phrase said in happiness, repeated in tragedy (irony); Daily ritual shown across time showing change/constancy. Narrative Uses: Parallel (showing similarity between situations), Evolution (how action/meaning changes over time), Contrast (ironic difference in contexts), Theme (reinforcing central theme through repetition). Symbolism: Repeated action becomes symbolic through context changes. Character Development: Shows how character has changed (or hasn\'t) through same action in different context.', '2026-01-27 00:02:04', '2026-01-27 00:02:04', 1),
(26, 'The \"Eye to Eye\" (Gaze Match)', 'Cut matching character eyes creating connection or confrontation. Visual Description: Cut from one character\'s eyes directly to another character\'s eyes. Creates instant connection, confrontation, or understanding between characters. Technical Details: Framing (Eyes positioned similarly in frame), Focus (Sharp focus on eyes), Expression (Eye expression carries emotional transition), Timing (Usually held briefly before or after cut). Emotional Effect: Connection, confrontation, understanding, challenge, recognition, soul-gazing. Common Uses: Character confrontations, Recognition moments, Challenges, Understanding reached, Soul connections, Rivalry establishment. Cultural Significance: Eyes as \"windows to soul\" universal concept across cultures. Genre: Drama, action, rivalry, psychological anime.', '2026-02-01 12:14:11', '2026-02-01 12:14:11', 1),
(27, 'The \"Hand to Hand\" (Action Continuity)', 'Matching hand positions or actions across cut. Visual Description: Cut matches hand position or action from one shot to another, creating seamless action flow or symbolic connection. Technical Details: Position Match (Hand in same screen position), Action Match (Same gesture or movement), Object (Often passing or reaching for same object), Timing (Matched to create seamless flow). Types: Reaching to grasping, Passing object, Gesture continuation, Touch connection. Emotional Effect: Connection, continuity, flow, seamlessness, symbolic link. Common Uses: Action sequences, Object passing, Connection moments, Continuity creation, Symbolic links. Practical Purpose: Creates smooth action flow across cuts. Genre: Action, drama, any genre needing smooth flow.', '2026-02-01 12:14:11', '2026-02-01 12:14:11', 1),
(28, 'The \"Reflection to Reality\" (Mirror Match)', 'Cut from reflection to actual subject or vice versa. Visual Description: Cut from character\'s reflection (mirror, water, glass) to actual character or reverse, creating identity, duality, or self-examination theme. Technical Details: Framing (Similar composition), Angle (Often flipped/reversed), Focus (Shift from reflection to real), Reveal (Can reveal difference between reflection and reality). Symbolic Meanings: Self-examination, Identity questions, Duality, True self vs. facade, Inner vs. outer. Emotional Effect: Self-reflection, identity, duality, introspection, revelation. Common Uses: Character self-examination, Identity themes, Duality reveals, Introspection moments, Morning routines. Revelation Potential: Can show reflection different from reality for dramatic effect. Genre: Psychological, drama, identity-focused anime.', '2026-02-01 12:14:11', '2026-02-01 12:14:11', 1),
(29, 'The \"Silhouette to Detail\" (Reveal Match)', 'Cut from silhouette to detailed view revealing character. Visual Description: Cut from character as silhouette or shadow to detailed view, revealing identity, details, or true appearance. Technical Details: Contrast (From dark shape to lit detail), Position (Matched position/pose), Reveal (Progressive detail revelation), Timing (Dramatic pause before reveal). Emotional Effect: Revelation, drama, identity reveal, mystery solved, dramatic entrance. Common Uses: Character reveals, Identity unveiling, Dramatic entrances, Mystery solving, Villain reveals, Hero arrivals. Drama Creation: Creates dramatic impact through progressive revelation. Genre: Mystery, thriller, action, dramatic anime.', '2026-02-01 12:14:11', '2026-02-01 12:14:11', 1),
(30, 'The \"Through the Gap\" (Portal Match)', 'Cut through gap, hole, or frame in previous shot. Visual Description: Camera appears to move through gap, doorway, window, or hole in previous shot, transitioning to new scene beyond. Technical Details: Gap Types (Door, window, hole, tunnel, legs, arms), Movement (Implied forward movement), Position (Gap centered before transition), Reveal (New scene beyond gap). Emotional Effect: Discovery, transition, passing through, entering new space, curiosity. Common Uses: Location changes, Entering new areas, Discovery moments, Portal transitions, Perspective shifts, Voyeuristic views. Tone Flexibility: Can be playful or serious depending on context. Genre: Adventure, mystery, any transition-heavy anime.', '2026-02-01 12:14:11', '2026-02-01 12:14:11', 1),
(31, 'The \"Sound Bridge\" (Audio Link)', 'Sound from next scene starts before visual cut. Visual Description: Audio from upcoming scene begins while still showing current scene, then cuts to match visual and audio. Technical Details: Lead Time (Sound starts 1-3 seconds before cut), Types (Dialogue, music, sound effects, ambient), Volume (Usually fades in or starts suddenly), Match (Visual cut matches audio already playing). Emotional Effect: Anticipation, connection between scenes, smooth flow, foreshadowing. Common Uses: Scene transitions, Foreshadowing, Connecting related scenes, Smooth flow, Time passage, Phone conversations. Editing Tradition: Classic editing technique used across all visual media. Genre: Universal across all genres.', '2026-02-01 12:14:11', '2026-02-01 12:14:11', 1),
(32, 'The \"Musical Phrase Cut\" (Rhythm Match)', 'Cut timed precisely to musical beat or phrase. Visual Description: Cut occurs exactly on musical beat, phrase end, or dramatic musical moment, creating rhythm and energy. Technical Details: Timing (Precise to beat, downbeat, or phrase), Music Types (Any music with clear beats), Energy (Matches musical energy), Multiple Cuts (Often series of cuts on beats). Emotional Effect: Energy, rhythm, musicality, excitement, flow, dance-like quality. Common Uses: Action sequences, Montages, Music videos, Dance sequences, Opening/ending credits, Energetic scenes. Editing Style: Similar to music video editing techniques. Genre: Action, music, idol, energetic anime.', '2026-02-01 12:14:11', '2026-02-01 12:14:11', 1),
(33, 'The \"Silence to Sound\" (Audio Reveal)', 'Cut from silence to sudden sound or vice versa. Visual Description: Dramatic cut from complete silence to sudden sound, or from sound to shocking silence, creating impact. Technical Details: Contrast (Maximum audio contrast), Timing (Sudden, no fade), Impact (Creates shock or relief), Types (Silence to explosion, sound to death silence). Emotional Effect: Shock, impact, relief, drama, emphasis, death, life. Common Uses: Explosion reveals, Death moments, Shock cuts, Dream to reality, Emphasis, Dramatic moments. Impact Creation: Maximum dramatic impact through audio contrast. Genre: Action, drama, thriller, horror anime.', '2026-02-01 12:14:11', '2026-02-01 12:14:11', 1),
(34, 'The \"Diegetic to Non-Diegetic\" (Sound Source Shift)', 'Music transitions from source in scene to soundtrack. Visual Description: Music starts as diegetic (source visible in scene like radio, performance) then becomes non-diegetic soundtrack as scene changes. Technical Details: Source (Starts with visible source), Transition (Seamless shift to soundtrack), Quality (May change in quality during shift), Continues (Music continues across scene change). Emotional Effect: Immersion, smooth transition, playful awareness, connection. Common Uses: Music-focused scenes, Performance to montage, Radio to soundtrack, Party to elsewhere, Playful transitions. Meta Quality: Plays with audience awareness of soundtrack and diegetic boundaries. Genre: Music, comedy, meta, self-aware anime.', '2026-02-01 12:14:11', '2026-02-01 12:14:11', 1),
(35, 'The \"Echo Transition\" (Sound Repeat)', 'Sound repeats or echoes as transition element. Visual Description: Sound from first scene echoes or repeats as transition to second scene, connecting them thematically or temporally. Technical Details: Repeat (Sound repeats across cut), Echo (Sound echoes with effects), Types (Dialogue, sound effects, music), Decay (May decay or transform). Emotional Effect: Memory, connection, haunting, emphasis, reverberation, impact lasting. Common Uses: Important dialogue emphasis, Trauma moments, Memory connections, Echoing consequences, Time passage, Haunting moments. Emphasis Function: Emphasizes importance of sound/words through repetition. Genre: Psychological, drama, trauma anime.', '2026-02-01 12:14:11', '2026-02-01 12:14:11', 1),
(36, 'The \"Crescendo Cut\" (Musical Peak)', 'Cut occurs at musical crescendo or climax. Visual Description: Cut timed to occur at exact moment of musical crescendo, climax, or dramatic peak, maximizing emotional impact. Technical Details: Timing (Precise to musical peak), Build (Music builds to cut), Impact (Maximum impact at peak), Visual (Often matches musical intensity). Emotional Effect: Climax, peak emotion, maximum impact, catharsis, triumph, tragedy. Common Uses: Climactic moments, Revelations, Transformations, Victories, Defeats, Emotional peaks. Cathartic Function: Creates cathartic emotional release through perfect timing. Genre: Drama, action, emotional, climactic anime.', '2026-02-01 12:14:11', '2026-02-01 12:14:11', 1),
(37, 'The \"Whisper to Scream\" (Volume Match)', 'Cut matches extreme volume change for effect. Visual Description: Cut from whisper or quiet sound directly to scream or loud sound, or reverse, creating shock or relief. Technical Details: Contrast (Extreme volume difference), Types (Quiet to loud, loud to quiet), Timing (Sudden shift, no fade), Impact (Creates strong emotional reaction). Emotional Effect: Shock, relief, contrast, emphasis, surprise, impact. Common Uses: Horror scares, Shock moments, Contrast emphasis, Calm to chaos, Tension to release. Horror Technique: Common horror technique for creating jump scares. Genre: Horror, thriller, action, dramatic anime.', '2026-02-01 12:14:11', '2026-02-01 12:14:11', 1),
(38, 'The \"Dialogue Overlap\" (Conversation Bridge)', 'Dialogue from next scene overlaps current scene. Visual Description: Character begins speaking in next scene while still showing current scene, creating smooth conversational flow. Technical Details: Overlap (1-2 seconds typical), Visual (Cuts during dialogue), Flow (Creates conversational rhythm), Context (Provides context before visual). Emotional Effect: Flow, connection, anticipation, smooth transition, context. Common Uses: Conversation scenes, Explanations, Narration transitions, Story flow, Flashback setups. Natural Flow: Creates natural conversational flow across scenes. Genre: Universal, particularly dialogue-heavy anime.', '2026-02-01 12:14:11', '2026-02-01 12:14:11', 1),
(39, 'The \"Song Lyric Match\" (Thematic Audio)', 'Cut timed to match song lyrics thematically. Visual Description: Visual cut shows imagery that matches or contrasts with song lyrics being sung, creating meaning. Technical Details: Synchronization (Visual matches lyric meaning), Timing (Cut on key lyric words), Contrast (Can match or ironically contrast), Meaning (Creates layered meaning). Emotional Effect: Thematic depth, irony, meaning, connection, poetry. Common Uses: Opening/ending sequences, Montages with songs, Music scenes, Thematic emphasis, Ironic contrast. Music Video Style: Music video style editing creating visual-lyrical synergy. Genre: Music, opening/endings, montage-heavy anime.', '2026-02-01 12:14:11', '2026-02-01 12:14:11', 1),
(40, 'The \"Heartbeat Rhythm\" (Internal Sound)', 'Cuts follow heartbeat rhythm for tension. Visual Description: Cuts timed to heartbeat sound, creating tension, fear, or anticipation with rhythmic editing. Technical Details: Rhythm (Follows heartbeat tempo), Acceleration (Often accelerates), Sound (Heartbeat audible or implied), Intensity (Builds tension). Emotional Effect: Tension, fear, anticipation, anxiety, intensity, biological. Common Uses: Tension building, Fear scenes, Anticipation, Chase sequences, Panic, Anxiety. Visceral Impact: Creates visceral biological response in audience. Genre: Thriller, horror, tension, suspense anime.', '2026-02-01 12:14:11', '2026-02-01 12:14:11', 1),
(41, 'The \"Falling Transition\" (Descent Match)', 'Character or object falling transitions to new scene. Visual Description: Character or object falling in first scene transitions to falling in second scene, or falling transitions to landed/different context. Technical Details: Continuity (Fall continues across cut), Speed (Matched falling speed), Direction (Maintained direction), Landing (May land in different context). Symbolic Meanings: Descent, falling, Loss of control, Metaphorical fall, Time passage, Fate. Emotional Effect: Falling, descent, loss of control, fate, inevitability. Common Uses: Dream sequences, Time passage, Metaphorical falls, Location changes, Despair visualization. Symbolic Function: Often symbolic of character arc or emotional state. Genre: Psychological, metaphorical, surreal anime.', '2026-02-01 12:14:11', '2026-02-01 12:14:11', 1),
(42, 'The \"Flame Transition\" (Fire Link)', 'Flame, fire, or burning transitions scenes. Visual Description: Flame, fire, candle, or burning object in first scene transitions to flame or fire in second scene, linking through fire. Technical Details: Element (Fire, flame, embers, smoke), Match (Similar fire positions), Meaning (Fire connects scenes thematically), Types (Candle, campfire, explosion, passion). Symbolic Meanings: Passion, Destruction, Transformation, Life force, Continuity of spirit. Emotional Effect: Passion, intensity, transformation, destruction, life, spirit. Common Uses: Passion transitions, Destruction sequences, Spirit continuation, Transformation, Life force, Thematic links. Elemental Connection: One of four classical elements used for symbolic linking. Genre: Action, passionate, transformative anime.', '2026-02-01 12:14:11', '2026-02-01 12:14:11', 1),
(43, 'The \"Water Flow\" (Liquid Transition)', 'Water, rain, or liquid flowing transitions scenes. Visual Description: Water, rain, tears, or liquid in first scene flows or transitions to water/liquid in second scene. Technical Details: Element (Water, rain, tears, rivers, ocean), Flow (Flowing movement connects), Meaning (Water theme connects), Types (Tears, rain, rivers, ocean waves). Symbolic Meanings: Emotion flowing, Time flowing, Life flowing, Tears, Cleansing, Change. Emotional Effect: Emotion, time flowing, sadness, cleansing, change, life. Common Uses: Emotional transitions, Time passage, Cleansing, Sadness, Life flow, Thematic water. Elemental Connection: Classical element representing emotion and flow. Genre: Emotional, time-passage, thematic anime.', '2026-02-01 12:14:11', '2026-02-01 12:14:11', 1),
(44, 'The \"Light to Dark\" (Illumination Shift)', 'Transition from light to darkness or vice versa. Visual Description: Scene transitions from light to darkness or darkness to light, creating symbolic meaning through illumination change. Technical Details: Direction (Light to dark, or dark to light), Meaning (Symbolic of hope/despair), Method (Gradual or sudden), Source (Any light source change). Symbolic Meanings: Hope to despair (light to dark), Despair to hope (dark to light), Knowledge to ignorance, Life to death, Good to evil. Emotional Effect: Hope, despair, change, moral shift, life, death, knowledge. Common Uses: Moral changes, Hope/despair shifts, Life/death, Knowledge reveals, Character arcs. Universal Symbolism: Light/dark symbolism universal across cultures. Genre: Moral, philosophical, dramatic anime.', '2026-02-01 12:14:11', '2026-02-01 12:14:11', 1),
(45, 'The \"Seasonal Shift\" (Nature Transition)', 'Transition shows seasonal change for time passage. Visual Description: Scene transitions showing seasonal change - leaves falling, snow melting, flowers blooming - indicating time passage. Technical Details: Seasons (Spring, summer, fall, winter), Markers (Leaves, snow, flowers, weather), Time (Shows time passage clearly), Types (Quick montage or single cut). Symbolic Meanings: Time passing, Life cycles, Change, Growth, Endings and beginnings. Emotional Effect: Time passage, change, life cycles, nostalgia, growth. Common Uses: Time passage montages, Year passing, Growth over time, Change visualization, Life cycles. Natural Cycles: Uses nature\'s own cycles to show passage of time. Genre: Slice-of-life, time-passage, growth anime.', '2026-02-01 12:14:11', '2026-02-01 12:14:11', 1),
(46, 'The \"Birth to Death\" (Life Cycle)', 'Symbolic transition showing life cycle extremes. Visual Description: Transition from birth imagery to death imagery, or reverse, showing complete life cycle or ironic contrast. Technical Details: Imagery (Birth: baby, egg, beginning to death: grave, end), Meaning (Life cycle, irony, fate), Direction (Birth to death, or death to rebirth), Contrast (Can be tragic or hopeful). Symbolic Meanings: Life cycle, Mortality, Rebirth, Cycle continues, Irony of life. Emotional Effect: Mortality, cycle, irony, life, death, continuity. Common Uses: Philosophical moments, Life cycle themes, Mortality, Rebirth, Ironic contrasts, Fate. Profound Impact: Creates profound meaning about existence. Genre: Philosophical, life-focused, mortality anime.', '2026-02-01 12:14:11', '2026-02-01 12:14:11', 1),
(47, 'The \"Mirror to Mirror\" (Reflection Link)', 'Transition through mirrors or reflective surfaces. Visual Description: Transition moves through mirror or reflection in first scene to mirror or reflection in second scene, creating doubled reality. Technical Details: Surfaces (Mirrors, water, glass, eyes), Match (Reflective surface to reflective surface), Meaning (Reality, duality, inner/outer), Reveal (May reveal truth vs. facade). Symbolic Meanings: Duality, Reality vs. reflection, Inner vs. outer self, Truth, Multiple realities. Emotional Effect: Duality, truth, reflection, inner/outer, mystery. Common Uses: Identity themes, Truth reveals, Duality, Multiple realities, Self-examination. Philosophical Depth: Creates philosophical depth about reality and identity. Genre: Psychological, identity, philosophical anime.', '2026-02-01 12:14:11', '2026-02-01 12:14:11', 1),
(48, 'The \"Dream to Reality\" (State Shift)', 'Transition from dream state to waking reality. Visual Description: Transition from dream (often surreal, soft focus, different color) to harsh reality, showing state change. Technical Details: Visual Change (Surreal to real, soft to sharp), Color (Often desaturated dream to saturated reality), Sound (Different sound quality), Trigger (Often alarm, sound, or shock). Symbolic Meanings: Fantasy to reality, Hope to harsh truth, Escape to confrontation, Illusion to truth. Emotional Effect: Awakening, harsh reality, disillusionment, confrontation, truth. Common Uses: Waking up scenes, Fantasy to reality, Disillusionment, Truth confrontation, Escape ended. Harsh Reality: Often emphasizes harshness of reality versus dream. Genre: Psychological, reality-focused, dream anime.', '2026-02-01 12:14:11', '2026-02-01 12:14:11', 1);
INSERT INTO `anivoc_transitions` (`id`, `name`, `description`, `created_at`, `updated_at`, `is_ingredient`) VALUES
(49, 'The \"Memory Fade\" (Temporal Blur)', 'Transition with fading or blurring for memory/time. Visual Description: Scene fades or blurs as it transitions to memory or past, becoming softer, different quality, often sepia or desaturated. Technical Details: Blur (Soft focus, motion blur), Fade (Gradual opacity change), Color (Often sepia, warm, or desaturated), Quality (Dreamlike, soft). Symbolic Meanings: Memory, Past, Time distance, Nostalgia, Fading memory. Emotional Effect: Nostalgia, memory, past, time distance, fading, gentle. Common Uses: Flashbacks, Memory sequences, Time passage, Nostalgia, Past events. Gentle Quality: Creates gentle transition to past or memory. Genre: Memory, flashback, nostalgic anime.', '2026-02-01 12:14:11', '2026-02-01 12:14:11', 1),
(50, 'The \"Transformation Morph\" (Metamorphosis)', 'Smooth morph transition showing transformation. Visual Description: One image smoothly morphs into another, showing transformation, connection, or metaphorical change. Technical Details: Morph (Smooth transformation), Speed (Slow to fast), Types (Character to character, object to object), Meaning (Transformation, connection, becoming). Symbolic Meanings: Transformation, Becoming, Connection, Metaphorical change, Evolution. Emotional Effect: Transformation, change, connection, becoming, evolution. Common Uses: Transformation sequences, Character connections, Metaphorical changes, Evolution, Time passage changes, Before/after. Smooth Transformation: Creates smooth visual transformation between states. Genre: Transformation, magical girl, evolution anime.', '2026-02-01 12:14:11', '2026-02-01 12:14:11', 1);
INSERT INTO `audio_counter` (`id`, `next_audio`) VALUES
(1, 1);
INSERT INTO `audio_voice_identity` (`id`, `name`, `description`, `model_path`, `created_at`, `updated_at`) VALUES
(27, 'alloy', 'alloy - Pollinations Qwen TTS preset voice', 'pollinations API', '2026-04-14 12:55:58', '2026-04-14 12:55:58'),
