INSERT INTO `interactions` (`id`, `name`, `description`, `interaction_group`, `category`, `example_prompt`, `active`, `created_at`, `updated_at`, `is_ingredient`) VALUES
(1, 'Ask Simple Question', 'One character asks a simple question.', 'Everyday', 'Question', 'Character asks: \"How are you?\"', 1, '2025-11-26 16:46:02', NULL, 1),
(2, 'Small Talk While Working', 'Two characters exchange small talk while occupied with a task.', 'Everyday', 'SmallTalk', 'Two characters chat about nothing while fixing the radio.', 1, '2025-11-26 16:46:02', NULL, 1),
(3, 'Handing Object', 'Someone hands an object to another.', 'Everyday', 'Transfer', 'One character hands an object to another; describe the exchange.', 1, '2025-11-26 16:46:02', NULL, 1),
(4, 'Casual Observation', 'A character observes something and comments casually.', 'Everyday', 'Observation', 'Character notices something small and comments aloud.', 1, '2025-11-26 16:46:02', NULL, 1),
(5, 'Walk Together', 'Two characters walk together without talking.', 'Everyday', 'Walk', 'Two characters walk side by side in silence.', 1, '2025-11-26 16:46:02', NULL, 1),
(6, 'Quick Joke', 'A character makes a quick joke; the other reacts.', 'Everyday', 'Joke', 'A quick joke lands and the other gives a half-smile.', 1, '2025-11-26 16:46:02', NULL, 1),
(7, 'Simple Instruction', 'Someone gives simple instructions to another.', 'Everyday', 'Instruction', 'One character says: \"Do this, then that.\"', 1, '2025-11-26 16:46:02', NULL, 1),
(8, 'Show Object', 'A character shows something (phone, object, photo).', 'Everyday', 'Show', 'A character lifts a photo and says, \"Look at this.\"', 1, '2025-11-26 16:46:02', NULL, 1),
(9, 'Greeting/Goodbye', 'A short greeting or goodbye.', 'Everyday', 'Greeting', 'A quick \"Hi\" or \"Bye\" exchanged at the door.', 1, '2025-11-26 16:46:02', NULL, 1),
(10, 'Check In', 'A character checks on someone\'s well-being.', 'Everyday', 'CheckIn', 'Character asks: \"Are you okay?\"', 1, '2025-11-26 16:46:02', NULL, 1),
(11, 'Solve Problem Together', 'Two characters solve a problem together.', 'Cooperative', 'ProblemSolving', 'Two characters work together to fix the problem.', 1, '2025-11-26 16:46:02', NULL, 1),
(12, 'Help Carry', 'One character helps another carry something.', 'Cooperative', 'Help', 'One character assists another with a heavy object.', 1, '2025-11-26 16:46:02', NULL, 1),
(13, 'Group Brainstorm', 'Group gathers and exchanges ideas.', 'Cooperative', 'Brainstorm', 'A group trades quick ideas around the table.', 1, '2025-11-26 16:46:02', NULL, 1),
(14, 'Teach Something', 'Someone teaches something to someone else.', 'Cooperative', 'Teach', 'One character demonstrates how to do a task.', 1, '2025-11-26 16:46:02', NULL, 1),
(15, 'Coordinate Movement', 'Two characters coordinate movement or action.', 'Cooperative', 'Coordinate', 'They synchronize their actions to move the crate.', 1, '2025-11-26 16:46:02', NULL, 1),
(16, 'Warn of Danger', 'Someone warns another before danger.', 'Cooperative', 'Warning', 'One character hisses: \"Watch out!\"', 1, '2025-11-26 16:46:02', NULL, 1),
(17, 'Boost Confidence', 'One character boosts another\'s confidence.', 'Cooperative', 'Encourage', '\"You can do this,\" says one, steadying the other.', 1, '2025-11-26 16:46:02', NULL, 1),
(18, 'Announce Plan', 'Characters share a common goal and announce a plan.', 'Cooperative', 'Plan', 'The group agrees on a clear next step.', 1, '2025-11-26 16:46:02', NULL, 1),
(19, 'Volunteer', 'Someone volunteers to take responsibility.', 'Cooperative', 'Volunteer', 'A character steps forward and says: \"I\'ll do it.\"', 1, '2025-11-26 16:46:02', NULL, 1),
(20, 'Explain Discovery', 'A character explains a discovery to the group.', 'Cooperative', 'Explain', '\"Look what I found,\" explains the character.', 1, '2025-11-26 16:46:02', NULL, 1),
(21, 'Start Disagreement', 'Two characters start a disagreement.', 'Conflict', 'Argument', 'Two characters begin arguing over a decision.', 1, '2025-11-26 16:46:02', NULL, 1),
(22, 'Accuse', 'One character accuses another.', 'Conflict', 'Accusation', 'One accuses the other: \"You did this!\"', 1, '2025-11-26 16:46:02', NULL, 1),
(23, 'Refuse Cooperation', 'A character refuses to cooperate.', 'Conflict', 'Refusal', 'Character crosses arms and says: \"No.\"', 1, '2025-11-26 16:46:02', NULL, 1),
(24, 'Harsh Truth Revealed', 'Harsh truth is revealed.', 'Conflict', 'Reveal', 'A hard truth is spoken and the room falls silent.', 1, '2025-11-26 16:46:02', NULL, 1),
(25, 'Aggressive Interruption', 'A character interrupts someone aggressively.', 'Conflict', 'Interrupt', 'A sharp interruption cuts off the sentence.', 1, '2025-11-26 16:46:02', NULL, 1),
(26, 'Demand Explanation', 'Someone demands an explanation.', 'Conflict', 'Demand', '\"Explain yourself,\" one demands.', 1, '2025-11-26 16:46:02', NULL, 1),
(27, 'Calm Attempt Fails', 'One character tries to calm another but fails.', 'Conflict', 'CalmFail', 'An attempt to soothe only fans the flame.', 1, '2025-11-26 16:46:02', NULL, 1),
(28, 'Group Splits', 'Group splits into factions.', 'Conflict', 'Faction', 'People divide into opposing sides.', 1, '2025-11-26 16:46:02', NULL, 1),
(29, 'Abrupt Heated Exchange', 'A heated exchange ends abruptly.', 'Conflict', 'HeatedExchange', 'A sudden argument that stops on a gasp.', 1, '2025-11-26 16:46:02', NULL, 1),
(30, 'Silent Standoff', 'Silent standoff — no words, only tension.', 'Conflict', 'Standoff', 'Silence thickens between them.', 1, '2025-11-26 16:46:02', NULL, 1),
(31, 'Open Up About Fear', 'Someone opens up about a fear.', 'Emotional', 'OpenUp', 'A character admits a deep fear in a low voice.', 1, '2025-11-26 16:46:02', NULL, 1),
(32, 'Comforting', 'A character comforts another physically or verbally.', 'Emotional', 'Comfort', 'A soft touch and quiet words: \"It\'ll be okay.\"', 1, '2025-11-26 16:46:02', NULL, 1),
(33, 'Confession of Love', 'Someone confesses admiration or love.', 'Emotional', 'Confession', 'A blunt confession: \"I love you.\"', 1, '2025-11-26 16:46:02', NULL, 1),
(34, 'Reminisce', 'Two characters reminisce about the past.', 'Emotional', 'Reminisce', 'They share a faded memory and laugh softly.', 1, '2025-11-26 16:46:02', NULL, 1),
(35, 'Deep Apology', 'A character apologizes deeply.', 'Emotional', 'Apology', '\"I\'m sorry,\" offered with visible regret.', 1, '2025-11-26 16:46:02', NULL, 1),
(36, 'Reveal Secret', 'Someone reveals a secret.', 'Emotional', 'Secret', 'A whispered secret changes everything.', 1, '2025-11-26 16:46:02', NULL, 1),
(37, 'Mutual Understanding', 'Mutual understanding without speaking.', 'Emotional', 'Understanding', 'Eyes meet and everything is suddenly clear.', 1, '2025-11-26 16:46:02', NULL, 1),
(38, 'Warm Embrace', 'A warm embrace or close gesture.', 'Emotional', 'Embrace', 'Two characters hold each other for a long beat.', 1, '2025-11-26 16:46:02', NULL, 1),
(39, 'Reassurance', 'Character reassures another during stress.', 'Emotional', 'Reassure', '\"You\'re not alone,\" a voice insists.', 1, '2025-11-26 16:46:02', NULL, 1),
(40, 'Express Regret', 'Someone expresses regret about a decision.', 'Emotional', 'Regret', 'A character admits they regret their choice.', 1, '2025-11-26 16:46:02', NULL, 1),
(41, 'Notice Something Unusual', 'One character notices something unusual.', 'Mystery', 'Notice', 'A glance catches an odd detail no one else sees.', 1, '2025-11-26 16:46:02', NULL, 1),
(42, 'Investigate Together', 'Characters investigate something together.', 'Mystery', 'Investigate', 'They inspect the scene, whispering clues.', 1, '2025-11-26 16:46:02', NULL, 1),
(43, 'Stay Quiet', 'Someone warns another to stay quiet.', 'Mystery', 'StayQuiet', '\"Don\'t make a sound,\" one hisses.', 1, '2025-11-26 16:46:02', NULL, 1),
(44, 'Cryptic Info', 'Character gives cryptic information.', 'Mystery', 'Cryptic', 'A cryptic line: \"It won\'t be there tomorrow.\"', 1, '2025-11-26 16:46:02', NULL, 1),
(45, 'Whispered Suspicion', 'Suspicious exchange in whispers.', 'Mystery', 'Whisper', 'Two exchange quiet, suspicious phrases.', 1, '2025-11-26 16:46:02', NULL, 1),
(46, 'Hide Object', 'Someone hides an object from another.', 'Mystery', 'Hide', 'An object slips beneath a coat unnoticed.', 1, '2025-11-26 16:46:02', NULL, 1),
(47, 'Realize Watched', 'Two people realize they\'re being watched.', 'Mystery', 'Watched', 'They share a look and freeze—someone is watching.', 1, '2025-11-26 16:46:02', NULL, 1),
(48, 'Decode Clue', 'Someone decodes a message or clue.', 'Mystery', 'Decode', 'A character mutters and deciphers a hidden note.', 1, '2025-11-26 16:46:02', NULL, 1),
(49, 'Lie and Avoid', 'A character lies and tries not to get caught.', 'Mystery', 'Lie', 'A hesitant lie meant to cover a secret.', 1, '2025-11-26 16:46:02', NULL, 1),
(50, 'Extract Information', 'Someone subtly tries to extract information.', 'Mystery', 'Extract', 'Soft questions probe for guarded facts.', 1, '2025-11-26 16:46:02', NULL, 1),
(51, 'Question Authority', 'One character questions another\'s authority.', 'Authority', 'QuestionAuthority', '\"Who made that decision?\" one asks.', 1, '2025-11-26 16:46:02', NULL, 1),
(52, 'Give Orders', 'Leader gives firm orders.', 'Authority', 'Orders', 'A leader barks a terse command.', 1, '2025-11-26 16:46:02', NULL, 1),
(53, 'Refuse Orders', 'Someone refuses to follow instructions.', 'Authority', 'RefuseOrders', 'A curt refusal to obey the order.', 1, '2025-11-26 16:46:02', NULL, 1),
(54, 'Negotiate Rights', 'A character negotiates power or rights.', 'Authority', 'Negotiate', 'A tense negotiation over control.', 1, '2025-11-26 16:46:02', NULL, 1),
(55, 'Silent Dominance', 'Someone asserts dominance silently (posture, gaze).', 'Authority', 'Dominance', 'A look that makes others shift uneasily.', 1, '2025-11-26 16:46:02', NULL, 1),
(56, 'Strict Mentorship', 'One character mentors another with strict tone.', 'Authority', 'Mentor', 'A hard lesson delivered without warmth.', 1, '2025-11-26 16:46:02', NULL, 1),
(57, 'Demand Loyalty', 'Someone demands loyalty.', 'Authority', 'DemandLoyalty', '\"You owe me loyalty,\" one declares.', 1, '2025-11-26 16:46:02', NULL, 1),
(58, 'Orders Under Pressure', 'Orders are given under pressure.', 'Authority', 'PressureOrders', 'Commands shouted over chaos.', 1, '2025-11-26 16:46:02', NULL, 1),
(59, 'Challenge Leader', 'Someone challenges a leader\'s decision.', 'Authority', 'Challenge', 'A direct challenge to the leader\'s call.', 1, '2025-11-26 16:46:02', NULL, 1),
(60, 'Group Vote', 'Group votes or decides collectively.', 'Authority', 'Vote', 'Members raise hands and the choice is made.', 1, '2025-11-26 16:46:02', NULL, 1),
(61, 'Run Together', 'Two characters run together from something.', 'Action', 'Run', 'They sprint side by side, breath ragged.', 1, '2025-11-26 16:46:02', NULL, 1),
(62, 'Pull Out of Danger', 'Someone pulls another out of danger.', 'Action', 'RescuePull', 'A grab and a pull to safety.', 1, '2025-11-26 16:46:02', NULL, 1),
(63, 'Hand-to-hand Struggle', 'Hand-to-hand struggle.', 'Action', 'Struggle', 'Hands grapple; the fight is close and raw.', 1, '2025-11-26 16:46:02', NULL, 1),
(64, 'Block Path', 'A character blocks another\'s path.', 'Action', 'Block', 'One steps into the other\'s way, stopping them.', 1, '2025-11-26 16:46:02', NULL, 1),
(65, 'Silent Escape', 'Someone tries to escape silently.', 'Action', 'Escape', 'A quiet shimmy toward an open window.', 1, '2025-11-26 16:46:02', NULL, 1),
(66, 'Lift/Move Heavy', 'Characters coordinate to lift/move something heavy.', 'Action', 'Lift', 'They heave the object together, grunting.', 1, '2025-11-26 16:46:02', NULL, 1),
(67, 'Fall Reaction', 'A character falls; another reacts.', 'Action', 'Fall', 'A stumble and an urgent reach to catch them.', 1, '2025-11-26 16:46:02', NULL, 1),
(68, 'Chase Sequence', 'Chase sequence interaction.', 'Action', 'Chase', 'Footsteps thunder as they chase through alleys.', 1, '2025-11-26 16:46:02', NULL, 1),
(69, 'Use Tool/Weapon', 'Someone fires or uses a tool/weapon.', 'Action', 'UseWeapon', 'A quick, decisive use of a tool or weapon.', 1, '2025-11-26 16:46:02', NULL, 1),
(70, 'Rescue Interaction', 'A rescue interaction.', 'Action', 'Rescue', 'One dives in to save the other from harm.', 1, '2025-11-26 16:46:02', NULL, 1),
(71, 'Quick Glance', 'Quick glance exchanged between characters.', 'Micro', 'Glance', 'A brief look that says more than words.', 1, '2025-11-26 16:46:02', NULL, 1),
(72, 'Hesitate', 'Someone hesitates before speaking.', 'Micro', 'Hesitation', 'A pause before the next sentence.', 1, '2025-11-26 16:46:02', NULL, 1),
(73, 'Fidget', 'A character fidgets with an object.', 'Micro', 'Fidget', 'Fingers toy with a small item, betraying nerves.', 1, '2025-11-26 16:46:02', NULL, 1),
(74, 'Shared Laughter', 'Shared laughter at something minor.', 'Micro', 'Laughter', 'They laugh together at a tiny, shared thing.', 1, '2025-11-26 16:46:02', NULL, 1),
(75, 'Avoid Eye Contact', 'Someone avoids eye contact.', 'Micro', 'AvoidEye', 'Eyes drop to the floor to hide emotion.', 1, '2025-11-26 16:46:02', NULL, 1),
(76, 'Small Gratitude', 'A small gesture of gratitude.', 'Micro', 'Gratitude', 'A quiet \"thanks\" and a nod.', 1, '2025-11-26 16:46:02', NULL, 1),
(77, 'Step Closer/Back', 'Character steps closer or backs away.', 'Micro', 'Proximity', 'One inches forward; the other retreats a beat.', 1, '2025-11-26 16:46:02', NULL, 1),
(78, 'Subtle Misunderstanding', 'A subtle misunderstanding.', 'Micro', 'Misunderstand', 'A slight misread of intention causes tension.', 1, '2025-11-26 16:46:02', NULL, 1),
(79, 'Outside Interruption', 'Short interruption by an outside event.', 'Micro', 'Interruption', 'A distant sound interrupts the moment.', 1, '2025-11-26 16:46:02', NULL, 1),
(80, 'Body Language Choice', 'Someone makes a choice based on body language.', 'Micro', 'BodyChoice', 'Decision made after reading the other\'s stance.', 1, '2025-11-26 16:46:02', NULL, 1),
(81, 'Argument Over Plan', 'Characters argue over a plan.', 'Group', 'PlanArgument', 'Voices rise as they dispute the plan.', 1, '2025-11-26 16:46:02', NULL, 1),
(82, 'Split Into Roles', 'Group splits into roles.', 'Group', 'Roles', 'Members take on different roles without discussion.', 1, '2025-11-26 16:46:02', NULL, 1),
(83, 'Ignored By Group', 'Someone is ignored by the group.', 'Group', 'Ignored', 'Their comment goes unnoticed; they flinch.', 1, '2025-11-26 16:46:02', NULL, 1),
(84, 'Majority vs One', 'Majority agrees while one objects.', 'Group', 'MajorityOne', 'A lone dissent is met with quiet majority assent.', 1, '2025-11-26 16:46:02', NULL, 1),
(85, 'Dramatic Announcement', 'Group listens to a dramatic announcement.', 'Group', 'Announcement', 'All fall silent for the announcement.', 1, '2025-11-26 16:46:02', NULL, 1),
(86, 'Try to Unify', 'Someone tries to unify the group.', 'Group', 'Unify', '\"Hear me out,\" someone pleads, seeking unity.', 1, '2025-11-26 16:46:02', NULL, 1),
(87, 'Moment of Silence', 'Characters take a moment of silence together.', 'Group', 'Silence', 'They stand together in a shared, reverent quiet.', 1, '2025-11-26 16:46:02', NULL, 1),
(88, 'Single Out Suspicious', 'Someone is singled out as suspicious.', 'Group', 'SingleOut', 'Eyes turn toward the one now suspected.', 1, '2025-11-26 16:46:02', NULL, 1),
(89, 'Offer Support', 'The group offers support to one member.', 'Group', 'Support', 'Multiple hands pat the shoulder in solidarity.', 1, '2025-11-26 16:46:02', NULL, 1),
(90, 'Spontaneous Decision', 'A spontaneous collective decision.', 'Group', 'SpontDecision', 'Without discussion, the group chooses to move.', 1, '2025-11-26 16:46:02', NULL, 1),
(91, 'Stranger Enters', 'A stranger enters the scene.', 'Plot', 'StrangerEnter', 'A stranger walks in, dripping rain and mystery.', 1, '2025-11-26 16:46:02', NULL, 1),
(92, 'Message Arrives', 'A message arrives unexpectedly.', 'Plot', 'Message', 'A sealed envelope is thrust across the table.', 1, '2025-11-26 16:46:02', NULL, 1),
(93, 'Loud Noise Interrupts', 'A loud noise interrupts everything.', 'Plot', 'Noise', 'A sudden crash halts conversation mid-sentence.', 1, '2025-11-26 16:46:02', NULL, 1),
(94, 'Discover Something Shocking', 'One character discovers something shocking.', 'Plot', 'Discovery', 'They uncover something that changes everything.', 1, '2025-11-26 16:46:02', NULL, 1),
(95, 'Unexpected Reunion', 'Unexpected visitor or reunion.', 'Plot', 'Reunion', 'An old face appears, stopping hearts.', 1, '2025-11-26 16:46:02', NULL, 1),
(96, 'Change of Mind', 'Someone changes their mind suddenly.', 'Plot', 'ChangeMind', '\"No—I changed my mind,\" one declares unexpectedly.', 1, '2025-11-26 16:46:02', NULL, 1),
(97, 'Reveal Shifts Plot', 'Character reveals new information that shifts the plot.', 'Plot', 'RevealShift', 'New info arrives and the course is altered.', 1, '2025-11-26 16:46:02', NULL, 1),
(98, 'Object Malfunctions', 'An object breaks or malfunctions.', 'Plot', 'Break', 'A tool snaps and plans derail.', 1, '2025-11-26 16:46:02', NULL, 1),
(99, 'Propose Risky Idea', 'Someone proposes a risky idea.', 'Plot', 'RiskyIdea', '\"What if we tried this?\" a risky proposal is made.', 1, '2025-11-26 16:46:02', NULL, 1),
(100, 'Time Pressure', 'Characters realize time is running out.', 'Plot', 'TimePressure', 'They glance at the clock and panic sets in.', 1, '2025-11-26 16:46:02', NULL, 1),
(101, 'Silent Gesture Exchange', 'Two characters communicate a complex idea using only a short, deliberate gesture or look. Subtext-heavy and precise.', 'Micro', 'Gesture', 'A single raised hand and a look convey the plan, no words.', 1, '2025-12-11 11:51:36', NULL, 1),
(102, 'Power Shift Through Placement', 'A character shifts their physical position so control of the scene is transferred without dialogue.', 'Authority', 'PowerShift', 'One character steps between another and the exit, unspoken command.', 1, '2025-12-11 11:51:36', NULL, 1),
(103, 'Prop-Driven Subtext', 'A prop is handled in a way that reveals a hidden relationship or secret.', 'Subtext', 'PropReveal', 'She fingers the old ticket and the air changes — he understands.', 1, '2025-12-11 11:51:36', NULL, 1),
(104, 'Micro-Restraint', 'A character restrains an impulse — the small physical act says more than speech.', 'Micro', 'Restraint', 'His hand hovers then drops; the decision is silently kept.', 1, '2025-12-11 11:51:36', NULL, 1),
(105, 'Revelatory Monologue (Quiet)', 'A soft, focused monologue that shifts the audience’s understanding of a character’s motive.', 'Emotional', 'Monologue', 'In a low voice she confesses what she cannot show anyone else.', 1, '2025-12-11 11:51:36', NULL, 1),
(106, 'Call-and-Response', 'Two characters trade short verbal beats that build tension or rapport rhythmically.', 'Everyday', 'DialoguePattern', 'He says one line; she answers with a counter-line that reframes it.', 1, '2025-12-11 11:51:36', NULL, 1),
(107, 'Match-Cut Cue', 'An object/action becomes the linking motif for a future cut or transition.', 'Plot', 'MatchCut', 'The clink of a spoon cuts to the door slamming in another scene.', 1, '2025-12-11 11:51:36', NULL, 1),
(108, 'Unreliable Narrator Slip', 'Small contradiction appears between narration and reality, prompting reinterpretation.', 'Mystery', 'Narration', 'The voiceover claims innocence as the camera lingers on a guilty passport.', 1, '2025-12-11 11:51:36', NULL, 1),
(109, 'False Calm Before Burst', 'A deliberate, fragile calm that immediately precedes an emotional outburst or action.', 'Tension', 'CalmBeforeStorm', 'They sip tea in silence — then the lamp shatters.', 1, '2025-12-11 11:51:36', NULL, 1),
(110, 'Triadic Tension', 'Three characters form a shifting alliance; offbeat beats show loyalties sliding.', 'Group', 'Triad', 'One tries to side with the second, the third looks away and the balance shifts.', 1, '2025-12-11 11:51:36', NULL, 1),
(111, 'Subtle Betrayal Reveal', 'A small, plausible act reveals a betrayal (a turned letter, an exchanged look).', 'Conflict', 'Betrayal', 'A note falls open, revealing the line that undoes trust.', 1, '2025-12-11 11:51:36', NULL, 1),
(112, 'Non-Verbal Negotiation', 'A negotiation through posture, object exchange, and timing rather than words.', 'Authority', 'Negotiation', 'They bargain with the placement of a watch on the table.', 1, '2025-12-11 11:51:36', NULL, 1),
(113, 'Slow-Burn Flirtation', 'Gradual flirtation displayed through repeated micro-beats across scenes.', 'Emotional', 'Flirtation', 'Small touches accumulate: a shoulder brush, then a shared smile.', 1, '2025-12-11 11:51:36', NULL, 1),
(114, 'Electric Confrontation', 'A short, high-voltage confrontation where silence does the damage.', 'Conflict', 'Confrontation', 'They stare for a beat; the silence contains the accusation.', 1, '2025-12-11 11:51:36', NULL, 1),
(115, 'Sacrificial Decision', 'One character chooses loss for another; the decision is decisive and quiet.', 'Emotional', 'Sacrifice', 'He hands over the key and walks away, no fanfare — the choice made.', 1, '2025-12-11 11:51:36', NULL, 1),
(116, 'Offbeat Comic Beat', 'A small physical mishap becomes a comic punctuation to a serious moment.', 'Micro', 'Comedy', 'She trips at the exact wrong syllable and everyone’s tension cracks.', 1, '2025-12-11 11:51:36', NULL, 1),
(117, 'Echoed Line', 'A line spoken earlier is echoed later with new meaning.', 'Plot', 'Echo', 'The line about \"home\" returns, now loaded with betrayal.', 1, '2025-12-11 11:51:36', NULL, 1),
