INSERT INTO `perspectives` (`id`, `scene_part_id`, `angle`, `description`, `created_at`, `updated_at`) VALUES
(1, 1, 'Wide shot, elevated angle over aurora gardens; emphasize verticality and mystical alignment of cosmic energy.', 'Calm anticipation; mystical aura; soft background illumination suggested for readability.', '2025-08-17 03:55:44', '2025-08-17 03:55:44'),
(2, 2, 'Medium tracking shot, eye-level; follow Lyra’s movement across platforms; highlight chaos in tight spaces.', 'Playful chaos; slight disorientation from misfires; humorous framing.', '2025-08-17 03:55:44', '2025-08-17 03:55:44'),
(3, 3, 'Low-angle shot; focus on agility and dynamic interaction; include depth for multi-level garden platforms.', 'Energetic and light-hearted; heroic emphasis; convey verticality of movement.', '2025-08-17 03:55:44', '2025-08-17 03:55:44'),
(4, 4, 'Over-the-shoulder tracking shot of Kai’s workstation; combine foreground (Gearbit) and floating mischief (Chipster) in midground.', 'Inventive, humorous tension between order and chaos.', '2025-08-17 03:55:44', '2025-08-17 03:55:44'),
(5, 5, 'Bird’s-eye view / top-down; capture aurora glow across gardens; emphasize lines of sight toward distant festival prep.', 'Awe and wonder; strategic overview; mystical cosmic energy pulses highlighted.', '2025-08-17 03:55:44', '2025-08-17 03:55:44'),
(6, 6, 'Multi-angle split (wide for environment, close-up for artifact cues); show vertical rooftops and multi-level gardens.', 'Suspenseful; anticipation; focus on subtle energy pulses and hero-anima interaction spaces.', '2025-08-17 03:55:44', '2025-08-17 03:55:44'),
(7, 7, 'Tracking wide shot converging toward central plaza; slight tilt to foreshadow villain presence from shadows.', 'Tension building; playful chaos continues in foreground; visual continuity into Scene 2.', '2025-08-17 03:55:44', '2025-08-17 03:55:44');
INSERT INTO `poses` (`id`, `name`, `description`, `category`, `created_at`, `updated_at`, `active`) VALUES
(1, 'Standing', 'Full-body standing pose, neutral stance, relaxed arms by sides, facing forward', 'Full body', '2025-08-23 23:20:43', '2025-08-23 23:20:43', 1),
(2, 'Running', 'Full-body running pose, dynamic motion, legs extended, arms pumping, leaning forward', 'Full body', '2025-08-23 23:20:43', '2025-08-23 23:20:43', 1),
(3, 'Fight Pose', 'Full-body combat-ready pose, slightly crouched, fists raised, focused expression', 'Full body', '2025-08-23 23:20:43', '2025-08-23 23:20:43', 1),
(4, 'Blushing', 'Full-body standing pose, slightly shy, head tilted, cheeks flushed, hands near face', 'Full body', '2025-08-23 23:20:43', '2025-08-23 23:20:43', 1),
(5, 'Laughing', 'Full-body pose, joyful expression, mouth open in laughter, body relaxed, arms slightly extended', 'Full body', '2025-08-23 23:20:43', '2025-08-23 23:20:43', 1),
(6, 'Sitting', 'Full-body sitting pose, upright on a chair or surface, hands on knees or lap, neutral expression', 'Full body', '2025-08-23 23:20:43', '2025-08-23 23:20:43', 1),
(7, 'Standing Neutral', 'Default idle pose. Weight slightly on one foot. Arms relaxed at sides, one hand loosely at hip or hanging. Shoulders even. Head forward. Stable, grounded. Use as: base template for dialogue scenes, idle NPC, neutral shot composition.', 'standard', '2026-02-01 18:30:50', '2026-02-01 18:30:50', 1),
(8, 'Arms Crossed', 'Both arms folded across the chest. Elbows tight. Hands tucked at the opposite bicep. Shoulders slightly raised. Weight on one hip. Head level or tilted slightly. Use as: defensive stance, skepticism, authority, waiting.', 'standard', '2026-02-01 18:30:50', '2026-02-01 18:30:50', 1),
(9, 'Hands on Hips', 'Both hands planted firmly on hips. Elbows out. Chest open. Confident stance — weight slightly forward. Head level or chin raised. Use as: authority, challenge, impatience, leader energy.', 'standard', '2026-02-01 18:30:50', '2026-02-01 18:30:50', 1),
(10, 'One Hand on Hip', 'Single hand resting casually on one hip. Other arm hanging loose or holding an object. Relaxed asymmetry. Hip cocked slightly. Use as: casual confidence, idol pose variant, waiting, light conversation.', 'standard', '2026-02-01 18:30:50', '2026-02-01 18:30:50', 1),
(11, 'Hands Clasped Behind Back', 'Both hands interlocked behind the back. Posture straight and formal. Weight centered. Head slightly elevated. Use as: authority figure, lecturer, inspector, calm villain surveying.', 'standard', '2026-02-01 18:30:50', '2026-02-01 18:30:50', 1),
(12, 'Hands Clasped in Front', 'Both hands clasped together at waist or chest height. Fingers interlocked. Posture composed. Use as: servant/butler stance, nervous prayer, polite waiting, formal greeting.', 'standard', '2026-02-01 18:30:50', '2026-02-01 18:30:50', 1),
(13, 'Prayer Pose (Hands at Chest)', 'Both palms pressed together at chest level, fingertips at chin. Elbows tucked in. Eyes closed or looking up. Use as: wishing, begging, reverence, idol signature, desperate hope.', 'standard', '2026-02-01 18:30:50', '2026-02-01 18:30:50', 1),
(14, 'Single Finger Point', 'One arm fully extended, index finger pointing directly forward or at target. Other arm at side or behind back. Confident or accusatory stance. Use as: challenge, accusation, declaration, \"you there!\".', 'standard', '2026-02-01 18:30:50', '2026-02-01 18:30:50', 1),
(15, 'Thumbs Up', 'One fist closed with thumb extended upward. Arm relaxed at side or raised to chest. Other hand free. Use as: approval, encouragement, cheerful confirmation, comedic OK.', 'standard', '2026-02-01 18:30:50', '2026-02-01 18:30:50', 1),
(16, 'Peace Sign (V-Sign)', 'Index and middle finger extended in V shape near face or chest. Other hand at side. Head may tilt. Use as: photo pose, idol greeting, casual cheerfulness, victory.', 'standard', '2026-02-01 18:30:50', '2026-02-01 18:30:50', 1),
(17, 'Hand on Chin (Thinking)', 'One hand supporting the chin, elbow resting on the other arm or a surface. Head tilted into the hand. Gaze distant or focused. Use as: contemplation, planning, boredom, deduction.', 'standard', '2026-02-01 18:30:50', '2026-02-01 18:30:50', 1),
(18, 'Hand on Forehead', 'One palm flat against the forehead. Elbow raised. Expression weary or frustrated. Other hand at side. Use as: headache, exasperation, \"why\", regret, migraine.', 'standard', '2026-02-01 18:30:50', '2026-02-01 18:30:50', 1),
(19, 'Hand Over Mouth', 'One hand covering the mouth and lower jaw. Palm flat or fingers splayed slightly. Eyes wide or narrow. Use as: shock, gasp, concealing laughter, hiding a smirk, secret.', 'standard', '2026-02-01 18:30:50', '2026-02-01 18:30:50', 1),
(20, 'Both Hands on Face', 'Both palms pressed against cheeks, fingers spread. Elbows at chest. Use as: horror, overwhelm, \"oh no\", comedic panic, blushing frame.', 'standard', '2026-02-01 18:30:50', '2026-02-01 18:30:50', 1),
(21, 'Fist Pump (Raised)', 'One or both fists raised overhead, clenched tight. Arms fully extended upward. Chest out. Use as: victory, determination, rallying cry, celebration.', 'standard', '2026-02-01 18:30:50', '2026-02-01 18:30:50', 1),
(22, 'Crossed Arms Lean', 'Arms crossed at chest. Body leaning back against a wall, railing, or doorframe. Weight shifted to one hip. Casual authority. Use as: waiting, guard duty, cool entrance, watching the scene unfold.', 'standard', '2026-02-01 18:30:50', '2026-02-01 18:30:50', 1),
(23, 'Sitting Seiza', 'Formal Japanese seated position. Knees together on the ground. Back straight. Hands on thighs or lap. Use as: formal meeting, apology setup, meditation, traditional scene.', 'standard', '2026-02-01 18:30:50', '2026-02-01 18:30:50', 1),
(24, 'Sitting Cross-Legged', 'Casual seated position on floor. Legs crossed loosely. Back relaxed. Hands on knees or in lap. Use as: casual rest, campfire scene, waiting room, training break.', 'standard', '2026-02-01 18:30:50', '2026-02-01 18:30:50', 1),
(25, 'Sitting at Desk (Hands Folded)', 'Seated at a desk or table. Both hands folded on the surface. Back straight. Facing forward. Use as: interrogation, business meeting, interview, villain in chair.', 'standard', '2026-02-01 18:30:50', '2026-02-01 18:30:50', 1),
(26, 'Leaning on Elbow (Table)', 'One elbow on a surface, hand supporting the head at the temple. Body relaxed, tilted. Use as: boredom, listening lazily, casual conversation, half-asleep.', 'standard', '2026-02-01 18:30:50', '2026-02-01 18:30:50', 1),
(27, 'Back Turn (Walking Away)', 'Character facing away from camera. Back fully visible. Arms at sides or one hand in pocket. Mid-stride or standing still. Use as: dramatic exit, rejection, ignoring someone, mysterious departure.', 'standard', '2026-02-01 18:30:50', '2026-02-01 18:30:50', 1),
(28, 'Over-Shoulder Look Back', 'Body angled away, head turned over one shoulder to look back at camera/target. Hair may drape across face. Use as: goodbye glance, \"follow me\", flirtatious look, warning.', 'standard', '2026-02-01 18:30:50', '2026-02-01 18:30:50', 1),
(29, 'Profile Stand', 'Body fully in profile, facing left or right. Weight on back foot. Posture straight. Use as: silhouette shot, dramatic reveal, character intro, identity concealment.', 'standard', '2026-02-01 18:30:50', '2026-02-01 18:30:50', 1),
(30, 'Three-Quarter Stance', 'Body at roughly 45 degrees to camera. One shoulder forward. Head turned to face camera. Most versatile conversational angle. Use as: default dialogue pose, character design showcase, natural interaction.', 'standard', '2026-02-01 18:30:50', '2026-02-01 18:30:50', 1),
(31, 'Hands in Pockets', 'Both hands slipped into jacket or pants pockets. Shoulders relaxed or slightly hunched. Casual, guarded. Use as: lone wolf idle, nonchalant arrival, hiding nervousness, cool character default.', 'standard', '2026-02-01 18:30:50', '2026-02-01 18:30:50', 1),
(32, 'One Hand in Pocket', 'Single hand in pocket. Other arm hanging or holding something. Relaxed asymmetry. Use as: casual confidence, mid-conversation, cool character variant.', 'standard', '2026-02-01 18:30:50', '2026-02-01 18:30:50', 1),
(33, 'Reaching Out (One Arm Extended)', 'One arm extended forward, hand open — reaching for something or someone. Other arm at side. Weight shifted forward. Use as: offering help, desperate grab, reaching across gap, emotional reach.', 'standard', '2026-02-01 18:30:50', '2026-02-01 18:30:50', 1),
(34, 'Both Arms Extended (Welcoming)', 'Both arms spread wide, palms forward. Chest open. Stance wide. Use as: welcoming, showmanship, \"look at all this\", villain monologue stance, embrace invitation.', 'standard', '2026-02-01 18:30:50', '2026-02-01 18:30:50', 1),
(35, 'Hugging Self', 'Both arms wrapped around own torso. Hands gripping opposite shoulders or arms. Shoulders hunched inward. Use as: cold, lonely, scared, self-comfort, vulnerability.', 'standard', '2026-02-01 18:30:50', '2026-02-01 18:30:50', 1),
(36, 'Formal Bow (45 Degrees)', 'Upper body bent forward at 45 degrees at the waist. Back straight. Arms at sides or hands clasped in front. Head down. Use as: greeting, respect, gratitude, apology (non-dogeza).', 'standard', '2026-02-01 18:30:50', '2026-02-01 18:30:50', 1),
(37, 'Casual Wave', 'One hand raised to chest or head height, palm open, waving loosely. Other hand at side. Relaxed posture. Use as: greeting, farewell, \"hey\", casual acknowledgment.', 'standard', '2026-02-01 18:30:50', '2026-02-01 18:30:50', 1),
(38, 'Salute', 'One hand raised to forehead or brow in a military salute. Back straight. Other arm at side. Use as: military acknowledgment, comedic obedience, \"yes sir\", mock salute.', 'standard', '2026-02-01 18:30:50', '2026-02-01 18:30:50', 1),
(39, 'Stretching Arms Above Head', 'Both arms raised and stretched overhead, possibly interlocked fingers. Body elongated. Use as: waking up, post-rest, relaxation, transition moment, idle animation.', 'standard', '2026-02-01 18:30:50', '2026-02-01 18:30:50', 1),
(40, 'Holding Something at Chest', 'Both arms cradling an object (book, box, folder) against the chest. Hands beneath and around it. Use as: presenting, protecting, nervous holding, carrying something precious.', 'standard', '2026-02-01 18:30:50', '2026-02-01 18:30:50', 1),
(41, 'Tapping Chin', 'One finger (index) lightly tapping the chin repeatedly. Other hand supporting the elbow. Head slightly tilted. Use as: thinking, deciding, playful consideration, \"hmm\".', 'standard', '2026-02-01 18:30:50', '2026-02-01 18:30:50', 1),
(42, 'Finger on Lips (Shh)', 'One index finger pressed vertically against lips. Eyes may close or look at target. Other hand at side. Use as: \"be quiet\", secret, playful shushing, teasing.', 'standard', '2026-02-01 18:30:50', '2026-02-01 18:30:50', 1),
(43, 'Adjusting Hair', 'One hand in or near hair — tucking a strand behind ear, running fingers through, or fixing style. Other arm relaxed. Use as: nervous habit, idle moment, vanity, subtle emotion tell.', 'standard', '2026-02-01 18:30:50', '2026-02-01 18:30:50', 1),
(44, 'Adjusting Glasses', 'One hand pushing glasses up the nose bridge with one or two fingers. Other hand at side. Use as: thinking, calculation mode, nervous tic, character signature.', 'standard', '2026-02-01 18:30:50', '2026-02-01 18:30:50', 1),
(45, 'Crossed Arms Behind Head', 'Both arms crossed behind the head, hands resting at the back of the skull. Elbows out. Completely relaxed. Use as: lounging, boredom, confidence, post-victory rest.', 'standard', '2026-02-01 18:30:50', '2026-02-01 18:30:50', 1),
(46, 'Leaning Forward (Eager)', 'Upper body leaning forward from standing or seated. Weight on the balls of feet or front edge of chair. Eyes fixed ahead. Use as: intense interest, eagerness, about to act, eavesdropping.', 'standard', '2026-02-01 18:30:50', '2026-02-01 18:30:50', 1),
(70, 'The Power Stance', 'Legs spread wide, feet planted. Both fists at sides, clenched. Shoulders squared and back. Chest out. Head slightly forward. Aura radiating outward. The \"I am here\" composition. Use as: power reveal, arrival, challenge declaration.', 'special', '2026-02-01 18:30:50', '2026-02-01 18:30:50', 1),
(71, 'The Lone Sword Draw', 'One arm at side holding weapon in scabbard. Other hand on the grip, mid-draw or just drawn. Body in a low, side-facing stance. Weight on back foot. Eyes locked forward. Use as: duel opening, standoff, samurai moment.', 'special', '2026-02-01 18:30:50', '2026-02-01 18:30:50', 1),
(72, 'The Dual Weapon Cross', 'Both arms crossed in front of the body, one weapon in each hand forming an X. Blades angled outward. Stance wide. Use as: guard stance, intimidation, mirror-match setup, assassin default.', 'special', '2026-02-01 18:30:50', '2026-02-01 18:30:50', 1),
(73, 'The Overhead Strike', 'Both arms raised fully above the head, weapon or fists gripped overhead. Body coiled, weight on back foot, about to come down. Full extension. Use as: finishing blow setup, massive attack wind-up, axe/hammer drop.', 'special', '2026-02-01 18:30:50', '2026-02-01 18:30:50', 1),
(74, 'The Thrust Forward', 'One arm fully extended forward — weapon, fist, or palm aimed at target. Other arm trailing behind for balance. One leg forward in a lunge. Body low. Use as: stabbing attack, decisive strike, \"gotcha\" moment.', 'special', '2026-02-01 18:30:50', '2026-02-01 18:30:50', 1),
(75, 'The Spin Slash', 'Body rotating mid-spin. One arm extended outward with weapon at full reach, tracing an arc. Other arm pulled in for momentum. Hair and clothing streaming. Use as: area attack, crowd clear, flashy combat moment.', 'special', '2026-02-01 18:30:50', '2026-02-01 18:30:50', 1),
(76, 'The Deflect Block', 'Weapon or forearm raised at an angle to intercept an incoming attack. Body braced, weight back. Sparks or impact lines visible at the point of contact. Grimace or determination on face. Use as: blocking, parrying, surviving a hit.', 'special', '2026-02-01 18:30:50', '2026-02-01 18:30:50', 1),
(77, 'The Back-to-Back Stance', 'Two-character composition. Both standing back to back, shoulders touching. Each facing opposite directions, weapons or fists ready. Use as: surrounded scenario, duo combat intro, trust moment.', 'special', '2026-02-01 18:30:50', '2026-02-01 18:30:50', 1),
(78, 'The Protective Shield', 'Arms crossed tightly over chest and face forming a barrier. Body hunched forward. Bracing for impact. Use as: shielding someone, taking a blast, desperate defense.', 'special', '2026-02-01 18:30:50', '2026-02-01 18:30:50', 1),
(79, 'The Falling Catch', 'One arm extended downward catching a falling person or object. Body twisted mid-motion. Other arm for balance. Dynamic diagonal composition. Use as: rescue moment, dramatic save, trust fall.', 'special', '2026-02-01 18:30:50', '2026-02-01 18:30:50', 1),
(80, 'The Transformation Silhouette', 'Full body silhouette against a bright backlight (white, gold, or elemental color). Arms slightly away from body. Head tilted back. Energy or light particles surrounding the outline. Use as: transformation sequence, power-up, reveal frame.', 'special', '2026-02-01 18:30:50', '2026-02-01 18:30:50', 1),
(81, 'The Ascent Float', 'Body floating upward, arms trailing loosely downward or spread. Head tilted back. Hair flowing upward with gravity reversed. Light source above. Use as: awakening, ascension, divine power activation, end-of-life peace.', 'special', '2026-02-01 18:30:50', '2026-02-01 18:30:50', 1),
(82, 'The Wings Unfurl', 'Standing straight, arms slightly out. Wings (feathered, mechanical, shadow, magical) extending fully from shoulders — mid-unfurl or fully spread. Head held high. Use as: angel/demon reveal, flight readiness, power declaration.', 'special', '2026-02-01 18:30:50', '2026-02-01 18:30:50', 1),
(83, 'The Kneeling Declaration', 'One knee on the ground. Head bowed or looking up with intensity. One fist planted on the ground. Other hand at side or on knee. Use as: oath-swearing, loyalty pledge, \"I will protect you\", villain submission (ironic).', 'special', '2026-02-01 18:30:50', '2026-02-01 18:30:50', 1),
(84, 'The Throne Claim', 'Seated on a throne or elevated seat. One leg crossed over the other. One arm draped over the armrest. Head slightly tilted. Relaxed but commanding. Use as: villain reveal, king/queen intro, power demonstration through stillness.', 'special', '2026-02-01 18:30:50', '2026-02-01 18:30:50', 1),
(85, 'The Rooftop Edge Stand', 'Standing at the very edge of a rooftop or cliff. Toes at the precipice. Wind blowing. Coat or hair streaming. Arms at sides or one hand in pocket. Looking out or down. Use as: brooding moment, dramatic intro, \"I could jump\" tension.', 'special', '2026-02-01 18:30:50', '2026-02-01 18:30:50', 1),
(86, 'The Rain Kneel', 'Kneeling in the rain. Head bowed. Arms limp. Water streaming down. Broken posture. Use as: defeat, grief, emotional rock bottom, surrender.', 'special', '2026-02-01 18:30:50', '2026-02-01 18:30:50', 1),
(87, 'The Outstretched Sacrifice', 'Arms spread wide, palms open — cruciform pose. Head back or forward. Body exposed, no defense. Light or energy consuming the body. Use as: self-sacrifice, sealing ritual, final gambit, protective barrier cast.', 'special', '2026-02-01 18:30:50', '2026-02-01 18:30:50', 1),
(88, 'The Fallen Hero Stand', 'Standing but barely. One leg buckling. Weapon dragging on the ground. Blood or smoke trailing. Head down but eyes still forward. The body should be collapsing but isn\'t yet. Use as: \"not yet\", final stand, refusing to die.', 'special', '2026-02-01 18:30:50', '2026-02-01 18:30:50', 1),
(89, 'The Mid-Air Clash', 'Two characters (or one vs projectile) frozen mid-collision in the air. Both fully extended into each other. Impact point at center. Weapons locked or fists connected. Use as: aerial battle peak, clash moment, evenly matched.', 'special', '2026-02-01 18:30:50', '2026-02-01 18:30:50', 1),
(90, 'The Dramatic Backflip Escape', 'Body inverted mid-backflip. Arms trailing. Legs tucked or extended. Debris or attack passing beneath. Hair streaming. Use as: last-second dodge, flashy escape, \"not even close\" moment.', 'special', '2026-02-01 18:30:50', '2026-02-01 18:30:50', 1),
(91, 'The Wall Slide', 'Back against a wall. Sliding downward — knees bent, one hand pressed against the wall. Head tilted back or down. Exhausted or defeated. Use as: post-fight collapse, emotional breakdown, \"it\'s over\".', 'special', '2026-02-01 18:30:50', '2026-02-01 18:30:50', 1),
(92, 'The Pointing at the Sky', 'One arm extended fully upward, finger pointing at the sky/heavens. Other arm at side or fist at chest. Head tilted back looking up. Stance wide and triumphant. Use as: declaration, \"I\'ll reach that\", goal announcement, hero moment.', 'special', '2026-02-01 18:30:50', '2026-02-01 18:30:50', 1),
(93, 'The Weapon on Shoulder', 'Large weapon (sword, rifle, staff) rested casually over one shoulder. Hand loosely gripping it. Other arm at side. Relaxed, confident posture. Use as: warrior idle, cool intro walk, \"just finished a fight\" vibe.', 'special', '2026-02-01 18:30:50', '2026-02-01 18:30:50', 1),
(94, 'The Dramatic Coat Flip', 'Mid-motion: coat or cloak billowing fully behind the character as they turn or stride forward. Body in motion, weight forward. Use as: entrance, villain arrival, cool character walk, wind-assisted drama.', 'special', '2026-02-01 18:30:50', '2026-02-01 18:30:50', 1),
(95, 'The Debris Emerging', 'Standing in a crater or destruction field. Dust and debris clearing around the character. Silhouette emerging from the cloud. Arms at sides, head forward. Use as: \"still standing\", survived the blast, power reveal after attack.', 'special', '2026-02-01 18:30:50', '2026-02-01 18:30:50', 1),
(96, 'The Protective Embrace', 'Arms wrapped around another character — pulling them close, shielding them. Body angled to protect. Head over theirs. Use as: rescue, emotional comfort, \"I\'ve got you\", shield from harm.', 'special', '2026-02-01 18:30:50', '2026-02-01 18:30:50', 1),
(97, 'The Sheathe (Post-Victory)', 'Weapon being slid back into scabbard or holster. One smooth motion. Body relaxed. Eyes already looking away from the defeated enemy. Use as: fight over, clean victory, \"that\'s done\", cool aftermath.', 'special', '2026-02-01 18:30:50', '2026-02-01 18:30:50', 1),
(98, 'The Charging Dash', 'Body low, leaning extremely forward. Both arms pumping back. One leg extended behind, other driving forward. Maximum forward momentum. Speed lines implied. Use as: charge attack, sprint, closing the gap, \"here I come\".', 'special', '2026-02-01 18:30:50', '2026-02-01 18:30:50', 1),
(99, 'The Summoning Gesture', 'One or both arms raised with hands open, fingers spread. Energy, light, or magical circles forming around the hands. Concentration on face. Use as: spell casting, summoning, calling an ally, activating ability.', 'special', '2026-02-01 18:30:50', '2026-02-01 18:30:50', 1),
(100, 'The Mirror Duel Stance', 'Two characters in identical mirrored poses facing each other. Same stance, same weapon position, same expression. Perfect symmetry. Use as: rivals, clone fight, \"we are the same\", duel opening.', 'special', '2026-02-01 18:30:50', '2026-02-01 18:30:50', 1),
(101, 'The Piggyback Carry', 'One character carrying another on their back. Arms hooked under the carried character\'s legs. Leaning forward slightly for balance. Use as: injured rescue, exhausted companion, comedic carry, trust demonstration.', 'special', '2026-02-01 18:30:50', '2026-02-01 18:30:50', 1),
(102, 'The Dramatic Hand Extension', 'One arm extended toward the viewer or target with hand open — offering, reaching, or demanding. Palm facing forward. Body weight shifted toward the extended arm. Intense gaze. Use as: \"take my hand\", offer, villain\'s invitation, dramatic plea.', 'special', '2026-02-01 18:30:50', '2026-02-01 18:30:50', 1),
(103, 'The Gravity Defiance', 'Standing or floating with impossible orientation — on a ceiling, sideways on a wall, hovering inches off the ground. Body completely relaxed despite the wrongness. Use as: power demonstration, supernatural ability, god-tier character reveal.', 'special', '2026-02-01 18:30:50', '2026-02-01 18:30:50', 1),
(104, 'The Slow Walk Forward', 'Walking directly toward the camera/target. Measured, unhurried pace. Arms swinging naturally or at sides. Eye contact maintained. Explosions or chaos happening behind, ignored. Use as: \"nothing can stop me\", final approach, climactic confrontation walk.', 'special', '2026-02-01 18:30:50', '2026-02-01 18:30:50', 1),
(121, 'Forward Lunge Punch', 'Explosive forward lunge, dominant fist driving straight toward the target in full extension. Back leg fully extended behind, body torqued at the hips, teeth gritted. Hair and clothing blown back by kinetic force. Use as: decisive attack opener, finishing blow, unstoppable charge moment.', 'action', '2026-04-08 12:24:23', '2026-04-08 12:24:23', 1),
(122, 'Spinning Heel Kick', 'Full-body spinning heel kick, body near-horizontal in mid-air. Kicking leg fully extended at head height. Opposite arm swept back for counterbalance. Torso twisted, hair and clothing caught in centrifugal motion. Use as: mid-combo pivot strike, crowd-clearing sweep, showy combat flourish.', 'action', '2026-04-08 12:24:23', '2026-04-08 12:24:23', 1),
(123, 'Dual Palm Ki Blast', 'Wide combat stance, both palms thrust forward at chest height, fingers spread. Glowing energy condensed between hands as twin crackling orbs. Forearms parallel, shoulders squared. No weapons, no wands — energy originates from the hands. Use as: ranged energy attack, power reveal, standoff opening shot.', 'action', '2026-04-08 12:24:23', '2026-04-08 12:24:23', 1),
(124, 'Overhead Axe Kick Descent', 'Body fully inverted in mid-air, dominant leg raised vertically overhead beginning a downward axe-kick. Arms swept back in aerodynamic tuck. Face angled down toward target with fierce focus. Hair cascading upward against gravity. Use as: aerial finisher, decisive overhead smash, gravity-assisted power move.', 'action', '2026-04-08 12:24:23', '2026-04-08 12:24:23', 1),
(125, 'Rising Uppercut', 'Explosive upward rising uppercut, body fully uncoiled from crouched base. Fist arcing upward, legs leaving the ground. Entire body stretched in one diagonal line from rear foot to fist apex. Opposite arm tucked tight. Face tilted skyward, open-mouth battle cry. Use as: anti-air counter, combo ender, launching the opponent skyward.', 'action', '2026-04-08 12:24:23', '2026-04-08 12:24:23', 1),
(126, 'Condensed Energy Sphere Charge', 'Standing upright, both hands cupped together at solar plexus level cradling a rapidly condensing sphere of volatile energy. Electricity arcing between fingers. Hair fully raised and spiked outward from electromagnetic surge. Eyes glowing faintly. Expression of extreme concentrated effort, slight lean forward. No wands, no staffs. Use as: charging ultimate attack, calm-before-the-storm moment, power level reveal.', 'action', '2026-04-08 12:24:23', '2026-04-08 12:24:23', 1),
(127, 'Defensive Cross-Block Braced for Impact', 'Wide low defensive stance, both forearms crossed in X-block directly in front of the face. Knees deeply bent, weight shifted to rear leg. Hair and clothing buffeted by the shockwave of incoming force. Eyes just visible above crossed arms, showing fierce resolve. Ground cracking beneath feet. Use as: receiving a devastating blow, holding the line, demonstrating resilience.', 'action', '2026-04-08 12:24:23', '2026-04-08 12:24:23', 1),
(128, 'Leaping Side Kick Apex', 'At the full apex of a leaping side kick. Body horizontal in the air, kicking leg fully extended. Chambering knee visible on opposite leg. Both arms extended for balance. Head turned toward the viewer over the shoulder. Hair streaming horizontally. Expression calm and precise. Use as: precision strike, mid-air engagement, acrobatic skill showcase.', 'action', '2026-04-08 12:24:23', '2026-04-08 12:24:23', 1),
(129, 'Ground Slam Both Fists', 'Both fists driven simultaneously into the ground, body crouched low over the impact point. Elbows flared wide. Shockwave ripple emanating outward from the fists. Hair hanging downward with gravity and blast turbulence. Face angled down toward ground, roaring battle-cry expression. Use as: area-of-effect attack, rage moment, ground-breaking power demonstration.', 'action', '2026-04-08 12:24:23', '2026-04-08 12:24:23', 1),
(130, 'Full-Body Energy Eruption Release', 'Standing centered, arms thrown wide open at shoulder height, palms outward. Head thrown back, chest open to the sky. Entire body radiating torrents of energy from every surface. Hair exploding upward and outward at full volume. Feet slightly lifted off the ground. Pure unbridled power-release expression. No wands, no staffs — energy emanates from the body itself. Use as: limit break activation, transformation trigger, ultimate power reveal.', 'action', '2026-04-08 12:24:23', '2026-04-08 12:24:23', 1),
(131, 'Side Roll Evasion', 'Full body mid-roll along the ground to one side. Knees tucked, one shoulder leading, arms close to body. The feet have just left the ground. Use as: dodging a ground-level sweep, gap closer escape, comic tumble recovery.', 'action', '2026-04-08 12:43:05', '2026-04-08 12:43:05', 1),
(132, 'Back Dash Lean', 'Body thrown dramatically backward at a steep diagonal angle, both feet still on the ground, torso nearly parallel to the floor. Arms trailing behind for balance. Use as: last-second dodge, taunting near-miss, matrix-style avoidance.', 'action', '2026-04-08 12:43:05', '2026-04-08 12:43:05', 1),
(133, 'Aerial Backflip Dodge', 'Body fully inverted mid-backflip, arms trailing, legs tucked or extended. Weight is clearly traveling backward and upward. Use as: escape from a low sweep, flashy repositioning, \"not even close\" moment.', 'action', '2026-04-08 12:43:05', '2026-04-08 12:43:05', 1),
(134, 'Low Crouch Slide', 'Body dropped into a full ground-level slide on one hip, lead leg extended forward, back leg folded. Upper body low, one hand grazing the ground. Use as: sliding under a high attack, surprise leg sweep entry, fast repositioning.', 'action', '2026-04-08 12:43:05', '2026-04-08 12:43:05', 1),
(135, 'Handspring Forward Vault', 'One or both hands planted on a surface mid-vault, body arched fully overhead. Legs extending upward at apex. Use as: vaulting over an obstacle or opponent, acrobatic gap close, momentum burst.', 'action', '2026-04-08 12:43:05', '2026-04-08 12:43:05', 1),
(136, 'Diagonal Wall Push-Off', 'One foot planted on a vertical wall surface, body pushed off at a diagonal. The wall foot is mid-kick-off, arms angled for the new trajectory. Use as: wall-run redirect, surprise change of direction, environmental combat.', 'action', '2026-04-08 12:43:05', '2026-04-08 12:43:05', 1),
(137, 'Splinter Stance — Split Dodge', 'Full horizontal split performed mid-air or on the ground to avoid an attack passing over or through at waist height. Both legs fully extended in opposite directions. Upper body upright. Use as: dodging a horizontal beam or sweep, flexibility showcase.', 'action', '2026-04-08 12:43:05', '2026-04-08 12:43:05', 1),
(138, 'Aerial Stomp Descent', 'Body dropping straight down from height, one leg cocked and about to extend downward into a stomp. Arms pulled back for speed. Face angled at the target below. Use as: aerial finisher, surprise drop attack, momentum-crushing overhead.', 'action', '2026-04-08 12:43:05', '2026-04-08 12:43:05', 1),
(139, 'Aerial Spin Combo — Mid-Rotation', 'Body caught mid-spin in the air, one leg extended for a rotational kick, arms swept out for momentum. The figure is clearly on the second or third rotation of a multi-hit combo. Use as: aerial juggle sequence, spinning multi-hit, showing sustained air dominance.', 'action', '2026-04-08 12:43:05', '2026-04-08 12:43:05', 1),
(140, 'Air Dash Punch — Horizontal', 'Body fully horizontal in the air, one fist leading, body straight as an arrow in a flying horizontal dash punch. Hair and clothing blasted back. Speed lines implied. Use as: closing aerial distance instantly, high-speed surprise strike, \"bullet\" approach.', 'action', '2026-04-08 12:43:05', '2026-04-08 12:43:05', 1),
(141, 'Ceiling Push-Off Dive Attack', 'One or both hands on a ceiling surface, body compressed then releasing — legs driving downward in a sudden diving attack. The push-off moment visible. Use as: ambush from above, surprise environmental attack, gravity-assisted dive.', 'action', '2026-04-08 12:43:05', '2026-04-08 12:43:05', 1),
(142, 'Mid-Air Guard Stance', 'Full combat guard stance held perfectly in mid-air — both fists raised, knees slightly bent, body balanced despite no ground contact. Completely calm and controlled. Use as: aerial defensive posture, showing supernatural balance, floating combat style.', 'action', '2026-04-08 12:43:05', '2026-04-08 12:43:05', 1),
(143, 'Collar Grab Slam Initiation', 'One hand gripping the opponent\'s collar or lapel, arm fully extended forward, body leaning back into the throw initiation. The grip is decisive and the weight transfer has begun. Use as: grapple opener, power reversal, \"you\'re done\" moment.', 'action', '2026-04-08 12:43:05', '2026-04-08 12:43:05', 1),
(144, 'Shoulder Throw Apex', 'Body fully committed to a hip or shoulder throw — the thrower bent forward, one arm sweeping the opponent over the shoulder at the apex. The person being thrown is implied by the body mechanics. Use as: judo/wrestling technique, crowd-clearing slam, power demonstration.', 'action', '2026-04-08 12:43:05', '2026-04-08 12:43:05', 1),
(145, 'Chokehold Standing', 'One arm locked around an opponent\'s neck from behind, body pressed close, feet planted wide. Free arm at side or pressing on the captive\'s head. Use as: capture moment, power over opponent, intimidation grip.', 'action', '2026-04-08 12:43:05', '2026-04-08 12:43:05', 1),
(146, 'Ground Mount Pin', 'Figure straddling a downed opponent, both hands pinning the opponent\'s collar or shoulders to the ground. Dominant posture, weight fully committed downward. Use as: fight won moment, interrogation position, ground dominance.', 'action', '2026-04-08 12:43:05', '2026-04-08 12:43:05', 1),
(147, 'Mutual Clinch Struggle', 'Both fighters locked together at close range, each gripping the other\'s arms or collar, bodies straining against each other. Neither has the upper hand yet. Intense eye contact. Use as: evenly matched grapple, strength contest, tension buildup.', 'action', '2026-04-08 12:43:05', '2026-04-08 12:43:05', 1),
(148, 'Two-Hand Overhead Swing', 'Both hands gripping a weapon or object overhead, full arc swing in progress. Body rotated at the waist, weight transferred. Maximum force in the swing. Use as: powerful cleave attack, axe/hammer/club technique, rage moment.', 'action', '2026-04-08 12:43:05', '2026-04-08 12:43:05', 1),
(149, 'Low Sweep Leg Kick', 'Body low to the ground, one leg fully extended in a sweeping arc at ankle height. Supporting arm on the ground for balance. Other arm raised for recovery. Use as: leg sweep, trip attack, taking the opponent off their feet.', 'action', '2026-04-08 12:43:05', '2026-04-08 12:43:05', 1),
(150, 'Flying Knee Strike', 'Body launched forward, dominant knee driving upward into the target at chest or chin height. Both arms reaching forward for balance. Back leg trailing. Use as: Muay Thai finishing move, sudden close-range explosive strike, gap close to knee.', 'action', '2026-04-08 12:43:05', '2026-04-08 12:43:05', 1),
(151, 'Elbow Drop Landing', 'Body in the air, dropping downward, dominant elbow pointed directly downward at the target. One hand supporting the angle. Eyes locked on impact point. Use as: finishing stomp variant, pro-wrestling technique, overhead elbow finisher.', 'action', '2026-04-08 12:43:05', '2026-04-08 12:43:05', 1),
(152, 'Palm Strike — Full Extension', 'One arm fully extended forward, palm flat and leading — heel of the hand as the striking surface. Fingers splayed back. Body fully committed to the extension. Use as: internal-style martial arts strike, force push variant, chi-based technique.', 'action', '2026-04-08 12:43:05', '2026-04-08 12:43:05', 1),
(153, 'Spinning Back Fist', 'Body mid-spin, back of the dominant fist leading at face height, arm fully extended by centrifugal force. The spin is nearly complete. Other arm pulled tight. Use as: surprise reversal strike, disorienting combo transition, showy technique.', 'action', '2026-04-08 12:43:05', '2026-04-08 12:43:05', 1),
(154, 'Last Stand Crouch', 'One knee on the ground, the other foot planted. One arm propped on the raised knee. Head bowed, then snapping up with one eye visible — bloodied, exhausted, but refusing to stop. Use as: hero\'s final stand, \"I\'m not done\", getting back up after defeat.', 'action', '2026-04-08 12:43:05', '2026-04-08 12:43:05', 1),
(155, 'Rage Break Posture', 'Standing, but barely — body vibrating, fists clenched at sides so hard the knuckles are white. Head bowed, shoulders hunched forward, shaking. The posture of someone about to snap. Use as: limit broken, berserk trigger, \"you just made a mistake\".', 'action', '2026-04-08 12:43:05', '2026-04-08 12:43:05', 1),
(156, 'Snarl Step Forward', 'Aggressive forward step, full weight transferring to the front foot. Shoulders rolled forward, chin down, eyes up — predatory low posture. Arms slightly forward and ready. Use as: intimidation advance, berserk approach, \"I\'m going to enjoy this\".', 'action', '2026-04-08 12:43:05', '2026-04-08 12:43:05', 1),
(157, 'Victory Stand — One Foot on Fallen', 'Standing upright, one foot raised and placed on a defeated opponent (implied or visible). Arms at sides or one fist raised. Head held high. Use as: fight-over declaration, dominance moment, villain or hero victory.', 'action', '2026-04-08 12:43:05', '2026-04-08 12:43:05', 1),
(158, 'Exhaustion Kneel Post-Battle', 'Both knees on the ground, back hunched, one or both fists on the floor supporting weight. Head hanging down. Breathing hard. The fight is over — this figure won, but it cost them. Use as: pyrrhic victory, end of battle, emotional release.', 'action', '2026-04-08 12:43:05', '2026-04-08 12:43:05', 1),
(159, 'Taunt — Beckoning Finger', 'Standing relaxed in a wide comfortable stance, one hand raised at chest height, one or two fingers curling slowly inward in a deliberate beckoning gesture. Expression contemptuous or amused. Use as: taunting the opponent forward, psychological warfare, overconfident villain moment.', 'action', '2026-04-08 12:43:05', '2026-04-08 12:43:05', 1),
(160, 'Taunt — Shoulder Turn Away', 'Body half-turned away from the opponent, one eye glancing back over the shoulder with a dismissive or mocking expression. Weight on the back foot, completely relaxed. Use as: ignoring an attack, psychological provocation, \"you\'re not worth turning around for\".', 'action', '2026-04-08 12:43:05', '2026-04-08 12:43:05', 1),
(161, 'Vertical Wall Run', 'Body running up a vertical surface — foot contact on the wall, knees driving upward, arms pumping. Only a few steps in. Use as: escaping a ground engagement, reaching height quickly, environmental agility.', 'action', '2026-04-08 12:43:05', '2026-04-08 12:43:05', 1),
(162, 'Rooftop Running Leap', 'Body fully committed to a running leap between two high surfaces — both feet off the ground, reaching forward, the gap visible below. Use as: chase sequence, parkour moment, high-stakes crossing.', 'action', '2026-04-08 12:43:05', '2026-04-08 12:43:05', 1),
(163, 'Landing Crouch — Impact Absorbed', 'Both feet landing simultaneously from a great height, knees deeply bent to absorb impact. One fist on the ground for balance. Head down but eyes forward. Dust or cracks emanating from the landing point. Use as: dramatic arrival, falling into scene, post-flight landing.', 'action', '2026-04-08 12:43:05', '2026-04-08 12:43:05', 1),
(164, 'Sliding Under Barrier', 'Full baseball-style feet-first slide, body low, passing beneath an obstacle or attack at ground level. One arm extended back, the other forward. Completely committed. Use as: tight escape, speed combat transition, environmental navigation.', 'action', '2026-04-08 12:43:05', '2026-04-08 12:43:05', 1),
(165, 'Climbing Reach — Upper Grip', 'Body hanging from a ledge, wall, or structure. Both hands gripping the edge above, one foot finding a foothold, the other dangling. Mid-climb effort. Use as: infiltration, escape, cliff-hanging moment, environmental traversal.', 'action', '2026-04-08 12:43:05', '2026-04-08 12:43:05', 1),
(166, 'Crawling Low Advance', 'Body flat and low, crawling on elbows and knees with deliberate forward motion. Head raised just enough to see the target ahead. Use as: stealth approach, surviving a debris field, ground-level advance under fire.', 'action', '2026-04-08 12:43:05', '2026-04-08 12:43:05', 1),
(167, 'Kip-Up Recovery', 'Body snapping upward from flat on the back — hips thrust skyward, using momentum to spring to both feet in one motion. The figure is mid-kip, not yet upright. Use as: getting up after being knocked down, refusing to stay defeated, acrobatic recovery.', 'action', '2026-04-08 12:43:05', '2026-04-08 12:43:05', 1),
(168, 'Hit Stagger — Backward Reel', 'Body thrown backward by an impact — torso whipping back, one arm thrown wide, feet skidding or leaving the ground. Expression of pain or surprise. Use as: receiving a powerful hit, damage reaction, vulnerability moment.', 'action', '2026-04-08 12:43:05', '2026-04-08 12:43:05', 1),
(169, 'Hit Stagger — Forward Collapse', 'Body pitched forward by an impact from behind — torso folding, knees buckling, arms splaying forward. Mid-fall, not yet on the ground. Use as: ambush hit from behind, betrayal moment, devastating blow received.', 'action', '2026-04-08 12:43:05', '2026-04-08 12:43:05', 1),
(170, 'Skidding Stop — Braking Slide', 'Body leaning sharply back, both feet dragging forward, arms thrown wide for balance — coming to a sudden forced stop. Friction implied at the feet. Use as: arriving at a scene dramatically, sudden halt, \"wait\" moment.', 'action', '2026-04-08 12:43:05', '2026-04-08 12:43:05', 1),
(171, 'Guard Break Reaction', 'Body recoiling from having a defensive block shattered — arms flung apart, body exposed and off-balance, weight thrown backward. The moment of vulnerability. Use as: guard broken moment, \"oh no\" beat, setup for a follow-up strike.', 'action', '2026-04-08 12:43:05', '2026-04-08 12:43:05', 1),
(172, 'Parry Counter — Redirect and Strike', 'One arm sweeping an incoming attack to the outside, the other arm already cocked for an immediate counter. Body weight shifted smoothly into the counter. One fluid motion of deflect-and-hit. Use as: skilled counter technique, aikido/judo redirect, superior technique demonstration.', 'action', '2026-04-08 12:43:05', '2026-04-08 12:43:05', 1),
(173, 'Crossed Arms Pre-Fight Drop', 'Both arms crossed over the chest, then the hands opening and dropping to the sides simultaneously — the fighter\'s version of \"let\'s go\". Stance widening as the arms drop. Eyes locked on the opponent. Use as: fight acceptance moment, \"I\'m ready\" declaration, calm pre-battle ritual.', 'action', '2026-04-08 12:43:05', '2026-04-08 12:43:05', 1),
(174, 'Collar Pop Walk-In', 'Walking forward with a decisive stride, one hand reaching up to adjust the collar or roll the shoulders — the casual pre-fight approach. Expression unimpressed. Use as: villain walk-in, overconfident entry, casual intimidation.', 'action', '2026-04-08 12:43:05', '2026-04-08 12:43:05', 1),
(175, 'Knuckle Crack Preparation', 'Standing relaxed, one hand gripping the other fist and cracking the knuckles with deliberate patience. Slight smile or neutral expression. Weight casual. Use as: \"you\'re about to regret this\" setup, villain leisure, pre-fight ritual.', 'action', '2026-04-08 12:43:05', '2026-04-08 12:43:05', 1),
(176, 'Back-to-Wall Last Breath', 'Pressed against a wall or corner, facing forward, both fists raised in a last-resort guard. Cornered but not broken. Eyes wide and scanning. Use as: surrounded scenario, final fight before retreat, desperation that becomes a turning point.', 'action', '2026-04-08 12:43:05', '2026-04-08 12:43:05', 1),
(177, 'Frozen Mid-Draw — Standoff', 'Hand on weapon grip but not yet drawn. Other hand visible and open. Completely still. Eyes fixed on opponent in a mutual standoff — the trigger moment before everything explodes. Use as: western-style duel beat, standoff freeze, \"first one to move\" tension.', 'action', '2026-04-08 12:43:05', '2026-04-08 12:43:05', 1),
(178, 'Lunging Tackle Body Slam', 'Full body launched horizontally like a missile toward the target — both arms reaching forward, head tucked, all weight committed forward. Pure kinetic mass. Use as: desperation tackle, taking someone to the ground fast, sacrifice move.', 'action', '2026-04-08 12:43:05', '2026-04-08 12:43:05', 1),
(179, 'Spinning Takedown — Leg Sweep in Arc', 'Body low and rotating, one leg fully extended sweeping a wide arc at ankle height, the other leg bent as pivot. One hand on the ground for balance. Use as: full rotation leg sweep, crowd-clearing spin, acrobatic floor technique.', 'action', '2026-04-08 12:43:05', '2026-04-08 12:43:05', 1),
(180, 'The Staredown — Zero Movement', 'Standing completely still. Feet shoulder-width apart. Arms at sides. Expression calm and absolute. No dramatic pose — just presence. The stillness itself is the threat. Use as: villain who doesn\'t need to move, power through inaction, the most dangerous person in the room.', 'action', '2026-04-08 12:43:05', '2026-04-08 12:43:05', 1);
INSERT INTO `poses_anima` (`id`, `name`, `description`, `category`, `anima_type`, `hierarchy_level`, `is_merge`, `merge_type`, `created_at`, `updated_at`, `active`) VALUES
(1, 'Chrono Trace — The Frozen Moment', 'Figure standing completely still amid a scene of motion — dust motes suspended mid-air, a falling object halted inches from the ground, fabric caught mid-billow. Gold time rings faintly visible around the wrists, barely glowing. Everything else paused, only the figure breathes. (Chrono Trace — dormant power, eerie stillness)', 'channel', 'CHRONO', 'Trace', 0, NULL, '2026-03-20 11:55:11', '2026-03-20 11:55:11', 1),
(2, 'Chrono Pulse — Echo Stance', 'Standing tall, one arm raised to chest height, gold and tarnished-silver geometric rings orbiting slowly around the forearm. The air behind the figure shimmers with ghost-image tracers — a faint echo of the same pose hanging a half-second behind, like a visual lag. Eyes glowing faint gold. (Chrono Pulse — time signature reveal)', 'channel', 'CHRONO', 'Pulse', 0, NULL, '2026-03-20 11:55:11', '2026-03-20 11:55:11', 1),
(3, 'Chrono Surge — Rewind', 'Figure mid-lunge forward, but a second translucent version of themselves is simultaneously visible mid-lunge backward — two temporal selves occupying the same space. Gold rings spinning rapidly, the air cracking with visible ripple distortion. Clothes and hair whipping in two directions at once. (Chrono Surge — temporal split, battle overclock)', 'channel', 'CHRONO', 'Surge', 0, NULL, '2026-03-20 11:55:11', '2026-03-20 11:55:11', 1),
(4, 'Chrono Manifest — The Clockwork Witness', 'The figure is gone — in their place a towering construct of interlocked gold rings and tarnished gears, roughly humanoid, twelve feet tall. The face is a clock face without hands. The air within a wide radius moves in slow motion, birds frozen mid-flight, dust hanging. Only the construct moves at normal speed, turning its featureless face slowly. (Chrono Manifest — Avatar form, legendary reveal)', 'channel', 'CHRONO', 'Manifest', 0, NULL, '2026-03-20 11:55:11', '2026-03-20 11:55:11', 1),
(5, 'Gravita Trace — The Heavy', 'Figure seated or standing with an unusual quality of weight — shoulders pressed down, feet planted as though fused to the ground. Deep purple shimmer barely visible around the ankles and spine. Nearby loose objects have drifted slightly closer, drawn by micro-gravity. (Gravita Trace — passive mass, quiet menace)', 'channel', 'GRAVITA', 'Trace', 0, NULL, '2026-03-20 11:55:11', '2026-03-20 11:55:11', 1),
(6, 'Gravita Pulse — Anchor', 'Wide stance, both arms extended outward at shoulder height, palms facing down. Deep purple and black visual lensing bends the space around the figure slightly, like heat haze but cold and crushing. Nearby objects hover an inch off the ground, held by redirected gravity. (Gravita Pulse — field assertion, power stance)', 'channel', 'GRAVITA', 'Pulse', 0, NULL, '2026-03-20 11:55:11', '2026-03-20 11:55:11', 1),
(7, 'Gravita Surge — Inversion', 'Figure standing on the ceiling or a vertical wall, completely relaxed, arms crossed, looking down with calm authority. The floor below is cracked and buckled. Debris floats in an orbital ring around the body at waist height. Deep purple-black spatial lensing warps the environment in a wide radius. (Gravita Surge — gravity override, god-tier composure)', 'channel', 'GRAVITA', 'Surge', 0, NULL, '2026-03-20 11:55:11', '2026-03-20 11:55:11', 1),
(8, 'Gravita Manifest — Event Horizon', 'A sphere of absolute darkness, the size of a room, hovers where the figure stood. Its edge distorts all light around it, bending and lensing reality into curved streaks. Debris, metal, stone spiral slowly into it. The figure is visible as a silhouette at the core, suspended in the void, arms wide. (Gravita Manifest — singularity form, scene-ending power)', 'channel', 'GRAVITA', 'Manifest', 0, NULL, '2026-03-20 11:55:11', '2026-03-20 11:55:11', 1),
(9, 'Momentum Pulse — Launch Position', 'Figure coiled low in a sprinter stance, one fist planted on the ground. Crimson and neon-orange speed lines already trailing from the knuckles and shoulders as if motion has begun before the body moved. Air visibly compresses ahead of them. Eyes blazing orange. (Momentum Pulse — kinetic charge, pre-strike)', 'channel', 'MOMENTUM', 'Pulse', 0, NULL, '2026-03-20 11:55:11', '2026-03-20 11:55:11', 1),
(10, 'Momentum Surge — Shockwave Strike', 'Figure captured mid-punch, arm fully extended. The impact point in the empty air ahead explodes with a shockwave — a visible disc of compressed air radiating outward. Crimson speed lines streak the entire body. The ground behind the figure has cracked from the backward force. Hair and clothing blast forward. (Momentum Surge — kinetic release, distance strike)', 'channel', 'MOMENTUM', 'Surge', 0, NULL, '2026-03-20 11:55:11', '2026-03-20 11:55:11', 1),
(11, 'Momentum Manifest — The Living Comet', 'The figure has become pure velocity — a human-shaped core of white-hot kinetic energy wrapped in a cone of crimson and neon streaks thirty feet long, moving so fast the form is only barely recognizable as a person at its leading edge. The ground beneath the trail is obliterated. (Momentum Manifest — full kinetic avatar, unstoppable force)', 'channel', 'MOMENTUM', 'Manifest', 0, NULL, '2026-03-20 11:55:11', '2026-03-20 11:55:11', 1),
(12, 'Energia Trace — Static Field', 'Figure standing casually, but every hair on their body is slightly raised. Tiny arcs of blue-white static jump between fingertips and nearby metal surfaces. The air smells of ozone. A faint electric hum is visible as heat shimmer around the skin. (Energia Trace — latent charge, pre-storm quiet)', 'channel', 'ENERGIA', 'Trace', 0, NULL, '2026-03-20 11:55:11', '2026-03-20 11:55:11', 1),
(13, 'Energia Pulse — Arc Hands', 'Both arms thrust forward, fingers splayed wide. Blinding electric blue arcs spider between every finger, jumping to the ground and ceiling in jagged fractal paths. The eyes are entirely white with charge. Clothing scorched at the edges. The air around the figure crackles with visible static discharge. (Energia Pulse — active channeling, electrical assertion)', 'channel', 'ENERGIA', 'Pulse', 0, NULL, '2026-03-20 11:55:11', '2026-03-20 11:55:11', 1),
(14, 'Energia Surge — Overload', 'Figure at the center of a sphere of pure electrical chaos — blue-white plasma arcs in every direction, the body barely visible through the blinding discharge. The floor has melted in a ring around them. Every nearby metal object is magnetized and vibrating. The figure screams or roars, face lit from below by their own light. (Energia Surge — full discharge, overclock)', 'channel', 'ENERGIA', 'Surge', 0, NULL, '2026-03-20 11:55:11', '2026-03-20 11:55:11', 1),
(15, 'Therma Pulse — Heat Side', 'Figure standing with one hand raised, palm up, a roiling ball of heat shimmer hovering above it — not flame, but visible thermal distortion, the air above the hand warping like a desert mirage. The iris glows deep infrared red. Sweat on the skin evaporates on contact. (Therma Pulse — heat expression, controlled burn)', 'channel', 'THERMA', 'Pulse', 0, NULL, '2026-03-20 11:55:11', '2026-03-20 11:55:11', 1),
(16, 'Therma Pulse — Cold Side', 'Figure standing with both arms crossed tight against the chest, body encased from the waist down in a shell of sharp crystalline ice fractals that they have generated. Breath visible as dense vapor. The skin at the fingertips is pale blue. The floor radiates frost outward in geometric patterns. (Therma Pulse — cold expression, crystalline control)', 'channel', 'THERMA', 'Pulse', 0, NULL, '2026-03-20 11:55:11', '2026-03-20 11:55:11', 1),
(17, 'Therma Surge — Flash Point', 'Figure at the epicenter of a thermal explosion — not fire, but a blinding radial shockwave of superheated air, the color shifting from deep red at the core to ultraviolet blue at the edges. The body is the still point at the center of the blast. Nearby objects are simultaneously melting and freezing depending on proximity. (Therma Surge — entropy release, thermal detonation)', 'channel', 'THERMA', 'Surge', 0, NULL, '2026-03-20 11:55:11', '2026-03-20 11:55:11', 1),
(18, 'Therma Manifest — The Absolute', 'One half of the figure is a being of pure heat — body rendered in glowing magma cracks, hair as rising flame. The other half is absolute zero — crystalline ice architecture, geometric frost, the eye a frozen blue star. The split runs directly down the center of the body. Where the two halves meet, a line of white fog billows endlessly. (Therma Manifest — bipolar avatar, entropy made flesh)', 'channel', 'THERMA', 'Manifest', 0, NULL, '2026-03-20 11:55:11', '2026-03-20 11:55:11', 1),
(19, 'Lumina Trace — The Tell', 'Figure in a dim environment, but shadows fall wrong around them — bending away rather than toward the figure. A faint prismatic shimmer clings to the skin like an oil slick on water. One eye catches the light at an impossible angle. (Lumina Trace — passive light bend, subtle wrongness)', 'channel', 'LUMINA', 'Trace', 0, NULL, '2026-03-20 11:55:11', '2026-03-20 11:55:11', 1),
(20, 'Lumina Pulse — Revelation', 'Figure standing with head tilted back, a beam of focused prismatic light projecting upward from the open palm. Rainbow lens flares scatter across every surface. Shadows in the room are hard-edged and wrong. The iris glows pure white. (Lumina Pulse — light channeling, truth revealing)', 'channel', 'LUMINA', 'Pulse', 0, NULL, '2026-03-20 11:55:11', '2026-03-20 11:55:11', 1),
(21, 'Lumina Surge — Hard Light Construct', 'Figure standing behind a towering geometric shield of solid light — translucent panels of crystallized photons arranged in interlocking hexagons, edges burning white-hot. Prismatic flares bloom from every joint. The figure\'s outline is partially dissolved into the light source. (Lumina Surge — hard light defense, luminous overclock)', 'channel', 'LUMINA', 'Surge', 0, NULL, '2026-03-20 11:55:11', '2026-03-20 11:55:11', 1),
(22, 'Resonantia Pulse — The Hum', 'Figure standing with arms slightly away from the body, head bowed in concentration. Transparent concentric ripples radiate outward through the air from the chest — like a stone dropped in still water, but in three dimensions. Dust on the ground has organized itself into perfect cymatic patterns. (Resonantia Pulse — frequency broadcast, vibration presence)', 'channel', 'RESONANTIA', 'Pulse', 0, NULL, '2026-03-20 11:55:11', '2026-03-20 11:55:11', 1),
(23, 'Resonantia Surge — Shatter Frequency', 'Figure screaming or roaring with arms thrown wide, the sound made visible — massive transparent shockwaves blasting outward in all directions. Nearby stone and glass is mid-shatter, caught in the act of structural failure. The cymatic patterns on the floor have become violent, cracked earth. (Resonantia Surge — destructive frequency, structural assault)', 'channel', 'RESONANTIA', 'Surge', 0, NULL, '2026-03-20 11:55:11', '2026-03-20 11:55:11', 1),
(24, 'Resonantia Manifest — Living Frequency', 'The figure has dissolved into a being of pure vibration — a humanoid shape made of stacked, overlapping transparent waveforms, each one slightly out of phase with the last. Where they step, the ground resonates visibly. Their voice, if opened, would unmake walls. (Resonantia Manifest — waveform avatar, harmonic transcendence)', 'channel', 'RESONANTIA', 'Manifest', 0, NULL, '2026-03-20 11:55:11', '2026-03-20 11:55:11', 1),
(25, 'Magnetica Pulse — Field Active', 'Figure standing with one fist raised, a swirling pattern of iron filings orbiting the forearm in tight aurora-like loops. Blue electromagnetic light pulses along the path of the field lines. Nearby metal objects have lifted and oriented themselves toward the figure like compass needles. (Magnetica Pulse — field assertion, metallic command)', 'channel', 'MAGNETICA', 'Pulse', 0, NULL, '2026-03-20 11:55:11', '2026-03-20 11:55:11', 1),
(26, 'Magnetica Surge — Ferro Storm', 'Figure at the center of a vortex of metallic debris — shards, beams, coins, weapons — all orbiting in a dense roaring cloud held by magnetic force. Blue aurora light streams between every piece. The figure stands calm at the eye of the storm, one hand conducting. (Magnetica Surge — ferro vortex, metallic dominion)', 'channel', 'MAGNETICA', 'Surge', 0, NULL, '2026-03-20 11:55:11', '2026-03-20 11:55:11', 1),
(27, 'Fluidica Pulse — Flow State', 'Figure mid-movement in an impossible fluid motion — every joint and limb tracing paths of least resistance, the body moving like water around an obstacle. Visible air currents curl off the fingertips. Loose cloth moves as if underwater despite no wind. (Fluidica Pulse — fluid motion, adaptive grace)', 'channel', 'FLUIDICA', 'Pulse', 0, NULL, '2026-03-20 11:55:11', '2026-03-20 11:55:11', 1),
(28, 'Fluidica Surge — The Current', 'Figure standing inside a contained vertical cyclone of liquid air — water-like currents of atmosphere made visible, swirling in perfect laminar flow around the body. Bubbles rise from the ground. The figure breathes at the center like the eye of an underwater storm. (Fluidica Surge — flow vortex, hydrodynamic overclock)', 'channel', 'FLUIDICA', 'Surge', 0, NULL, '2026-03-20 11:55:11', '2026-03-20 11:55:11', 1),
(29, 'Cohesiva Pulse — Lattice Skin', 'Figure standing in a defensive posture, arms raised, skin overlaid with a visible amber geometric lattice — molecular bonds made visible as glowing structural lines mapping the entire body. The ground under the feet has fused solid. Nothing can move this figure. (Cohesiva Pulse — matter hardening, unbreakable stance)', 'channel', 'COHESIVA', 'Pulse', 0, NULL, '2026-03-20 11:55:12', '2026-03-20 11:55:12', 1),
(30, 'Cohesiva Surge — The Juggernaut', 'Figure mid-charge, body encased in a thickening shell of fused material — stone, metal, debris — all bonded together by amber lattice energy into improvised armor that grows denser as speed increases. The ground shatters under each footfall. The form is barely human-shaped anymore, a mass in motion. (Cohesiva Surge — matter fusion armor, unstoppable charge)', 'channel', 'COHESIVA', 'Surge', 0, NULL, '2026-03-20 11:55:12', '2026-03-20 11:55:12', 1),
(31, 'Probabilis Trace — The Glitch', 'Figure standing normally but flickering — for a fraction of a second a ghost image of a different version of them occupies the same space. Objects near them behave slightly wrong: a coin lands on its edge, a door opens the wrong way. Reality databends at the margins. (Probabilis Trace — quantum uncertainty, wrongness)', 'channel', 'PROBABILIS', 'Trace', 0, NULL, '2026-03-20 11:55:12', '2026-03-20 11:55:12', 1),
(32, 'Probabilis Pulse — Ghost Outcomes', 'Figure in a fighting stance, but surrounded by three or four translucent ghost-images of themselves in different poses — possible futures flickering in and out of visibility like corrupted video. Each ghost is a different decision not yet made. Reality rapidly color-shifts at the edges of the frame. (Probabilis Pulse — probability sight, trickster awareness)', 'channel', 'PROBABILIS', 'Pulse', 0, NULL, '2026-03-20 11:55:12', '2026-03-20 11:55:12', 1),
(33, 'Probabilis Surge — The Jackpot', 'Figure laughing or grinning wildly, arms thrown wide, as improbable chaos erupts around them — lightning strikes precisely placed, a wall collapses in the perfect direction, weapons jam, birds flock from nowhere. Reality itself glitches and databends in expanding rings. The figure is the only stable point in a world of cascading accidents. (Probabilis Surge — cascading improbability, chaos incarnate)', 'channel', 'PROBABILIS', 'Surge', 0, NULL, '2026-03-20 11:55:12', '2026-03-20 11:55:12', 1),
(34, 'Vitalis Pulse — Bloom', 'Figure kneeling, one hand pressed flat to the ground. Emerald glowing veins trace up the arm from the point of contact. In a ring around the hand, plant life erupts from stone — flowers blooming in seconds, vines reaching, moss spreading in real time. Floating spores drift upward like green embers. (Vitalis Pulse — life channeling, growth manifestation)', 'channel', 'VITALIS', 'Pulse', 0, NULL, '2026-03-20 11:55:12', '2026-03-20 11:55:12', 1),
(35, 'Vitalis Surge — Apex Predator', 'Figure standing tall, body alight with emerald bio-glow tracing every vein and muscle. They are visibly larger — not supernatural size, but the body at its absolute biological limit. Roots and vines have erupted from the ground around them uninvited. The eyes are pure animal. Floating spores fill the air like a living cloud. (Vitalis Surge — biological overclock, apex state)', 'channel', 'VITALIS', 'Surge', 0, NULL, '2026-03-20 11:55:12', '2026-03-20 11:55:12', 1),
(36, 'Vitalis Manifest — The Green', 'A being of pure living matter — the humanoid figure overgrown, roots for a spine, flowers blooming from the shoulders, the face half-visible through a mask of living bark and leaves. Emerald light pulses from within like a heartbeat. Every step leaves a permanent bloom of life behind. (Vitalis Manifest — living avatar, nature sovereign)', 'channel', 'VITALIS', 'Manifest', 0, NULL, '2026-03-20 11:55:12', '2026-03-20 11:55:12', 1),
(37, 'Noetica Trace — The Listener', 'Figure standing in a crowd or empty space, eyes closed, face tilted slightly as if hearing something no one else can. Silver mist barely visible around the temples. The air feels thin and cold. Others nearby look subtly uneasy without knowing why. (Noetica Trace — passive telepathy, psychic presence)', 'channel', 'NOETICA', 'Trace', 0, NULL, '2026-03-20 11:55:12', '2026-03-20 11:55:12', 1),
(38, 'Noetica Pulse — Mind Touch', 'Figure standing with two fingers pressed gently to their own temple, silver mist curling from the eyes and fingertips. A faint halo of soft radiance behind the head. Their gaze is direct and penetrating, looking through rather than at the world in front of them. (Noetica Pulse — active telepathy, consciousness reach)', 'channel', 'NOETICA', 'Pulse', 0, NULL, '2026-03-20 11:55:12', '2026-03-20 11:55:12', 1),
(39, 'Noetica Surge — Broadcast', 'Figure at the center of an expanding silver psychic shockwave — concentric rings of conscious energy radiating outward at head height. Every person in range clutches their head, overwhelmed. The figure stands in the eye of it, surrounded by swirling silver mist, eyes blazing silver-white, the halo now a blinding ring. (Noetica Surge — psychic broadcast, mass consciousness assault)', 'channel', 'NOETICA', 'Surge', 0, NULL, '2026-03-20 11:55:12', '2026-03-20 11:55:12', 1),
(40, 'Spatia Pulse — The Fold', 'Figure standing with one hand outstretched, fingers pinching the air as if gripping fabric. In that grip, space itself is visibly folding — an Escher-like distortion where the background bends and curls toward the pinch point. A void-black edge is just visible at the crease. (Spatia Pulse — spatial fold, topology manipulation)', 'channel', 'SPATIA', 'Pulse', 0, NULL, '2026-03-20 11:55:12', '2026-03-20 11:55:12', 1),
(41, 'Spatia Surge — Blink Strike', 'Figure caught in the act of spatial teleportation — the body half-dissolved into a void-black hole edged with starry texture, the other half still present, arm extended mid-strike. A shockwave from the arrival pressure is still visible. The destination and origin points are both simultaneously in frame. (Spatia Surge — teleportation strike, spatial overclock)', 'channel', 'SPATIA', 'Surge', 0, NULL, '2026-03-20 11:55:12', '2026-03-20 11:55:12', 1),
(42, 'Spatia Manifest — The Unfold', 'The figure has become a doorway — their silhouette is an open portal, void black filled with a starfield and impossible M.C. Escher geometry visible through them. They remain standing but their body is the threshold between spaces. The ground around them warps into recursive architectural loops. (Spatia Manifest — portal avatar, dimensional sovereign)', 'channel', 'SPATIA', 'Manifest', 0, NULL, '2026-03-20 11:55:12', '2026-03-20 11:55:12', 1),
(43, 'Oscilla Pulse — The Rhythm', 'Figure moving in a slow, deliberate pattern — arms tracing arcs, body weight shifting in a visible cycle. Glowing spirals trail from the hands in perfect loops. Pulsating rings of soft light expand and contract from the chest in time with the movement like a heartbeat made visible. (Oscilla Pulse — cycle assertion, rhythmic presence)', 'channel', 'OSCILLA', 'Pulse', 0, NULL, '2026-03-20 11:55:12', '2026-03-20 11:55:12', 1),
(44, 'Oscilla Surge — Time Lock', 'Figure at the center of a zone where everything repeats — nearby objects cycling back to their starting positions every three seconds, visible as stuttering ghost loops. The figure stands perfectly still at the focal point of the loop, spirals orbiting them in tight synchronized rings, eyes calm and certain. (Oscilla Surge — temporal loop field, cycle dominion)', 'channel', 'OSCILLA', 'Surge', 0, NULL, '2026-03-20 11:55:12', '2026-03-20 11:55:12', 1),
(45, 'Oscilla Manifest — The Pendulum', 'A towering being of pure rhythm — the body formed from interlocking glowing spirals and pendulum arcs, roughly humanoid, each limb a different cycle at a different phase. Where it moves, the world falls into sync — fires pulse, water ripples in time, even breathing in the area synchronizes. (Oscilla Manifest — cycle avatar, rhythmic sovereign)', 'channel', 'OSCILLA', 'Manifest', 0, NULL, '2026-03-20 11:55:12', '2026-03-20 11:55:12', 1),
(46, 'Merge — The Meteor (Momentum + Gravita)', 'Two figures back-to-back, hands linked, auras bleeding into each other — crimson speed lines wrapping a deep purple gravitational core. Between them a dense projectile object hovers, vibrating with impossible acceleration while held in place by crushing mass. The ground beneath them is cracked in a perfect ring. (Harmonic Merge — kinetic siege weapon, orbital strike charge)', 'merge', 'MERGE', 'Surge', 1, 'Harmonic', '2026-03-20 11:55:12', '2026-03-20 11:55:12', 1),
(47, 'Merge — The Plasma Arc (Therma + Energia)', 'Two figures facing each other at arm length, palms pressed together between them. Where their Anima meets — infrared heat and electric blue — a column of blinding white plasma erupts upward between their joined hands, too bright to look at directly. Both figures are silhouetted against their own creation. (Harmonic Merge — plasma artillery, heavy fire)', 'merge', 'MERGE', 'Surge', 1, 'Harmonic', '2026-03-20 11:55:12', '2026-03-20 11:55:12', 1),
(48, 'Merge — The Bloom Wither (Chrono + Vitalis)', 'Two figures flanking a single target or object — one hand each extended toward it. From one side, gold time rings accelerate growth, flowers erupting in fast-forward. From the other, the same rings reverse it, the same flowers withering to dust. The object caught between them experiences both simultaneously, splitting down the middle. (Harmonic Merge — temporal biology, heal and rot)', 'merge', 'MERGE', 'Surge', 1, 'Harmonic', '2026-03-20 11:55:12', '2026-03-20 11:55:12', 1),
(49, 'Merge — The Hard Light Bridge (Lumina + Spatia)', 'A figure alone, both hands extended forward, fingers spread. From one hand prismatic solid light, from the other void-black spatial geometry. Where they meet in the air ahead, a platform of crystallized light frozen in spatial coordinates materializes — solid, walkable, hovering in nothing. (Harmonic Merge — hard light construction, spatial architecture)', 'merge', 'MERGE', 'Pulse', 1, 'Harmonic', '2026-03-20 11:55:12', '2026-03-20 11:55:12', 1),
(50, 'Merge — The Siren (Noetica + Resonantia)', 'Figure standing with mouth open in song or speech, but the sound is visible — translucent sound waves carrying silver psychic light outward in all directions. Those nearby are caught mid-step, expressions blank, minds hijacked by the frequency. The figure looks serene and terrible. (Forced Merge — psychic sound, mass hypnosis)', 'merge', 'MERGE', 'Surge', 1, 'Forced', '2026-03-20 11:55:12', '2026-03-20 11:55:12', 1),
(51, 'Merge — The Cryo Lock (Therma + Fluidica)', 'Figure with both arms sweeping outward in a wide arc. The humid air ahead flash-freezes into a wall of crystalline ice fractals spreading at speed, blue thermal color meeting the liquid air currents of Fluidica in sharp geometric explosions of frost. The figure stands at the origin point of an expanding frozen wave. (Harmonic Merge — environmental freeze, area denial)', 'merge', 'MERGE', 'Surge', 1, 'Harmonic', '2026-03-20 11:55:12', '2026-03-20 11:55:12', 1),
(52, 'Merge Initiation — The Bloom (Generic)', 'Two figures making first physical contact to initiate a merge — hands clasped or back-to-back, eyes closed in concentration. Both auras visible and distinct, circling each other like oil and water before beginning to synchronize. A visible pulse of combined light erupts from the contact point. This is the moment before the effect. (Merge Ritual — initiation beat, the money shot setup)', 'merge', 'MERGE', 'Pulse', 1, NULL, '2026-03-20 11:55:12', '2026-03-20 11:55:12', 1),
(53, 'Misfire — Self Backfire', 'Figure staggering backward, scorched or disheveled, the Anima effect clearly having hit the wrong target — themselves. Expression caught between pain and embarrassed surprise. Their own aura color splatters across their clothing. Whatever they tried to do is manifestly not what happened. (Misfire — self-hit, comedy beat)', 'misfire', NULL, 'Pulse', 0, NULL, '2026-03-20 11:55:12', '2026-03-20 11:55:12', 1),
(54, 'Misfire — The Dampen', 'Figure in a full power stance, both arms extended dramatically, expression fierce — but nothing is happening. A few weak sparks. A sad wisp of aura color. The fists are shaking with effort that is producing nothing. The dramatic pose held in complete silence and failure. (Misfire — null discharge, embarrassing fizzle)', 'misfire', NULL, 'Pulse', 0, NULL, '2026-03-20 11:55:12', '2026-03-20 11:55:12', 1),
(55, 'Misfire — Wild Surge', 'Figure at the center of total uncontrolled chaos — their own Anima erupting in every direction without intent, the effect wildly overshooting or misfiring. Expression of shock and alarm rather than intent. They are trying to stop it rather than direct it. Everything around them is caught in the crossfire. (Misfire — uncontrolled surge, collateral chaos)', 'misfire', NULL, 'Surge', 0, NULL, '2026-03-20 11:55:12', '2026-03-20 11:55:12', 1),
(56, 'Misfire — Feedback Drop', 'Figure mid-collapse — knees buckling, one hand on the ground, expression of sudden incapacitation. A dissipating halo of conflicting aura colors rings their head. Eyes rolled back or squeezed shut in pain. The Anima effect has already ended. Just the aftermath. (Misfire — psychic feedback, knocked out)', 'misfire', NULL, 'Surge', 0, NULL, '2026-03-20 11:55:12', '2026-03-20 11:55:12', 1),
(57, 'Ambient — Anima Saturated Environment', 'No primary figure or figure is distant background. The environment itself is the subject — walls, ground, air alive with visible Anima presence. Colored fractal light drifts like bioluminescent plankton. Reality is visibly thinner here. Power exists in this place whether anyone channels it or not. (Ambient — lore environment, world texture)', 'ambient', NULL, 'Trace', 0, NULL, '2026-03-20 11:55:12', '2026-03-20 11:55:12', 1),
(58, 'Ambient — Feral Anima Creature', 'A non-human creature made entirely of Anima energy — translucent, luminous, behaving according to its principle rather than animal instinct. Moving through the environment like wildlife, unbonded, untamed. Beautiful and indifferent. (Ambient — feral ecology, world alive)', 'ambient', NULL, 'Pulse', 0, NULL, '2026-03-20 11:55:12', '2026-03-20 11:55:12', 1),
(59, 'Ambient — Anima Residue', 'A location where a massive Anima event has recently ended — scorch marks, frost crystals, shattered geometry, lingering aura color fading in the air. No figure present, or figure standing in the aftermath surveying the damage. History written in the environment. (Ambient — aftermath, world consequence)', 'ambient', NULL, 'Trace', 0, NULL, '2026-03-20 11:55:12', '2026-03-20 11:55:12', 1),
(61, 'Chrono Surge — The Still Hunter', 'Figure moving with eerie deliberateness through a scene of absolute chaos — explosions, combatants, debris — all frozen mid-motion around them. They alone move, stepping through the frozen moment with one hand trailing through a frozen object as if testing reality. Gold rings barely visible at wrist. Expression: calm, predatory. Use as: apex predator reveal, time-slowed assassination approach, god-tier patience.', 'channel', 'CHRONO', 'Surge', 0, NULL, '2026-04-08 12:43:05', '2026-04-08 12:43:05', 1),
(62, 'Chrono Pulse — Age Touch', 'Figure with one palm pressed flat against a wall or object. Where the hand touches, the surface rapidly ages — stone crumbling, wood rotting, metal rusting — in a spreading ring outward from the contact point. Gold temporal rings visible up the forearm. Expression concentrated, eyes glowing faint gold. Use as: environmental ability, time-based destruction, dramatic demonstration.', 'channel', 'CHRONO', 'Pulse', 0, NULL, '2026-04-08 12:43:05', '2026-04-08 12:43:05', 1),
(63, 'Gravita Pulse — Compression Fist', 'Figure driving a punch, but the air ahead of the fist is visibly compressed into a dense purple-black disc of gravitational force — a shockwave of concentrated mass rather than kinetic impact. The ground directly beneath the punch is cracking under the localized gravity spike. Use as: ranged gravity punch, close-range mass weapon, \"heavier than it looks\" hit.', 'channel', 'GRAVITA', 'Pulse', 0, NULL, '2026-04-08 12:43:05', '2026-04-08 12:43:05', 1),
(64, 'Gravita Surge — Orbit Field', 'Figure standing in a wide stance, both arms slightly raised at sides. Three large objects — boulders, vehicles, structural elements — orbit the body in a slow, perfect elliptical path, held by the character\'s gravitational field. Expression relaxed. Use as: environmental weapon array, power demonstration, orbital siege setup.', 'channel', 'GRAVITA', 'Surge', 0, NULL, '2026-04-08 12:43:05', '2026-04-08 12:43:05', 1),
(65, 'Momentum Trace — Heat Trail', 'Figure standing still, but the air behind them carries faint crimson heat-shimmer trails — residual kinetic energy still bleeding off from recent movement. Every micro-motion leaves a ghost trail half a second behind. Use as: speed ability passive reveal, \"this person just moved very fast\", pre-combat tell.', 'channel', 'MOMENTUM', 'Trace', 0, NULL, '2026-04-08 12:43:05', '2026-04-08 12:43:05', 1),
(66, 'Momentum Surge — Ricochet Chain', 'Figure caught mid-leap between two surfaces — one foot just kicked off a wall, body angling sharply toward a second wall, third surface visible ahead. Crimson speed trails chain through every bounce point in the sequence. The path is clearly a weapon. Use as: pinball attack, wall-to-wall speed chain, environment as combat tool.', 'channel', 'MOMENTUM', 'Surge', 0, NULL, '2026-04-08 12:43:05', '2026-04-08 12:43:05', 1),
(67, 'Momentum Manifest — Afterimage Army', 'Figure standing still at center — but five or six identical crimson-traced ghost images of themselves surround the area, each in a different attack pose, each exactly where the figure was milliseconds ago. The figure is everywhere they have been. Use as: overwhelming speed manifest, afterimage attack, too fast to follow.', 'channel', 'MOMENTUM', 'Manifest', 0, NULL, '2026-04-08 12:43:05', '2026-04-08 12:43:05', 1),
(68, 'Energia Pulse — Lightning Rod Stance', 'Figure standing with both arms raised overhead, fingers spread, actively drawing electrical energy downward from the sky or ceiling — a column of blue-white lightning feeding into the body from above. Hair standing fully vertical. Expression exhilarated or straining. Use as: charging from the environment, absorbing incoming lightning, power intake.', 'channel', 'ENERGIA', 'Pulse', 0, NULL, '2026-04-08 12:43:05', '2026-04-08 12:43:05', 1),
(69, 'Energia Surge — Magnetic Acceleration', 'Figure launching a metal projectile object — but instead of throwing, both hands are extended flat, and the object is visibly accelerating down a line of electromagnetic force between the palms like a railgun. Blue plasma trace along the acceleration path. Use as: railgun technique, metal object as weapon, physics-based ranged attack.', 'channel', 'ENERGIA', 'Surge', 0, NULL, '2026-04-08 12:43:05', '2026-04-08 12:43:05', 1),
(70, 'Energia Manifest — Storm Avatar', 'The figure has become a being of living storm — body half-dissolved into a rotating column of plasma and lightning that crackles upward. The face is still visible at the center, surrounded by arcing electricity. Every surface within range is conducting. Use as: ultimate electric form, airborne combat state, environmental lightning weapon.', 'channel', 'ENERGIA', 'Manifest', 0, NULL, '2026-04-08 12:43:05', '2026-04-08 12:43:05', 1),
(71, 'Therma Pulse — Frost Armor Build', 'Figure standing with arms slightly raised, watching with calm focus as crystalline ice plates assemble themselves onto the body from moisture pulled from the air — building outward from the torso. Pale blue glow at the skin beneath. Use as: defensive ability activation, environmental armor, preparation pose.', 'channel', 'THERMA', 'Pulse', 0, NULL, '2026-04-08 12:43:05', '2026-04-08 12:43:05', 1),
(72, 'Therma Surge — Magma Step', 'Figure walking forward on a surface that liquefies beneath each footstep into glowing magma — the heat of their passage melting stone or metal underfoot. Each step leaves a cooling crater of orange-black slag behind. Expression calm and deliberate. Use as: environmental destruction walk, heat embodiment, slow unstoppable advance.', 'channel', 'THERMA', 'Surge', 0, NULL, '2026-04-08 12:43:05', '2026-04-08 12:43:05', 1),
(73, 'Therma Pulse — Breath Weapon', 'Figure with head tilted back slightly and mouth open, exhaling a visible controlled stream — either a blade of superheated thermal distortion or a cone of crystalline ice particles, depending on polarity. The temperature differential visible in the air. Use as: breath-based technique, close-range cone attack, dramatic channeling.', 'channel', 'THERMA', 'Pulse', 0, NULL, '2026-04-08 12:43:05', '2026-04-08 12:43:05', 1),
(74, 'Lumina Surge — Blinding Flash', 'Figure with both eyes closed, head bowed, arms raised slightly — and then releasing a spherical burst of pure white prismatic light in all directions simultaneously. The figure is the epicenter. Expression serene. Use as: area blind, light grenade, divine reveal, enemy incapacitation.', 'channel', 'LUMINA', 'Surge', 0, NULL, '2026-04-08 12:43:05', '2026-04-08 12:43:05', 1),
(75, 'Lumina Pulse — Refraction Clone', 'Figure standing, but slightly transparent — body partially bent light, creating a ghost image offset six inches in a different direction. One is real, one is light. Expression unchanged, making it impossible to determine which. Use as: decoy technique, light-based misdirection, illusion ability.', 'channel', 'LUMINA', 'Pulse', 0, NULL, '2026-04-08 12:43:05', '2026-04-08 12:43:05', 1),
(76, 'Lumina Manifest — Radiant Ascent', 'Figure rising upward slowly, feet leaving the ground, body radiating prismatic light from every surface — not blinding, but deeply luminous. White feather-like structures of solidified light extend from the shoulders. Expression transcendent and calm. Use as: divine power form, healing manifest, ascension moment.', 'channel', 'LUMINA', 'Manifest', 0, NULL, '2026-04-08 12:43:05', '2026-04-08 12:43:05', 1),
(77, 'Resonantia Pulse — Frequency Scan', 'Figure standing with eyes closed, one palm raised flat and slowly rotating in a wide arc. Concentric ripple rings radiate outward from the palm, bouncing off surfaces and returning information visibly — like sonar made visible. Use as: environment reading, locating the invisible, detective ability reveal.', 'channel', 'RESONANTIA', 'Pulse', 0, NULL, '2026-04-08 12:43:05', '2026-04-08 12:43:05', 1),
(78, 'Resonantia Surge — Structural Collapse', 'Figure standing with both fists at sides, a sustained bass vibration emanating from the body. The structure around them is failing — cracks spider-webbing outward from the figure\'s feet, walls fracturing, load-bearing elements beginning to buckle. Expression grim and deliberate. Use as: building destruction, seismic assault, slow inevitable demolition.', 'channel', 'RESONANTIA', 'Surge', 0, NULL, '2026-04-08 12:43:05', '2026-04-08 12:43:05', 1),
(79, 'Magnetica Pulse — Weapon Seizure', 'Figure extending one open palm toward an armed opponent. The opponent\'s weapon is visibly yanked from their grip — mid-air, flying toward the character\'s hand. Blue electromagnetic lines trace the seizure path. Use as: disarming technique, crowd control, \"that\'s mine now\" moment.', 'channel', 'MAGNETICA', 'Pulse', 0, NULL, '2026-04-08 12:43:05', '2026-04-08 12:43:05', 1),
(80, 'Magnetica Surge — Pole Shift', 'Figure dropping into a wide stance, both arms thrusting outward in opposite directions. Two massive opposing magnetic poles manifest — objects to the left are violently attracted, objects to the right equally repelled. A line of nothing between the two forces. Use as: crowd separation, area control, physics battlefield.', 'channel', 'MAGNETICA', 'Surge', 0, NULL, '2026-04-08 12:43:05', '2026-04-08 12:43:05', 1),
(81, 'Magnetica Manifest — Iron Colossus', 'The figure is now sheathed in a full suit of assembled ferrous debris — metal shards, structural beams, vehicles — all compacted magnetically into an improvised armor ten feet tall. The figure moves at the center, barely visible. Blue field lines pulse across every surface. Use as: ultimate armor form, titan combat state, environmental weapon as body.', 'channel', 'MAGNETICA', 'Manifest', 0, NULL, '2026-04-08 12:43:05', '2026-04-08 12:43:05', 1),
(82, 'Fluidica Pulse — Liquid Body', 'Figure mid-dodge, but the torso has literally flowed around the incoming attack — the body splitting and rejoining like water around an obstacle, the attack passing through empty space that was just flesh. Expression focused and calm. Use as: physical pass-through dodge, impossibly fluid evasion, liquid-state ability.', 'channel', 'FLUIDICA', 'Pulse', 0, NULL, '2026-04-08 12:43:05', '2026-04-08 12:43:05', 1),
(83, 'Fluidica Surge — Maelstrom Form', 'Figure at the center of a rising column of water-like atmospheric current — a vertical whirlpool of liquefied air with the figure as the calm axis. Enemies within range are caught in the current. Use as: crowd control vortex, defensive dome, environmental battlefield control.', 'channel', 'FLUIDICA', 'Surge', 0, NULL, '2026-04-08 12:43:05', '2026-04-08 12:43:05', 1),
(84, 'Cohesiva Pulse — Bind', 'Figure extending both hands toward a target, amber lattice energy projecting forward and wrapping around the target\'s limbs — crystallized molecular bonds locking joints in place. Expression of precise concentration. No weapons, only structured will. Use as: restraint ability, capture technique, combat immobilization.', 'channel', 'COHESIVA', 'Pulse', 0, NULL, '2026-04-08 12:43:05', '2026-04-08 12:43:05', 1),
(85, 'Cohesiva Surge — Fortress Stance', 'Figure standing still, eyes closed, as the environment fuses around them into a shell — ground rising, walls drawing in, stone and metal lattice-bonding into an improvised fortification with the figure at the center. The world itself becomes armor. Use as: defensive ultimate, siege preparation, \"you can\'t move me\" moment.', 'channel', 'COHESIVA', 'Surge', 0, NULL, '2026-04-08 12:43:05', '2026-04-08 12:43:05', 1),
(86, 'Probabilis Pulse — Lucky Deflection', 'Figure standing in a completely relaxed non-combat pose while an incoming attack curves inexplicably around them — the projectile or strike path bending at the last moment due to improbable physics. The figure hasn\'t moved. May not even have noticed. Use as: passive luck field, comedic invincibility, reality-bending defense.', 'channel', 'PROBABILIS', 'Pulse', 0, NULL, '2026-04-08 12:43:05', '2026-04-08 12:43:05', 1),
(87, 'Probabilis Surge — Cascade Event', 'Figure crouched with hands on the ground, eyes glowing with datacorrupt visual static. A chain of improbable events radiates outward in sequence — the first causes the second causes the third, each more impossible. The figure is the origin event, grinning. Use as: rube goldberg combat technique, battlefield manipulation, chaos catalyst.', 'channel', 'PROBABILIS', 'Surge', 0, NULL, '2026-04-08 12:43:05', '2026-04-08 12:43:05', 1),
(88, 'Probabilis Manifest — The Variable', 'The figure has become visually unstable — their form flickering between multiple possible physical states simultaneously, each one real, none certain. The face changes. The height changes. The clothes change. Only the eyes are constant. Reality glitches in rings around them. Use as: true probability avatar, identity dissolution, ultimate chaos form.', 'channel', 'PROBABILIS', 'Manifest', 0, NULL, '2026-04-08 12:43:05', '2026-04-08 12:43:05', 1),
(89, 'Vitalis Pulse — Regeneration Visible', 'Figure bearing a visible wound — and in real time, the wound is closing. Emerald bio-light traces the healing front as tissue visibly knits back together. The figure watches this with focused concentration, accelerating it. Use as: mid-combat healing, stamina demonstration, \"that won\'t stop me\" beat.', 'channel', 'VITALIS', 'Pulse', 0, NULL, '2026-04-08 12:43:05', '2026-04-08 12:43:05', 1),
(90, 'Vitalis Surge — Root Cage', 'Figure with both hands thrust into the ground to the wrists, emerald veins blazing up both arms. From the ground ahead, a cage of massive organic roots and vines erupts — encircling and locking down the target zone. The figure directs it with focused will. Use as: area denial, capture technique, nature-based cage.', 'channel', 'VITALIS', 'Surge', 0, NULL, '2026-04-08 12:43:05', '2026-04-08 12:43:05', 1),
(91, 'Noetica Pulse — Memory Read', 'Figure standing with two fingers pressed gently to another person\'s temple (person implied). Eyes closed, silver mist flowing from the contact point inward. Expression neutral and focused — reading, not forcing. Use as: memory access ability, investigation technique, gentle psychic intrusion.', 'channel', 'NOETICA', 'Pulse', 0, NULL, '2026-04-08 12:43:05', '2026-04-08 12:43:05', 1),
(92, 'Noetica Surge — Psychic Scream', 'Figure mid-scream — not a physical sound but a psychic one, silver shockwave blasting outward from the open mouth. Everyone nearby clutches their heads. The figure is the only one unaffected. Use as: area psychic assault, desperate release, the sound that ends conversations.', 'channel', 'NOETICA', 'Surge', 0, NULL, '2026-04-08 12:43:05', '2026-04-08 12:43:05', 1),
(93, 'Noetica Manifest — The Witness', 'The figure floats three feet off the ground, surrounded by dozens of thin silver threads extending outward to every conscious being in range — each thread a live connection. The eyes are open and see everything simultaneously. Expression overwhelmed but controlled. Use as: omniscient awareness form, battlefield coordinator, psychic network hub.', 'channel', 'NOETICA', 'Manifest', 0, NULL, '2026-04-08 12:43:05', '2026-04-08 12:43:05', 1),
(94, 'Spatia Pulse — Window Cut', 'Figure with one finger drawing a line through the air — and the line stays, a thin void-black seam in reality along the traced path. Through the seam, a different location is faintly visible. Use as: scouting ability, portal initiation, reality cutting technique.', 'channel', 'SPATIA', 'Pulse', 0, NULL, '2026-04-08 12:43:05', '2026-04-08 12:43:05', 1),
(95, 'Spatia Surge — Pocket Pull', 'Figure reaching into a void-black spatial pocket torn open in the air beside them — arm disappearing into empty space up to the shoulder, rummaging for something inside reality\'s gap. Use as: storing or retrieving objects, spatial inventory, mid-combat resupply.', 'channel', 'SPATIA', 'Surge', 0, NULL, '2026-04-08 12:43:05', '2026-04-08 12:43:05', 1),
(96, 'Oscilla Pulse — Sync Aura', 'Figure extending both arms forward slowly, palms outward, pulsing rings of warm light spreading from the chest. Allies nearby begin moving in subtle synchronization — breathing, footsteps, even blink timing aligning. Use as: team buff, coordination ability, rhythmic synchronization.', 'channel', 'OSCILLA', 'Pulse', 0, NULL, '2026-04-08 12:43:05', '2026-04-08 12:43:05', 1),
(97, 'Oscilla Surge — Desync Field', 'Figure at the center of a field where rhythm collapses — enemies nearby stumble, their own heartbeats disrupted, motor control firing out of sequence. The figure stands in perfect measured stillness at the eye of the desynchronization. Use as: enemy debuff, disorientation field, anti-rhythm attack.', 'channel', 'OSCILLA', 'Surge', 0, NULL, '2026-04-08 12:43:05', '2026-04-08 12:43:05', 1),
(98, 'Merge — The Seismic Spiral (Gravita + Resonantia)', 'Two figures back to back, one sending deep bass vibration into the ground while the other amplifies the gravity differential — the earth ahead buckles in a spiral pattern, cracks chasing a logarithmic path outward. Where frequency meets gravity, the ground opens. Use as: structural devastation, area denial, siege-breaking technique.', 'merge', 'MERGE', 'Surge', 1, 'Harmonic', '2026-04-08 12:43:05', '2026-04-08 12:43:05', 1),
(99, 'Merge — Ghost Velocity (Probabilis + Momentum)', 'One figure moving at extreme speed, the other manipulating probability to ensure every high-speed action produces the perfect improbable outcome — a strike that hits despite being aimed wrong, a dodge that works despite impossible angles. Together they are inevitable. Use as: aimbot + speed combo, impossible precision, luck-guided blitz.', 'merge', 'MERGE', 'Surge', 1, 'Harmonic', '2026-04-08 12:43:05', '2026-04-08 12:43:05', 1),
(100, 'Merge — The Living Glacier (Therma + Cohesiva)', 'One figure pulling all thermal energy from a zone to absolute cold, the other bonding every molecule in place as it freezes — creating not just ice but an invincible crystalline lattice that nothing can break or melt. The two figures stand encased at its core. Use as: inescapable area freeze, fortress construction, environmental lockdown.', 'merge', 'MERGE', 'Manifest', 1, 'Harmonic', '2026-04-08 12:43:05', '2026-04-08 12:43:05', 1),
(101, 'Merge — The Rewrite (Noetica + Probabilis)', 'Two figures flanking a single target — one reads the target\'s anticipated choices while the other alters the probability of each outcome. Together they steer reality: the target does what the figures need them to do, convinced it was their own decision. Expression between them: quiet, terrifying satisfaction. Use as: mind control through probability, the perfect manipulation, the most dangerous merge.', 'merge', 'MERGE', 'Surge', 1, 'Forced', '2026-04-08 12:43:05', '2026-04-08 12:43:05', 1),
(102, 'Merge — Tidal Bore (Fluidica + Momentum)', 'Two figures in unison, both at a dead sprint, auras blending into a single hydrodynamic torpedo of pure kinetic fluid — the leading edge liquefies air into a battering wave of compressed velocity. Whatever is in the path is destroyed by moving water that is also a fist. Use as: breakthrough charge, wall-breaker technique, unstoppable combination rush.', 'merge', 'MERGE', 'Surge', 1, 'Harmonic', '2026-04-08 12:43:05', '2026-04-08 12:43:05', 1),
(103, 'Merge — Photon Cage (Lumina + Spatia)', 'Two figures in a wide stance around a contained area. One projects hard light walls, the other folds space at their edges — creating a cage where the walls can be anywhere and the interior can be any size. The prisoner sees no escape. Use as: perfect containment, dimensional prison, inescapable hard light enclosure.', 'merge', 'MERGE', 'Surge', 1, 'Harmonic', '2026-04-08 12:43:05', '2026-04-08 12:43:05', 1),
(104, 'Dissonant Merge — The Fracture (Gravita + Spatia — Forced)', 'Two figures straining against each other in a forced merge — their auras visibly fighting, purple gravity crushing inward while void-black spatial topology pulls outward. Where the two forces meet, reality itself is tearing — a raw rift, neither a portal nor a collapse, just a wound in space. Both figures are losing control. Use as: catastrophic merge failure, villain\'s forbidden technique, universe-damaging moment.', 'merge', 'MERGE', 'Manifest', 1, 'Dissonant', '2026-04-08 12:43:05', '2026-04-08 12:43:05', 1),
(105, 'Misfire — Hiccup Pulse', 'Figure attempting a controlled Pulse but producing a series of tiny, uncontrolled bursts at random intervals — small pops of their Anima color going off like hiccups. Completely undignified. Expression of mortified frustration. Use as: comedic training scene, power instability, embarrassing reveal in front of audience.', 'misfire', NULL, 'Trace', 0, NULL, '2026-04-08 12:43:05', '2026-04-08 12:43:05', 1),
(106, 'Misfire — Redirect Backfire', 'Figure having attempted to redirect an incoming Anima attack with their own ability — but the two forces have combined wrong and the redirected result has come back twice as large, directly at the figure. They see it coming. Expression: oh no. Use as: technique failure, \"that made it worse\", escalation beat.', 'misfire', NULL, 'Surge', 0, NULL, '2026-04-08 12:43:05', '2026-04-08 12:43:05', 1),
(107, 'Ambient — Anima Storm Weather', 'The sky above is the subject — massive weather event made entirely of Anima energy rather than meteorological cause. Lightning the wrong color, clouds moving against the wind, temperature dropping in geometric patches. The world reacting to an unseen Anima event happening somewhere nearby. Use as: establishing shot, world texture, approaching threat.', 'ambient', NULL, 'Surge', 0, NULL, '2026-04-08 12:43:05', '2026-04-08 12:43:05', 1);
INSERT INTO `poses_anima` (`id`, `name`, `description`, `category`, `anima_type`, `hierarchy_level`, `is_merge`, `merge_type`, `created_at`, `updated_at`, `active`) VALUES
(108, 'Ambient — The Crater Memory', 'A vast crater, perfectly circular, with all the visual signatures of a long-past Manifest-level event — fused glass at the center, residual aura color faintly visible in the soil, geometry at the edge too regular to be natural. A figure standing at the rim, small against the scale. Use as: lore establishing shot, history told by geography, power scale reference.', 'ambient', NULL, 'Manifest', 0, NULL, '2026-04-08 12:43:05', '2026-04-08 12:43:05', 1),
(109, 'Hierarchy Transition — Trace to Pulse Ignition', 'Figure in a Trace-level pose — dormant, still, barely glowing — and then the exact moment of Pulse ignition captured: the aura color flaring outward from the chest, eyes snapping open, body involuntarily straightening. The transition between sleeping and waking power. Use as: power awakening beat, fight beginning, first use of ability.', 'channel', NULL, 'Trace', 0, NULL, '2026-04-08 12:43:05', '2026-04-08 12:43:05', 1),
(110, 'Hierarchy Transition — Surge Collapse to Trace', 'Figure at the aftermath of an overextended Surge — aura color rapidly fading, body trembling, one knee nearly touching the ground. The power is retreating back to baseline. Expression of forced calm concealing the cost. Use as: post-ultimate exhaustion, power cost visible, strategic vulnerability window.', 'channel', NULL, 'Surge', 0, NULL, '2026-04-08 12:43:05', '2026-04-08 12:43:05', 1);
