INSERT INTO `sketch_templates` (`id`, `name`, `core_idea`, `shot_type`, `camera_angle`, `perspective`, `entity_slots`, `tags`, `example_prompt`, `entity_type`, `active`, `category_id`, `created_at`, `is_ingredient`) VALUES
(1, 'Establishing Shot – Wide Location', 'The audience learns where the story is taking place', 'ESTABLISHING', 'HIGH', 'WIDE', '[\"ENVIRONMENT\"]', '[\"establishing\",\"wide\",\"location\",\"exterior\"]', 'Extreme wide angle view of {{ENVIRONMENT}}, cinematic establishing shot, 2-point perspective, dramatic lighting', 'sketches', 1, 6, '2025-11-03 11:21:22', 1),
(2, 'Establishing Shot – Interior Room', 'Shows the interior of a building and gives a sense of scale', 'ESTABLISHING', 'HIGH', 'WIDE', '[\"ENVIRONMENT\",\"PROP\"]', '[\"interior\",\"room\",\"establishing\",\"wide\"]', 'Wide angle interior of {{ENVIRONMENT}}, {{PROP}} in foreground, soft ambient lighting, architectural detail', 'sketches', 1, 6, '2025-11-03 11:21:22', 1),
(3, 'Two-Shot Dialogue – Over-Shoulder', 'Two characters converse, focus on interaction', 'OVER_SHOULDER', 'EYE', 'MEDIUM', '[\"CHARACTER\",\"CHARACTER\"]', '[\"dialogue\",\"two-shot\",\"over-shoulder\",\"conversation\"]', 'Over-shoulder shot, {{CHARACTER_1}} facing {{CHARACTER_2}}, medium shot, eye level, natural dialogue framing', 'sketches', 1, 4, '2025-11-03 11:21:22', 1),
(4, 'Close-Up Profile – Emotional Beat', 'Single character emotional reaction from the side', 'CLOSE_UP', 'EYE', 'CLOSE', '[\"CHARACTER\"]', '[\"close-up\",\"profile\",\"emotion\",\"intimate\"]', 'Profile close-up of {{CHARACTER}}, emotional expression, shallow depth of field, cinematic lighting', 'sketches', 1, 4, '2025-11-03 11:21:22', 1),
(5, 'Extreme Close-Up (ECU) – Detail', 'Highlights a specific detail', 'ECU', 'EYE', 'EXTREME_CLOSE', '[\"DETAIL\"]', '[\"detail\",\"ecu\",\"focus\",\"texture\"]', 'Extreme close-up of {{DETAIL}}, macro detail, sharp focus, dramatic texture', 'sketches', 1, 5, '2025-11-03 11:21:22', 1),
(6, 'Two-Shot – Low Angle Power Stance', 'Two characters, power dynamics', 'TWO_SHOT', 'LOW', 'MEDIUM', '[\"CHARACTER\",\"CHARACTER\"]', '[\"low-angle\",\"power\",\"two-shot\",\"dramatic\"]', 'Low angle shot, {{CHARACTER_1}} and {{CHARACTER_2}} in power stance, dramatic perspective, intimidating framing', 'sketches', 1, 4, '2025-11-03 11:21:22', 1),
