(137, 'The Void Scale (Isolation)', 'Tiny character, massive empty space', 'ESTABLISHING', 'HIGH', 'EXTREME_WIDE', '[\"CHARACTER\",\"EMPTY_SPACE\"]', '[\"void\",\"isolation\",\"negative-space\",\"scale\",\"lonely\"]', 'Isolation: Tiny {{CHARACTER}} placed in the bottom corner of the frame, the rest is massive, empty {{EMPTY_SPACE}} (sky/wall), overwhelming negative space', 'sketches', 1, 3, '2026-01-21 14:16:38', 1),
(138, 'The Ground Skim (Speed)', 'Camera inches off the floor, rushing forward', 'TRACKING', 'LOW', 'WIDE', '[\"GROUND_TEXTURE\",\"SUBJECT\"]', '[\"ground-skim\",\"speed\",\"rushing\",\"low-angle\",\"kinetic\"]', 'High velocity: Camera skimming inches above the {{GROUND_TEXTURE}}, debris blurring past the lens, rushing towards {{SUBJECT}}, sense of speed', 'sketches', 1, 3, '2026-01-21 14:16:38', 1),
(139, 'The Z-Axis Rush', 'Object flying directly into the camera', 'ACTION', 'EYE', 'CLOSE', '[\"OBJECT\",\"CAMERA\"]', '[\"z-axis\",\"3d\",\"depth\",\"impact\",\"incoming\"]', '3D Impact: {{OBJECT}} flying directly at the camera lens along the Z-axis, extreme foreshortening, breaking the fourth wall', 'sketches', 1, 3, '2026-01-21 14:16:38', 1),
(140, 'The Impact Shake', 'Camera jolted by explosion or footstep', 'ACTION', 'EYE', 'MEDIUM', '[\"SOURCE\",\"DEBRIS\"]', '[\"camera-shake\",\"impact\",\"chaos\",\"war\",\"vibration\"]', 'Visceral impact: The camera frame is physically jolted/blurred by the shockwave of {{SOURCE}}, dust and {{DEBRIS}} shaken loose from the ceiling', 'sketches', 1, 3, '2026-01-21 14:16:38', 1);
INSERT INTO `sketch_templates` (`id`, `name`, `core_idea`, `shot_type`, `camera_angle`, `perspective`, `entity_slots`, `tags`, `example_prompt`, `entity_type`, `active`, `category_id`, `created_at`, `is_ingredient`) VALUES
(141, 'The Pivot Reveal', 'Camera circling subject to reveal what they see', 'TRACKING', 'EYE', 'MEDIUM', '[\"CHARACTER\",\"REVEAL_TARGET\"]', '[\"pivot\",\"orbit\",\"reveal\",\"tension\",\"turn\"]', 'Orbit shot: Camera pivots 180 degrees around {{CHARACTER}}\'s head to reveal the {{REVEAL_TARGET}} they are staring at', 'sketches', 1, 3, '2026-01-21 14:16:38', 1),
(142, 'The Motion Smear', 'Physics-based blur of high speed object', 'ACTION', 'EYE', 'MEDIUM', '[\"FAST_OBJECT\",\"BACKGROUND\"]', '[\"motion-smear\",\"blur\",\"speed\",\"physics\",\"shutter\"]', 'Shutter speed physics: {{FAST_OBJECT}} is moving so fast it is rendered as a directional motion smear against the {{BACKGROUND}}, raw kinetic energy', 'sketches', 1, 3, '2026-01-21 14:16:38', 1),
(143, 'The Puddle Reflection', 'Looking down at reflection in water', 'REFLECTION', 'HIGH', 'CLOSE', '[\"REFLECTION_SUBJECT\",\"GROUND\"]', '[\"puddle\",\"reflection\",\"rain\",\"oshii\",\"melancholy\"]', 'Melancholy perspective: Camera focused on a dirty rain puddle on the {{GROUND}}, seeing the perfect reflection of {{REFLECTION_SUBJECT}} within it', 'sketches', 1, 3, '2026-01-21 14:16:38', 1),
(144, 'Suspended Particles (Time Stop)', 'Dust/Ash/Snow frozen in air', 'CLOSE_UP', 'EYE', 'EXTREME_CLOSE', '[\"PARTICLE_TYPE\",\"LIGHT\"]', '[\"particles\",\"time-stop\",\"freeze\",\"detail\",\"atmosphere\"]', 'Time frozen: {{PARTICLE_TYPE}} (ash/snow/dust) suspended motionless in the air, catching the {{LIGHT}}, extreme detail', 'sketches', 1, 3, '2026-01-21 14:16:38', 1),
(145, 'The Steam Shroud', 'Character obscured by heavy vapor', 'CLOSE_UP', 'EYE', 'CLOSE', '[\"CHARACTER\",\"STEAM_SOURCE\"]', '[\"steam\",\"shroud\",\"fog\",\"obscured\",\"breath\"]', 'Atmospheric obscurity: {{CHARACTER}} partially hidden by heavy venting steam or breath fog from {{STEAM_SOURCE}}, silhouettes in the vapor', 'sketches', 1, 3, '2026-01-21 14:16:38', 1),
(146, 'The Rim Silhouette', 'Black screen, only light outline visible', 'SILHOUETTE', 'EYE', 'CLOSE', '[\"CHARACTER\",\"RIM_LIGHT\"]', '[\"rim-light\",\"silhouette\",\"mystery\",\"darkness\",\"outline\"]', 'Total darkness: Screen is pitch black, only the thin {{RIM_LIGHT}} rim-light outline of {{CHARACTER}}\'s profile is visible, defining the shape', 'sketches', 1, 3, '2026-01-21 14:16:38', 1),
(147, 'The Heat Shimmer', 'Telephoto distortion caused by hot air', 'ESTABLISHING', 'EYE', 'WIDE', '[\"DISTANT_OBJECT\",\"HEAT_SOURCE\"]', '[\"heat-shimmer\",\"haze\",\"telephoto\",\"distortion\",\"hot\"]', 'Telephoto compression: The image of {{DISTANT_OBJECT}} is rippling and distorted by the heat shimmer rising from {{HEAT_SOURCE}}, oppressive atmosphere', 'sketches', 1, 3, '2026-01-21 14:16:38', 1),
(148, 'The Mirror Twin (Symmetry)', 'Perfect symmetrical composition of two opposing forces', 'TWO_SHOT', 'EYE', 'MEDIUM', '[\"CHARACTER_A\",\"CHARACTER_B\"]', '[\"symmetry\",\"duality\",\"mirror\",\"luminari\",\"balance\"]', 'Visual Duality: {{CHARACTER_A}} and {{CHARACTER_B}} standing in perfect mirror symmetry, dividing the frame, lighting split between Warm and Cold, representing the schism', 'sketches', 1, 3, '2026-01-21 18:15:45', 1),
(149, 'The Tyrant\'s Throne (Low Angle)', 'Looking up at absolute authority', 'ESTABLISHING', 'LOW', 'WIDE', '[\"CHARACTER\",\"THRONE_ROOM\"]', '[\"tyrant\",\"low-angle\",\"dominance\",\"authority\",\"noctura\"]', 'Oppressive authority: Extreme low angle looking up at {{CHARACTER}} seated on a throne in {{THRONE_ROOM}}, geometric lines leading to the center, god-like perspective', 'sketches', 1, 3, '2026-01-21 18:15:45', 1),
(150, 'The Harmony Flow (Long Take)', 'Continuous camera movement following connection', 'TRACKING', 'EYE', 'MEDIUM', '[\"CHARACTER\",\"ENVIRONMENT\"]', '[\"long-take\",\"flow\",\"harmony\",\"connection\",\"eve\"]', 'Unbroken fluid tracking shot: Camera floats weightlessly around {{CHARACTER}}, matching their movements perfectly as they interact with {{ENVIRONMENT}}, symbolizing harmony', 'sketches', 1, 3, '2026-01-21 18:15:45', 1),
(151, 'The HUD Overlay (True-Sight)', 'World seen through digital augmentation', 'POV', 'EYE', 'POV', '[\"TARGET\",\"DATA_STREAM\"]', '[\"hud\",\"augmented-reality\",\"data\",\"kaori\",\"cybernetic\"]', 'First-person POV: Viewing {{TARGET}} through a digital interface, overlaid with {{DATA_STREAM}} code, wireframe topography, and heat signatures (True-Sight)', 'sketches', 1, 3, '2026-01-21 18:15:45', 1),
(152, 'The Time-Lapse Anchor', 'Subject remains still while world speeds by', 'MONTAGE', 'EYE', 'WIDE', '[\"STILL_SUBJECT\",\"MOVING_WORLD\"]', '[\"time-lapse\",\"anchor\",\"time-distortion\",\"kaelen\",\"stillness\"]', 'Temporal distortion: {{STILL_SUBJECT}} sits perfectly motionless and sharp in the center, while the {{MOVING_WORLD}} around them is a blur of light trails and time-lapse motion', 'sketches', 1, 3, '2026-01-21 18:15:45', 1),
(153, 'The Cable Weave (Integration)', 'Character visually merging with background cables', 'CLOSE_UP', 'EYE', 'CLOSE', '[\"CHARACTER\",\"MACHINERY\"]', '[\"cable-weave\",\"body-horror\",\"integration\",\"kaelen\",\"tech\"]', ' biomechanical composition: {{CHARACTER}} visually indistinguishable from the background {{MACHINERY}}, cables and wires weaving through the frame and body, loss of self', 'sketches', 1, 3, '2026-01-21 18:15:45', 1),
(154, 'The Shaky Cam (Chaos)', 'Handheld camera simulation for raw kinetic energy', 'ACTION', 'EYE', 'MEDIUM', '[\"CHARACTER\",\"ACTION\"]', '[\"shaky-cam\",\"handheld\",\"grit\",\"wasteland\",\"mira\"]', 'Documentary war-footage style: Handheld camera shaking violently as {{CHARACTER}} performs {{ACTION}}, motion blur, dust on lens, raw survivalist energy', 'sketches', 1, 3, '2026-01-21 18:15:45', 1),
(155, 'The Phantom Cut (Speed)', 'Character disappears between frames due to speed', 'ACTION', 'EYE', 'WIDE', '[\"CHARACTER\",\"ENEMIES\"]', '[\"phantom-cut\",\"speed\",\"teleport\",\"rin\",\"stealth\"]', 'Visualizing speed: {{CHARACTER}} is not visible, only the after-image trail and the falling bodies of {{ENEMIES}}, implying movement too fast for the shutter', 'sketches', 1, 3, '2026-01-21 18:15:45', 1),
(156, 'The Dust Silhouette', 'Character revealed through clearing smoke/sand', 'SILHOUETTE', 'LOW', 'WIDE', '[\"CHARACTER\",\"STORM\"]', '[\"dust\",\"silhouette\",\"reveal\",\"wasteland\",\"storm\"]', 'Dramatic reveal: {{CHARACTER}} standing as a dark silhouette within a swirling {{STORM}} of sand/dust, glowing eyes visible through the haze', 'sketches', 1, 3, '2026-01-21 18:15:45', 1),
(157, 'The Halo Effect (Backlight)', 'Soft spiritual glow around the subject', 'CLOSE_UP', 'LOW', 'CLOSE', '[\"CHARACTER\",\"LIGHT\"]', '[\"halo\",\"spiritual\",\"soft\",\"taro\",\"empathy\"]', 'Ethereal portrait: {{CHARACTER}} backlit by a soft {{LIGHT}}, creating a glowing halo effect around their hair/silhouette, dream-like diffusion, pastel tones', 'sketches', 1, 3, '2026-01-21 18:15:45', 1),
(158, 'The Liquid Transition', 'Scene melting into the next (Dream Logic)', 'MONTAGE', 'EYE', 'MEDIUM', '[\"SCENE_A\",\"SCENE_B\"]', '[\"liquid\",\"transition\",\"dream\",\"sleepers\",\"surreal\"]', 'Surreal morphing: The architecture of {{SCENE_A}} is melting and dripping like liquid, transforming seamlessly into the shape of {{SCENE_B}}, dream logic', 'sketches', 1, 3, '2026-01-21 18:15:45', 1);
