(3, 0, 1, 'anime studio J.C. Staff style (J.C. Staff)', 1, 'Balanced, polished commercial anime; realistic proportions; works well for school-life, romance, and comedy.', 'clean lineart, balanced proportions, soft colors, polished, natural character expressions, smooth shading', 'soft, natural, vibrant', '2025-09-01 12:54:00', '2026-01-05 23:03:45'),
(6, 0, 1, 'anime studio Sunrise style (Sunrise)', 1, 'Epic mecha & sci-fi storytelling; large-scale environments; colorful, iconic character design.', 'detailed sci-fi architecture, bold character design, vibrant colors, dynamic composition, futuristic technology', 'vibrant, epic, futuristic', '2025-09-01 12:54:00', '2026-01-05 23:03:44'),
(11, 0, 1, 'anime studio CLAMP style (CLAMP)', 1, 'Elegant and stylized manga-inspired lines; fantasy and romance; ornate and flowing character designs.', 'elegant lineart, flowing hair and clothing, delicate proportions, fantasy elements, expressive eyes, intricate detail', 'delicate, flowing, pastel', '2025-09-01 12:54:00', '2026-02-18 21:19:05'),
(12, 0, 1, 'anime studio Kyoto Animation style (Kyoto Animation)', 1, 'Soft, polished, emotionally resonant; expressive faces and body language; detailed, vibrant backgrounds.', 'smooth cel-shading, cinematic lighting, warm atmosphere, expressive characters, lush backgrounds, consistent proportions', 'warm, soft, vibrant', '2025-09-01 12:54:00', '2026-01-19 12:36:54'),
(13, 0, 1, 'Realistic', 1, 'Three-point lighting with a softbox flash, creating a dramatic effect. Photo has a depth of field. Highly detailed, hyper-realistic, 8k resolution, 32k resolution, masterpiece', NULL, NULL, '2025-09-08 17:27:27', '2026-01-01 18:28:41'),
